-- dev_lessons share_summary updates generated on 2026-07-16T01:55:10.001Z
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos os seus súditos se curvassem diante de uma grande estátua de ouro. Enquanto a multidão obedecia ao som dos instrumentos musicais, os jovens hebreus Sadraque, Mesaque e Abednego permaneceram de pé. Diante da ameaça de serem lançados em uma fornalha ardente, eles declararam ao rei que não serviriam a outros deuses nem adorariam a imagem. Os três mantiveram sua posição firme, recusando-se a negociar sua fé, mesmo enfrentando a morte imediata pelo monarca.' WHERE "id" = '007e8630-e9e5-4d72-b59b-b1a57f96c090';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos se prostrassem ao som da música, sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abede-Nego recusaram-se a adorar a imagem, permanecendo de pé diante do monarca. Confrontados pelo governante, os três jovens mantiveram sua posição com firmeza, declarando que não adorariam outros deuses. Eles enfrentaram a autoridade real sem negociações, preparados para encarar as consequências severas impostas por sua escolha diante da multidão.' WHERE "id" = '00ff9dc6-f0df-4755-ab45-3336f120839e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em uma terra distante, o filho mais novo ficou na miséria, alimentando porcos e passando fome. Reconhecendo a abundância na casa de seu pai, decidiu retornar e pedir emprego como um servo. Ao se aproximar, foi avistado pelo pai, que correu ao seu encontro e o abraçou calorosamente. O pai ordenou prontamente que vestissem o jovem com as melhores roupas, colocassem um anel em seu dedo e preparassem um banquete para celebrar seu retorno.' WHERE "id" = '0118f762-7f79-4ccc-a111-dc130891a1a9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos se prostrassem ao som de música, sob pena de morte na fornalha. Sadraque, Mesaque e Abednego recusaram o comando e foram levados à presença do monarca. Pressionados a ceder, os três homens mantiveram sua posição com firmeza. Declararam ao rei que seu Deus poderia livrá-los da condenação, mas afirmaram que, ainda que isso não ocorresse, jamais adorariam os deuses do rei nem a sua estátua dourada.' WHERE "id" = '01d8a7a3-46a4-4783-ba2d-adcf08894f4c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após ser coroado rei, o jovem Salomão recebeu de Deus a oportunidade única de pedir o que desejasse. Em vez de buscar riquezas, vitórias militares ou a destruição de seus inimigos, Salomão solicitou humildemente o dom do discernimento para governar seu povo com justiça. Reconhecendo os limites do seu próprio juízo, ele demonstrou total confiança na sabedoria divina. Por essa atitude, Deus respondeu prontamente ao seu pedido, concedendo-lhe não apenas a sabedoria desejada, mas também uma grande abundância.' WHERE "id" = '01e7f6cf-156e-409b-954e-4801d2323710';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem foi atacado por salteadores, ficando ferido e desamparado na estrada. Diversos viajantes passaram pelo local, mas ignoraram a vítima. Entretanto, um samaritano, ao cruzar o caminho, avistou o homem ferido e sentiu compaixão. Ele aproximou-se, tratou os machucados com óleo e vinho, e colocou o homem sobre seu próprio animal. Levou-o a uma estalagem, cuidou dele durante a noite e, ao partir, pagou ao hospedeiro para que garantisse a continuidade de sua plena recuperação física.' WHERE "id" = '01f8e0aa-c8c7-43d8-8b29-5518af705cbd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em Babilônia, enfrentou uma ordem real para consumir alimentos proibidos pela sua lei. Com firmeza, ele recusou a comida do rei, optando por não se contaminar. Daniel propôs ao responsável uma alternativa de dieta, baseada em vegetais e água, por um período de dez dias. Ao final do teste, ele e seus amigos apresentavam uma aparência mais saudável e robusta que os demais jovens que comeram das iguarias oferecidas pelo monarca babilônico Nabucodonosor.' WHERE "id" = '021ea3fc-a09b-416f-b53e-77b497972064';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem tinha dois filhos. O mais novo pediu sua parte da herança, partiu para um país distante e desperdiçou tudo o que possuía vivendo de forma desregrada. Ao enfrentar uma severa fome, caiu em si e decidiu retornar para casa pedindo perdão ao pai. Mesmo vindo de longe, o pai o avistou e correu ao seu encontro, abraçando-o com alegria. Ele ordenou que servissem um banquete e celebrassem o retorno daquele que estava perdido e agora vivia.' WHERE "id" = '0250a559-6c26-43be-9c9c-b52682856cd4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi descobriu que o rei Saul pretendia matá-lo e decidiu buscar seu amigo Jônatas para revelar o grave perigo. Jônatas, filho do rei, ouviu o relato de Davi e escolheu proteger o companheiro, apesar da posição de seu pai. Os dois estabeleceram um compromisso de lealdade mútua, firmando uma aliança diante de Deus para garantir a segurança de Davi. Eles enfrentaram juntos a ameaça real contra a vida de Davi, decidindo agir com honestidade diante daquela situação crítica.' WHERE "id" = '02e20acb-694d-483a-94f7-8008c40ab5b3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O gigante Golias aterrorizava o exército de Israel com ameaças diárias, enquanto os soldados permaneciam paralisados pelo medo. Davi, um jovem pastor, apresentou-se ao rei Saul para enfrentar o filisteu sozinho. Embora fosse apenas um adolescente sem armadura, Davi recordou suas vitórias passadas contra um leão e um urso enquanto protegia suas ovelhas. Confiante no auxílio divino que o livrou anteriormente, o jovem decidiu ignorar a zombaria dos soldados e avançou corajosamente contra o formidável guerreiro inimigo.' WHERE "id" = '02ebe8aa-dcdf-4b1b-9d71-14d6c9ae85b9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança vivendo desregradamente, o filho mais novo enfrentou a miséria extrema ao cuidar de porcos. Em meio à fome, ele decidiu retornar à casa de seu pai. Enquanto caminhava, planejou confessar que havia pecado contra o céu e contra seu progenitor, pedindo apenas para ser tratado como um servo. Ao avistá-lo à distância, o pai correu ao seu encontro, abraçou-o com compaixão e iniciou a restauração de seu filho, que finalmente voltava para casa.' WHERE "id" = '0326d84c-78d9-4ffd-a91e-942a39e62463';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José, levado ao Egito como escravo, conquistou a confiança de seu senhor, Potifar, ganhando prestígio na casa. A esposa de Potifar passou a assediá-lo repetidamente, tentando seduzi-lo na ausência de testemunhas. Diante das investidas constantes da mulher, José recusou-se a pecar e manteve sua integridade. Em um momento de insistência, ela agarrou sua veste, mas José fugiu rapidamente, deixando a túnica para trás. Por essa atitude, ele acabou sendo injustamente acusado e enviado para a prisão egípcia.' WHERE "id" = '0349b994-7c9a-44dc-98da-770fb6170e39';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava em um campo aberto rodeado por uma multidão de pessoas preocupadas. Ele apontou para os pássaros que voavam no céu, observando que eles não semeiam, não colhem nem armazenam mantimentos em celeiros, mas ainda assim são alimentados diariamente por Deus. Ao notar o cuidado divino com essas criaturas, Jesus questionou os ouvintes sobre o valor humano. Ele ensinou que as pessoas possuem muito mais importância diante do Criador do que os pequenos pássaros que cruzam o firmamento.' WHERE "id" = '0350b006-4753-4af0-add5-ad6ec56f7897';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos adorassem uma gigantesca estátua de ouro, mas os jovens Sadraque, Mesaque e Abednego recusaram o decreto. Mesmo sob forte pressão, eles mantiveram sua posição firme. Por desobediência, os três foram lançados em uma fornalha ardente, mas saíram ilesos, sem qualquer sinal de queimadura ou cheiro de fumaça. Enquanto estavam presos no fogo, o próprio Deus manifestou Sua presença, preservando a vida dos três amigos diante da sentença de morte imposta pelo monarca babilônico.' WHERE "id" = '03bc7b03-39ef-464a-9e88-85ebde1338fd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na véspera de sua morte, Jesus sabia que o Pai lhe confiara autoridade total. Ciente de sua origem divina, Ele se levantou da mesa durante a ceia, despiu-se do manto e amarrou uma toalha na cintura. Em um gesto surpreendente, Jesus lavou os pés de cada um de seus discípulos. Após concluir a tarefa, Ele perguntou se compreendiam a ação realizada e afirmou que, entre eles, aquele que deseja ser o maior deve se comportar como um servo.' WHERE "id" = '03bda273-259e-4620-a677-9059d58c43c0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imponente estátua de ouro e ordenou que todos no império se prostrassem diante dela ao som da orquestra. Enquanto o povo obedecia, Sadraque, Mesaque e Abednego permaneceram em pé, recusando a adoração exigida pelo monarca. Ameaçados com a morte em uma fornalha ardente, os três jovens mantiveram sua posição firme. Eles declararam ao rei que seu Deus era capaz de livrá-los, mas reafirmaram que jamais serviriam aos ídolos, mesmo diante da iminente execução punitiva.' WHERE "id" = '04973b6e-fc53-4ccc-91ca-65553e6a2df3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi traído e vendido pelos próprios irmãos, enfrentando anos de injusta prisão no Egito. Apesar do sofrimento e das correntes que carregava, ele manteve uma conduta íntegra em todas as posições que ocupou. O tempo de provação transformou o rapaz ingênuo em um homem resiliente e maduro. Quando finalmente foi convocado ao palácio pelo Faraó, o caráter desenvolvido durante seus anos de silêncio e dificuldade tornou-se o elemento fundamental para a sobrevivência de toda a nação egípcia.' WHERE "id" = '04afc16f-30e4-4d2d-a0cc-b40ddeb1b99a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante da necessidade de separar seus rebanhos, Abraão permitiu que Ló escolhesse primeiro para onde seguir. Ló observou o vale do Jordão, notando sua fertilidade e abundância de águas, comparando-o ao jardim do Senhor. Seduzido pela prosperidade da região, ele optou por habitar aquelas planícies, distanciando-se de Abraão. Enquanto o patriarca permaneceu em Canaã, Ló armou suas tendas gradualmente até chegar às proximidades de Sodoma, cujos moradores eram homens extremamente perversos e pecadores diante do Senhor Deus.' WHERE "id" = '051a22c0-1779-4e15-b0f7-2165f287fd3b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria, utilizou uma metáfora cotidiana sobre o consumo de mel para ilustrar um princípio fundamental. Ele observou que, embora o mel seja um alimento bom e agradável ao paladar, a ingestão em excesso torna-se prejudicial ao corpo, causando náuseas e doenças. Assim, o monarca descreveu o fato de que mesmo algo inerentemente positivo e prazeroso pode se transformar em um veneno nocivo quando consumido sem qualquer limite ou discernimento pelo ser humano.' WHERE "id" = '05fa1f1f-4b08-4143-b58b-d5a55f45a554';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens leprosos encontraram Jesus à beira do caminho e clamaram por misericórdia. O Mestre ordenou que fossem apresentar-se aos sacerdotes. Enquanto seguiam viagem, todos foram instantaneamente purificados da lepra. Apenas um deles, um samaritano, retornou imediatamente para glorificar a Deus em voz alta e prostrar-se aos pés de Jesus. O Senhor então indagou sobre o paradeiro dos outros nove que foram curados, destacando que somente aquele estrangeiro voltou para render graças diante do milagre recebido por eles.' WHERE "id" = '063fcc61-844d-426c-a4ba-51d71885bc65';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, redigiu os Provérbios como orientações fundamentais para seu filho. No quarto capítulo, ele instrui sobre a vigilância constante em três esferas da existência: o coração, os olhos e os passos. O rei enfatiza que as escolhas realizadas no âmbito privado, longe dos olhares públicos, determinam o caráter e o destino de cada pessoa. Assim, ele estabelece a necessidade de atenção plena em cada decisão tomada nas circunstâncias mais ocultas.' WHERE "id" = '064ffd33-3d00-400a-89f6-413481cd24a9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem levado cativo para a Babilônia, viu seu mundo mudar drasticamente quando o império impôs novas rotinas e nomes aos prisioneiros. Ao receberem ordens para comer os alimentos da mesa do rei, Daniel recusou-se firmemente a se contaminar. Ele propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de legumes e água. Ao final do período, Daniel e seus três amigos apresentaram uma aparência física muito superior aos outros jovens que consumiam o banquete real.' WHERE "id" = '066b9005-c768-4e5d-ba82-6113548c471e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Doze espias foram enviados à terra de Canaã para realizar uma expedição de reconhecimento. Ao retornarem, dez deles relataram a existência de gigantes e cidades fortificadas, comparando-se a gafanhotos diante dos habitantes locais. O povo, aterrorizado pelo relato pessimista, entrou em pânico imediato. Contudo, Calebe posicionou-se contra a maioria, afirmando com convicção que o povo era plenamente capaz de conquistar aquela terra. Apesar da pressão exercida pela multidão temerosa, ele manteve sua postura firme perante todos os israelitas presentes.' WHERE "id" = '067a74c9-e934-45d7-891a-8430c070263a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia ao som dos instrumentos, Sadraque, Mesaque e Abednego recusaram-se a prestar adoração à imagem. Diante do monarca, os três jovens afirmaram que seu Deus era capaz de livrá-los das chamas. Eles declararam firmemente que, mesmo que não fossem salvos, jamais se curvariam diante da estátua, mantendo sua decisão diante da terrível ameaça real.' WHERE "id" = '06866db1-664a-4752-9f34-c09a17397119';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, Daniel recusou-se a consumir as iguarias da mesa do rei, mantendo sua fidelidade aos mandamentos divinos. Ele propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de vegetais e água. Ao final do prazo estabelecido, o semblante de Daniel e de seus companheiros mostrou-se mais saudável e robusto do que o de todos os outros jovens que comiam as finas porções reais. Assim, Daniel continuou sua dieta escolhida com pleno êxito.' WHERE "id" = '069dd0aa-aab6-412b-8c48-b45c0fec6dbe';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro na Babilônia e ordenou que todos se prostrassem ao som da música, sob pena de morte na fornalha. Sadraque, Mesaque e Abednego recusaram o decreto real, mantendo sua fidelidade. Confrontados pelo monarca para justificar tal desobediência, os três jovens hebreus responderam firmemente que não precisariam dar explicações sobre sua decisão. Eles escolheram enfrentar a ameaça da fornalha ardente em vez de adorar a imagem, permanecendo inabaláveis diante da pressão imposta.' WHERE "id" = '06e8856e-baa5-4d79-8b40-f1e2905cee1b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ana sofria profundamente por ser estéril e desejava intensamente ter um filho. Em um momento de grande angústia, ela foi ao templo e derramou sua alma diante de Deus, chorando e suplicando com sinceridade. O sacerdote Eli observou sua oração silenciosa. Deus ouviu o clamor de Ana e, conforme o tempo passou, ela concebeu e deu à luz um menino, a quem chamou Samuel. Com gratidão, Ana reconheceu a resposta divina que transformou definitivamente a sua vida familiar.' WHERE "id" = '070975a7-8a5a-47ea-bc04-1f27b41a1db8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado ao palácio do rei da Babilônia como prisioneiro. Para demonstrar lealdade, ele deveria consumir as iguarias da mesa real. Decidido a não se contaminar com tais alimentos, Daniel propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de legumes e água. Ao fim desse período, Daniel e seus três amigos apresentavam uma aparência mais saudável e robusta que os jovens que comeram a comida do rei, sendo assim aprovados pelo governante babilônico.' WHERE "id" = '076f7a51-f2ac-40e8-a078-437288dcc2b1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava o povo depositando ofertas no templo. Ricos entregavam grandes quantias, exibindo generosidade aparente. Em seguida, uma viúva pobre aproximou-se e ofertou apenas duas moedas pequenas. Jesus chamou seus discípulos para analisar a cena e afirmou que aquela mulher havia contribuído mais que todos os outros. Enquanto os ricos doavam o que sobrava de suas posses, a viúva entregou tudo o que possuía para seu sustento. Foi um gesto silencioso de total entrega diante dos olhos atentos do Messias.' WHERE "id" = '078527d5-7a64-4c37-8e6e-b2ae27a963a2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão foi o rei mais sábio da história e possuía grandes riquezas, como ouro, castelos e exércitos. Contudo, ele ficou reconhecido por sua postura diante das pessoas. O monarca ouvia todos com atenção, tratava bem seus súditos e respeitava até os cidadãos mais humildes do seu reino. Esse comportamento constante e íntegro consolidou um nome grandioso para ele, perdurando por muitos séculos. Deus afirmou que essa reputação positiva é superior a qualquer tesouro material existente em toda a terra.' WHERE "id" = '07aca7f3-80e4-4823-aa46-8481109fab15';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra distante, onde o rei ordenou que ele consumisse as mesmas iguarias da corte real. Discordando da dieta imposta, que violava seus princípios, o jovem recusou o banquete oferecido. Ele solicitou ao guarda que o colocasse à prova, alimentando-se apenas de vegetais e água durante dez dias. Após esse período, Daniel e seus três amigos apresentaram uma aparência mais robusta e saudável do que todos os outros jovens que aceitaram a comida real.' WHERE "id" = '07be85b8-8821-4cd5-a63d-e011e10e9403';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao final de sua vida, Josué convocou todas as tribos de Israel em Siquém para um momento decisivo. Diante de todo o povo, ele propôs que escolhessem entre servir aos deuses que seus antepassados adoraram no Egito ou seguir ao Senhor. Josué declarou firmemente que, independentemente da decisão coletiva daquela nação, ele e sua família já haviam escolhido servir exclusivamente ao Deus único. Assim, o líder estabeleceu um compromisso público e inegociável diante de todos os israelitas reunidos.' WHERE "id" = '07e30633-bcd3-4e25-a385-90faf890a0c7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreveu aos cristãos de Filipos que disputavam posição e importância. Ele apresentou o exemplo de Jesus Cristo para ilustrar o caminho correto. Sendo Deus, Jesus abriu mão de seus direitos e escolheu servir àqueles que possuíam menos poder. O ápice desse gesto de humildade ocorreu quando ele mesmo lavou os pés de seus discípulos. Assim, ele demonstrou que a verdadeira força não reside na busca por autoridade, mas na disposição voluntária de servir ao próximo com total desprendimento.' WHERE "id" = '08111499-2ee7-4ba3-b12c-9720c411ae7c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago e João pediram a Jesus lugares de honra em seu reino, despertando indignação entre os outros discípulos. Diante daquela tensão e rivalidade, Jesus reuniu o grupo para contrastar dois modelos de liderança. Ele explicou que, ao contrário dos governantes que exercem poder sobre as nações, seus seguidores devem adotar uma postura de serviço. Por fim, Jesus apresentou a si mesmo como o padrão definitivo, afirmando que veio ao mundo para dar sua vida em resgate por muitos.' WHERE "id" = '0884f7ce-dfe9-4b77-89e9-6757a27f534f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias liderou a reconstrução dos muros de Jerusalém enfrentando constante oposição de inimigos que buscavam interromper a obra através de ameaças e zombaria. Para garantir o progresso, ele organizou os operários de modo que trabalhassem com uma das mãos, enquanto mantinham armas de prontidão com a outra. Apesar da pressão externa e dos ataques, a determinação do povo permaneceu firme. A muralha foi concluída porque os construtores focaram no serviço, mantendo a vigilância constante e uma disposição inabalável.' WHERE "id" = '08bd855f-cc01-4de5-aa8f-c8b86f1a53a1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após Tiago e João solicitarem lugares de honra no reino, os outros dez discípulos reagiram com indignação, gerando um conflito entre eles. Jesus interveio, explicando que, ao contrário dos governantes gentios que dominam com autoridade, a verdadeira grandeza entre os seus seguidores provém do serviço aos outros. Ele afirmou que aquele que deseja ser o primeiro deve tornar-se escravo de todos, destacando que o próprio Filho do Homem não veio para ser servido, mas para servir e dar sua vida.' WHERE "id" = '0900a274-1300-4389-a47a-d5b57f2cb062';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus visitou a casa de Marta e Maria. Marta ocupou-se intensamente com os preparativos do serviço doméstico, enquanto sua irmã Maria permaneceu sentada aos pés de Jesus para ouvir seus ensinamentos. Irritada com a falta de auxílio, Marta pediu que Jesus ordenasse a ajuda de Maria. Contudo, Jesus respondeu que Marta estava agitada com muitas ocupações desnecessárias. Ele afirmou que Maria escolheu a melhor parte, a única verdadeiramente essencial, a qual nunca lhe seria tirada pelos outros.' WHERE "id" = '09b13b2c-2700-4785-bc5b-284c1d26c5f3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho solicitou sua parte na herança ao pai e partiu para uma terra distante, onde desperdiçou todos os bens com uma vida desregrada. Após gastar tudo, enfrentou uma fome severa e decidiu retornar ao lar paterno para pedir perdão e ser tratado como um empregado. Enquanto o jovem caminhava, o pai o avistou de longe, correu ao seu encontro, abraçou-o calorosamente e o acolheu de volta, demonstrando pleno amor e prontidão em perdoar aquele filho arrependido.' WHERE "id" = '09c23206-adc6-41cf-9e65-5b48826f9c4a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José, vendido como escravo pelos irmãos, tornou-se autoridade no Egito. Anos depois, seus irmãos foram até ele pedir alimento devido à grande fome. Ao reconhecê-los, José afastou os servos e revelou sua verdadeira identidade entre intensas lágrimas. Ele os perdoou prontamente pelo passado, declarando que Deus permitira sua vinda ao Egito para salvar vidas. José abraçou seus irmãos e chorou com eles, encerrando o longo distanciamento e permitindo que toda a família se reunisse finalmente na terra egípcia.' WHERE "id" = '09c73731-c23e-4aa0-b27d-0039b62e8dd3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo enfrentou uma severa fome e a solidão. Reconhecendo sua situação miserável, ele decidiu retornar à casa de seu pai, preparando um pedido de desculpas por seus erros passados. Enquanto o rapaz ainda caminhava pela estrada, o pai avistou-o de longe. Movido por profunda compaixão, o progenitor correu ao encontro do filho, abraçando-o antes mesmo de qualquer explicação, selando assim o retorno do jovem ao lar paterno.' WHERE "id" = '0a97e21b-dff8-4bef-94b6-1f46fd651716';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um alto cargo no império persa, despertando inveja nos outros administradores. Eles convenceram o rei Dario a assinar um decreto proibindo orações a qualquer ser que não fosse o monarca. Sabendo da proibição, Daniel continuou orando fielmente ao seu Deus diante de todos. Por causa dessa desobediência ao decreto, ele foi lançado na cova dos leões. No dia seguinte, o rei encontrou Daniel vivo e ileso, enquanto os responsáveis pela conspiração foram condenados ao mesmo destino.' WHERE "id" = '0af51922-e35f-493c-b212-68734b0a18ad';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta direcionada às famílias cristãs da cidade de Éfeso. No texto, ele orienta os filhos a obedecerem aos seus pais no Senhor, destacando que essa atitude é justa. Paulo também menciona que esse mandamento possui uma promessa específica, pois acompanha a promessa de que, ao honrar pai e mãe, os filhos terão vida longa e prosperarão na terra. Assim, o apóstolo estabelece as bases divinas para o relacionamento saudável e harmonioso entre pais e filhos.' WHERE "id" = '0b1cc802-a07b-4c1f-b774-8e2e8ea4473e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó era um homem íntegro, próspero e profundamente temente a Deus. Em um único dia de devastação, ele perdeu todos os seus rebanhos, seus servos e a vida de seus dez filhos em uma série de tragédias repentinas. Diante dos escombros de sua existência, Jó rasgou suas vestes em sinal de luto e prostrou-se no chão. Ele declarou que o Senhor deu e retirou, bendizendo o nome divino sem atribuir qualquer injustiça ou pecado ao Criador diante da dor.' WHERE "id" = '0b65c0e8-e56d-4d91-8d0e-e03a76dffc7a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a liderança do povo de Israel com a missão de conduzir a nação rumo à terra prometida. O território estava ocupado por nações fortemente armadas, o que gerou temor diante do desafio iminente. Nesse momento crítico, Deus falou diretamente com Josué, ordenando que fosse forte e corajoso. O Senhor garantiu que não haveria motivo para se apavorar, pois prometeu estar presente ao lado de seu servo por onde quer que ele andasse.' WHERE "id" = '0b65d496-d89e-4c3c-a8c9-f3a735383407';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Pedro escreveu uma carta endereçada a diversas comunidades cristãs que viviam espalhadas por todo o Império Romano. Embora esses grupos fossem marginalizados e desprovidos de influência política ou social, Pedro os orientou a adotar uma conduta específica baseada em quatro ações fundamentais. Ele instruiu os cristãos a honrarem todas as pessoas, demonstrarem amor genuíno aos seus irmãos na fé, cultivarem o temor a Deus em seus corações e, finalmente, prestarem a devida honra ao rei vigente.' WHERE "id" = '0b9603a3-e1b7-4b2f-b541-98497c9d2bc6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas estabeleceram um profundo pacto de amizade enquanto o medo dominava o reino de Israel sob o governo de Saul. Superando o clima de desconfiança generalizada, os dois jovens decidiram unir seus propósitos. Jônatas demonstrou seu compromisso ao entregar a Davi seu manto, suas vestes, sua espada, seu arco e seu cinto. Esse acordo mútuo foi firmado diante de Deus, consolidando uma aliança leal e corajosa que persistiu apesar das perseguições e das tensões enfrentadas por ambos.' WHERE "id" = '0ba0dedf-6e65-4339-8be6-1dd03e6c201f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia, onde o rei ordenou que ele e seus amigos comessem das iguarias da mesa real. Daniel recusou o alimento, pois isso violava suas convicções pessoais. Ele solicitou respeitosamente ao chefe dos eunucos que lhes fornecesse apenas legumes e água durante dez dias de teste. Ao final do período estipulado, Daniel e seus companheiros apresentaram uma aparência mais saudável e robusta do que todos os jovens que consumiram a porção oferecida pelo monarca.' WHERE "id" = '0bc465ff-2fd6-45d8-aecd-6357bdce46fc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante do poderoso rei da Babilônia, Sadraque, Mesaque e Abednego receberam a ordem de adorar a estátua de ouro ou enfrentar a morte na fornalha ardente. Enquanto a multidão se curvava, os três jovens permaneceram de pé, recusando-se a negociar suas convicções. Como punição pela desobediência, foram lançados na fornalha, que estava sete vezes mais quente. Contudo, eles sobreviveram ao fogo intensamente aquecido e saíram ilesos, sem sequer carregar o cheiro de fumaça em suas vestes diante do monarca.' WHERE "id" = '0c5f3aa1-9891-4a86-9836-901adf7c03b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, estabeleceu diretrizes fundamentais sobre limites e moderação em Provérbios. Ele alertou que consumir mel em excesso causa náuseas e vômitos, transformando o prazer em algo prejudicial. Da mesma forma, afirmou que visitar um vizinho com frequência demasiada torna a presença do visitante um fardo indesejado. Assim, o sábio ensinou que o aproveitamento de qualquer coisa boa exige discernimento, pois a falta de controle converte benefícios em um peso insuportável.' WHERE "id" = '0d0f7fe3-125e-4b81-8e1f-aebd376c3ec6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar sua herança em terras distantes, o filho mais novo enfrentou uma grande escassez. Ao reconhecer sua miséria, ele decidiu retornar à casa do pai para pedir perdão e ser tratado como um empregado. Enquanto ainda estava longe, seu pai o avistou e, movido por profunda compaixão, correu ao seu encontro e o abraçou. Imediatamente, o pai ordenou que trouxessem a melhor túnica, um anel e sandálias, celebrando com uma grande festa o retorno do filho.' WHERE "id" = '0e7110cb-14ed-42b0-8d79-1c8b6352653a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança, o filho mais novo viveu na miséria, cuidando de porcos e passando fome. Em um momento de lucidez, ele reconheceu sua condição deplorável e decidiu retornar à casa de seu pai para pedir perdão, aceitando trabalhar como um simples empregado. O jovem levantou-se e iniciou sua jornada de volta. Ao vê-lo aproximar-se ainda distante, seu pai, movido por profunda compaixão, correu ao seu encontro, abraçou-o e o recebeu prontamente antes mesmo de qualquer confissão.' WHERE "id" = '0e7aaae2-5a45-478b-bc88-a7d8ab910a51';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de sua estátua de ouro sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia, Sadraque, Mesaque e Abednego recusaram-se a adorar o ídolo. Confrontados pelo monarca, os três jovens afirmaram corajosamente que não prestariam culto à imagem. Eles declararam que seu Deus poderia livrá-los, mas, mesmo que não o fizesse, permaneceriam firmes em sua decisão, aceitando as consequências impostas pelo governante perante todo o seu reino.' WHERE "id" = '0eca71dd-f73e-4a14-b390-1aa85f947a7b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a difícil missão de liderar o povo de Israel em direção a uma terra desconhecida e repleta de perigos. Reconhecendo o peso da responsabilidade e o medo natural diante dos desafios, Deus ordenou que ele fosse forte e corajoso por três vezes. Fortalecido por essa instrução divina direta, Josué tomou a decisão de seguir em frente com sua tarefa. Ele atravessou o rio Jordão, conquistou a terra prometida e consolidou sua trajetória.' WHERE "id" = '0ecf614c-d0ad-4ade-82ac-7cdc6881035d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ofereceu a Salomão a oportunidade de pedir qualquer coisa, incluindo riquezas, fama ou vitória sobre seus inimigos. Diante da responsabilidade de governar um vasto reino, Salomão decidiu não buscar ganhos pessoais ou poder imediato. Ele pediu a Deus sabedoria para liderar seu povo com justiça e discernimento. Reconhecendo a importância de depender da orientação divina, Salomão obteve a sabedoria desejada e recebeu de Deus muito mais do que havia solicitado originalmente durante aquela experiência extraordinária.' WHERE "id" = '0ef77545-4556-4c1d-9a42-88528254edf1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em Babilônia, recebeu a oferta de banquetes reais e uma nova identidade. Determinado a seguir suas convicções, ele recusou os alimentos do rei, solicitando uma dieta alternativa para si e seus três amigos. Após dez dias de prova, eles apresentaram melhor saúde e aparência do que os demais jovens. Anos mais tarde, a fidelidade de Daniel aos seus princípios o estabeleceu como o principal e mais confiável conselheiro entre todos os sábios do vasto império babilônico.' WHERE "id" = '0fcd6630-3ecd-4e43-88a8-748bb7138079';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel recusou comer as finas iguarias oferecidas pelo rei, pois desejava manter sua fidelidade aos mandamentos de Deus. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de vegetais e água, em vez da dieta real. Ao final do período, Daniel e seus três amigos apresentavam uma aparência mais saudável e robusta que os demais jovens que consumiram a comida do palácio, provando que sua obediência foi recompensada.' WHERE "id" = '111d35f2-81ee-466d-a429-1a79f6ec95b9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A borboleta desenvolve-se dentro de um casulo, onde precisa enfrentar um esforço intenso para conseguir emergir. Se um observador cortar prematuramente essa proteção para auxiliá-la, o inseto surgirá debilitado, incapaz de voar. O processo de superação e a espera prolongada são condições indispensáveis para que ela adquira a força necessária e a beleza de suas asas. Somente através dessa luta solitária e difícil a borboleta torna-se apta para a vida fora do casulo, fortalecendo plenamente o seu corpo.' WHERE "id" = '1166865c-1b65-4e74-ba03-b5ed6d78100d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abednego adorassem uma grande estátua de ouro sob a ameaça de morte em uma fornalha ardente. Diante da pressão coletiva para curvarem-se ao ídolo, os três jovens recusaram firmemente a ordem real. Eles declararam que o seu Deus era capaz de livrá-los daquele castigo. Contudo, afirmaram resolutamente que, mesmo que não fossem salvos, não adorariam a estátua do monarca. Assim, eles permaneceram fiéis, aceitando enfrentar o fogo antes de cederem.' WHERE "id" = '117bf8ef-b492-4367-84d2-f9128e3794a7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, o filho mais novo de Jessé, vivia no anonimato cuidando de ovelhas enquanto seus irmãos eram reconhecidos. Longe dos olhares humanos, ele enfrentou leões e ursos para proteger o rebanho, desenvolvendo coragem e resiliência solitária no campo. Quando o gigante Golias desafiou o exército de Israel, Davi não hesitou em enfrentá-lo. Sua preparação, construída durante as noites silenciosas no pasto, permitiu que ele vencesse o inimigo, demonstrando uma força interior forjada muito antes de se tornar rei.' WHERE "id" = '119e217f-b887-4ef4-b589-25b8fb69e15d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario assinou um decreto proibindo orações a qualquer deus que não fosse ele próprio. Consciente dessa nova lei, Daniel retornou à sua casa, abriu as janelas voltadas para Jerusalém e orou três vezes ao dia, conforme seu costume habitual. Seus inimigos, que vigiavam atentamente seus movimentos, observaram a atitude de Daniel e o denunciaram imediatamente ao rei. O profeta manteve sua fidelidade religiosa, recusando-se a cessar suas orações, mesmo diante da pressão imposta pelo decreto real vigente.' WHERE "id" = '11afff0b-dd85-4f0f-95af-7fba30466352';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua fortuna e enfrentar a fome, o filho pródigo reconheceu seu erro e decidiu retornar à casa de seu pai. Abandonando o orgulho, preparou palavras sinceras e iniciou sua longa jornada de volta. Enquanto ainda estava distante, o pai o avistou. Movido por profunda compaixão, o homem correu ao encontro do jovem. Antes mesmo de ouvir qualquer explicação, o pai o abraçou calorosamente, acolhendo seu filho que estava perdido e agora retornava para casa.' WHERE "id" = '11d0f394-a3c0-4a21-aee5-338211247e7a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Criado no palácio egípcio, Moisés possuía poder, nome e um futuro garantido pelas riquezas daquela nação. Contudo, ao atingir a maturidade, ele recusou ser chamado filho da filha de Faraó. Preferindo sofrer junto ao povo de Deus a desfrutar dos prazeres temporários do pecado, Moisés abandonou os privilégios reais. Ele deixou o Egito sem temer a ira do rei, movido pela visão da recompensa eterna e pela fé naquele que permanece invisível, mantendo sua firme decisão até o fim.' WHERE "id" = '1252fd7f-85d1-4800-a269-61cbb36d55c7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O filho que havia abandonado o lar e esbanjado sua herança enfrentou uma profunda escassez. Ao cair em si, ele reconheceu seus erros, planejou pedir perdão ao pai e decidiu retornar para casa, mesmo temendo a rejeição. Sem esperar por condições perfeitas, levantou-se e iniciou a longa caminhada de volta. O pai, que aguardava atentamente, avistou o filho ainda distante. Movido por compaixão, correu ao seu encontro, acolhendo-o com um abraço antes mesmo que ele terminasse seu discurso.' WHERE "id" = '127d7f38-f884-4e18-b1e1-73d9b8d19f2a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido e dos filhos de Noemi em terra estrangeira, a viúva pediu que suas noras retornassem às suas famílias de origem. Orfa despediu-se e partiu, mas a moabita Rute decidiu permanecer ao lado de Noemi, jurando segui-la aonde quer que fosse. A lealdade de Rute a acompanhou até Israel, onde ela construiu uma nova vida. Mais tarde, Rute tornou-se bisavó do rei Davi, ocupando um lugar de destaque na linhagem histórica do próprio Jesus Cristo.' WHERE "id" = '12a2c586-bef2-4b53-99be-d61f65bde51c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga prepara-se antecipadamente para o inverno rigoroso, trabalhando com diligência enquanto o sol ainda aquece o solo. Ela coleta grãos e pequenos pedaços de alimento com constância e paciência. Em vez de agir por impulso ou correr sem direção, o inseto demonstra prudência em cada movimento realizado. Com essa sabedoria natural, a formiga garante o sustento, protege o seu grupo e mantém o formigueiro seguro e devidamente abastecido, agindo de forma planejada antes que as dificuldades cheguem.' WHERE "id" = '12e5e3da-b3e2-4ba0-a32b-39dc5941353b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, embora fosse o homem mais sábio da terra e construtor do Templo, cometeu erros graves em suas escolhas pessoais. Ele formou alianças matrimoniais com muitas mulheres estrangeiras proibidas pelo Senhor. Com o passar do tempo, essas esposas influenciaram seu coração e o desviaram do caminho de Deus. Gradualmente, o monarca deixou de ser totalmente fiel ao Senhor e passou a edificar altares para deuses falsos, como Moloque, decepcionando gravemente o Criador com suas atitudes.' WHERE "id" = '12fc80ba-6a04-415f-96e9-271684ebed15';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Neemias liderava a reconstrução dos muros de Jerusalém, inimigos como Sambalate e Tobias zombavam e conspiravam contra os trabalhadores. Ameaçados, os judeus sentiram desânimo diante da destruição e da oposição crescente. Neemias, contudo, agiu com prontidão para proteger o projeto. Ele organizou a guarda armada em pontos estratégicos, distribuiu tarefas específicas entre o povo e estabeleceu um ritmo constante de trabalho. Além de manter a vigilância física rigorosa, Neemias apresentou a situação em oração constante diante de Deus.' WHERE "id" = '13a4cedb-e08c-4ebc-9116-bda9cdb2c7d6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo viveu momentos de extrema adversidade durante seu ministério marcado por prisões, naufrágios, rejeição e traição constante. Enquanto enfrentava o sofrimento físico e a pressão das perseguições, ele escreveu cartas fundamentais sobre a vida cristã. Paulo afirmou que as tribulações não apenas testam a fé, mas produzem paciência constante naqueles que perseveram. Esse processo de resistência constante forja um caráter aprovado e resulta em uma esperança sólida, ancorada na transformação interna alcançada através dos desafios enfrentados.' WHERE "id" = '13f0683c-57bd-404d-adbb-e395e8bb1172';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi interceptado por assaltantes, espancado e deixado quase morto à beira do caminho. Um sacerdote e um levita passaram pelo local, viram o ferido, mas optaram por desviar e seguir viagem. Posteriormente, um samaritano aproximou-se, compadeceu-se da vítima, tratou suas feridas com óleo e vinho, colocou-o em seu animal, levou-o a uma hospedaria para cuidar dele e ainda pagou antecipadamente todas as despesas necessárias para sua completa e devida recuperação.' WHERE "id" = '142575f8-b102-43f9-8248-4ece598b56fa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo atingiu o fundo do poço e reconheceu seu erro. Decidido a mudar, levantou-se e iniciou sua jornada de volta à casa paterna. Ao chegar, ele confessou suas falhas diretamente ao pai, sem buscar desculpas ou manipulações. O pai, avistando-o de longe, correu prontamente ao seu encontro. Esse retorno concreto do filho e a recepção imediata de seu pai marcaram o início de uma restauração em sua vida.' WHERE "id" = '14293988-f35a-4e86-8df2-0b1189e1f1e1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um cargo de alto destaque no governo persa, despertando inveja nos rivais. Eles buscaram falhas em sua conduta, mas não encontraram nada. Então, manipularam o rei para promulgar um decreto proibindo qualquer petição a deuses ou homens, exceto ao próprio soberano, sob pena de morte. Ao tomar conhecimento da nova lei, Daniel retornou à sua casa, abriu as janelas e continuou a orar ao seu Deus três vezes ao dia, exatamente como fazia anteriormente, sem hesitar.' WHERE "id" = '147c141a-4ae6-4b86-b8bf-38f817fab932';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Próximo ao fim da vida, Josué reuniu todas as tribos de Israel em Siquém para um momento decisivo de compromisso. Diante de todo o povo, o líder relembrou a trajetória da nação e exigiu uma decisão clara sobre a quem serviriam dali em diante. Josué declarou publicamente que ele e sua própria casa serviriam exclusivamente ao Senhor. O povo, diante do desafio, também escolheu abandonar outros deuses e confirmou solenemente que serviria somente ao Deus de Israel.' WHERE "id" = '148267b7-5526-4427-9205-effdc570f9d0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão observou dois tipos distintos de conduta ao edificar um lar. Ele notou que a mulher sábia constrói sua própria casa com esforço diligente, peça por peça, através de decisões cuidadosas. Em contrapartida, percebeu que a insensata destrói o que foi edificado com as próprias mãos, agindo com pressa, descuido e palavras impensadas. Assim, o sábio rei concluiu que a estabilidade de uma morada depende diretamente da sabedoria ou da tolice presentes nas atitudes diárias de alguém.' WHERE "id" = '152cafde-a612-4e98-ad35-8845b2b88f66';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido e dos filhos de Noemi, a viúva decidiu retornar para sua terra natal e pediu que suas noras voltassem para suas famílias. Enquanto Orfa partiu, Rute recusou a despedida. Ela declarou fidelidade incondicional à sogra, afirmando que seguiria seus passos e adotaria seu povo e seu Deus. Permanecendo ao lado de Noemi, Rute mudou seu destino, estabelecendo uma linhagem familiar que, futuramente, incluiria o rei Davi, consolidando uma história de profunda lealdade.' WHERE "id" = '1532fe82-8651-4c7a-8521-9472af5910d6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém a Jericó quando foi atacado, roubado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo local, mas ignoraram a vítima e seguiram caminho. Em seguida, um samaritano aproximou-se, sentiu compaixão e cuidou dos ferimentos daquele homem. Ele o colocou sobre seu próprio animal, levou-o a uma hospedaria e custeou os cuidados necessários. Ao final, o samaritano prometeu retornar para pagar eventuais despesas extras do tratamento médico e da estadia completa.' WHERE "id" = '15931dfa-13ff-4c47-9157-ff57ccf59773';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A Sabedoria personificada declara sua existência desde antes da criação do mundo, quando habitava junto a Deus. Ela atua como guia essencial para reis, juízes e todos os governantes que buscam exercer autoridade com integridade e justiça. A Sabedoria distingue-se por oferecer riquezas duradouras e honra aos que trilham seus caminhos retos. Ela convida aqueles que valorizam a prudência e o discernimento, distanciando-se dos impulsivos e arrogantes, para estabelecer fundamentos sólidos que perduram além do momento presente.' WHERE "id" = '15b24a43-8ab8-4ce0-a240-0e8f3b720abd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Josué, já em idade avançada, convocou todo o povo de Israel para uma assembleia final. Consciente de que seus dias se aproximavam do fim, ele propôs que os israelitas escolhessem naquele momento a quem serviriam, seja aos deuses dos seus antepassados ou ao Senhor. Diante de toda a multidão reunida, Josué declarou firmemente que ele e sua casa serviriam exclusivamente ao Deus de Israel. Com essa decisão, o líder estabeleceu um posicionamento claro diante de todo o povo.' WHERE "id" = '163a3b24-72ef-4d46-8ff5-4b576b70ba9b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Saul perseguia Davi com um exército quando entrou sozinho em uma caverna em En-Gedi. Davi estava escondido nas sombras e teve a oportunidade de matar seu inimigo, mas apenas cortou a borda do manto real. Ao sair, Davi revelou o pedaço de tecido a Saul, declarando que não tocaria no ungido do Senhor. Comovido, o rei chorou, admitiu a justiça de Davi e reconheceu a integridade do homem que ele tentava eliminar com tanto ódio naquele momento específico.' WHERE "id" = '16a9ef82-6c52-42d7-9355-793659af2ba4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu aos filipenses enquanto estava preso, enfrentando uma situação de extrema pressão e incerteza sobre o futuro. Em vez de se entregar à especulação angustiante ou ao medo diante das circunstâncias adversas, ele optou por redirecionar seus pensamentos. Mesmo em meio à turbulência do cárcere, ele declarou experimentar uma paz profunda, que descreveu como algo superior a qualquer cálculo humano. Assim, Paulo manteve sua integridade e serenidade, focando no presente em vez de temer o amanhã.' WHERE "id" = '170e5dd1-55d6-419a-b4fd-6e407acc7bcc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma grande estátua de ouro e ordenou que todos se curvassem diante dela ao som de instrumentos musicais. Quem desobedecesse seria lançado em uma fornalha ardente. Sadraque, Mesaque e Abede-Nego recusaram-se a adorar a imagem, permanecendo de pé diante do monarca furioso. Confrontados pelo rei sobre sua atitude, os três jovens declararam firmemente que não prestariam culto aos deuses babilônicos, mesmo que enfrentassem a morte nas chamas, mantendo sua fidelidade absoluta ao único Deus.' WHERE "id" = '17166f34-8d1d-4484-bb0c-75d44bd5dffa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus contou a história de dois servos sob o comando de um mesmo senhor. Um deles cuidava com zelo de todas as coisas, inclusive das pequenas responsabilidades diárias. O outro, por sua vez, tratava suas obrigações com total desleixo. Quando chegou o momento de delegar tarefas maiores e mais importantes, o dono escolheu o servo que demonstrara fidelidade nos afazeres triviais. Aquele homem recebeu mais autoridade porque provou ser confiável durante suas rotinas diárias e tarefas simples.' WHERE "id" = '1768fbff-b539-46a9-99fe-f3938d68284b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria e a fome, chegando a alimentar porcos. Reconhecendo sua situação deplorável, ele decidiu retornar à casa de seu pai, ensaiando um humilde pedido de perdão. Enquanto ainda estava longe, o pai avistou o rapaz e correu ao seu encontro. Em vez de julgá-lo por seus erros, o pai o recebeu com um abraço caloroso, acolhendo o filho que retornava para casa após um longo período distante.' WHERE "id" = '1769a068-8e5c-4ecb-90fd-b006c83b8983';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus criou o mel como uma substância extremamente doce e prazerosa para o consumo humano. No entanto, o rei Salomão observou que o consumo exagerado desse alimento causa náuseas e mal-estar físico. Por essa razão, o monarca registrou em seus provérbios a instrução prática de comer apenas a quantidade suficiente. A narrativa destaca que, embora o mel seja um item bom, o excesso transforma algo benéfico em prejudicial, exigindo que a pessoa saiba identificar o momento correto de parar.' WHERE "id" = '177dc729-777c-4a87-b6d7-3664489ad284';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria superior, observou atentamente o comportamento das pessoas ao seu redor durante seu reinado. Ele constatou uma realidade constante na vida cotidiana: aqueles que caminham ao lado de indivíduos sábios tornam-se, gradualmente, pessoas mais sábias. Em contrapartida, ele percebeu que aqueles que optam por manter proximidade com companheiros tolos inevitavelmente sofrem prejuízos. Por meio de suas observações práticas, Salomão concluiu que a influência das amizades molda diretamente as atitudes e o destino final.' WHERE "id" = '18041a9a-396d-48cb-9d6a-c4317486f9fd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria singular após pedi-la a Deus em vez de riquezas, dedicou anos de sua vida a observar profundamente o comportamento humano. A partir de suas reflexões, ele chegou à conclusão histórica de que a língua possui autoridade real, carregando o peso da morte e da vida. Segundo o monarca, palavras imprudentes destroem carreiras e casamentos, enquanto o silêncio ou afirmações corretas moldam o legado que cada homem constrói ao longo de sua existência.' WHERE "id" = '1809a0db-cdc2-45ac-81ca-f7f8889b8f4d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor levou Daniel e outros jovens nobres de Israel para a Babilônia com o objetivo de treiná-los na cultura local. Daniel, junto a seus três companheiros, decidiu não se contaminar com a dieta real oferecida pelo palácio. Após dez dias de uma alimentação à base de vegetais e água, eles demonstraram estar em melhor saúde física e intelectual que os demais. Ao final do treinamento, o rei os considerou dez vezes superiores a todos os sábios babilônicos.' WHERE "id" = '1864cd35-0bba-4065-84bb-3b3e9de999c3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Tiago escreveu uma carta direcionada a cristãos que enfrentavam intensas provações em diversos aspectos de suas vidas. Ele abordou os desafios relacionados à fé, aos relacionamentos e às decisões complexas que exigiam firmeza diante das pressões externas. Em vez de prometer facilidades, Tiago explicou que a resistência ativa nessas situações difíceis promove o desenvolvimento da integridade e a maturidade espiritual. Assim, o crente é incentivado a manter a constância e não abandonar seus princípios diante das dificuldades enfrentadas.' WHERE "id" = '18926b9a-06b6-486e-b661-37696dbe3b96';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem prisioneiro levado à Babilônia, enfrentou um dilema quando o rei ordenou que consumisse alimentos que violavam suas convicções religiosas. Em vez de ceder, ele solicitou respeitosamente ao responsável uma dieta alternativa baseada em vegetais e água. Após dez dias de teste, Daniel e seus amigos apresentaram uma aparência visivelmente mais saudável e robusta do que os outros jovens que se alimentaram com as iguarias reais, mantendo assim sua integridade e fidelidade aos mandamentos de Deus.' WHERE "id" = '18eaf8e6-c804-4192-9a8a-d755d825953c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas em campos abertos. Enquanto o rebanho pastava sob o céu, ele cantava louvores a Deus com sinceridade, sem qualquer auxílio de instrumentos ou palcos montados. Naquela solidão do campo, ele expressava seu profundo amor ao Criador através do canto. Esse ato contínuo de adoração fazia com que Davi se sentisse constantemente conectado ao Pai, que observava cada passo seu, transformando o cuidado diário das ovelhas em um momento íntimo.' WHERE "id" = '195636a2-6825-403c-9508-e4c84a7074fb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão e Ló precisaram se separar porque a terra disponível era insuficiente para ambos. Abraão permitiu que Ló escolhesse primeiro o local de sua habitação. Ló observou o vale do Jordão, notando sua fertilidade e abundância de água, e decidiu seguir para aquela região. O vale abrigava a cidade de Sodoma, um local marcado por intensa corrupção. Ló mudou-se para lá, estabelecendo sua residência nas proximidades e, pouco tempo depois, passou a viver dentro da própria cidade pecaminosa.' WHERE "id" = '197b59ba-583c-4ce7-a4a7-31d7ef703c5f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No átrio do templo, Jesus observa os ricos depositando grandes quantias nas caixas de ofertas. Em seguida, uma viúva se aproxima e deposita apenas duas pequenas moedas de cobre. Diante disso, Jesus interrompe a cena e afirma aos seus discípulos que aquela mulher ofereceu mais do que todos os outros juntos. Enquanto os ricos doavam apenas o que lhes sobrava de suas riquezas, a viúva entregou tudo o que possuía para o seu próprio sustento naquele momento específico.' WHERE "id" = '197dc869-1cdb-4a41-8ab4-8bcd8b893eed';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Samuel cresceu no templo sob a tutela do sacerdote Eli, enquanto os filhos deste desprezavam as ordenanças divinas e o povo. Diferente deles, Samuel manteve uma postura distinta no serviço ao Senhor. Ele aprendeu a obedecer com integridade, dedicando-se fielmente às suas responsabilidades diárias no ambiente sagrado. Consequentemente, o jovem prosperou em seu chamado e conquistou o reconhecimento de todos ao seu redor. Sua trajetória de crescimento revelou um caráter exemplar diante de Deus e dos homens.' WHERE "id" = '19a6fddd-cee6-4b51-bd64-b729c348db3d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os discípulos de Jesus discutiam fervorosamente sobre quem era o mais importante entre eles. Percebendo a situação, Jesus chamou uma criança, posicionou-a no centro do grupo e explicou que a verdadeira grandeza reside na humildade e no serviço ao próximo. Para ilustrar seu ensino, o mestre surpreendeu a todos ao lavar os pés de seus seguidores. Com esse gesto, Jesus demonstrou que o maior no Reino de Deus é aquele que serve, invertendo a lógica de poder humana.' WHERE "id" = '19f945e1-c4b6-42ca-a0bf-956b2ef632be';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Pedro perguntou a Jesus sobre o limite do perdão ao próximo. Jesus respondeu que se deve perdoar setenta vezes sete. Em seguida, contou sobre um servo que devia uma fortuna impagável ao rei e teve sua dívida totalmente perdoada. Contudo, ao encontrar um colega que lhe devia uma quantia irrisória, o servo o estrangulou e mandou prendê-lo. O rei soube da crueldade, enfureceu-se com a atitude do homem e entregou aquele servo impiedoso aos torturadores até que pagasse tudo.' WHERE "id" = '1a2558d4-210d-4623-a430-2d330e4b23ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio da história, registrou ensinamentos fundamentais sobre a natureza das palavras humanas. Ele estabeleceu um contraste direto entre a veracidade e a mentira, afirmando que a língua verdadeira permanece firme através do tempo, enquanto a falsidade possui curta duração. Ao analisar o comportamento social, o monarca observou que reinos inteiros entraram em colapso devido à falta de confiança. Portanto, a integridade da comunicação é o alicerce essencial para a estabilidade.' WHERE "id" = '1a4f6424-ab10-401a-9a12-d15cbf211f24';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro, sob pena de morte na fornalha. Sedraque, Mesaque e Abede-Nego foram convocados para obedecer ao decreto imperial. Confrontados pelo monarca, os três jovens recusaram curvar-se ao ídolo. Eles afirmaram que seu Deus tinha poder para livrá-los da sentença. Contudo, declararam que, mesmo que não fossem salvos, não adorariam a estátua de ouro. Por essa firme decisão, os três permaneceram fiéis ao Senhor diante do rei.' WHERE "id" = '1aacac06-9b69-4832-86a0-71a38ded3f3e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra estranha onde o rei determinou que os jovens comessem dos manjares reais. Daniel, mantendo sua fidelidade, decidiu não se contaminar com a comida e a bebida oferecidas pelo monarca. Ele solicitou ao chefe dos eunucos uma dieta composta apenas por vegetais e água por dez dias. Após o período de prova, Daniel e seus amigos apresentaram uma aparência mais saudável e robusta do que todos os jovens que consumiram a porção real.' WHERE "id" = '1ada0bd6-51e1-4f64-b616-26e0145ebcce';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após vencer os profetas de Baal, Elias fugiu para o deserto ao ser ameaçado pela rainha Jezabel. Exausto e temeroso, ele desejou a morte sob uma árvore. Deus enviou um anjo para alimentá-lo e fortalecê-lo para sua longa jornada. O profeta seguiu até o monte Horebe, onde se refugiou em uma caverna. Lá, o Senhor manifestou Sua presença, não através de ventos fortes ou fogo, mas por meio de uma voz mansa e delicada, que falou com Elias.' WHERE "id" = '1b5fc897-53dd-4e21-bf7c-de7d9ea3b6bd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreve aos cristãos de Corinto para alertar sobre uma grave crise interna na comunidade. Falsos mestres infiltraram-se no meio dos fiéis por meio de conversas persuasivas e inofensivas. Essas ideias distorcidas foram gradualmente corroendo as convicções fundamentais dos membros da igreja. O apóstolo identifica que o perigo não provinha de ataques externos, mas dos próprios vínculos relacionais e das vozes influentes do círculo íntimo, que estavam alterando silenciosamente a maneira de pensar e de agir daquela geração.' WHERE "id" = '1b65baef-cee4-443c-9f4a-d3c3fc7674c9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia, onde o rei ordenou que ele e seus amigos consumissem as iguarias e vinhos da mesa real. Discordando daquela dieta por questões de convicção, Daniel solicitou respeitosamente ao oficial responsável uma alternativa composta apenas por legumes e água. Após um período de dez dias de teste, Daniel e seus companheiros apresentaram uma aparência física muito mais saudável e robusta do que os outros jovens que se alimentaram das porções oferecidas pelo rei babilônico.' WHERE "id" = '1cf792f0-b515-4771-a7bc-4c2922a0639f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, Daniel recusou as iguarias e o vinho oferecidos pelo rei, mantendo firme sua identidade. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de legumes e água. O oficial aceitou o desafio e permitiu a dieta diferenciada. Ao final do período estipulado, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos os jovens que consumiram a comida real. O acordo foi mantido, preservando a fidelidade deles.' WHERE "id" = '1d29aec4-6c19-4036-b444-d384a6580894';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um alto cargo no império persa, despertando a inveja de seus rivais. Eles manipularam o rei Dario a assinar um decreto que proibia orações a qualquer pessoa ou deus, exceto ao próprio monarca, sob pena de morte na cova dos leões. Ao tomar conhecimento da proibição, Daniel não cedeu às pressões externas. Ele retornou para sua casa, abriu as janelas voltadas para Jerusalém e continuou orando fielmente ao seu Deus, mantendo seu costumeiro hábito diário.' WHERE "id" = '1d997423-24c4-42b1-894e-949009f229bb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante do rei Nabucodonosor e da multidão, Sadraque, Mesaque e Abednego foram ordenados a adorar uma estátua de ouro sob a ameaça de serem lançados em uma fornalha ardente. Enquanto todos se curvavam ao som da música, os três hebreus recusaram terminantemente o decreto real. Eles declararam ao monarca que seu Deus era capaz de livrá-los, mas, caso isso não ocorresse, não adorariam outros deuses nem se prostrariam diante da imagem que o rei havia estabelecido naquela ocasião.' WHERE "id" = '1e42daf7-6fab-46e5-b1ce-74b407532500';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio de sua geração, utilizou a metáfora de uma cidade sem muros para descrever o indivíduo que não governa a si mesmo. No mundo antigo, essas muralhas eram vitais para a sobrevivência e proteção contra invasores. Ao observar reis e guerreiros, ele concluiu que a falta de domínio próprio deixa o ser humano vulnerável e exposto. Assim, a verdadeira batalha ocorre no interior de cada pessoa, mesmo quando ninguém mais está olhando.' WHERE "id" = '1e6fcf97-2828-4585-99a1-4a88eea29bd6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Às vésperas de sua morte, Jesus reuniu seus doze discípulos para um importante discurso. Ele elevou o status daqueles homens, deixando de chamá-los de servos para tratá-los como amigos. Enquanto o servo obedece sem compreender o propósito, o amigo compartilha as intenções e os segredos de quem ama. Jesus estabeleceu que a verdadeira amizade exige o sacrifício supremo, definindo que não existe prova de amor maior do que alguém dar a própria vida pelos seus amigos escolhidos.' WHERE "id" = '1ec6964d-e672-4f65-b002-58a0f510f9b7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O passarinho Simão desobedeceu aos avisos de sua mãe sobre não voar para longe da árvore. Por ignorar o conselho, ele acabou se perdendo durante uma forte tempestade. Após passar por essa experiência difícil, Simão decidiu aprender a ouvir e a confiar nas instruções recebidas. Com o passar do tempo, tornou-se um pássaro maduro que sabia tomar boas decisões. Graças à sua mudança de comportamento, ele conquistou o respeito de todo o bosque devido à sua nova sabedoria.' WHERE "id" = '1ed0861d-de79-44d4-8c66-5c450962a1b2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de modo desregrado, o filho mais novo ficou sem recursos e enfrentou uma severa fome. Reconhecendo sua miséria, ele decidiu retornar à casa de seu pai, planejando pedir para ser tratado apenas como um empregado. Ao se aproximar, o rapaz confessou sinceramente seu erro, assumindo que não era mais digno de ser chamado filho. Antes que ele terminasse sua fala, o pai o recebeu com um abraço e profunda compaixão.' WHERE "id" = '1ed695c6-04ff-4f71-a196-05945acc3137';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após assumir o trono de Israel ainda jovem, o rei Salomão recebeu uma visita de Deus em um sonho. O Criador ofereceu realizar qualquer pedido que ele desejasse. Em vez de solicitar riquezas, poder ou a destruição de seus inimigos, Salomão pediu humildemente um coração sábio e discernimento para governar seu povo com justiça entre o bem e o mal. Impressionado com sua escolha, Deus concedeu o discernimento solicitado e ainda lhe acrescentou grande honra e prosperidade.' WHERE "id" = '1edb0ac2-e45b-43b0-82a4-67a5f47426e5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi cometeu adultério e ordenou a morte de Urias, ocultando o pecado por meses. O profeta Natã confrontou o rei através de uma parábola sobre um homem que roubou o cordeiro de seu próximo. Indignado, Davi condenou o vilão, mas Natã revelou que o rei era o verdadeiro culpado daquela história. Diante da verdade exposta pelo profeta, Davi não ofereceu desculpas ou justificativas. Ele reconheceu seu erro perante Deus e confessou diretamente: Pequei contra o Senhor.' WHERE "id" = '1f0c7f6c-ab4d-479b-8d98-daeb7003cddb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, observou profundamente a trajetória de diversos seres humanos ao longo de sua vida. Ele testemunhou reis que acumularam grandes fortunas e riquezas, mas caíram rapidamente no esquecimento após a morte. Em contrapartida, viu homens pobres que, por viverem com retidão, foram recordados por décadas com respeito genuíno. Baseado em sua vasta experiência, o sábio rei concluiu que a integridade de um indivíduo é mais valiosa do que qualquer tesouro acumulado durante sua existência.' WHERE "id" = '1fc08045-6675-415f-821c-8788f492f3be';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus reuniu multidões diversificadas, incluindo zelotes militantes, fariseus julgadores e seus próprios discípulos orgulhosos. Em meio a esse ambiente de tensões políticas e religiosas, Ele proferiu uma beatitude revolucionária. O Mestre declarou bem-aventurados os pacificadores, subvertendo as hierarquias de poder vigentes na época. Ele desafiou seus ouvintes a não ignorarem os conflitos, mas a agirem com coragem e propósito. Essa mensagem de Jesus posicionou o pacificador como alguém disposto a sacrificar interesses pessoais para restaurar a ordem em um cenário hostil.' WHERE "id" = '1ffc2513-421d-45e0-88d2-a667d153c652';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus criou um jardim para Adão e Eva, permitindo que comessem quase todos os frutos, exceto os de uma árvore específica. A serpente aproximou-se de Eva, questionando a proibição divina e incentivando o consumo do fruto. Seduzida pela oferta, Eva cedeu à tentação e comeu. Logo em seguida, ela ofereceu o fruto a Adão, que também aceitou comer. Ao desobedecerem a ordem expressa de Deus, a condição de vida do casal no jardim foi alterada para sempre naquele momento.' WHERE "id" = '201dcac2-5cd1-4df2-b38d-30175768f1d0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sansão era um homem dotado de força sobrenatural, chamado e com um propósito divino específico. Ele permitiu que Dalila, uma mulher próxima e aparentemente amorosa, conquistasse sua confiança. Por meio de insistência contínua e da intimidade que compartilhavam, Dalila enfraqueceu o discernimento do guerreiro. Sansão acabou revelando o segredo de sua consagração, o que resultou na perda de seus cabelos, na captura pelos filisteus e, finalmente, no distanciamento da presença de Deus em sua vida diária.' WHERE "id" = '20234dbc-215f-4a63-af1d-522db127d802';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o renomado filho do rei Davi, desfrutou de riquezas, poder e uma sabedoria incomparável entre os monarcas de sua época. Após observar profundamente a trajetória humana e as consequências das escolhas individuais ao longo da vida, ele consolidou seu entendimento em um provérbio registrado. O rei concluiu que a reputação, um bom nome, possui um valor superior a todas as grandes riquezas acumuladas. Essa reflexão foi fruto de sua longa experiência de vida e observação da conduta humana.' WHERE "id" = '204d499e-114a-4213-bb2e-250879e741c2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança em escolhas imprudentes, o filho mais novo decidiu retornar à casa de seu pai, esperando ser tratado apenas como um dos empregados. Enquanto se aproximava, ainda distante, o pai o avistou e correu ao seu encontro. Sem permitir que o jovem terminasse o discurso que havia ensaiado para pedir perdão, o pai o abraçou afetuosamente. Ele acolheu seu filho com amor, interrompendo qualquer julgamento e selando a reconciliação imediata entre eles naquela ocasião.' WHERE "id" = '20958134-9248-41ad-8c69-4b95109f6c97';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um viajante descia por uma estrada quando encontrou um homem gravemente ferido caído no chão. Enquanto outros passavam sem prestar socorro, esse homem parou ao vê-lo. Com profunda compaixão, aproximou-se e cuidou de seus ferimentos, limpando-os cuidadosamente. Em seguida, colocou o desconhecido sobre seu próprio animal e o conduziu a uma hospedaria. Lá, ele garantiu que o homem ferido recebesse os cuidados necessários para sua plena recuperação, pagando por todas as despesas da estadia até que melhorasse.' WHERE "id" = '20a1e0ba-e861-4fae-ac19-a074992ce27b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Aos setenta e cinco anos, Abraão recebeu uma ordem direta de Deus para abandonar sua terra natal na Mesopotâmia. Sem possuir um mapa ou conhecer o destino final de sua jornada, o patriarca não hesitou diante do desconhecido. Ele deixou para trás suas raízes e seus costumes, levantando-se imediatamente para iniciar o caminho. Abraão obedeceu ao chamado divino e partiu rumo a uma terra que lhe seria revelada, movendo-se com absoluta convicção mesmo sem qualquer garantia visível anterior.' WHERE "id" = '212f6ee6-5584-4ce5-99aa-8cc9249cb003';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Aos dezessete anos, José foi traído por seus irmãos, que o venderam como escravo por inveja. Levado ao Egito, serviu com diligência, mas sofreu uma falsa acusação e terminou encarcerado. Após anos de injusto esquecimento na prisão, José interpretou os sonhos de Faraó. Reconhecendo sua sabedoria divina e capacidade administrativa, o monarca egípcio libertou José do cárcere e o nomeou governador sobre toda a terra do Egito, concedendo-lhe autoridade absoluta para gerir a nação durante a crise.' WHERE "id" = '2163a3f1-8a75-45c1-86d6-4b3b45710cf5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua vasta sabedoria, realizou observações constantes sobre o comportamento humano dentro de sua corte real. Ele notou que jovens que escolhiam andar ao lado de companheiros sábios desenvolviam honra e inteligência ao longo do tempo. Por outro lado, aqueles que preferiam a proximidade com pessoas que praticavam o mal acabavam seguindo o mesmo caminho de perdição. Diante desses fatos, Salomão registrou essa verdade essencial para orientar a escolha das amizades de seus filhos.' WHERE "id" = '219b0bfd-42cb-42fd-a592-a0c4ce7a22ae';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após anos afastados devido a um conflito, Jacó retornou à sua terra temendo a reação de seu irmão, Esaú. Ao avistá-lo à distância, Jacó aproximou-se curvando-se repetidamente até chegar perto dele. Surpreendentemente, Esaú correu ao seu encontro, abraçou-o fervorosamente e lançou-se sobre o seu pescoço, beijando-o. Diante daquela reconciliação inesperada, ambos os irmãos choraram copiosamente. O antigo ressentimento foi substituído por um gesto de afeto, restaurando assim o vínculo familiar que havia sido rompido no passado.' WHERE "id" = '222a5cb9-fcfb-4730-8614-6667a4ff5ade';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar toda a sua herança, o filho pródigo enfrentou uma severa escassez de recursos. Reconhecendo sua miséria, decidiu retornar à casa do pai para pedir perdão e trabalho como servo. Durante o caminho de volta, ainda distante, foi avistado pelo pai, que correu ao seu encontro. Antes que o rapaz pudesse concluir sua confissão preparada, o pai o recebeu com compaixão e abraços, acolhendo o filho que havia se perdido e agora retornava para o seu lar.' WHERE "id" = '2232ca16-2685-45ad-9f29-742cd2388a9e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, possuidor de sabedoria única e de um reino próspero, desobedeceu às advertências divinas ao casar-se com muitas mulheres estrangeiras. Tais esposas, devotas a outros deuses, influenciaram suas escolhas e distorceram sua fidelidade ao Senhor. Com o passar do tempo, o coração do monarca desviou-se da obediência plena, levando-o a abandonar o caminho de seu pai, Davi. Salomão curvou-se diante de ídolos e construiu altares para agradar suas esposas, comprometendo assim a aliança estabelecida por Deus.' WHERE "id" = '22831bcf-95ee-44eb-873b-ddc12a3c3eec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, através de suas observações, registrou uma verdade fundamental sobre a gestão dos recursos humanos. Ele analisou dois perfis distintos de indivíduos: aqueles que mantinham as mãos fechadas sobre seus bens, tempo e influência, acabando por serem esquecidos pelo tempo, e aqueles que distribuíam intencionalmente o que possuíam com generosidade. Para o monarca, a forma como cada pessoa lidava com suas posses determinava o seu impacto e o legado que seria deixado para as futuras gerações.' WHERE "id" = '22f68fef-7505-41f1-87e5-aea2b36bdf6a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos de Filipos enquanto enfrentava o rigor de um confinamento em uma prisão romana. Em meio à incerteza sobre o seu próprio futuro e cercado por adversários, ele não se deixou dominar pela ansiedade. Pelo contrário, Paulo instruiu os fiéis a apresentarem todas as suas necessidades diante de Deus através de orações sinceras, acompanhadas por gratidão constante. Como resultado, ele assegurou que uma paz divina guardaria os corações e mentes deles.' WHERE "id" = '23749ec2-a4cf-474f-a6b6-1e49f3c57716';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus contou a história de uma viúva que buscava justiça perante um juiz corrupto em sua cidade. Esse magistrado não temia a Deus nem respeitava qualquer pessoa, ignorando inicialmente o pedido da mulher. Contudo, devido à persistência constante da viúva em clamar por socorro, o juiz decidiu atender sua petição para não ser mais incomodado por ela. Jesus utilizou esse exemplo para contrastar a atitude do homem injusto com a prontidão de Deus em ouvir seus escolhidos.' WHERE "id" = '23b609c6-e094-4a41-af34-92e05deee08f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após cometer adultério com Bate-Seba e ordenar a morte de Urias para ocultar seu pecado, o rei Davi viveu meses em silêncio. Deus enviou o profeta Natã ao palácio, que confrontou o monarca por meio de uma parábola sobre um homem rico e um cordeiro. Ao compreender a gravidade de suas ações e a condenação contida na história, Davi reconheceu sua transgressão perante o profeta, declarando abertamente que havia pecado contra o Senhor. O rei não buscou qualquer justificativa.' WHERE "id" = '243d1c60-a9d2-4d3e-8c92-44f1e2546c66';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José administrava com excelência a casa de Potifar, que nele depositava total confiança. A esposa de seu senhor começou a pressioná-lo diariamente para que se deitasse com ela. José recusou firmemente todas as suas investidas, declarando que não pecaria contra Deus ao trair a confiança de seu mestre. Em um momento de insistência, ela o agarrou pelas vestes, mas ele fugiu da casa e a deixou para trás, sofrendo as consequências de sua decisão ao ser preso injustamente.' WHERE "id" = '246b72ad-e2cb-4738-98d7-07397be2c6a6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A mulher descrita em Provérbios 31 conquistou a plena confiança de seu marido por meio de uma postura constante e diligente. Ela antecipava as necessidades do lar, agindo com sabedoria e eficiência em suas tarefas cotidianas. O marido depositava total segurança nela, pois observava um padrão consistente de caráter e trabalho árduo. Essa confiança não se baseava em promessas superficiais, mas no reconhecimento prático da integridade demonstrada por ela, servindo como o fundamento sólido para toda a estrutura familiar.' WHERE "id" = '24bce7c0-4b93-45d1-b7fc-e785dbcc03ff';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia, Sadraque, Mesaque e Abednego recusaram-se a adorar o ídolo. Confrontados pelo rei, os três jovens mantiveram sua posição firme. Eles declararam que seu Deus era capaz de livrá-los daquele fogo, mas afirmaram categoricamente que, mesmo que o livramento não ocorresse, eles jamais se curvariam diante daquela imagem de ouro imposta pelo monarca.' WHERE "id" = '24bfb230-955a-4d72-a2a1-9fd9f3c52f28';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho partiu após receber sua herança, mas gastou tudo em terras distantes, passando fome e privações. Arrependido, ele decidiu retornar à casa de seu pai para pedir perdão e oferecer-se como servo. Enquanto o jovem caminhava, seu pai o avistou de longe e correu ao seu encontro, abraçando-o com afeto. Embora o rapaz tenha confessado seus erros, o pai prontamente o recebeu com uma grande festa, celebrando o retorno daquele que antes estava completamente perdido.' WHERE "id" = '24db7077-8452-4c73-a066-bc757e0c8e9d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga é um pequeno inseto que trabalha diligentemente sem precisar de supervisão ou ordens externas. Durante o período do verão, ela observa a mudança das estações e antecipa a chegada do inverno. Enquanto outros seres se distraem, a formiga coleta seus grãos com cuidado e disciplina, armazenando suprimentos com paciência. Quando o frio intenso finalmente chega e o alimento torna-se escasso, ela permanece protegida e suprida em seu abrigo, garantindo sua sobrevivência por ter se preparado antecipadamente.' WHERE "id" = '24df8fc3-4208-49c7-a010-4a35d2ceee44';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão vivia confortavelmente em sua terra, cercado por sua família, posses e uma rotina estabelecida. Deus ordenou que ele partisse para um lugar desconhecido, que seria revelado posteriormente. Sem um mapa, garantias concretas ou explicações lógicas que justificassem tal mudança, Abraão obedeceu prontamente. Ele deixou seu lar e seguiu em direção a um destino incerto, guiado apenas pela convicção sobre a promessa divina. Assim, o patriarca iniciou sua jornada em total obediência ao chamado de Deus.' WHERE "id" = '255afafe-492c-476b-bfac-5b1df333341c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus desceu sobre o Monte Sinai cercado por trovões e chamas intensas, provocando grande temor nos israelitas que observavam o evento. Diante do povo reunido e atento, o Senhor estabeleceu um mandamento fundamental para a vida em sociedade: a ordem de honrar pai e mãe. O Criador afirmou que essa postura de respeito e obediência aos pais garantiria uma vida longa e próspera. Assim, o povo recebeu essa diretriz divina diretamente de Deus enquanto estavam diante do monte sagrado.' WHERE "id" = '258d6e16-8548-4609-b836-4e9a4f0e8744';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel enfrentou a pressão de adotar a cultura local e consumir alimentos oferecidos a ídolos. Decidido a manter sua fidelidade, ele propôs ao responsável um teste de dez dias, consumindo apenas vegetais e água. Após esse período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que aceitaram a dieta real. Deus concedeu a eles conhecimento e sabedoria, destacando-os entre todos os servos da corte.' WHERE "id" = '25977ad1-b271-4db2-bd32-dcb57d67583e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pediu sua herança antecipada e partiu para terras distantes, onde desperdiçou todos os seus bens em uma vida desregrada. Após passar por extrema escassez e fome, ele reconheceu seu erro e decidiu retornar à casa de seu pai para pedir perdão e emprego. Enquanto ainda estava longe, o pai o avistou e, movido por profunda compaixão, correu ao seu encontro, abraçando-o calorosamente. O filho foi recebido com amor, apesar de ter esbanjado tudo o que possuía anteriormente.' WHERE "id" = '25cf110c-429e-4b86-9bb8-eb88f31d8a89';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Neemias liderava a reconstrução dos muros de Jerusalém, seus inimigos enviaram quatro convites insistentes para uma reunião na planície de Ono. O objetivo era interromper o trabalho estratégico através de uma falsa diplomacia. Percebendo a intenção maliciosa por trás de cada insistência, Neemias recusou todos os pedidos com a mesma resposta firme e direta. Ele afirmou que realizava uma grande obra e que, por isso, não poderia descer para encontrá-los, mantendo-se focado exclusivamente em sua missão principal.' WHERE "id" = '25d86472-2a0f-4f35-96af-269f5fc3d026';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo viveu na miséria cuidando de porcos. Ao reconhecer sua situação desesperadora, decidiu retornar à casa de seu pai, planejando um pedido de desculpas por seus erros. Durante o trajeto de volta, ele carregava o medo de ser rejeitado. Contudo, ao avistá-lo à distância, o pai correu ao seu encontro, acolhendo-o com um abraço afetuoso antes mesmo de ouvir qualquer palavra. A restauração iniciou-se naquele momento de humilde retorno.' WHERE "id" = '2642aff0-f90a-46b7-8b45-5b3673019470';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas mantiveram uma amizade profunda, marcada pela lealdade. Quando o rei Saul, pai de Jônatas, planejou assassinar Davi, Jônatas decidiu proteger o ungido de Deus em vez de priorizar o sangue e o trono. Ao agir contra o desejo do seu próprio pai, o príncipe abriu mão da herança real para salvar a vida de Davi. Essa escolha deliberada preservou o futuro rei e consolidou uma aliança baseada no caráter, honrando a decisão de Jônatas na história bíblica.' WHERE "id" = '2714d066-1e17-4adb-a337-9d377783669b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem foi assaltado na estrada entre Jerusalém e Jericó, ficando gravemente ferido. Um sacerdote e um levita passaram pelo local, mas ignoraram a vítima. Em seguida, um samaritano aproximou-se, tratou os ferimentos do homem e o transportou até uma hospedaria. O samaritano cuidou dele pessoalmente e pagou as despesas da estalagem, prometendo ao hospedeiro cobrir qualquer gasto adicional necessário para a recuperação completa do desconhecido. Assim, o samaritano garantiu o tratamento integral daquele homem ferido e abandonado.' WHERE "id" = '273b69ad-7cf9-4d8a-bb8f-7c0db110b8f3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, dotado de sabedoria divina singular, governou Israel com discernimento superior a todos os homens. Contudo, ao longo de seu reinado, ele desobedeceu aos mandamentos ao tomar setecentas esposas e trezentas concubinas de nações estrangeiras. Essas mulheres desviaram gradualmente o coração de Salomão, levando-o a construir altares para diversos deuses pagãos em seu território. Assim, o homem outrora mais sábio da terra abandonou o Senhor, perdendo a fidelidade exclusiva que devia ao seu Deus.' WHERE "id" = '278475ae-6126-48f7-b51b-6f4ba6059f74';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem levado para um lugar estrangeiro, recusou-se a consumir as iguarias oferecidas pelo rei, pois desejava manter sua fidelidade aos princípios alimentares. Ele propôs ao chefe dos eunucos um teste de dez dias, consumindo apenas vegetais e água. O oficial aceitou a sugestão e observou o desenrolar do período. Ao final dos dez dias, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta do que todos os jovens que comeram a comida do rei.' WHERE "id" = '29506ce1-ee27-4bd7-a7c5-9ef3c3466756';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi começou sua jornada cuidando de ovelhas no campo, onde aprendeu a ser corajoso e a confiar em Deus por meio de convivências salutares. Após ser ungido rei, ele consolidou um reinado poderoso. Contudo, em momentos cruciais, Davi afastou-se de seus conselhos sábios e deu ouvidos a pessoas que não agiam corretamente. Essas escolhas infelizes resultaram em grandes confusões e graves problemas pessoais, demonstrando como as companhias exercem uma influência direta e profunda sobre as decisões tomadas pelo monarca.' WHERE "id" = '29c389e6-0d3f-4478-bbb3-42dc84e02225';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi encontrava-se em um período humilhante de sua vida, fugindo de seus inimigos. Para escapar com vida, ele fingiu loucura diante do rei Aquis, perdendo sua reputação e autoridade. Apesar da situação embaraçosa e de estar desamparado, Davi decidiu bendizer ao Senhor em todo o tempo. Ele afirmou que o louvor estaria continuamente em seus lábios e convidou as pessoas que estavam ao seu redor para engrandecerem a Deus junto com ele, compartilhando assim a mesma confiança divina.' WHERE "id" = '29ead731-8089-4c8d-8302-44f2ea5821d0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, conhecido como o homem mais sábio que já existiu, transmitiu um conselho fundamental ao seu próprio filho. Ele instruiu que o jovem mantivesse seus olhos fixos e atentos ao caminho diante de si, evitando distrações laterais. Salomão enfatizou que o foco direcionado é essencial para que alguém alcance seus objetivos com êxito. Essa orientação histórica destaca a importância de manter a visão firme no propósito, evitando que desvios momentâneos desviem o indivíduo do trajeto correto escolhido.' WHERE "id" = '2a8c1c0c-7699-40d7-b3ad-8411e63a5844';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em um único dia, Jó sofreu perdas avassaladoras. Mensageiros chegaram sucessivamente relatando a destruição de seu gado, a morte de seus servos e o falecimento de todos os seus filhos. A calamidade despojou Jó de seus bens e de sua família em um intervalo curtíssimo. Diante de tamanha devastação, ele rasgou suas vestes, rapou a cabeça e prostrou-se no chão. Jó declarou que veio nu ao mundo e que voltaria sem nada, bendizendo o nome do Senhor.' WHERE "id" = '2b3ae018-dec4-49a7-88d9-d60b9049b978';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho mais novo enfrentou uma severa escassez e fome. Em meio ao desespero, ele reconheceu sua miséria e decidiu retornar à casa de seu pai, planejando pedir perdão para trabalhar como um de seus servos. Ao iniciar a jornada de volta, seu pai o avistou de longe. Movido por profunda compaixão, o pai correu ao encontro do filho, acolhendo-o prontamente antes mesmo que ele terminasse de falar suas palavras de arrependimento.' WHERE "id" = '2b579ff7-02af-43f4-92e7-5f06c947d12f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Elias fugiu para o deserto, exausto e desanimado, desejando a própria morte após confrontar seus inimigos. Deitado sob um zimbro, ele adormeceu profundamente. Um anjo do Senhor tocou-o e ofereceu pão assado nas brasas e uma jarra de água. Elias comeu e bebeu, mas tornou a dormir. O mensageiro divino retornou, serviu-lhe novamente e ordenou que se alimentasse, pois a jornada seria longa. Fortalecido por aquela provisão, o profeta caminhou quarenta dias até o monte Horebe.' WHERE "id" = '2bd78f31-15aa-4962-bb72-a89aba0d82b7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens com lepra avistaram Jesus e pediram misericórdia. Seguindo a ordem do Mestre, eles foram apresentar-se aos sacerdotes e, durante o trajeto, foram curados de sua enfermidade. Apenas um homem, um samaritano, retornou para glorificar a Deus em alta voz e lançar-se aos pés de Jesus em gratidão. Jesus então questionou o paradeiro dos outros nove, observando que somente o estrangeiro voltara para reconhecer o milagre recebido, enquanto os demais seguiram seus caminhos após a cura.' WHERE "id" = '2c44ed79-d6de-4532-a6ad-9c41e832af10';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a liderança de Israel em um momento de incerteza diante de territórios desconhecidos e inimigos poderosos. Reconhecendo o temor diante da nova responsabilidade, Deus falou diretamente com ele. O Senhor ordenou que Josué fosse corajoso, agisse com firmeza e seguisse estritamente a lei, sem desviar-se para a direita ou para a esquerda. Essa instrução divina tornou-se a base fundamental para a condução do povo e a conquista da terra prometida por Deus.' WHERE "id" = '2caed807-a3c5-4421-a1fd-65ed0266d997';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens leprosos avistaram Jesus e suplicaram por misericórdia à distância. Seguindo a ordem do Mestre, caminharam em direção aos sacerdotes e foram milagrosamente curados. Apenas um deles, um samaritano, retornou imediatamente para glorificar a Deus em alta voz e prostrar-se aos pés de Jesus. O Salvador questionou o paradeiro dos outros nove, que não voltaram para agradecer. Enquanto os outros seguiram seu caminho após a cura, aquele samaritano recebeu uma bênção especial ao reconhecer a fonte do milagre.' WHERE "id" = '2cbdbe8b-6496-466c-90dd-7585ee12b7d3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra distante, onde precisava seguir as ordens dos chefes locais. Quando lhe ofereceram uma comida que ele não deveria consumir, Daniel recusou o banquete com calma, enquanto os outros jovens aceitaram o alimento. Ele propôs um teste ao guarda responsável para provar que legumes e água seriam suficientes. Ao final de dez dias, Daniel e seus amigos apresentaram uma aparência mais saudável e robusta que todos os outros que comeram as iguarias.' WHERE "id" = '2cc10378-8f7b-4df7-800d-ad52d25fab21';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após vencer o gigante Golias, Davi encontrou Jônatas, filho do rei Saul. No momento em que se conheceram, formou-se um vínculo profundo entre eles, descrito como um amor intenso, semelhante ao que Jônatas tinha por si mesmo. Para consolidar essa aliança de lealdade, o príncipe presenteou o jovem pastor com suas próprias vestes reais, incluindo seu manto, sua espada, seu arco e sua armadura. Assim, ambos os homens decidiram unir seus destinos, selando uma amizade marcada pela entrega mútua.' WHERE "id" = '2cd4d47a-d8d0-425f-aa9c-47e68a96ab5d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos se prostrassem perante ela, sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem, declarando que seu Deus era capaz de livrá-los, mas que, ainda que não o fizesse, não serviriam aos deuses do rei. Furioso, o monarca ordenou que fossem lançados ao fogo. Contudo, os três jovens saíram ilesos, permanecendo fiéis à sua fé diante da intensa pressão real.' WHERE "id" = '2ce9aba7-d197-4b5f-94f7-7da15d0e7de2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança, abandonou o pai e partiu para terras distantes. Lá, desperdiçou todos os seus bens e acabou vivendo em extrema miséria, cuidando de porcos. Arrependido, decidiu retornar à casa paterna para pedir perdão e servir como um empregado. Enquanto ainda estava longe, o pai o avistou, correu ao seu encontro e o abraçou com profunda compaixão. O pai acolheu o rapaz, restaurou sua dignidade e preparou uma grande festa pela sua volta.' WHERE "id" = '2d380c25-c04b-45e7-b025-2655b573ff47';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia ao decreto real, Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem, permanecendo de pé. Questionados pelo monarca, os três jovens afirmaram firmemente que não precisavam se defender diante daquela exigência. Eles mantiveram sua posição inabalável, declarando ao rei que não se curvariam diante da estátua, aceitando as consequências de sua escolha.' WHERE "id" = '2d71c9fc-66de-47c3-a5ef-aceee8e2bcca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Neemias liderava a reconstrução dos muros de Jerusalém, seus opositores Sambalate e Gesém tentaram interromper o trabalho por quatro vezes. Eles enviaram mensagens insistentes convidando Neemias para uma reunião estratégica no vale de Ono, visando distraí-lo de sua tarefa. Contudo, Neemias recusou todos os convites, mantendo-se firme em sua posição original. Ele respondeu prontamente que estava ocupado realizando uma grande obra e não poderia descer, priorizando assim a conclusão da restauração das muralhas da cidade.' WHERE "id" = '2d762370-4532-422c-b810-c749a2cc24d4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na véspera de sua morte, Jesus levantou-se da mesa durante a refeição, despiu-se do manto e cingiu-se com uma toalha. Ele começou a lavar os pés de seus discípulos, realizando uma tarefa tipicamente reservada aos servos. Pedro inicialmente resistiu ao gesto, mas Jesus afirmou a necessidade daquele ato para que tivessem comunhão com Ele. Após concluir o serviço, o Mestre sentou-se novamente e questionou o grupo, demonstrando que a verdadeira grandeza reside na disposição de servir ao próximo humildemente.' WHERE "id" = '2d7b82dc-c9b0-4f6b-a6ba-15590988603b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No deserto, Deus dirigiu-se ao seu povo como um pai orienta seu filho antes de uma jornada. Ele apresentou claramente duas estradas distintas diante deles: um caminho conduzia à vida, enquanto o outro levava ao erro. O Senhor ordenou que os israelitas escolhessem a vida, enfatizando que cada passo dado representava uma decisão consciente. Assim, Ele demonstrou que cada ação humana gera consequências reais, comparáveis ao ato de plantar sementes boas ou ruins na mesma terra fértil.' WHERE "id" = '2dd1d69c-0b49-44cd-a312-d0379fed1f38';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Rute, uma jovem estrangeira, decidiu acompanhar sua sogra Noemi e buscar sustento trabalhando nos campos de colheita. Enquanto recolhia espigas, chamou a atenção de Boaz, o dono da propriedade. Impressionado com a dedicação e a lealdade da moça, Boaz ordenou que seus trabalhadores deixassem cair intencionalmente mais grãos pelo caminho. Dessa forma, ele facilitou a colheita de Rute, garantindo que ela encontrasse comida suficiente para suprir as necessidades de ambas durante aquele período de grande escassez.' WHERE "id" = '2e2a2969-8bd4-4a14-8353-98fec685c514';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido e de seus filhos, Noemi decidiu retornar a Belém. Ela instruiu suas noras, Orpá e Rute, a voltarem para suas famílias em Moabe. Orpá despediu-se e partiu, mas Rute recusou-se a abandonar a sogra. Ela afirmou que seguiria Noemi aonde quer que fosse, declarando que o povo e o Deus de Noemi seriam os seus. Com esse compromisso firme, as duas mulheres viajaram juntas, consolidando um laço de lealdade incondicional durante o retorno.' WHERE "id" = '2eaa1093-6f1a-4e6d-af83-aa0747eaee49';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pediu sua parte na herança ao pai e partiu para terras distantes, onde desperdiçou todo o dinheiro vivendo de forma desregrada. Após passar fome e enfrentar extrema miséria, ele decidiu retornar à casa paterna para pedir perdão e servir como empregado. Enquanto caminhava de volta, seu pai o avistou ainda de longe. Movido por compaixão, o pai correu ao seu encontro, abraçou-o e o beijou, recebendo o filho arrependido com uma grande festa de celebração familiar.' WHERE "id" = '2ebd7203-5754-4f0b-947e-1350eb53c21a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O autor de Hebreus dirige-se a uma comunidade cristã exausta pela perseguição, incentivando-a a persistir na fé. Ele menciona uma vasta nuvem de testemunhas do passado, cujos exemplos de resistência servem como modelo. O foco central é Jesus, que suportou o sofrimento da cruz mantendo o olhar fixo no propósito eterno. Ao enfrentar a oposição, Cristo demonstrou uma perseverança inabalável, superando a dor intensa. Esse relato histórico convoca os fiéis a seguirem seu exemplo, mantendo a firmeza necessária diante das dificuldades.' WHERE "id" = '2f4f7ad8-ea48-4699-9410-91d843f9169e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Adão e Eva viviam em perfeita comunhão com Deus no jardim até desobedecerem a ordem divina. Ao ouvirem os passos do Criador, esconderam-se por causa da culpa que sentiam. Deus chamou Adão e perguntou onde ele estava. Adão confessou que se ocultou por estar nu e culpou Eva pela desobediência. Eva, por sua vez, justificou seu erro alegando que a serpente a enganara. Assim, o casal buscou transferir a responsabilidade de suas ações diante do questionamento direto de Deus.' WHERE "id" = '2f81309a-fb6c-4f37-b16b-2ae192917540';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança com arrogância, o filho mais novo enfrentou uma severa escassez de alimentos. Sem recursos, reconheceu seu erro e decidiu retornar à casa de seu pai, esperando ser tratado como um empregado. Enquanto ainda estava longe, o pai avistou o jovem e, movido por compaixão, correu ao seu encontro. Ele o abraçou, ordenou que vestissem o rapaz com as melhores roupas e organizou um grande banquete para celebrar o retorno daquele que estava perdido.' WHERE "id" = '3030a8f3-045b-4f7c-acb9-0733c3010d0e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio de sua geração, observou a estrutura de cidades antigas para ilustrar uma realidade humana. Ele descreveu uma cidade destituída de muros como um local vulnerável, onde qualquer inimigo pode entrar e saquear sem enfrentar resistência. O rei utilizou essa imagem brutal para comparar a falta de proteção física com a ausência de autocontrole pessoal. Assim, o indivíduo que não domina seus impulsos torna-se um território aberto, incapaz de defender sua própria integridade diante dos problemas.' WHERE "id" = '303d4d9f-2271-4a12-b72f-4c22f0455148';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deportado para a Babilônia, Daniel foi selecionado para servir na corte do rei Nabucodonosor. Ofereceram-lhe as iguarias e o vinho da mesa real, mas ele decidiu não se contaminar. Daniel propôs ao supervisor um teste de dez dias, alimentando-se apenas de vegetais e água. O oficial aceitou o desafio e permitiu a dieta diferenciada. Ao final do período, Daniel e seus companheiros apresentavam uma aparência mais saudável e robusta do que todos os jovens que consumiam a dieta real.' WHERE "id" = '309b49b1-006f-4c5e-a920-50ca41553499';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em uma vida de excessos, o filho pródigo enfrentou a miséria extrema e a solidão, sendo abandonado por seus falsos amigos. Isolado e passando fome enquanto cuidava de porcos, ele finalmente caiu em si, reconhecendo sua condição deplorável e a abundância na casa de seu pai. Decidido a pedir perdão, ele deixou o campo, iniciou sua jornada de volta para casa e, ao aproximar-se, foi avistado pelo pai, que correu ao seu encontro.' WHERE "id" = '311296c2-9a2c-4dca-8b78-7899f5903f75';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo viveu na miséria extrema e passou fome. Certo dia, reconhecendo sua condição deplorável, decidiu retornar à casa de seu pai para pedir emprego como servo. Ele levantou-se e iniciou sua jornada de volta. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o e o beijou com profunda compaixão. O filho confessou seus pecados, enquanto o pai o acolheu prontamente em seu lar novamente.' WHERE "id" = '31172b9d-ea4b-45e3-9693-bdd414e505ca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sentado sobre um morro, Jesus encontrava-se cercado por uma multidão de pessoas comuns. Muitos daqueles ouvintes carregavam o peso de brigas antigas, ressentimentos profundos e reputações gravemente danificadas por palavras descuidadas. Diante desse cenário de tensões, Jesus proferiu um ensinamento surpreendente que desafiou a percepção popular sobre a força e a coragem. Ele declarou que aqueles que trabalham ativamente para construir pontes onde antes existiam muros seriam reconhecidos como filhos de Deus, transformando a compreensão de seus seguidores.' WHERE "id" = '31a49f62-4230-4d8c-93b3-4d6f9ba7c16a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José revelou sua identidade aos seus irmãos, que o haviam vendido como escravo por inveja anos antes. Ao reconhecê-los, ele chorou copiosamente, a ponto de ser ouvido por toda a casa de Faraó. Apesar da traição sofrida no passado, José não buscou vingança. Em vez disso, declarou que Deus o enviara àquela terra para preservar a vida de sua família. Ele abraçou seus irmãos e beijou cada um deles, selando finalmente a reconciliação entre toda a sua parentela.' WHERE "id" = '321d3222-6cf8-4894-81ea-6ba3b38a6236';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, observou como as companhias influenciam o destino das pessoas. Ele afirmou que caminhar com sábios torna alguém sábio, enquanto conviver com insensatos conduz à ruína. O exemplo de Jó ilustra essa realidade, pois seus amigos, embora presentes durante sua profunda tragédia, proferiram palavras inadequadas no momento de maior fragilidade dele. Assim, Salomão concluiu que a escolha das amizades determina o rumo da vida, pois companhias incorretas geram consequências negativas e destrutivas.' WHERE "id" = '322bc913-421a-4edb-8712-9dcfae29d98e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No deserto, o povo de Israel queixou-se de fome. Deus, então, prometeu enviar pão do céu, orientando que cada pessoa recolhesse apenas o suficiente para o dia. Contudo, alguns desobedeceram e guardaram uma porção extra para o dia seguinte. Como resultado, o alimento apodreceu e criou vermes. Em contraste, aqueles que seguiram rigorosamente a instrução divina encontraram pão fresco todas as manhãs. Assim, o sustento diário foi providenciado conforme a ordem estabelecida pelo Senhor para todo o seu povo.' WHERE "id" = '33abd918-5255-461e-843c-e4c20847bf1f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi trabalhava como pastor de ovelhas cuidando de seu rebanho sozinho no campo. Durante o serviço, um leão enorme surgiu repentinamente tentando atacar um dos animais sob seus cuidados. Embora sentisse medo diante da ameaça da fera selvagem, o jovem não recuou. Ele enfrentou o animal feroz e protegeu a ovelha contra o predador, agindo com coragem naquele momento crítico. Sua atitude demonstrou uma firme confiança em Deus, mesmo enquanto experimentava o temor natural daquela situação perigosa.' WHERE "id" = '341acae2-91c5-4835-b49b-e11602a9900f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo encontrava-se encarcerado em uma cela escura, fria e distante de seu lar. Diante daquela situação difícil e incerta, ele não se permitiu ser dominado pelo medo ou pela angústia. Em vez disso, escolheu apresentar todas as suas preocupações a Deus em oração, confiando como um filho faz com seu pai. Como resultado direto dessa comunhão, Paulo experimentou uma paz profunda que guardou sua mente e seu coração, mesmo estando confinado sob terríveis condições adversas.' WHERE "id" = '3445ab4c-f205-4512-99eb-86fde9fa3e76';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio do mundo, observou a trajetória de diversos monarcas que perderam seus tronos devido à falta de controle emocional. Ele percebeu que a impulsividade ao falar ou decidir precipitadamente levava à ruína. Por essa razão, Salomão declarou que a capacidade de dominar a própria raiva e os impulsos negativos é uma conquista superior à vitória militar. Para ele, o verdadeiro poder reside na autodisciplina necessária para pensar antes de agir.' WHERE "id" = '345fecdd-c0cf-41de-a9cd-e869160ea7d8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua fortuna, o filho pródigo viveu na miséria cuidando de porcos. Em meio ao sofrimento, ele reconheceu seus erros e decidiu retornar à casa de seu pai para pedir perdão e trabalho. Sem oferecer desculpas ou transferir culpas, o jovem iniciou sua jornada de volta. Ao avistá-lo à distância, o pai correu ao seu encontro com prontidão e afeto, acolhendo seu filho com alegria antes mesmo que ele terminasse de confessar sua falha cometida anteriormente.' WHERE "id" = '347c501a-d40f-42d9-9480-8622c30b8e4c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No Sermão do Monte, Jesus dirigiu-se à multidão para ensinar sobre o Reino de Deus. Durante seu discurso, Ele declarou que os pacificadores são bem-aventurados, identificando-os como filhos do Altíssimo. O Mestre apresentou o princípio da reconciliação como uma ação transformadora diante das tensões humanas. Ele demonstrou que atuar pela paz exige firmeza e poder, não omissão. Assim, Cristo estabeleceu esse padrão elevado de conduta, apresentando a busca ativa pela harmonia como uma característica essencial daqueles que seguem seus ensinamentos.' WHERE "id" = '352b001b-bd78-48aa-9629-154f31f5836a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez leprosos encontraram Jesus enquanto viajavam por uma região entre Samaria e Galileia. Mantendo distância, clamaram por misericórdia. Jesus ordenou que fossem apresentar-se aos sacerdotes para comprovarem a cura. Obedientes, partiram e foram purificados no caminho. Apenas um deles, um samaritano, retornou para glorificar a Deus em alta voz e agradecer aos pés do Mestre. Jesus observou que os outros nove não voltaram e questionou o paradeiro deles, enquanto confirmava a fé daquele único homem que retornou.' WHERE "id" = '357fe55e-0dc7-4690-a258-85f9fbef4789';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em Babilônia, recusou a comida e o vinho oferecidos pelo rei, mantendo sua fidelidade aos preceitos alimentares de sua fé. Ele propôs um teste de dez dias ao guarda responsável, consumindo apenas vegetais e água. Ao final do período, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta do que todos os jovens que comeram das iguarias reais. O teste confirmou a integridade de Daniel e a aprovação divina sobre suas escolhas.' WHERE "id" = '35cfb53c-55f7-4a39-9740-8097a85e99ef';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão partiu rumo ao desconhecido confiando em uma promessa divina. Moisés optou por renunciar ao conforto do palácio egípcio em favor do seu povo. Raabe arriscou a própria vida ao acreditar no compromisso firmado. Esses personagens bíblicos agiram sob a convicção de realidades que ainda não podiam enxergar. Embora tenham mantido a fé ao longo de suas trajetórias, nenhum deles presenciou o cumprimento pleno das promessas, pois Deus reservou um destino superior que integraria também as gerações futuras.' WHERE "id" = '368f2d82-1941-4ee3-9ff5-9e8efb495c96';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão e Ló retornaram do Egito com rebanhos tão grandes que a terra tornou-se insuficiente para ambos. A escassez de recursos gerou conflitos entre seus pastores. Para evitar maiores discórdias, Abraão propôs uma separação e permitiu que Ló escolhesse primeiro o território. Ló observou a planície fértil do Jordão e decidiu habitar próximo a Sodoma. Abraão permaneceu nas terras restantes de Canaã. Assim, o patriarca cedeu a preferência ao seu sobrinho, estabelecendo o limite entre seus grupos familiares.' WHERE "id" = '36ec0107-c3dd-44f4-8a81-194f4f75002b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Noé construísse uma arca gigantesca, apesar de estarem distantes do mar e sob o sol. Durante muito tempo, Noé trabalhou cortando madeira e martelando, enquanto as pessoas ao redor zombavam de sua tarefa. Ele persistiu na construção, obedecendo fielmente às instruções divinas, mesmo sem compreender todos os detalhes do plano. Quando a chuva finalmente começou a cair, a arca estava completamente pronta. Assim, Noé conseguiu salvar sua família e diversos animais da grande enchente mundial.' WHERE "id" = '37163cec-fb1b-4d61-8fd6-8e39414e9055';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria inigualável, observou atentamente o comportamento humano durante anos. Ele percebeu que as companhias exercem uma influência direta na formação do caráter das pessoas. Em seus escritos, o monarca declarou que aquele que caminha junto aos sábios torna-se sábio, enquanto quem escolhe a companhia de tolos acaba sofrendo graves consequências. Salomão descreveu esse fenômeno como uma lei natural observada em todas as famílias, crianças e reinos que existiam ao seu redor naquele tempo.' WHERE "id" = '371fb3b0-421a-4f33-832f-30997791eb46';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, jovem cativo na Babilônia, recusou a comida e o vinho oferecidos pelo rei, pois violavam suas convicções religiosas. Ele solicitou ao chefe dos eunucos uma dieta alternativa baseada apenas em vegetais e água. Após um período de prova de dez dias, Daniel e seus três companheiros apresentaram uma aparência física superior e maior vigor do que todos os outros jovens que consumiam as iguarias reais. Assim, Deus concedeu a eles sabedoria e inteligência em todo conhecimento e letras.' WHERE "id" = '373a1caf-3c89-4065-8556-5b811941fcfb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Noé construísse uma arca gigantesca, prevendo um grande dilúvio que cobriria a terra. Embora o céu estivesse limpo e não houvesse sinais de chuva, Noé obedeceu prontamente à instrução divina. Ele trabalhou arduamente por um longo período enquanto enfrentava o escárnio dos seus vizinhos. Finalmente, quando a tempestade começou, Noé, sua família e todos os animais entraram na embarcação. Assim, eles foram preservados com segurança dentro da arca durante todo o tempo da enchente.' WHERE "id" = '37a103cf-2dcb-45da-b208-c2fdd3d34752';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó vivia na terra de Uz como um homem íntegro, justo e temente a Deus. Repentinamente, ele perdeu todos os seus bens, seus dez filhos e sua saúde física, enfrentando o desprezo daqueles que o rodeavam. Apesar do sofrimento profundo e das terríveis provações, Jó permaneceu fiel em seu caráter. Após esse período de intensa aflição, o Senhor restaurou sua sorte, concedendo-lhe o dobro de tudo o que possuía antes, além de novos filhos e uma longevidade abençoada até o fim.' WHERE "id" = '381771fd-9f1c-4feb-89c7-0374f748aa1b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou a Abrão que deixasse sua terra, sua parentela e a casa de seu pai, rumo a uma região que Ele lhe indicaria futuramente. Com setenta e cinco anos de idade, Abrão possuía uma vida estabelecida, porém prontamente acatou a instrução divina. Sem questionar ou hesitar diante da falta de detalhes sobre o destino, ele reuniu seus pertences e partiu conforme a ordem recebida. Assim, Abrão iniciou sua jornada obedecendo rigorosamente à voz do Senhor, conforme o relato bíblico.' WHERE "id" = '387150aa-22a1-4900-916b-3fbb691ed2fa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para um lugar distante, onde chefes exigiam que consumisse alimentos contrários às suas convicções. Enquanto os outros jovens aceitaram a dieta imposta, Daniel recusou-se firmemente a comer. Ele propôs um teste de dez dias aos seus supervisores, alimentando-se apenas de legumes e água. Após esse período, Daniel e seus companheiros apresentavam uma aparência muito mais saudável e robusta que os demais jovens. Assim, eles permaneceram fiéis às suas práticas alimentares sem consumir as iguarias reais.' WHERE "id" = '387c175b-e2ad-49f8-99bb-4d521a9bf4c8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava as pessoas depositarem ofertas no cofre do templo. Muitos ricos contribuíam com grandes quantias de forma ostensiva. Em seguida, uma viúva pobre aproximou-se discretamente e depositou apenas duas moedas pequenas. Jesus chamou seus discípulos para ressaltar que aquela mulher ofertou mais que todos os outros. Enquanto os ricos doaram apenas o que lhes sobrava, ela entregou tudo o que possuía para seu sustento diário, sacrificando seu próprio alimento em um gesto de devoção absoluta e total confiança.' WHERE "id" = '387f242b-460b-43d7-8034-6606c5dd58ac';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto viajavam, os discípulos de Jesus discutiam entre si sobre quem seria o mais importante no grupo. Ao chegarem em Cafarnaum, Jesus percebeu a inquietação e perguntou sobre o assunto da conversa. Após sentar-se, Ele reuniu os doze apóstolos e ensinou um princípio fundamental para o Reino. Jesus afirmou claramente que aquele que deseja ser o primeiro deve comportar-se como o último de todos, colocando-se na posição de servo daqueles que estão ao seu redor naquele momento.' WHERE "id" = '389c1438-da4c-4753-a0a0-1942753ad4de';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi tornou-se um guerreiro famoso após derrotar o gigante filisteu em uma batalha histórica. O príncipe Jônatas, filho do rei Saul, conheceu Davi e estabeleceu uma aliança profunda de amizade com ele. Em um gesto solene e significativo, Jônatas tirou seu manto real, sua espada e seu arco, entregando esses objetos preciosos a Davi. Esse ato selou o compromisso de lealdade entre ambos, demonstrando que o príncipe reconhecia Davi como alguém muito especial e digno de todo o seu respeito.' WHERE "id" = '38a8a8d9-ca2c-45bc-8bdf-1ad303ee7940';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, observou gerações inteiras de pessoas ao longo de sua vida. Ele testemunhou homens que acumularam grandes riquezas, mas perderam o respeito de sua descendência e o legado de seu nome. Simultaneamente, viu indivíduos que partiram sem posses materiais, porém deixaram ensinamentos que continuaram a guiar seus netos por muitos anos. Diante desses fatos, ele concluiu que a reputação e o caráter cultivado possuem um valor superior ao ouro e prata.' WHERE "id" = '38ec8394-1e76-4fc3-a8e1-e7654cf0f5da';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o jovem herdeiro do trono de Israel, recebeu uma oportunidade singular de Deus, que lhe ofereceu realizar qualquer pedido. Diante da responsabilidade de governar uma nação inteira, ele escolheu não pedir riquezas, poder ou a vingança contra seus inimigos. Em vez disso, solicitou sabedoria para discernir entre o bem e o mal. Impressionado com essa decisão, Deus concedeu a Salomão a sabedoria desejada e também lhe deu as outras dádivas que ele não havia solicitado anteriormente.' WHERE "id" = '39a083c1-e701-415f-b101-284e74a2f688';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao assumir o trono de Israel, o rei Salomão recebeu de Deus a extraordinária oportunidade de solicitar qualquer dom que desejasse. Em vez de pedir por riquezas materiais, fama ou uma vida terrivelmente longa, o monarca demonstrou uma confiança profunda e peculiar. Ele solicitou apenas discernimento para governar o povo com sabedoria. Essa escolha estratégica de priorizar a orientação divina sobre a própria ambição pessoal consolidou seu reinado e estabeleceu um legado histórico duradouro que atravessou muitos séculos.' WHERE "id" = '39e90f19-f294-464e-bf89-567422557905';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar sua herança, o filho pródigo enfrentou fome e vergonha vivendo em uma pocilga. Ao retomar a consciência, reconheceu seus erros sem fabricar desculpas ou culpar seu pai. Decidido, levantou-se e iniciou a longa caminhada de retorno para casa. Enquanto ainda estava distante, o pai o avistou e correu ao seu encontro. O rapaz então confessou sua falha perante ele, sendo prontamente acolhido após ter abandonado a vida errante e escolhido voltar ao seu lar original.' WHERE "id" = '39f6ceec-307a-4d3b-9ef3-5f2a9ab6ad93';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Shadraque, Mesaque e Abede-Nego adorassem uma estátua de ouro, sob pena de morte em uma fornalha ardente. Confrontados pelo monarca, os três hebreus recusaram-se a dobrar os joelhos diante do ídolo. Eles afirmaram diante do rei que o seu Deus era capaz de livrá-los daquele fogo. Declararam, contudo, que mesmo que não fossem salvos, não serviriam aos deuses babilônicos nem adorariam a estátua. Permaneceram firmes em sua decisão, enfrentando a autoridade real sem qualquer negociação.' WHERE "id" = '3a601af4-98ce-4fbf-8f06-5b0d1562fa4c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um cargo de alto poder na Pérsia, despertando a inveja de outros oficiais. Sem encontrar falhas em sua conduta, seus rivais articularam um decreto real proibindo orações, visando incriminá-lo. Apesar da ameaça da cova dos leões, Daniel permaneceu fiel aos seus hábitos de oração. Ele foi lançado aos animais, mas permaneceu ileso. Na manhã seguinte, o rei Dario o retirou da cova, constatando que Deus livrara seu servo fiel por causa de sua integridade diante do perigo.' WHERE "id" = '3a77005c-178c-4541-9661-de182481d844';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga é um pequeno inseto que vive de forma independente, sem possuir comandantes, oficiais ou governantes. Mesmo sem ninguém ordenando suas tarefas, ela demonstra uma diligência notável. Durante o período da colheita, o animal se esforça para coletar e armazenar seus mantimentos com antecedência. Ao agir dessa maneira metódica, a formiga garante seu sustento antes que a estação do inverno chegue, assegurando que terá alimento suficiente para sobreviver ao tempo frio e à escassez de suprimentos.' WHERE "id" = '3ad75754-0cd6-4073-bdc7-e032eb639d2b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo encontrou-se em total miséria. Refletindo sobre sua situação degradante, ele decidiu retornar à casa de seu pai, não como herdeiro, mas como um simples empregado. Ao se aproximar, o rapaz reconheceu seu pecado contra o céu e contra o progenitor. Antes que terminasse sua confissão preparada, o pai, movido por profunda compaixão, correu ao seu encontro, abraçou-o e o beijou, restaurando sua dignidade perante toda a família.' WHERE "id" = '3aea73c0-c01d-4ad1-b4ab-77a9efe2c1fd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago e João aproximaram-se de Jesus solicitando lugares de honra ao Seu lado na glória, despertando a indignação dos outros discípulos que almejavam a mesma posição. Percebendo a disputa por poder e reconhecimento entre eles, Jesus interrompeu a discussão para ensinar um novo princípio. Ele afirmou que, no Seu reino, aquele que deseja ser grande deve tornar-se servo de todos. Jesus concluiu declarando que veio ao mundo não para ser servido, mas para servir e oferecer Sua vida.' WHERE "id" = '3b4bd7b9-ec9f-4afd-a1de-131c4b1f2c42';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos da Galácia, instruindo-os a perseverar na prática do bem. Ele reconheceu que a vida sob pressão poderia causar cansaço, mas encorajou a comunidade a não desistir de suas ações bondosas. Paulo enfatizou que quem não desanima diante das dificuldades, colherá frutos duradouros no tempo certo. Assim, orientou os fiéis a realizarem atos de generosidade com todos, priorizando especialmente os membros da própria família da fé durante toda a caminhada cristã.' WHERE "id" = '3b66c100-394b-4acc-bfec-a43f13e2e65f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Gideão quebrou o pote favorito de sua mãe enquanto brincava dentro de casa, desobedecendo a uma ordem clara. Com medo de uma repreensão, ele escondeu os fragmentos atrás do armário e permaneceu em silêncio. A angústia interna e o peso da mentira tornaram impossível para o menino brincar ou rir durante o restante do dia. Ao confessar o ocorrido para sua mãe, ele enfrentou as consequências de suas ações, mas, após a revelação da verdade, encontrou alívio e acolhimento.' WHERE "id" = '3b79679e-4d98-4bed-a67a-e6f87d46a193';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A Sabedoria personificada declara ter existido antes da própria criação do mundo. Ela percorre as encruzilhadas e os portões das cidades, buscando aqueles dispostos a ouvi-la. Enquanto promete discernimento e prosperidade aos que a buscam com intenção, ela se distancia dos arrogantes e apressados. Aqueles que seguem seus caminhos governam com justiça e retidão. Contudo, os que desprezam sua voz enfrentam as consequências naturais de seus próprios erros, colhendo a erosão silenciosa decorrente de suas más decisões.' WHERE "id" = '3bcc061a-131c-4f73-8d40-9a7eeae8478f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Hofni e Finéias, filhos do sacerdote Eli, possuíam influência e acesso ao templo, contudo, desprezavam a Deus. Eles agiam com corrupção, roubando as ofertas destinadas ao Senhor e profanando o culto sagrado através de suas condutas pecaminosas. Deus observou todas as atitudes rebeldes daqueles homens. Devido à persistência na impiedade e à negligência de Eli em corrigi-los, o Senhor decretou um julgamento severo, que resultou na destruição completa da vida de ambos e na ruína de toda a linhagem sacerdotal.' WHERE "id" = '3bccf683-be28-4520-8b15-7908f6964e90';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua herança vivendo sem limites, o filho pródigo enfrentou a escassez e alimentou porcos. Em um momento de clareza, ele decidiu retornar para a casa de seu pai. Enquanto caminhava, o pai o avistou de longe e, movido por compaixão, correu ao seu encontro antes mesmo de qualquer explicação. O pai não exigiu desculpas, mas o acolheu prontamente, ordenando que trouxessem roupas novas e comida para celebrar o retorno daquele que estava perdido.' WHERE "id" = '3bfe0625-6a90-4ec0-becd-f20af0bc7eac';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém a Jericó quando foi atacado, roubado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo ferido, porém seguiram viagem sem ajudá-lo. Posteriormente, um samaritano aproximou-se, tratou suas feridas com azeite e vinho, colocou-o sobre seu animal e levou-o a uma hospedaria. Ele pagou pelos cuidados e prometeu custear gastos adicionais ao retornar. Esse homem socorreu o ferido, agindo com compaixão e cuidando de todas as suas necessidades imediatas ali presentes.' WHERE "id" = '3c6ce26f-c4b3-4f84-bf1f-1e1a4ef5d111';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas estabeleceram uma aliança profunda enquanto a perseguição de Saul contra o jovem pastor crescia. Jônatas, filho do rei e herdeiro legítimo do trono, optou por proteger o amigo em vez de defender a linhagem de seu pai. Ele demonstrou sua lealdade incondicional ao entregar a Davi suas vestes, espada, arco e cinto. Esse pacto, selado diante de Deus, comprometeu Jônatas a zelar pela vida de Davi, colocando sua própria segurança e sucessão real em risco constante.' WHERE "id" = '3cc2fdb0-85aa-4029-b281-df6dbe01c9a0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, em sua observação perspicaz sobre o comportamento humano, constatou que as palavras possuem um impacto profundo na realidade. Ele presenciou diversos indivíduos destruírem casamentos através de comentários imprudentes, além de líderes que perderam sua autoridade ao falarem sob o efeito da raiva. O monarca também observou como laços relacionais se desfizeram quando o silêncio foi utilizado como ferramenta de punição. Para Salomão, cada expressão verbal proferida representa uma escolha direta que gera consequências imediatas na vida.' WHERE "id" = '3ce3abca-21b8-41e3-94d7-0ad8a3f529b3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um grupo de pássaros convocou Tito para bicar as flores do jardim de um fazendeiro por pura diversão. Tito, ciente de que as flores não lhes pertenciam, recusou o convite dos companheiros e decidiu não participar daquela ação. Enquanto os outros pássaros insistiam na brincadeira, ele manteve sua firme decisão. Ao cair da noite, o fazendeiro fechou o celeiro com grãos quentinhos e permitiu a entrada apenas de Tito, deixando os outros pássaros do lado de fora.' WHERE "id" = '3dae101a-2601-4d42-bb1e-a504c7e2ca75';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Abraão deixasse sua terra natal, sua casa e tudo o que conhecia para caminhar em direção a um destino desconhecido. Embora não tivesse um mapa ou clareza sobre onde dormiria, o patriarca obedeceu prontamente ao chamado divino. Abraão iniciou sua longa jornada confiando na direção de Deus, que revelava o trajeto a cada passo dado. Seguindo essas orientações com fidelidade, ele finalmente alcançou o lugar preparado, cumprindo o propósito estabelecido pelo Criador em sua vida.' WHERE "id" = '3dc5a0ff-7256-4d97-9333-08412953c29a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história de Israel, enfrentou as consequências das companhias que escolheu. Apesar de sua sabedoria inicial, ele permitiu que alianças afetivas inadequadas influenciassem suas decisões espirituais. Ao tolerar relacionamentos com pessoas que não seguiam a Deus, Salomão desviou seu coração e comprometeu seu legado. Ele não foi derrotado por exércitos inimigos em campos de batalha, mas sucumbiu gradualmente ao peso das influências daqueles que permitiu estarem próximos ao seu trono e aos seus altares.' WHERE "id" = '3e96cd28-df9c-408e-9e2e-25a55fc55d9a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem partiu de casa após receber sua parte na herança e desperdiçou todos os seus bens em terras distantes. Ao enfrentar a fome e o arrependimento, decidiu retornar para pedir perdão ao seu pai. Enquanto ainda estava longe, o pai o avistou e correu para abraçá-lo. O filho confessou seus erros, mas foi prontamente acolhido com roupas novas e uma grande celebração, pois o pai se alegrou imensamente com o retorno do seu filho antes perdido.' WHERE "id" = '3f05e542-86f4-4bc7-b569-4548bbc715f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sadraque, Mesaque e Abednego permaneceram de pé diante do rei Nabucodonosor enquanto uma multidão se curvava diante de uma estátua de ouro conforme a ordem real. A fornalha ardente estava pronta para punir qualquer desobediência. Questionados sobre sua postura, os três jovens declararam com firmeza que seu Deus era capaz de livrá-los daquele fogo. Afirmaram ainda que, mesmo se não fossem salvos, jamais serviriam aos deuses do rei. Eles escolheram a fidelidade, mesmo enfrentando a ameaça iminente de morte.' WHERE "id" = '3f174642-df17-419c-b502-98f84b6d07cf';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias servia como copeiro do rei persa quando recebeu a notícia de que Jerusalém permanecia em ruínas e o povo enfrentava humilhação. Diante daquela situação trágica, ele não agiu precipitadamente. Durante vários dias, Neemias dedicou-se ao choro, ao jejum e a uma profunda oração a Deus. Somente após esse período de intercessão, ele se apresentou ao rei para relatar o problema. O monarca, tocado por seu pedido, decidiu financiar integralmente a reconstrução da cidade histórica de Jerusalém.' WHERE "id" = '3f60c790-0b20-4256-855e-c0be91ccbafa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José, após ser vendido como escravo pelos próprios irmãos e passar anos sofrendo injustiças, ascendeu ao governo do Egito. Quando seus irmãos, temendo vingança, se prostraram diante dele, o governante escolheu não puni-los. José afirmou que, embora eles tivessem planejado o mal, Deus converteu aquela traição em bem para preservar a vida de muitos. Ele tranquilizou seus irmãos, prometendo cuidar deles e de suas famílias, provendo o sustento necessário durante aquele período de profunda escassez na região.' WHERE "id" = '3f856921-18b1-4da3-8724-2610697b686c';
UPDATE "public"."dev_lessons" SET "share_summary" = NULL WHERE "id" = '3fcf23f5-ec98-45e4-af2c-f116482efc13';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão descreve dois perfis distintos de conduta humana nas decisões cotidianas. O ingênuo caracteriza-se por acreditar cegamente em tudo o que ouve, agindo de forma impulsiva e sem qualquer análise prévia. Em contrapartida, o homem prudente demonstra cautela ao observar e examinar cuidadosamente cada passo antes de tomar uma atitude. Essa comparação destaca como a falta de reflexão diante das escolhas diárias gera consequências inevitáveis, diferenciando claramente o comportamento de quem é sensato daquele que é precipitado.' WHERE "id" = '3ffb9e78-3855-430a-996d-da2284dd7636';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Miquéias atravessava um período de profunda angústia e adversidade, sentindo como se a escuridão tivesse se estabelecido permanentemente sobre sua vida. Diante dessa realidade difícil e dolorosa, ele reconheceu sua própria queda, expressando sua tristeza de maneira honesta e transparente. Contudo, em um ato de extrema coragem e determinação, Miquéias afirmou categoricamente que se levantaria novamente. Ele escolheu confiar na luz divina, que permanecia brilhando intensamente mesmo durante os momentos mais sombrios de sua jornada pessoal.' WHERE "id" = '40b4ece0-da34-4047-85a1-f93571d8b222';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel recebeu ordens reais para consumir os alimentos da mesa do rei. Como a dieta violava suas convicções, ele se recusou firmemente e propôs uma alternativa ao oficial responsável. Sem buscar desculpas ou evitar a situação, Daniel manteve sua posição diante da pressão. Após dez dias de uma alimentação diferenciada, ele e seus três companheiros apresentavam uma aparência mais saudável e robusta do que todos os outros jovens que consumiam as iguarias reais.' WHERE "id" = '40bbb542-96d3-49cd-8e41-521c56d557ec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio de sua geração, estabeleceu seu reinado selecionando cuidadosamente com quem caminharia, negociaria e compartilharia os segredos de seu governo. Sua sabedoria era um hábito cultivado por meio de escolhas conscientes sobre companhias e conselhos. Contudo, ao se desviar desse princípio fundamental e permitir que influências equivocadas moldassem suas decisões privadas, o reino que ele construiu durante décadas começou a rachar silenciosamente por dentro, muito antes de qualquer ameaça externa surgir contra a nação.' WHERE "id" = '40be4108-ee23-41b4-bf94-f8f4ae1754b5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e planejou a morte de Urias. Após meses em silêncio, o profeta Natã visitou o rei e contou a parábola de um homem rico que roubou o único cordeiro de um pobre. Indignado, Davi exigiu justiça contra o infrator da história. Natã então revelou que o próprio Davi era o homem culpado. Confrontado com a verdade sobre seus graves pecados, o rei reconheceu seu erro e confessou diante de Deus que pecou.' WHERE "id" = '40c3f33f-65b5-4588-a518-39415c7d676b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo viveu na miséria cuidando de porcos. Em meio à escassez, ele reconheceu sua situação e decidiu retornar à casa de seu pai. Abandonando o orgulho, levantou-se e iniciou o caminho de volta sem dar desculpas. Enquanto ainda estava longe, o pai o avistou e, movido por grande compaixão, correu ao encontro do filho. Antes mesmo de ouvir qualquer justificativa, o pai o abraçou, selando a reconciliação imediata entre ambos.' WHERE "id" = '40e76907-8a6c-4955-8123-0f5cee972b74';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua profunda sabedoria, transmitiu um conselho fundamental ao seu filho. Ele instruiu que o jovem mantivesse o olhar fixo exclusivamente no caminho à sua frente, evitando distrações visuais que pudessem desviar sua atenção. Ao focar corretamente nos passos dados e manter os pés afastados de veredas perigosas, a pessoa assegura retidão em sua conduta. Salomão enfatizou que essa postura de atenção constante e vigilante é essencial para trilhar um caminho íntegro e seguro.' WHERE "id" = '41162ae6-f15e-4373-99a4-e6307b4238ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi vendido como escravo pelos próprios irmãos e enfrentou anos de injusta prisão no Egito. Contudo, alcançou autoridade como governador e, ao reencontrar seus irmãos que buscavam mantimentos, revelou sua identidade. Dominado pela emoção, José chorou diante deles, revelando quem era. Ele não buscou vingança pelos atos passados, mas escolheu abraçá-los e oferecer perdão. Assim, José garantiu o sustento de sua família, promovendo a reconciliação e o reencontro entre eles em terras egípcias, restaurando os laços familiares rompidos.' WHERE "id" = '418614c3-ad2d-4bfb-a074-690e78346b3b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imponente estátua de ouro e ordenou que todos se prostrassem diante dela sob pena de morte. Shadraque, Mesaque e Abede-Nego recusaram a ordem, mantendo sua fidelidade ao Deus de Israel. Confrontados pelo monarca e ameaçados com a fornalha de fogo ardente, os três jovens mantiveram sua posição com firmeza. Eles declararam que seu Deus poderia livrá-los, mas, mesmo que não o fizesse, jamais adorariam a imagem de ouro estabelecida pelo rei babilônico.' WHERE "id" = '41d47b61-73f2-4df9-a22a-66679f6a05f0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio de sua geração, escreveu que andar com sábios traz sabedoria, enquanto o convívio com insensatos leva à destruição. Apesar de sua profunda compreensão, Salomão viveu o oposto em seus últimos anos. Envolvido por alianças políticas estratégicas e relacionamentos de afeto mal direcionado, ele permitiu que essas influências externas desviassem seu coração dos mandamentos que ele próprio havia ensinado anteriormente. Suas escolhas relacionais negligentes acabaram por corromper a trajetória do rei de Israel.' WHERE "id" = '41f33213-7f73-492c-9727-f16a9bd175dc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta à igreja na cidade de Corinto, um ambiente marcado por filosofias sedutoras e costumes imorais que corrompiam gradualmente seus habitantes. Diante desse cenário de influência silenciosa, Paulo advertiu severamente os cristãos sobre o perigo das más companhias. Ele afirmou que o convívio cotidiano com pessoas de conduta duvidosa acaba por destruir a integridade dos bons costumes. Segundo o apóstolo, essas pequenas concessões e hábitos compartilhados redesenhavam silenciosamente o caráter daqueles fiéis que estavam vulneráveis.' WHERE "id" = '4230985e-4b59-4be5-8eba-de551004441e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Jeosafá soube que três exércitos marchavam contra Judá e buscou a orientação divina. Deus afirmou que a batalha pertencia a Ele. No dia seguinte, o rei enviou cantores à frente de suas tropas em direção aos inimigos. Enquanto o povo louvava ao Senhor, os exércitos adversários entraram em confusão e destruíram-se mutuamente. Quando os homens de Judá chegaram ao local da vigia, encontraram apenas cadáveres. Assim, o povo de Judá venceu sem precisar desembainhar suas espadas.' WHERE "id" = '428c7484-c74e-4bcd-b6e4-706a037466e8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos os povos se curvassem perante ela, sob a ameaça de morte na fornalha ardente. Os jovens Sadraque, Mesaque e Abednego recusaram prontamente tal ordem. Diante da pressão do monarca, os três declararam que seu Deus poderia livrá-los, mas, mesmo que isso não acontecesse, eles permaneceriam fiéis aos seus princípios. Eles não se prostraram, mantendo-se firmes em sua posição, desafiando a ordem real perante toda a multidão.' WHERE "id" = '43573979-e0b2-43f2-9d03-8bedd3d28a38';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e ordenou a morte de Urias para esconder seu pecado. O profeta Natã confrontou o monarca usando a parábola de um homem rico que roubou o único cordeiro de um pobre. Ao ouvir a história, Davi expressou indignação, mas Natã revelou que ele era o culpado. Confrontado pela verdade sobre suas ações diante de Deus, Davi não ofereceu justificativas, admitindo prontamente seu erro com a frase curta: Pequei contra o Senhor.' WHERE "id" = '4416fc46-463d-4f81-b1db-5c179c5de2fe';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo encontrava-se aprisionado, privado de sua liberdade e incerto quanto ao próprio futuro. Em meio a esse confinamento, o apóstolo redigiu uma carta aos cristãos de Filipos. Na mensagem, ele instruiu que, diante da angústia ou preocupação, as pessoas devem apresentar seus pedidos e necessidades a Deus por meio da oração. Como resultado dessa entrega sincera ao Criador, ele assegurou que a paz divina, que excede todo o entendimento humano, guardaria os corações e as mentes dos fiéis.' WHERE "id" = '446fd3ab-d1b4-403d-bae9-2ca6f1c680b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi vendido por seus irmãos como escravo e levado ao Egito, onde enfrentou anos de prisão injusta. Com o tempo, tornou-se governador egípcio. Durante uma grave escassez, seus irmãos viajaram ao Egito em busca de mantimentos, sem reconhecê-lo. Diante da presença deles, José revelou sua identidade, chorou intensamente e declarou ser o irmão que eles venderam no passado. Ele os perdoou, consolou-os pelo sofrimento vivido e providenciou sustento para toda a sua família na terra de Gósen.' WHERE "id" = '44b617b9-9305-48e5-bdd2-3e5b9c65f5ff';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos da Galácia, que enfrentavam um grande cansaço ao praticarem o bem. Ele utilizou a metáfora da perseverança contínua para encorajar aqueles fiéis. Assim como uma formiga que insiste em subir uma pedra carregando uma carga pesada até atingir seu destino final, Paulo instruiu os crentes a não desistirem de suas boas obras. Ele garantiu que a persistência na prática do que é correto resulta, inevitavelmente, na colheita de bons frutos futuros.' WHERE "id" = '45245967-c255-4dd2-907e-a7a1004b9a10';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem tinha dois filhos e o mais novo pediu sua parte na herança. Ele partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Após enfrentar uma severa fome, o jovem decidiu retornar à casa de seu pai, reconhecendo seu erro e desejando ser tratado como um simples empregado. Ao vê-lo aproximar-se, o pai correu ao seu encontro, abraçou-o com grande alegria e ordenou que preparassem uma festa para celebrar seu retorno seguro.' WHERE "id" = '4561d495-4f36-4170-915d-095ed1b391d5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava sozinho de suas ovelhas nos campos. Durante as noites, quando animais selvagens rondavam o rebanho, ele sentia medo e seu coração batia rapidamente no escuro. Para enfrentar esses momentos de perigo e incerteza, Davi recorria à oração, conversando com Deus. O jovem aprendeu a lidar com seu temor natural ao buscar refúgio no Senhor, reconhecendo que era para Ele que deveria correr sempre que o medo surgisse em sua vida.' WHERE "id" = '457e3483-62e2-4214-b49c-3330eaac9ea7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi tornou-se amigo íntimo de Jônatas, filho do rei Saul. Reconhecendo o valor de Davi, Jônatas selou uma aliança de amizade profunda com ele. Ele despiu-se de seu manto, túnica, espada, arco e cinto, entregando-os ao jovem pastor como símbolos de apoio. Mais tarde, diante da hostilidade de Saul contra Davi, Jônatas reafirmou seu compromisso leal, jurando proteção ao amigo. Esse pacto foi mantido através de ações concretas enquanto Davi fugia do rei Saul.' WHERE "id" = '45a537c1-89ad-41e4-8d55-9370e9370c4d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem que viajava foi atacado, ferido e deixado caído no caminho. Sacerdote e levita passaram pelo local, mas seguiram adiante sem prestar qualquer auxílio. Um samaritano, ao passar pelo mesmo trajeto, viu o homem ferido, aproximou-se e cuidou de suas feridas com óleo e vinho. Em seguida, colocou-o sobre seu próprio animal, levou-o a uma hospedaria para garantir sua recuperação e pagou ao hospedeiro todas as despesas necessárias para que o homem fosse devidamente tratado e cuidado.' WHERE "id" = '45e0a3d1-8118-469d-ae21-010f4abe890a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Antes de morrer, o rei Davi aconselhou seu filho Salomão a respeitar a Deus em todas as suas ações. Salomão seguiu fielmente essa orientação durante seu reinado. Com o tempo, ele tornou-se reconhecido mundialmente como o rei mais sábio de todos. Sua fama atraiu governantes de terras distantes, que viajavam longas distâncias para aprender como ele resolvia conflitos e tomava decisões justas. O segredo de Salomão consistia em priorizar o temor ao Senhor, o que orientava seu tratamento para com todos.' WHERE "id" = '462d2277-92b9-4ad4-b3fe-24efda9bb7f5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, buscou a sabedoria divina em vez de riqueza ou poder. Experiente nas consequências de escolhas equivocadas, ele registrou orientações fundamentais para seu filho. O rei aconselhou que os olhos permanecessem fixos no caminho adiante, evitando desvios para a direita ou para a esquerda. Essa instrução enfatizava a necessidade de manter uma postura reta e vigilante, afastando os pés de qualquer mal, garantindo assim que a trajetória de vida fosse conduzida com total prudência.' WHERE "id" = '468419de-12aa-4b9f-ba78-b84276cbc80c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na véspera de sua traição, Jesus dirigiu-se a Pedro e revelou que Satanás solicitara permissão para peneirá-lo como trigo. Ciente da futura falha do discípulo, Jesus afirmou que havia intercedido pessoalmente por ele. O Mestre não pediu que a queda fosse evitada, mas orou para que a fé de Pedro não desfalecesse. Após o seu retorno, o objetivo era que ele fortalecesse seus irmãos. Esse diálogo ocorreu momentos antes dos eventos que levaram à negação de Pedro.' WHERE "id" = '469f76e3-ade5-41d5-ab79-938b80fb1806';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de ovelhas em campos distantes. Durante os momentos de solidão, medo ou diante de dificuldades, ele não se entregava às reclamações. Em vez disso, escolhia cantar louvores a Deus enquanto estava no pasto. Essas constantes expressões de adoração moldaram seu caráter ao longo do tempo. Consequentemente, o menino cresceu e se tornou um homem notável, sendo reconhecido por sua profunda coragem, bondade e sabedoria, desenvolvidas através da sua prática diária de louvar.' WHERE "id" = '476d1953-f9a2-4002-950d-cd89bcdd43fa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava no templo observando o povo depositar ofertas. Enquanto homens ricos lançavam quantias generosas no gazofilácio, uma viúva pobre aproximou-se e depositou duas pequenas moedas de pouco valor. Jesus chamou seus discípulos e afirmou que aquela mulher havia ofertado mais do que todos os outros. Enquanto os ricos contribuíram apenas com o que lhes sobrava de sua abundância, a viúva entregou tudo o que possuía para o seu próprio sustento, demonstrando um sacrifício total ao colocar suas últimas moedas.' WHERE "id" = '47da1cd5-0ef0-4e0e-aef0-68724e633385';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Zaqueu, um cobrador de impostos que enriquecia de forma desonesta sobrecarregando o povo, subiu em uma árvore para observar Jesus passar pela cidade. Ao ser chamado pelo nome, Zaqueu desceu prontamente e declarou diante do mestre que restituiria quatro vezes mais todo o valor que havia obtido de maneira ilícita através de cobranças indevidas. Arrependido de suas ações passadas, ele comprometeu-se a reparar os danos causados, escolhendo agir com total verdade e integridade diante do próprio Jesus.' WHERE "id" = '47f1773d-b8a2-4295-afed-03980b022e03';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto estava encarcerado em uma prisão romana, o apóstolo Paulo aguardava um julgamento que poderia resultar em sua execução. Apesar da incerteza sobre o seu futuro e do contexto de perseguição, ele escreveu uma carta aos filipenses. Em vez de permitir que a ansiedade dominasse sua mente, Paulo instruiu os fiéis a apresentarem seus pedidos a Deus com gratidão. Ele demonstrou na prática, mesmo acorrentado, uma paz profunda que transcendia as circunstâncias externas, protegendo inteiramente o seu coração.' WHERE "id" = '485a12c6-3844-4d96-a008-544132e4bc41';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu a sua herança ao pai e partiu para terras distantes, onde desperdiçou todos os seus bens vivendo de forma desregrada. Após enfrentar escassez e miséria, ele reconheceu seu erro e decidiu retornar para casa como um servo. Enquanto ainda estava longe, o pai o avistou, correu ao seu encontro e o abraçou com compaixão. Em vez de puni-lo, o pai ordenou uma grande festa para celebrar o retorno de seu filho que estava perdido.' WHERE "id" = '487efd78-0697-445b-92e3-ae60af0589bc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte da herança ao pai e partiu para uma terra distante, onde esbanjou todos os seus bens. Ao enfrentar uma severa escassez e fome, decidiu retornar para casa pedindo perdão por seus erros. Antes mesmo de chegar, seu pai o avistou e correu ao seu encontro, abraçando-o calorosamente. O rapaz confessou seu arrependimento e, prontamente, o pai ordenou que trouxessem vestes nobres e organizou um grande banquete festivo para celebrar o seu retorno.' WHERE "id" = '488e8e53-f5a0-453a-9488-20839ac3efb3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens que sofriam de uma doença contagiosa avistaram Jesus e clamaram por socorro. Ele atendeu ao pedido e curou todos eles imediatamente. Radiantes com a restauração, os dez seguiram seus caminhos, mas apenas um deles decidiu retornar. Esse único homem aproximou-se de Jesus, parou e expressou sua gratidão em voz alta. Jesus notou a ausência dos outros nove curados e questionou onde eles estavam. Aquele gesto simples de gratidão do homem marcou profundamente o momento diante de Cristo.' WHERE "id" = '48b04f8f-6e8e-4b32-9ffb-5a699e370086';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, um jovem pastor de ovelhas, apresentou-se diante do rei Saul para enfrentar o gigante filisteu chamado Golias, que aterrorizava o exército de Israel. Embora não fosse um soldado experiente, Davi relatou a Saul como Deus o capacitou a derrotar um leão e um urso enquanto protegia seu rebanho. Confiante no livramento divino que já havia experimentado anteriormente no campo, o jovem corajoso prontificou-se a combater o guerreiro filisteu, recusando-se a permanecer parado diante daquela grande ameaça iminente.' WHERE "id" = '48e488ec-66b8-4e79-accb-e07bfc4c2459';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi traído por seus irmãos, vendido como escravo e encarcerado injustamente no Egito. Anos mais tarde, alcançou uma posição de grande autoridade sobre a nação. Quando seus irmãos apareceram diante dele buscando mantimentos, o confronto aconteceu. Em vez de exercer vingança, José reconheceu a gravidade da traição sofrida, mas escolheu perdoá-los. Ele declarou que, embora o plano deles fosse maligno, Deus interveio soberanamente para converter todo aquele sofrimento em um bem necessário para a preservação de muitas vidas.' WHERE "id" = '49c11e58-edf1-4db1-9998-69c16fb6bb76';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, ainda jovem, cuidava de suas ovelhas no campo. Ao observar a imensidão do céu, os pássaros e a natureza, sentia seu coração transbordar. Ele expressava esse sentimento cantando com toda a sua força, acompanhado de palmas e de sua harpa. Anos depois, o rei compôs um salmo declarando que tudo o que possui fôlego deve louvar ao Senhor. Assim, Davi estabeleceu que cada ser vivo, por sua própria existência e respiração, tem motivos para entoar cânticos ao Criador.' WHERE "id" = '49f984ef-e760-4d42-9934-dc0acefe4d3d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus viajava e encontrou dez homens que sofriam de lepra. Eles clamaram por misericórdia e o Mestre os curou instantaneamente enquanto iam ao encontro dos sacerdotes. Apenas um dos homens, sendo samaritano, retornou rapidamente para agradecer e glorificar a Deus aos pés de Jesus. O Salvador perguntou sobre o paradeiro dos outros nove, que não voltaram. Diante da atitude daquele único homem grato, Jesus o elogiou, afirmando que a sua fé o tinha salvado completamente naquela ocasião.' WHERE "id" = '4a327648-7e0b-4ae3-b172-0c64a5d6a0ac';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo caiu em profunda miséria, passando fome. Ao refletir sobre a abundância na casa de seu pai, ele decidiu retornar, preparando um discurso de arrependimento. Enquanto caminhava de volta, o pai, ao vê-lo de longe, correu prontamente ao seu encontro. Antes mesmo que o jovem terminasse de falar, o pai o acolheu com amor, restaurando sua dignidade e interrompendo o discurso, consolidando assim o retorno do filho ao seu lar.' WHERE "id" = '4a6290db-91db-44ab-a6ad-7e9962915ae3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus concedeu ao rei Salomão a oportunidade única de realizar qualquer pedido. Diante dessa oferta divina, o monarca escolheu solicitar sabedoria para governar em vez de pedir riquezas ou vitórias sobre seus inimigos. Essa decisão estratégica, tomada em uma conversa particular com Deus, fundamentou a construção de um reinado sólido e memorável. Salomão priorizou uma vida bem conduzida e duradoura. Sua escolha silenciosa definiu seu legado histórico e moldou permanentemente a trajetória de seu governo perante toda a nação.' WHERE "id" = '4a67f75e-aa59-4828-9c00-353a70c3f95f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão observou atentamente como a língua detém o poder de trazer vida ou morte. Ao longo de sua trajetória, ele presenciou reinos ruírem devido a palavras imprudentes e alianças fortalecidas por declarações oportunas. Buscando orientação divina, o monarca recebeu de Deus um discernimento profundo para identificar o momento exato de falar ou permanecer em silêncio. Essa sabedoria permitiu que Salomão estabelecesse sua reputação e autoridade muito antes da construção dos seus palácios, consolidando o seu legado histórico.' WHERE "id" = '4a6f73cb-4c03-40f9-beb5-5ddcf313d645';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel servia como um alto oficial do rei Dario, destacando-se pela sua integridade e fidelidade. Invejados, outros governantes manipularam o monarca para decretar a proibição de orações a qualquer deus, exceto ao rei. Daniel desobedeceu e continuou orando abertamente ao Senhor. Como punição, foi lançado na cova dos leões. Na manhã seguinte, o rei constatou que Daniel permanecia ileso, pois Deus enviara um anjo para fechar a boca dos animais, preservando a vida do seu servo fiel.' WHERE "id" = '4b55719d-caf3-4218-a378-899e0976ba8f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos se prostrassem em adoração. Sadraque, Mesaque e Abednego recusaram prontamente a ordem real. Diante da ameaça de serem lançados em uma fornalha ardente, os três jovens mantiveram sua posição com firmeza absoluta. Eles declararam ao monarca que não serviriam aos seus deuses nem adorariam a imagem erguida, confiando que Deus poderia livrá-los ou, caso contrário, mantendo a decisão de nunca se curvarem diante daquela estátua dourada.' WHERE "id" = '4b6740d8-5b29-44df-8a8c-012f188c8019';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga, embora seja um inseto minúsculo, demonstra grande esperteza ao buscar alimento. Antes de iniciar sua trajetória, ela observa atentamente o caminho, avaliando cuidadosamente possíveis obstáculos e escolhendo a melhor direção para seguir. Assim como este pequeno ser, a pessoa sábia para, analisa a situação ao seu redor e reflete antes de tomar qualquer decisão. Em contraste, o indivíduo imprudente age de forma precipitada, correndo sem olhar o trajeto, o que frequentemente resulta em erros ou acidentes dolorosos.' WHERE "id" = '4b75d232-de56-40d0-ad4e-9ab52dab0005';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo e Silas foram açoitados e aprisionados no cárcere mais profundo da cidade de Filipos. À meia-noite, enquanto oravam e cantavam hinos, um forte terremoto sacudiu os alicerces da prisão, abrindo todas as portas e soltando as correntes dos prisioneiros. O carcereiro, temendo que os detentos tivessem fugido, tentou tirar a própria vida. Contudo, os apóstolos o impediram. Naquela mesma noite, o carcereiro e toda a sua família ouviram a mensagem do evangelho e foram batizados prontamente pelos missionários.' WHERE "id" = '4bd07a34-f897-4d7e-9e1c-856a91058259';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Quando Deus ofereceu a Salomão qualquer coisa que desejasse, o rei não pediu riquezas, poder ou a destruição de seus inimigos. Em vez disso, Salomão solicitou discernimento para governar seu povo com justiça. Aprovando a escolha de seu coração, Deus concedeu ao rei a sabedoria pedida e, generosamente, acrescentou honra, glória e bens que ele não havia solicitado. Assim, o jovem monarca demonstrou um profundo temor ao Senhor, estabelecendo uma base sólida para um reinado próspero e duradouro.' WHERE "id" = '4c947c62-0f51-48e2-a1d3-ac85e97859d5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Zaqueu, um homem de baixa estatura e cobrador de impostos, desejava ver Jesus ao passar pela cidade de Jericó. Devido à multidão, ele subiu em uma árvore para observar o mestre. Ao passar pelo local, Jesus chamou Zaqueu e decidiu hospedar-se em sua casa. Impactado pela presença de Jesus, Zaqueu comprometeu-se publicamente a doar metade de todos os seus bens aos pobres e restituir quatro vezes mais qualquer valor que tivesse extorquido anteriormente de quem quer que fosse.' WHERE "id" = '4cf07e9c-0f3d-4048-b5a1-4273a4a34452';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um rei muito poderoso possuía exércitos enormes e muralhas altas, demonstrando grande força militar. No entanto, o livro de Provérbios destaca uma verdade fundamental sobre a natureza humana. O homem verdadeiramente forte não é aquele que conquista cidades ou destrói fortalezas alheias, mas aquele que domina o próprio coração. Como um cavalo veloz que necessita de controle para ser útil ao cavaleiro, a força humana requer direção precisa para não causar danos, evitando a destruição daquilo que amamos.' WHERE "id" = '4cf8c7e5-d538-4ac8-b502-a43d7eb3dbfe';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos adorassem uma estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão se curvava diante da imagem, os jovens judeus Sadraque, Mesaque e Abednego permaneceram de pé, recusando a ordem imperial. Confrontados pelo monarca, eles declararam firmemente que não prestariam culto ao ídolo, independentemente das consequências. Mantiveram sua postura inabalável diante do governante mais poderoso da época, enfrentando o risco iminente de execução por não negarem sua fé.' WHERE "id" = '4d6cb361-6f24-4e84-9ed5-f1a20d2d7e92';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus apareceu em um sonho ao jovem rei Salomão e ofereceu realizar qualquer pedido seu. Salomão, reconhecendo a complexidade de sua responsabilidade, não buscou riqueza, longevidade ou a morte de seus inimigos. Ele solicitou a Deus um coração compreensivo e discernimento para julgar o povo com justiça. Agradecido pela escolha altruísta, Deus concedeu a Salomão a sabedoria pedida e, além disso, conferiu-lhe as riquezas e a honra que ele não havia solicitado anteriormente durante aquela visão noturna.' WHERE "id" = '4e111662-15e0-4ba9-a5bf-c62e43415a14';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era o filho mais novo de Jessé e trabalhava como pastor de ovelhas, sendo ignorado por sua família quando o profeta Samuel chegou para ungir o novo rei de Israel. Enquanto seus irmãos mais velhos exibiam a aparência, Deus observou o caráter de Davi, desenvolvido durante o serviço solitário no campo. Sendo fiel na tarefa de cuidar do rebanho sem testemunhas, ele demonstrou a integridade necessária que, aos olhos de Deus, o preparou para governar todo o reino.' WHERE "id" = '4e1a21ae-7172-472a-89a3-657a6cf0c6e4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ofereceu a Salomão qualquer coisa que ele desejasse pedir. O monarca, possuidor de grande riqueza, poder e uma reputação inigualável, poderia ter escolhido fama ou vitórias militares sobre os seus inimigos. Contudo, reconhecendo que governar todo o povo de Israel superava a sua capacidade pessoal, ele solicitou sabedoria. Por causa dessa escolha, o Criador concedeu ao rei não apenas a sabedoria pedida, mas também muito mais honras, riquezas e sucesso do que ele poderia ter imaginado inicialmente.' WHERE "id" = '4e25f78f-5a93-4ce7-9d0d-8cc690c7d08e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sansão foi o homem mais forte de sua geração, possuindo uma força física extraordinária concedida por Deus. Contudo, ele não dominava seus próprios impulsos e desejos pessoais. Frequentemente, Sansão fazia escolhas precipitadas e se envolvia com mulheres erradas, revelando segredos que comprometeram sua missão. Eventualmente, essa falta de autocontrole interno tornou-se sua ruína. Ele não foi derrotado por exércitos inimigos em batalha, mas sim destruído por suas próprias decisões imprudentes, que corroeram gradualmente o grande chamado que havia recebido.' WHERE "id" = '4e99712b-427f-4485-b5bf-63ec23316e57';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens em uma vida distante, o filho mais novo passou fome e reconheceu a própria ruína. Decidiu retornar à casa de seu pai para pedir trabalho como um dos empregados. Enquanto se aproximava, seu pai o avistou e, movido por profunda compaixão, correu ao seu encontro. O jovem confessou seu erro ao pai, que ordenou aos servos que trouxessem a melhor túnica, um anel e sandálias, preparando um grande banquete para celebrar seu retorno.' WHERE "id" = '4eb5ae44-413b-4074-8373-7177cb9466d4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jacó trabalhou arduamente por quatorze anos na casa de Labão para conquistar Raquel. Durante esse longo período de espera, ele demonstrou resiliência e dedicação contínuas, moldando sua personalidade enquanto cuidava dos rebanhos. O esforço paciente transformou o homem que buscava uma esposa no patriarca capaz de sustentar uma nação. Ao final dessa jornada de serviço e fidelidade, Deus mudou seu nome para Israel, reconhecendo sua capacidade de lutar e prevalecer em meio aos desafios que enfrentou na Mesopotâmia.' WHERE "id" = '4efb4da1-cca2-4cfd-b25e-dbaead72b2fd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido de Noemi, ela aconselhou suas noras, Orpá e Rute, a retornarem para suas famílias de origem em Moabe. Enquanto Orpá decidiu partir, Rute recusou-se a abandonar a sogra. Ela declarou solenemente que permaneceria ao lado de Noemi, acompanhando-a onde quer que ela fosse, inclusive na morte. Assim, Rute abandonou sua terra e seu povo para seguir Noemi até Belém, selando um compromisso incondicional de lealdade que mudou completamente o destino de ambas as mulheres.' WHERE "id" = '4f0a93fe-6b47-4def-868b-7e2ba13d2819';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após receber sua parte na herança, um jovem partiu para terras distantes e dissipou todos os bens em uma vida desregrada. Enfrentando miséria e fome extrema, ele reconheceu sua falha e decidiu retornar à casa de seu pai para pedir perdão e ser tratado como servo. Ainda distante, o pai o avistou e, movido por profunda compaixão, correu ao seu encontro. O rapaz confessou seu erro, e o pai, acolhendo-o prontamente, ordenou que preparassem uma grande festa festiva.' WHERE "id" = '4f1d1205-9099-4d71-83ee-0076832e1a79';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio que já existiu, recebeu de Deus um discernimento incomparável. Contudo, ele desobedeceu às ordens divinas ao tomar setecentas esposas e trezentas concubinas estrangeiras. Além de seus casamentos proibidos, o rei acumulou excessivamente ouro e cavalos, ignorando os mandamentos que ele mesmo conhecia. Com o passar do tempo, seu coração se desviou da fidelidade ao Senhor. O rei, que governava nações com justiça, acabou permitindo que seus próprios apetites pessoais corrompessem o seu compromisso com Deus.' WHERE "id" = '4f2be0de-06ef-4440-80c4-3c66bc70c52e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi conquistou a admiração de Jônatas, filho do rei Saul. Eles selaram uma aliança profunda, baseada em lealdade e afeto mútuo. Mesmo sendo herdeiro do trono, Jônatas protegeu Davi da fúria de seu pai, arriscando a própria posição e segurança pessoal. O príncipe entregou suas vestes e armas ao jovem, confirmando um pacto de amizade incondicional. Jônatas honrou Davi constantemente, priorizando o vínculo estabelecido entre ambos, apesar dos graves conflitos familiares e riscos políticos enfrentados.' WHERE "id" = '507d4dd9-f24c-48e3-a092-6ba4b17f6633';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de forma desregrada longe de sua casa, o filho mais novo enfrentou uma fome severa. Percebendo sua miséria, decidiu retornar ao pai, preparando um pedido de perdão. Enquanto caminhava de volta, o pai o avistou de longe e, movido por profunda compaixão, correu ao seu encontro. Antes mesmo de o jovem concluir seu discurso de arrependimento, o pai o abraçou afetuosamente, restaurando sua dignidade e acolhendo-o novamente em seu lar.' WHERE "id" = '507f862f-7106-4025-9d4a-4192bf29fae7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez leprosos encontraram Jesus em uma estrada e clamaram por misericórdia. O Mestre ordenou que fossem apresentar-se aos sacerdotes. Enquanto caminhavam, todos foram curados milagrosamente daquela enfermidade. Entretanto, apenas um deles, um samaritano, retornou imediatamente para glorificar a Deus em alta voz e prostrar-se aos pés de Jesus com gratidão. O Senhor questionou o paradeiro dos outros nove homens que foram limpos, enquanto o estrangeiro, reconhecendo o milagre recebido, permaneceu ali para agradecer pelo livramento alcançado.' WHERE "id" = '50e9d3e8-7c7a-4f09-bf14-ee64c444e903';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas estabeleceram uma profunda aliança de amizade, selada quando o príncipe entregou suas vestes, espada e arco ao jovem pastor. Enquanto Saul, rei de Israel, perseguia Davi movido por inveja e ódio, Jônatas posicionou-se a favor de seu amigo. O filho do monarca protegeu Davi contra as intenções homicidas de seu pai, arriscando sua própria posição na corte. Ambos firmaram um pacto de lealdade mútua, comprometendo-se a preservar a vida um do outro diante do perigo.' WHERE "id" = '50fbfaba-07e3-4c01-9e90-74f6a2490f07';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Aos doze anos, Jesus permaneceu no templo debatendo com os sábios, enquanto seus pais, Maria e José, o procuravam aflitos. Ao ser encontrado, Jesus retornou prontamente com eles para Nazaré, onde vivia sob sua autoridade e obediência. Durante esse período de crescimento, o jovem Jesus desenvolveu-se em sabedoria, estatura e graça. Ele foi reconhecido progressivamente por Deus e pelos homens conforme amadurecia, mantendo uma postura de submissão e respeito dentro de seu contexto familiar e social cotidiano.' WHERE "id" = '512d87c2-6ce5-4cf9-ac39-aa8ae7c0cfe3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi traído e vendido como escravo pelos seus próprios irmãos por inveja. Com o passar do tempo, ele ascendeu ao posto de governador no Egito, ganhando autoridade suprema sobre toda a terra. Anos depois, reencontrou seus irmãos famintos que buscavam mantimentos. Mesmo detendo o poder absoluto para se vingar do mal que sofreu, José escolheu não retribuir a injustiça. Ele revelou sua identidade e promoveu a reconciliação com sua família, garantindo-lhes sustento e perdão em vez de destruição.' WHERE "id" = '51aa0b37-a288-4a47-8455-3fd94cb595b2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os pais de um homem que nasceu cego foram interrogados pelos líderes religiosos após o filho ser curado por Jesus. Embora soubessem que um milagre havia ocorrido, eles temiam represálias das autoridades judaicas. Por isso, os pais evitaram dar um testemunho completo sobre o evento e se esquivaram da responsabilidade, transferindo o questionamento diretamente para o filho. Eles optaram pelo silêncio sobre a verdade diante dos líderes, agindo estritamente por causa do medo que sentiam deles.' WHERE "id" = '51b223db-1c75-4261-99f0-0d188767f8d1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dois passarinhos dividiam o mesmo galho. Um deles costumava ceder os melhores grãos ao companheiro, enquanto o outro era egoísta e queria tudo para si. Quando uma forte tempestade surgiu, o pássaro egoísta permaneceu solitário e amedrontado, sem qualquer auxílio. Em contraste, aquele que compartilhava seus recursos estava cercado por amigos, partindo em conjunto rumo a um lugar seguro. Jesus ensinou seus seguidores a considerarem não apenas as próprias necessidades, mas também as daqueles que estavam ao redor.' WHERE "id" = '51c90621-5c1b-44bf-841b-a3010f010355';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus chamou Abraão para deixar sua terra natal, seus parentes e a casa de seu pai, rumo a uma região desconhecida que ele receberia como herança. Abraão atendeu prontamente à ordem divina, partindo sem saber exatamente para onde ia. Ele abandonou sua segurança e o conforto familiar, seguindo apenas a promessa feita pelo Senhor. Com total obediência, ele iniciou sua jornada em direção ao destino que lhe foi indicado, confiando inteiramente na palavra que recebeu do Criador.' WHERE "id" = '52343dbb-68ef-4ead-80dc-ce74a5b772c8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia e recebeu ordens reais para consumir a comida e o vinho da corte. Recusando-se a violar suas convicções, ele solicitou respeitosamente ao oficial uma alternativa alimentar. Daniel propôs um teste de dez dias para comparar sua saúde com a dos jovens que comiam as iguarias do rei. Ao final desse período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos aqueles que se alimentaram conforme o rei determinou.' WHERE "id" = '52c310e3-e0a6-4678-b5eb-085d709a91dd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio de sua geração, dedicou-se a observar o comportamento de reis, conselheiros, sábios e tolos ao longo de sua vida. A partir dessas experiências, ele registrou uma lei fundamental sobre as relações humanas: o convívio direto com os sábios resulta no desenvolvimento da própria sabedoria, enquanto a associação constante com os tolos conduz inevitavelmente à destruição. Ele compreendeu que o caráter de qualquer pessoa é profundamente moldado pelas companhias que escolhe manter diariamente.' WHERE "id" = '53a61a4d-e676-4e01-ad82-4e86a7126336';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem prisioneiro levado à Babilônia, enfrentou a pressão de consumir alimentos consagrados da mesa do rei. Determinando não se contaminar, ele recusou a dieta real e propôs um teste ao chefe dos eunucos. Daniel e seus três companheiros comeram apenas legumes e beberam água durante dez dias. Ao final do período, apresentavam uma aparência mais saudável e robusta que todos os outros jovens que se alimentaram das iguarias do monarca babilônico, mantendo sua fidelidade aos preceitos.' WHERE "id" = '53baa370-8495-4125-a355-90ce4edcbef4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua vasta sabedoria, registrou uma observação prática sobre o consumo do mel. Ele aconselhou que o indivíduo deve ingerir apenas a quantidade suficiente desse alimento. Caso alguém ultrapasse esse limite e consuma mel em excesso, o resultado inevitável será o vômito. A narrativa ilustra que a satisfação desmedida transforma algo benéfico em algo prejudicial ao corpo. Assim, o próprio monarca documentou que o descontrole no prazer sempre conduz à perda da medida certa.' WHERE "id" = '53f6d7c9-b168-4bb2-81b3-c568779da004';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario estabeleceu um decreto proibindo qualquer petição a deuses ou homens, exceto a ele mesmo. Daniel, ao tomar conhecimento da nova lei, não mudou sua rotina. Ele retornou à sua casa, abriu as janelas de seu quarto voltadas para Jerusalém e continuou a orar a Deus três vezes ao dia. Mantendo sua fidelidade de sempre, Daniel ignorou a proibição real e manteve sua prática habitual de oração, desafiando abertamente o decreto imposto pelo monarca babilônico.' WHERE "id" = '543c652c-13a6-45e4-ba50-bcbbd0f98b40';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Vendido como escravo por seus próprios irmãos, José tornou-se o segundo homem mais poderoso do Egito. Anos depois, durante uma severa fome, seus irmãos chegaram ao Egito em busca de alimentos. Diante deles, José revelou sua verdadeira identidade, chorou alto e afirmou que Deus o enviara àquela terra para preservar vidas. Em um gesto de reconciliação, ele abraçou cada um de seus irmãos, oferecendo-lhes perdão imediato e garantindo sustento para toda a sua família na região de Gósen.' WHERE "id" = '544044d1-6d32-4884-bbec-a13350d5294f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após comerem o fruto proibido, Adão e Eva esconderam-se de Deus entre as árvores do jardim. Quando o Senhor questionou seus paradeiros, Adão alegou sentir medo, omitindo sua desobediência e transferindo a culpa para Eva. Por sua vez, Eva justificou sua ação apontando a serpente como responsável pelo ocorrido. Diante do Criador, ambos evitaram admitir a própria falha, criando narrativas para mascarar a verdade. Assim, o primeiro casal da humanidade tentou ocultar seus atos diante da presença divina.' WHERE "id" = '54433b5a-9bd3-4644-b8bf-46bd78cd1343';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pediu ao pai a sua parte na herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Após enfrentar uma severa fome, ele caiu em si e decidiu retornar à casa paterna, arrependido e desejoso de servir como um empregado. Ao avistá-lo de longe, o pai correu ao seu encontro, abraçou-o com compaixão e ordenou que preparassem uma grande festa, celebrando o retorno seguro de seu filho que estava perdido.' WHERE "id" = '54780bca-0b17-491a-b9a5-ef987c0320db';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar seus bens, o filho pródigo percebeu sua condição miserável no chiqueiro. Decidiu abandonar as justificativas e confrontar a verdade sobre seus erros contra o pai e o céu. Levantou-se imediatamente e iniciou o caminho de volta para casa. Enquanto ainda estava longe, foi avistado pelo pai, que o esperava ansiosamente. Ao encontrar-se com ele, o filho confessou seu pecado e sua indignidade, sendo acolhido por um abraço que selou seu retorno ao convívio familiar paterno.' WHERE "id" = '54c3ee8c-bfae-48fc-bc01-86b7b96b9988';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Elias viajou até Sarepta e encontrou uma viúva coletando lenha para preparar a última refeição dela e de seu filho antes da morte por fome. Elias pediu que ela lhe desse o pão antes de comer. A mulher obedeceu ao profeta e preparou o alimento solicitado. Milagrosamente, a farinha na panela não acabou e o azeite na botija não secou. Eles comeram durante muitos dias, enquanto o suprimento sustentou a vida de toda a família.' WHERE "id" = '550e2478-a9b5-4cbe-a060-d15d351aa366';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dissipar sua herança vivendo sem limites, o filho pródigo enfrentou uma severa fome e as consequências de suas escolhas. Em um momento de lucidez, ele decidiu abandonar a miséria e retornar à casa do pai. Enquanto se aproximava, o pai avistou o filho de longe e correu ao seu encontro. Com o coração transformado, o jovem iniciou seu caminho de volta, sendo prontamente acolhido pelo pai, que demonstrou compaixão e restaurou seu lugar na família naquele instante.' WHERE "id" = '558b4a01-4cf9-4f4b-be59-7a73b25804ea';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Josué enfrentava o desafio monumental de atravessar um rio enorme liderando todo o povo de Israel. Diante da tarefa, ele sentiu medo, mas Deus lhe ordenou que fosse forte e corajoso, garantindo Sua presença constante ao seu lado para que não se apavorasse. Confiando na promessa divina, Josué decidiu não permitir que o temor dominasse suas ações. Ele deu o primeiro passo com determinação, sendo prontamente seguido por todo o povo, obedecendo a Deus durante aquela jornada incerta.' WHERE "id" = '5592aab9-469b-49e3-b4f1-9f28541c3c50';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Abraão oferecesse seu filho Isaque como sacrifício. Obediente, Abraão levantou-se cedo e partiu rumo ao local determinado com o jovem. Durante o caminho, Isaque questionou a ausência do animal para o holocausto, e seu pai respondeu que Deus proveria o cordeiro. Ao chegarem ao altar, Abraão ergueu a faca para sacrificar seu filho, mas o Anjo do Senhor interveio imediatamente, ordenando que ele não tocasse no rapaz, pois sua obediência havia sido provada diante de Deus.' WHERE "id" = '559fbbfc-d692-4b85-9ee6-74d999ba0742';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus reuniu seus discípulos para ensinar que a verdadeira grandeza não reside no poder, mas no serviço aos outros. Ele exemplificou esse princípio ao lavar os pés de seus seguidores e cuidar ativamente daqueles que enfrentavam a fome ou a solidão. O Mestre não aguardava solicitações para auxiliar as pessoas, pois mantinha um olhar atento sobre as necessidades ao seu redor, agindo prontamente para servir com dedicação total, demonstrando que veio ao mundo para servir a todos.' WHERE "id" = '55e52a0b-67e2-4436-a6c5-ff7049f1a2e9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério e ordenou a morte de um homem inocente. Deus enviou o profeta Natã, que utilizou uma parábola para confrontar o monarca sobre seus graves pecados. Diante da revelação profética de que ele era o culpado, Davi não tentou se justificar ou racionalizar suas ações cruéis. Em vez disso, o rei reconheceu prontamente sua transgressão perante o Senhor, confessando seu erro sem condições ou desculpas, assumindo a plena responsabilidade por todos os danos causados.' WHERE "id" = '55f1b9bd-f9bf-4f4f-bf79-ed1471c0e557';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel enfrentou intensa pressão para abandonar suas convicções. O império exigia a adoção de uma nova identidade, incluindo o consumo de alimentos reais e a adoração a deuses estranhos. Enquanto seus colegas cederam rapidamente às imposições da corte, Daniel decidiu manter firme sua postura, estabelecendo limites internos claros para sua conduta. Sua escolha silenciosa de ser diferente o preservou ao longo do tempo, tornando-o o homem mais confiável de todo o império babilônico.' WHERE "id" = '560c6638-0573-43e1-9a9b-803c73615afb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua herança, o filho mais novo atingiu o fundo do poço e caiu em si sobre sua condição miserável. Ele decidiu retornar à casa do pai, planejando um discurso de arrependimento para pedir que o aceitasse como um simples servo. Ao iniciar a jornada de volta para casa, o pai avistou o filho ainda distante. Movido por profunda compaixão, o pai correu ao seu encontro, abraçou-o e o recebeu prontamente antes mesmo da confissão.' WHERE "id" = '564684eb-bfcd-4c05-a586-0bd3bb9e0b8e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Jacó, os irmãos de José temeram uma possível vingança pela traição cometida no passado, quando o venderam como escravo. Eles se prostraram diante dele, suplicando por perdão e oferecendo-se como servos. José, que ocupava uma posição de grande autoridade no Egito, chorou ao ouvir o apelo. Ele afirmou que não ocupava o lugar de Deus para julgá-los. Em vez de puni-los, José garantiu sustento a eles e aos seus filhos, tratando-os com bondade.' WHERE "id" = '5648ea02-d4e9-41dc-a9f0-90c7c0932fc3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo da sua terra natal para o império babilônico, onde recebeu uma nova identidade imposta pelo rei. Confrontado com a ordem de se alimentar com as iguarias da corte, ele tomou a firme decisão de não se contaminar, mantendo seus princípios e integridade. Após dez dias de dieta simples, Daniel e seus três companheiros apresentaram uma saúde superior aos demais jovens. Por sua sabedoria e conhecimento, foram aprovados pelo rei, destacando-se entre todos os sábios.' WHERE "id" = '5682f8b4-2019-4ec0-a36d-ee9b17631fac';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo e Silas estavam presos em Filipos, com seus pés acorrentados e seus corpos feridos por causa das chicotadas que receberam. À meia-noite, em meio à escuridão da cela, ambos oravam e cantavam louvores a Deus enquanto os outros prisioneiros os escutavam. Subitamente, um forte terremoto sacudiu os alicerces da prisão, fazendo com que as portas se abrissem imediatamente e todas as correntes dos encarcerados se soltassem. O carcereiro, assustado com o evento, prostrou-se diante dos apóstolos naquele momento.' WHERE "id" = '56d89b07-2239-4bf4-9913-bb969f7b4f89';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi assaltado, espancado e abandonado à beira do caminho. Um sacerdote e um levita passaram pelo local, viram a vítima, mas ignoraram a situação e seguiram viagem. Posteriormente, um samaritano aproximou-se e teve compaixão daquele ferido. Ele tratou as feridas do homem, levou-o a uma hospedaria e pagou todas as despesas necessárias para o seu cuidado integral. O samaritano assumiu a responsabilidade pela recuperação total daquela vítima abandonada.' WHERE "id" = '56eeed0a-2aa4-4a9d-8242-d87c9fab7944';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No jardim perfeito, a serpente enganou Eva, que comeu do fruto proibido e compartilhou com Adão. Ao perceberem a nudez, eles se esconderam da presença de Deus entre as árvores. Quando confrontados pelo Criador sobre a desobediência, Adão culpou Eva, enquanto ela transferiu a responsabilidade para a serpente. Esse ato marcou a entrada do pecado na humanidade, estabelecendo uma barreira definitiva no relacionamento entre o homem e Deus e corrompendo a harmonia que existia entre o primeiro casal humano.' WHERE "id" = '56fb041a-857a-420e-97d5-dd0befd9cbfc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José era o filho favorito de Jacó, provocando inveja em seus irmãos. Após compartilhar sonhos proféticos sobre sua futura grandeza, eles o jogaram em uma cisterna e o venderam como escravo. Levado ao Egito, José serviu com integridade, mas foi injustamente preso por anos. Com o tempo, ele interpretou sonhos de Faraó sobre a fome na terra. Impressionado, o monarca o libertou e o nomeou governador de todo o Egito, elevando-o a uma posição de imensa autoridade e poder real.' WHERE "id" = '573beeae-ebc0-47a8-838a-9091b379101b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança e enfrentar a miséria extrema, o filho pródigo reconheceu seu erro e decidiu retornar à casa paterna. Ele abandonou as justificativas, assumiu sua culpa e iniciou a longa caminhada de volta, sentindo-se indigno de ser chamado filho. Enquanto o rapaz se aproximava, o pai, que o observava atentamente à distância, correu ao seu encontro. Esse encontro marcou o fim da jornada humilhante do jovem e o início de sua restauração na família.' WHERE "id" = '5754e382-6651-47f7-a6b9-351b7d8225e6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus ensinou seus ouvintes sobre a importância da fidelidade através da parábola do administrador. Ele afirmou que quem demonstra ser confiável nas mínimas coisas também o será nas grandes responsabilidades. Em contrapartida, quem age de maneira injusta ou desonesta nos pequenos assuntos revelará o mesmo comportamento diante de riquezas maiores. O Mestre enfatizou que o gerenciamento correto dos recursos alheios e das posses pessoais é o critério fundamental para a confiança e para o recebimento das riquezas verdadeiras.' WHERE "id" = '57935bbe-ea93-4609-98bc-4ec0b7306994';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel enfrentou a pressão de seguir os costumes da corte real. Determinado a não se contaminar com a comida e o vinho do rei, ele solicitou ao oficial responsável uma dieta baseada apenas em vegetais e água. Após dez dias de teste, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que consumiam as iguarias. O oficial permitiu que eles mantivessem sua dieta específica dali por diante.' WHERE "id" = '57ef598b-a4e3-4d44-808e-9638792e40c0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para a Babilônia, onde enfrentou uma cultura estrangeira que exigia a mudança de sua identidade. Ao receber o cardápio real, ele se recusou a consumir as iguarias do rei, pois desejava manter seus princípios. Daniel propôs um teste de dez dias ao guarda, alimentando-se apenas de legumes e água junto aos seus amigos. Após esse período, eles apresentavam uma aparência mais saudável e robusta que os jovens que comeram a comida oferecida pelo soberano.' WHERE "id" = '585939f4-bb23-45a2-812b-a9fa33259215';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho mais novo enfrentou a miséria cuidando de porcos. Em meio à fome, ele reconheceu seus erros, decidiu abandonar seu estilo de vida e planejou pedir perdão ao pai. O jovem levantou-se e iniciou sua jornada de volta para casa. Ao avistá-lo à distância, o pai correu ao seu encontro, abraçando-o antes mesmo de o filho concluir seu pedido de desculpas, restaurando prontamente sua dignidade e seu lugar na família.' WHERE "id" = '5873be59-8fac-4e41-a569-35f18a767538';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O livro de Provérbios apresenta um contraste comportamental entre dois perfis distintos diante das situações da vida cotidiana. O ingênuo aceita qualquer informação ou proposta sem qualquer tipo de questionamento, acreditando prontamente em tudo o que ouve. Em contrapartida, o homem prudente analisa cuidadosamente cada circunstância antes de tomar uma decisão, avaliando criteriosamente os seus passos. O texto descreve o padrão de conduta daqueles que agem por impulso e as consequências práticas de não refletir antes de agir.' WHERE "id" = '58987cbf-50b7-4bdb-850c-969ee90d5170';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pediu ao pai a sua parte da herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Diante da miséria e da fome, decidiu retornar à casa paterna para pedir trabalho como empregado. Ao vê-lo ainda de longe, o pai correu ao seu encontro, abraçou-o com compaixão e o beijou. O filho foi restaurado à sua posição e o pai ordenou que preparassem um grande banquete para celebrar seu retorno.' WHERE "id" = '58a80dee-bfb2-467f-8640-1c8b593d2494';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após enfrentar profundas perdas e acusações injustas, Jó intercedeu por seus três amigos. Ao orar por aqueles que o maltrataram, Deus mudou sua sorte e restaurou tudo o que ele possuía em dobro. Jó recebeu novamente irmãos e conhecidos, ganhou novos filhos e filhas, e viveu muitos anos em prosperidade. Ele viu seus descendentes até a quarta geração e morreu plenamente satisfeito com uma longa vida. Assim, sua história de restauração foi consolidada após todo o sofrimento passado.' WHERE "id" = '58cede49-93ab-4d71-9ca5-d4be0d77ac19';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava pessoas que realizavam orações longas e rebuscadas em lugares públicos apenas para atrair a atenção e impressionar os outros ao redor. Em vez de aprovar tal comportamento, Jesus ensinou que Deus conhece todas as necessidades humanas antes mesmo de qualquer palavra ser pronunciada. Ele orientou que o momento da oração deve ser íntimo, realizado em um quarto fechado, longe da exibição pública, para que a comunicação seja feita diretamente com Deus, sem necessidade de qualquer performance externa.' WHERE "id" = '5916ea72-c36d-430d-ab9e-fced0ba335fe';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava entre seus discípulos que desejavam ser os mais importantes. De forma surpreendente, ele pegou uma bacia com água e lavou os pés de cada um deles, agindo como um servo. Embora fosse o maior de todos, Jesus escolheu se abaixar para realizar essa tarefa humilde. Após o ato, ele ensinou aos seus seguidores que aquele que deseja ser grande deve aprender a servir e cuidar dos outros, colocando-se sempre à disposição para ajudar quem estiver ao seu redor.' WHERE "id" = '59353283-f84b-4b12-b9fa-f9250736c49a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia prontamente à exigência real, os jovens hebreus Sadraque, Mesaque e Abednego recusaram-se a participar do ato de adoração. Confrontados pelo monarca mais poderoso da época, eles mantiveram firmemente sua posição. Mesmo diante da ameaça de execução, os três declararam que jamais adorariam a imagem, confiando plenamente em Deus, independentemente do resultado final.' WHERE "id" = '593f3b95-01a0-402b-bef9-4447eb5465db';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia durante a juventude. Lá, o rei determinou que ele e seus amigos consumissem as iguarias da mesa real, alimentos que violavam suas convicções religiosas. Daniel decidiu firmemente não se contaminar com a comida do monarca. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de legumes e água. Ao final desse período, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta do que todos os outros jovens hebreus.' WHERE "id" = '5994a415-5ca1-44fe-899d-51fba57e5ce8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Inimigos de Daniel buscaram falhas em sua conduta, porém nada encontraram, exceto sua fidelidade a Deus. Eles conspiraram e conseguiram que o rei assinasse um decreto proibindo orações, tornando a fé de Daniel um crime punível. Mesmo ciente da nova lei e do grave perigo, Daniel não mudou seus hábitos. Ele entrou em seu quarto, abriu as janelas voltadas para Jerusalém e ajoelhou-se para orar, mantendo sua prática diária de comunhão com Deus, sem se importar com observadores.' WHERE "id" = '5994c30d-295f-4fd2-8c98-0dab2752e721';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi traído por seus irmãos, que, movidos por intenso ciúme, jogaram-no em uma cisterna e o venderam como escravo. Anos mais tarde, estabelecido como autoridade no Egito, José reencontrou seus irmãos em um momento de vulnerabilidade. Embora possuísse poder absoluto para retribuir a traição, ele escolheu não se vingar. Em vez disso, declarou que, embora o mal tivesse sido planejado contra ele, Deus transformou aquela situação em bem, garantindo sustento e proteção para toda a sua família.' WHERE "id" = '59a2d40c-762b-4c06-9da8-9875ee5ba680';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar o gigante Golias, Davi foi apresentado ao rei Saul. Durante esse encontro, ele conheceu Jônatas, filho do monarca. Uma profunda amizade surgiu imediatamente entre eles. Em um gesto simbólico de aliança e reconhecimento, o príncipe Jônatas despiu-se de suas vestes reais, retirou sua espada, seu arco e seu cinto, entregando todos esses pertences a Davi. Esse ato oficializou o forte vínculo estabelecido entre os dois homens, selando um compromisso de lealdade mútua diante de todo o povo.' WHERE "id" = '59d7bca1-5322-4ac4-b587-b35df8405f21';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de seu rebanho nos campos. Quando um urso enorme surgiu para atacar uma de suas ovelhas, o menino não recuou diante do perigo. Confiando plenamente no auxílio divino, Davi enfrentou o animal feroz para proteger o animal sob seus cuidados. Graças à força e proteção de Deus, ele conseguiu vencer a ameaça e salvar a ovelhinha. Após esse episódio, o jovem pastor aprendeu a lidar com seus medos por meio da confiança.' WHERE "id" = '59eb4224-aa2c-4acc-8e30-ebb959593cfb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu aos coríntios alertando sobre a influência das companhias na conduta humana. Ele afirmou que as más conversações corrompem os bons costumes. A narrativa bíblica estabelece que o convívio com pessoas de caráter duvidoso altera os hábitos e a integridade de alguém, funcionando como um aprendizado constante através da observação. Por isso, a instrução divina destaca que o padrão de comportamento de um indivíduo é moldado diretamente pelas escolhas das pessoas que o acompanham diariamente.' WHERE "id" = '59eb5a1e-329a-497c-82cc-6a7fb63445e7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem solicitou sua herança e partiu, gastando tudo de forma irresponsável até enfrentar extrema escassez. Reduzido a cuidar de porcos, ele reconheceu sua miséria e decidiu retornar à casa paterna para pedir perdão por seus atos. Sem oferecer desculpas, o filho iniciou o caminho de volta ao lar. Ao avistá-lo ainda distante, o pai, movido por profunda compaixão, correu prontamente ao seu encontro, recebendo-o com prontidão antes mesmo que o rapaz pudesse concluir seu discurso de arrependimento.' WHERE "id" = '5a1b3dba-789c-4d07-933c-d73e75bf957a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No mundo antigo, uma cidade sem muros permanecia exposta, vulnerável e totalmente à mercê de forças externas. Muros representavam segurança, destino e a proteção necessária para garantir o futuro dos habitantes. O rei Salomão utilizou essa imagem histórica e arquitetônica para descrever a condição de um homem que perdeu completamente o governo sobre si mesmo. Sem a estrutura de defesa do autocontrole, a vida dessa pessoa torna-se um lugar desprotegido, onde qualquer influência externa pode entrar livremente e causar destruição.' WHERE "id" = '5a27e7cd-00d1-44c0-9fb5-c953ced72d0c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugia de Saul, que desejava matá-lo injustamente. Escondido em uma caverna, Davi encontrou o rei desprevenido. Seus homens sugeriram que ele aproveitasse a oportunidade para eliminar o inimigo, mas Davi recusou-se a ferir o ungido de Deus. Ele apenas cortou silenciosamente a borda do manto de Saul. Posteriormente, Davi revelou-se à distância, exibindo o pedaço do tecido como prova de que teve a chance de tirar a vida do rei, porém escolheu poupá-lo naquele momento decisivo.' WHERE "id" = '5a29a96b-002c-477a-b64c-112ef6c5b5d4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança, o filho mais novo enfrentou fome e miséria em uma terra distante. Em meio ao desespero, ele decidiu retornar à casa de seu pai, planejando pedir apenas um lugar como servo. Ao aproximar-se, o pai, que o observava de longe, correu ao seu encontro e o abraçou. O jovem confessou ter pecado contra o céu e contra o pai. O filho foi acolhido calorosamente, encerrando assim sua longa jornada de retorno ao lar.' WHERE "id" = '5ad74470-6a3a-436b-a86a-95ebca649440';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus subiu a um monte cercado por uma grande multidão para ensinar seus seguidores. Durante esse momento, Ele proferiu um ensinamento marcante sobre a importância daqueles que buscam ativamente a reconciliação. O Mestre declarou que os pacificadores são verdadeiramente bem-aventurados, pois seriam reconhecidos como filhos de Deus. Esse relato histórico narra o instante em que Jesus estabeleceu um novo padrão de conduta, destacando o papel fundamental de quem escolhe ser um construtor de pontes entre as pessoas.' WHERE "id" = '5b0058c0-dddb-4aa3-a7d5-f5cb659aa0ec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após receber sua herança, o filho mais novo partiu para uma terra distante e desperdiçou todos os seus bens vivendo perdulariamente. Com a chegada de uma grande fome, ele passou necessidade e decidiu retornar à casa de seu pai, reconhecendo seu grave erro. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o e beijou-o. Em seguida, ordenou a seus servos que vestissem o rapaz com as melhores roupas e preparassem uma grande festa festiva.' WHERE "id" = '5b1f5c80-3699-4646-bbf7-9826e97dfbb3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo enfrentou uma severa escassez de alimentos e, reconhecendo sua condição miserável, decidiu retornar à casa de seu pai. Com arrependimento genuíno, ele preparou um pedido de perdão, admitindo sua indignidade como filho. Enquanto caminhava de volta, seu pai o avistou ainda distante. Movido por profunda compaixão, o pai correu ao encontro do jovem, abraçando-o prontamente, demonstrando misericórdia em vez de cobrar qualquer satisfação pela fortuna perdida anteriormente.' WHERE "id" = '5b3f9161-9d72-416d-ae01-83e457b8258f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o rei mais sábio da história, recebeu de Deus a capacidade de julgar com extrema precisão. Contudo, ao longo do tempo, ele começou a realizar escolhas cotidianas desprovidas de integridade, afastando seu coração do caminho correto. Essas decisões silenciosas, feitas longe da vista de outras testemunhas, culminaram em consequências profundas para a nação. O resultado final desse processo contínuo de escolhas equivocadas foi a fragmentação de seu reino, que acabou sendo dividido ao meio para sempre.' WHERE "id" = '5b4ced90-816b-4cee-80c3-d3014888b891';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão possuía imensa riqueza, poder e um trono admirado por todas as nações. Quando Deus lhe ofereceu a oportunidade de realizar qualquer desejo, o rei escolheu a sabedoria em vez de ouro ou vitórias militares. Ele compreendeu que o temor ao Senhor deveria ser a base de todas as suas ações. Salomão percebeu que a grandeza de um reinado não dependia de conquistas externas, mas da integridade do caráter formada nas decisões silenciosas que ocorrem longe dos olhares públicos.' WHERE "id" = '5b726224-7b89-4b80-8866-5a2b1f1c9bc3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro. Sadraque, Mesaque e Abednego recusaram-se a obedecer à ordem real. Enfurecido, o monarca ameaçou lançar os três em uma fornalha ardente caso não adorassem a imagem. Mesmo diante da morte iminente, eles mantiveram sua firme decisão de não curvar-se. Após serem lançados ao fogo, os jovens permaneceram intactos, pois Deus os acompanhou dentro das chamas, protegendo-os totalmente durante o terrível castigo imposto pelo soberano.' WHERE "id" = '5b968f14-9138-43e3-8c40-7c6e3f369ed7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava sentado em uma colina cercada por uma grande multidão de pessoas que o escutavam atentamente. Enquanto falava, ele apresentou um ensinamento que surpreendeu a todos os presentes. Jesus afirmou que são felizes aqueles que trabalham para fazer as pazes entre os outros. Ao contrário das expectativas do povo sobre guerreiros fortes, ele destacou que a verdadeira coragem pertence àqueles que decidem agir de forma diferente, encerrando brigas, acalmando conflitos e promovendo a reconciliação no dia a dia.' WHERE "id" = '5be109af-409d-4fad-85de-67814bd0d124';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em Babilônia, recusou a comida e o vinho oferecidos da mesa real por convicção pessoal. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de legumes e água. O oficial aceitou a sugestão e observou a saúde dos rapazes durante o período. Ao final do prazo, Daniel e seus amigos apresentavam uma aparência física superior e mais robusta do que todos os outros jovens que consumiam a dieta servida pelo rei.' WHERE "id" = '5c6dd376-b379-405e-972e-addbbf9efd4f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, analisou o comportamento humano e registrou um diagnóstico sobre o poder da comunicação. Ele observou que a língua detém a autoridade de causar tanto a morte quanto a vida nas relações sociais. O rei testemunhou impérios e amizades sendo arruinados por rumores e palavras imprudentes. Contudo, constatou que frases ditas no momento oportuno possuem a capacidade real de restaurar famílias e abrir portas decisivas para o destino das pessoas.' WHERE "id" = '5cb26733-b727-4696-89c8-335febd420a4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua vasta sabedoria, registrou uma instrução fundamental sobre a conduta humana ao tratar do consumo de mel. Ele alertou que, ao encontrar esse alimento doce, a pessoa deve ingerir apenas a quantidade necessária para satisfazer sua necessidade. Caso alguém ultrapasse esse limite e coma em excesso, o resultado inevitável será o mal-estar físico e o vômito. Essa observação prática sobre o autocontrole serve como um alerta direto sobre os perigos da falta de medida.' WHERE "id" = '5da133e3-9291-4486-a869-0e3639ae58d3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e ordenou a morte do marido dela, Urias, para ocultar seu erro. O profeta Natã confrontou o monarca utilizando uma parábola estratégica que revelava a gravidade de suas ações. Ao compreender que ele era o personagem citado pelo profeta, Davi não tentou negar o pecado ou justificar sua conduta. Diante de Natã, o rei confessou abertamente ter pecado contra o Senhor, reconhecendo sua culpa sem utilizar desculpas ou atenuantes para seu comportamento.' WHERE "id" = '5dbc2702-d305-419c-b4f7-05fc440da5a1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava quando foi atacado, ferido e deixado à beira da estrada. Um sacerdote e um levita passaram pelo local, viram o homem ferido, mas seguiram viagem sem prestar qualquer auxílio. Posteriormente, um samaritano passou por ali, aproximou-se do ferido e tratou suas feridas com cuidado. Ele colocou o homem em seu animal, levou-o para uma hospedaria, pagou pelas despesas médicas e de estadia, garantindo que o homem recebesse todos os cuidados necessários até sua plena recuperação.' WHERE "id" = '5ddbdab0-6a0c-474d-8942-5fddf8213408';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto viajava entre Samaria e Galileia, Jesus encontrou dez leprosos que viviam excluídos. À distância, eles clamaram por misericórdia e foram curados por Sua palavra. Seguindo a ordem, foram apresentar-se aos sacerdotes. Apenas um homem, um samaritano, retornou glorificando a Deus em voz alta e prostrando-se aos pés de Jesus para agradecer. Jesus observou a ausência dos outros nove curados, questionando sobre o paradeiro deles, e então declarou que a fé daquele samaritano o havia salvado daquela condição.' WHERE "id" = '5e0b7647-1452-429e-a1a8-35c527d9d9a7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, levado cativo para a Babilônia, recusou-se a consumir a porção diária de alimentos e vinhos do rei, pois desejava manter seus princípios. Ele propôs ao oficial responsável um teste de dez dias, substituindo o banquete real por vegetais e água. O oficial aceitou a sugestão e supervisionou o experimento. Ao final do período estipulado, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta do que todos os jovens que comeram da mesa do rei.' WHERE "id" = '5e37ee55-0b7d-4de9-8dc2-ef3102a9f923';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ananias vivia em meio a uma comunidade de pessoas boas, mas tomou uma decisão errada. Ele vendeu uma propriedade e decidiu esconder parte do valor recebido, entregando apenas uma fração aos apóstolos. Ao ser questionado, Ananias mentiu e afirmou que havia ofertado todo o montante arrecadado. Deus, que conhece todas as intenções e vê o que está oculto, revelou a falsidade do homem. Como consequência de sua atitude desonesta, Ananias perdeu totalmente a confiança de todos ao seu redor.' WHERE "id" = '5e4bf57c-7f5e-4ea9-8ce6-35888670ecde';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após vinte anos de separação, Jacó retornou para encontrar seu irmão Esaú, temendo as ameaças passadas. Ao se aproximar, Jacó organizou sua família e curvou-se humildemente diante dele. Contrariando as expectativas de vingança, Esaú correu ao encontro de Jacó, abraçou-o e chorou sobre seu pescoço. Jacó insistiu para que seu irmão aceitasse os presentes oferecidos como sinal de reconciliação, mas Esaú recusou, afirmando possuir o suficiente. Assim, os dois irmãos celebraram um encontro marcado pela paz inesperada.' WHERE "id" = '5ee9e6fe-2064-4e20-bc02-e5da33cb5b92';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Aos doze anos, Jesus viajou a Jerusalém com seus pais para celebrar uma festa religiosa. Após ser procurado intensamente, ele foi encontrado no templo, ouvindo e debatendo com os mestres da lei. Compreendendo a angústia de sua família, Jesus deixou o local e retornou com eles para Nazaré. O relato bíblico destaca que ele permaneceu submisso aos pais durante sua juventude, enquanto crescia em sabedoria, estatura e graça diante de Deus e também perante todos os homens.' WHERE "id" = '5f021eca-9c4b-441d-9c90-f2455038e1df';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O filho pródigo, após esgotar todos os seus recursos financeiros vivendo de maneira dissoluta, caiu em si ao enfrentar a escassez extrema. Em um momento de lucidez, ele reconheceu seus erros sem buscar justificativas ou culpar seu pai pelo desperdício de bens. O rapaz elaborou uma confissão sincera, decidindo retornar à casa paterna. Ele abandonou o orgulho e caminhou de volta, carregando o peso de sua vergonha enquanto se preparava para pedir ao pai apenas a condição de empregado.' WHERE "id" = '5f26ca6f-2267-4caf-899d-7048fa3fcb6a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de seu rebanho no campo. Certo dia, um urso surgiu para atacar as ovelhas. Sentindo medo, mas mantendo a firmeza, Davi enfrentou a fera para proteger os animais sob seus cuidados. Após o confronto, o menino chorou devido à tensão, descansou e levantou-se novamente para seguir com suas tarefas. Durante todo o episódio, Deus acompanhou cada passo de Davi, estando presente tanto nos momentos de coragem quanto nos instantes de susto.' WHERE "id" = '5f29fbdc-7af1-45c9-bd70-1090fe445bc7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No início, todos na terra possuíam uma única língua e o mesmo vocabulário. Ao migrarem, decidiram edificar uma cidade e uma torre cujo topo alcançasse os céus, visando glorificar seus próprios nomes. O Senhor desceu para observar a construção e notou a determinação daquele povo unido. Então, Deus confundiu o idioma deles para que não se entendessem mais. Por causa disso, cessaram a obra e foram espalhados por toda a superfície da terra, nomeando aquele lugar como Babel.' WHERE "id" = '5f8345cf-ef14-40cd-a53f-e9a7c6141ec1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor recém-chegado à corte, sem títulos ou proteção. Em vez de tratar o rapaz como um rival, Jônatas, filho do rei Saul, estabeleceu com ele uma profunda aliança de amizade e lealdade. O príncipe presenteou Davi com sua capa, espada e arco, símbolos de sua própria posição. Quando o rei Saul planejou matar Davi, Jônatas arriscou sua segurança pessoal e o relacionamento com o pai para proteger o amigo e garantir o seu livramento.' WHERE "id" = '601ed101-ff4e-4fb4-a95c-90fbbd1e3325';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria, riqueza e poder superiores aos seus contemporâneos, registrou uma reflexão sobre o consumo de mel. Ele observou que o mel é um presente de Deus disponível em abundância, mas alertou que o excesso pode ser prejudicial. Ao utilizar a imagem do consumo desse alimento, Salomão estabeleceu o princípio de que o limite no desfrute das coisas boas é essencial, pois o consumo exagerado transforma algo genuinamente benéfico em um veneno nocivo.' WHERE "id" = '601f12ea-f45e-4911-8f26-c455697d2cfa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Como cativo na Babilônia, Daniel recusou comer as iguarias e beber o vinho da mesa real, pois eram alimentos consagrados a ídolos. Ele propôs ao oficial responsável um teste de dez dias para si e seus três amigos. Durante esse período, alimentaram-se apenas de legumes e água. Ao final do prazo, notou-se que a aparência deles era muito melhor e mais saudável do que a dos jovens que consumiam as finas porções de comida oferecidas pelo rei babilônico.' WHERE "id" = '60478990-7b77-48f6-9c03-c0528a7b5816';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar sua herança em terras distantes, o filho mais novo enfrentou a miséria extrema. Ao recuperar o juízo, decidiu retornar à casa de seu pai, reconhecendo seu estado deplorável. Preparou uma confissão sincera, assumindo que havia pecado contra o céu e contra o genitor. Enquanto se aproximava, ainda distante, o pai o avistou. Com compaixão profunda, correu ao encontro do filho, abraçou-o e o beijou antes mesmo que ele pudesse concluir o pedido de perdão.' WHERE "id" = '6050b508-d47e-4909-8424-941c72148894';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de forma desenfreada, o filho mais novo caiu em profunda miséria. Reconhecendo sua situação deplorável, decidiu retornar à casa de seu pai, esperando ser tratado como um simples empregado. Ao avistá-lo de longe, o pai correu ao seu encontro, abraçou-o e o beijou. Ele ordenou aos servos que trouxessem a melhor veste, um anel e calçados, preparando um banquete festivo para celebrar o retorno de seu filho que estava perdido.' WHERE "id" = '60e328cc-acfa-4260-b574-8d2afa3cba04';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, em um momento de extremo desespero, buscou refúgio fugindo do rei filisteu Aquis. Para sobreviver à perseguição e escapar de uma execução iminente, ele fingiu insanidade diante do monarca estrangeiro. Após conseguir escapar daquela situação humilhante, Davi não se entregou ao medo ou ao silêncio. Em vez disso, ele decidiu elevar sua voz em louvor a Deus. Mesmo diante do cenário adverso e da vergonha vivida, o salmista escolheu exaltar o Senhor pelo livramento alcançado em sua jornada.' WHERE "id" = '61401a1e-3ea7-4b6f-93b7-dc5274099542';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança, o filho pródigo mergulhou na miséria, chegando a desejar a comida dos porcos. Em um momento de clareza, decidiu retornar à casa de seu pai. Abandonou sua vida de sofrimento e iniciou a longa caminhada de volta. Ao vê-lo ainda distante, o pai correu ao seu encontro, movido por profunda compaixão. Sem aguardar pedidos de desculpas, ele acolheu o filho, restaurando-o prontamente antes mesmo que o rapaz pudesse proferir qualquer palavra de confissão.' WHERE "id" = '614a1dee-465c-4e02-826a-d63d3d18a052';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo e Silas foram injustamente encarcerados em uma cela escura, com seus pés presos por correntes. Mesmo sozinhos e sem ninguém para observar, eles decidiram cantar louvores a Deus à meia-noite. Enquanto entoavam seus hinos, um forte terremoto sacudiu os alicerces da prisão. O impacto do tremor fez com que todas as portas das celas se abrissem imediatamente, e as correntes que prendiam todos os prisioneiros se soltassem por completo, libertando-os daquela condição de aprisionamento profundo e sombrio.' WHERE "id" = '616d7a2c-1dc2-44c2-a4a6-ebd69949ef0a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi traído por seus irmãos, que o jogaram em um buraco e o venderam como escravo para mercadores distantes. Após muitos anos vivendo longe de sua família, José reencontrou seus algozes no Egito. Embora tivesse motivos para buscar vingança, ele decidiu agir de forma diferente. Em um momento de profunda emoção, José revelou sua identidade, chorou intensamente com eles e os abraçou, declarando que os perdoava sinceramente pelo mal que lhe fizeram no passado distante.' WHERE "id" = '61ead4bd-f95e-47f2-82c4-62d1ec83fed1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar toda a sua herança e enfrentar uma terrível escassez, o filho pródigo passou a cuidar de porcos. Em meio à fome, ele recuperou a lucidez, reconheceu seus erros e decidiu retornar à casa de seu pai, não como filho, mas buscando apenas a posição de servo. Enquanto se aproximava, o pai avistou o jovem e correu ao seu encontro. O filho iniciou seu discurso de arrependimento, e o pai, movido pela compaixão, recebeu-o prontamente com um abraço.' WHERE "id" = '626235c0-e3f8-44a7-9e9b-b32c12b28870';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um cargo administrativo de destaque no império persa, despertando inveja nos outros oficiais. Eles convenceram o rei a assinar um decreto que proibia orações a qualquer deus ou homem, exceto ao próprio monarca, por trinta dias. Cientes do costume de Daniel de orar três vezes ao dia, os conspiradores vigiaram seus passos. Mesmo diante da nova lei proibitiva, Daniel retornou à sua casa, abriu as janelas voltadas para Jerusalém e continuou orando fielmente ao Deus único.' WHERE "id" = '62fa9ddd-9da2-40cc-8d6b-e2e5fb15c356';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após perder o marido e os filhos em terra estrangeira, Noemi decidiu retornar a Belém e aconselhou suas noras, Rute e Orpá, a voltarem para suas famílias. Orpá despediu-se e partiu, mas Rute escolheu permanecer ao lado da sogra. Em um ato de lealdade extrema, ela declarou que seguiria Noemi para onde fosse, adotando seu povo e seu Deus. Abandonando sua terra e segurança, Rute comprometeu-se a acompanhar Noemi até o fim, selando esse vínculo com um juramento solene.' WHERE "id" = '6333c65c-3e9d-40aa-833d-b8c627a19544';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, que pediu sabedoria a Deus, edificou um reino glorioso por meio de suas palavras e sentenças. Com a língua, ele forjou alianças políticas fundamentais e resolveu disputas complexas no seu governo. Contudo, o mesmo rei que construiu seu legado com discursos sábios também falhou ao falar no momento impróprio e omitir-se quando era necessário agir. Assim, a sua fala tornou-se o instrumento decisivo que pavimentou o caminho para a profunda divisão do reino de Israel.' WHERE "id" = '63594644-eea6-449c-a98e-ba773e54d684';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os discípulos de Jesus discutiram entre si sobre quem seria o maior no reino dos céus. Percebendo o questionamento, Jesus chamou uma criança e a colocou no meio deles. Ele declarou que, a menos que os discípulos mudassem e se tornassem como aquele pequeno, jamais entrariam no reino dos céus. Jesus ensinou que quem se humilha como uma criança é considerado o maior. Assim, o Mestre utilizou a figura do menor para definir o padrão de grandeza divina.' WHERE "id" = '63829d43-3452-4239-91e1-c744b3a1c352';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreve aos filipenses sobre a humildade e a unidade. Ele apresenta Jesus Cristo, que possuía a natureza divina, mas não a considerou um privilégio egoísta. O Filho de Deus esvaziou-se voluntariamente, assumindo a forma de um servo humano. Ele demonstrou obediência absoluta ao Pai, submetendo-se até mesmo à morte na cruz. Por essa atitude, Deus o exaltou soberanamente acima de todos os nomes, estabelecendo o seu senhorio sobre o céu, a terra e os lugares debaixo da terra.' WHERE "id" = '63b7f709-bc3b-4c73-9464-e5a7bdd7239b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No pátio do Templo, Jesus observava pessoas depositando ofertas no gazofilácio. Muitos ricos lançavam grandes quantias, buscando visibilidade. Então, uma viúva pobre aproximou-se e depositou duas pequenas moedas de pouco valor. Jesus chamou seus discípulos para enfatizar o ocorrido. Ele declarou que aquela mulher deu mais do que todos os outros, pois, enquanto os ricos ofertaram apenas o que lhes sobrava, ela entregou tudo o que possuía para seu próprio sustento, sacrificando sua única reserva financeira ali.' WHERE "id" = '63f4f009-9fff-43da-b28b-546b0cab7f9f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias liderava a reconstrução dos muros de Jerusalém quando seus inimigos tentaram interrompê-lo. Por quatro vezes, convidaram-no para reuniões com o intuito de sabotá-lo, mas Neemias recusou, afirmando que realizava uma grande obra e não poderia parar. Mesmo diante de difamações públicas, ele manteve a calma, orou e persistiu no trabalho. Após cinquenta e dois dias, os muros foram concluídos, provando aos adversários que a tarefa possuía um propósito divino, superando assim todo o esforço humano e as resistências enfrentadas.' WHERE "id" = '6426a436-10ce-4f94-8a0b-178786b7cc75';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus ensinou que o olho funciona como a lâmpada do corpo humano. Ele explicou que, quando o olho está saudável, todo o corpo permanece plenamente iluminado. Por outro lado, se o olho estiver doente, todo o interior da pessoa mergulha profundamente na escuridão. O Mestre utilizou essa analogia para ilustrar como o direcionamento da atenção e as escolhas sobre o que valorizar e perseguir definem o estado espiritual e a realidade interna de cada indivíduo perante Deus.' WHERE "id" = '65227870-83e6-4e39-a438-40b55b235c39';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Samuel vivia no templo servindo o sacerdote Eli. Certa noite, enquanto dormia, ouviu uma voz chamando seu nome. Por três vezes, o menino correu até Eli, que negou tê-lo chamado. Após a terceira ocorrência, Eli compreendeu que o Senhor falava com o jovem e instruiu Samuel a responder adequadamente. Seguindo a orientação, Samuel deitou-se e, ao ouvir o chamado novamente, respondeu pronto para escutar. Assim, Deus revelou sua mensagem ao menino, que permaneceu atento e totalmente quieto.' WHERE "id" = '6533a949-3e2e-43d4-8f09-a57e1c333324';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava no templo observando o povo depositar ofertas. Enquanto homens ricos lançavam quantias elevadas com orgulho, uma viúva pobre aproximou-se e depositou duas moedas pequenas. O Mestre chamou seus discípulos e afirmou que aquela mulher havia contribuído mais do que todos os outros. Enquanto os ricos ofertaram apenas o que lhes sobrava da abundância, ela entregou tudo o que possuía para o seu próprio sustento. Jesus destacou que ela não reteve absolutamente nada para si mesma naquele momento.' WHERE "id" = '65e126f1-d409-4393-b213-d9f58e56dff3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança e enfrentar a extrema miséria, o filho que havia abandonado o pai decidiu retornar para casa. Ele reconheceu seus erros e preparou um pedido de perdão para ser tratado como um empregado. Enquanto caminhava, ainda distante, o pai o avistou e, movido por profunda compaixão, correu ao seu encontro. Antes mesmo de qualquer justificativa, o pai o recebeu com um abraço, restaurando sua posição de filho naquele exato momento decisivo.' WHERE "id" = '6647acd3-b4fc-40a1-b28b-cd17e588c13f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à corte do rei Nabucodonosor, o jovem Daniel recusou comer as iguarias e o vinho oferecidos pela mesa real. Ele propôs ao chefe dos eunucos um teste de dez dias, consumindo apenas vegetais e água. O oficial aceitou o desafio e permitiu que Daniel e seus três amigos mantivessem a dieta restrita. Ao fim do período estipulado, os quatro jovens apresentavam uma aparência mais saudável e robusta do que todos os outros que se alimentavam das porções reais.' WHERE "id" = '6673aa0d-1f25-4c86-925a-c4ab76cba051';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus criou o mel das abelhas como um alimento bom e doce para o consumo humano. As abelhas trabalham diligentemente coletando néctar de diversas flores, sempre com cuidado para não destruí-las. Elas acumulam pequenas quantidades de forma constante até encherem a colmeia completamente. O relato ensina que o consumo excessivo de mel causa desconforto físico, por isso, deve ser ingerido com moderação. Assim, o comportamento desses insetos revela um processo gradual e equilibrado de produção e também de uso.' WHERE "id" = '667b7f1f-5c1a-4dc8-961d-c9fd167adda0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo reconheceu sua miséria e decidiu retornar à casa de seu pai. Abandonando as justificativas, ele admitiu seu erro com honestidade brutal e iniciou a caminhada de volta. Enquanto ainda estava longe, seu pai, que observava o horizonte constantemente, avistou-o. Movido por profunda compaixão, o pai correu ao encontro do filho, acolhendo-o prontamente. O retorno marcou o fim do distanciamento e restabeleceu uma relação baseada na verdade e no perdão.' WHERE "id" = '66d6214a-d31f-4769-938d-4e59a3db09c9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi assaltado, espancado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo local, viram o ferido, mas ignoraram a situação seguindo seus caminhos. Posteriormente, um samaritano aproximou-se, tratou suas feridas e o colocou sobre seu próprio animal. Ele levou o homem a uma hospedaria, cuidou de suas necessidades e pagou ao hospedeiro, garantindo que qualquer despesa adicional seria coberta por ele ao retornar de sua viagem.' WHERE "id" = '66f3e84e-5289-4b32-9398-29d018183f75';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José servia como escravo na casa de Potifar, um oficial egípcio. A esposa de seu senhor começou a cobiçá-lo e passou a pressioná-lo diariamente para que se deitasse com ela. José, porém, recusou todas as suas investidas, questionando como poderia cometer tal maldade contra Deus. Certo dia, quando estavam sozinhos dentro da casa, a mulher o agarrou pelas vestes. Decidido a não ceder à tentação, José fugiu rapidamente, deixando sua capa para trás nas mãos dela.' WHERE "id" = '671c88b6-8011-4e4e-816f-b2b0adc958de';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus proferiu as bem-aventuranças diante de uma grande multidão que aguardava ansiosamente por um Messias guerreiro. Em meio ao cenário de expectativas políticas, Ele surpreendeu a todos ao declarar que os pacificadores são chamados filhos de Deus. Ele explicou que a verdadeira paz não consiste em evitar conflitos ou ceder diante das tensões, mas em posicionar-se com integridade entre as partes opostas. Assim, Jesus estabeleceu um novo padrão para aqueles que buscam construir algo novo no Reino divino.' WHERE "id" = '676f7f09-ad31-44c7-93d7-d90c9bfe237a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua herança ao pai, partiu para uma terra distante e desperdiçou todos os seus bens vivendo perdulariamente. Após enfrentar uma severa fome e extrema miséria, decidiu retornar à casa paterna para pedir perdão e trabalhar como empregado. Antes que ele chegasse, seu pai o avistou de longe, correu ao seu encontro, abraçou-o e o beijou. O pai ordenou prontamente que preparassem uma grande festa, celebrando com alegria o retorno seguro do filho que estava perdido.' WHERE "id" = '680192c2-d919-44ba-9dd7-46810bd607ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém a Jericó quando foi atacado por salteadores, que o espancaram e deixaram semimorto na estrada. Um sacerdote e um levita passaram pelo caminho, mas ignoraram o ferido. Posteriormente, um samaritano aproximou-se, sentiu compaixão e cuidou de seus ferimentos com azeite e vinho. Ele colocou o homem em seu animal, conduziu-o até uma hospedagem e pagou pelas despesas de seu tratamento, garantindo que o estrangeiro recebesse todos os cuidados necessários para a sua plena recuperação.' WHERE "id" = '6814d2f9-86a4-4854-a186-dee17f2e414c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, firmou uma profunda aliança de amizade com o jovem pastor Davi, ungido para ser o futuro rei. Reconhecendo o valor de Davi, Jônatas entregou-lhe seu manto, espada, arco e cinto, selando um pacto solene entre ambos. Essa escolha custou a Jônatas a aprovação do próprio pai, enquanto Davi enfrentou anos de perseguição e fuga. Apesar das circunstâncias adversas, os dois permaneceram fiéis ao compromisso estabelecido, honrando a amizade que selaram diante do Senhor.' WHERE "id" = '681d0470-3d12-4f72-9142-c07ea1da641d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi cometeu adultério com Bate-Seba e ordenou a morte de Urias para ocultar seu pecado. Meses depois, o profeta Natã visitou o rei e narrou uma parábola sobre um homem rico que tomou a única ovelha de um pobre. Indignado, Davi condenou a atitude, levando Natã a declarar que ele era o homem da história. Diante da acusação direta, o rei reconheceu seu erro perante Deus, confessando imediatamente que havia pecado contra o Senhor, sem tentar buscar qualquer justificativa.' WHERE "id" = '6837ec18-5d84-43a2-af54-5a16f50fa676';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O passarinho Tito vivia em uma floresta com diversos amigos. Certo dia, eles o convidaram para comer frutas em um galho alto e perigoso. Embora sua mãe tivesse advertido que o galho poderia quebrar, Tito sentiu vontade de acompanhar o grupo para não ficar excluído. No entanto, ele decidiu recusar o convite e permaneceu em segurança. Momentos depois, o galho rachou e os outros pássaros caíram. Tito preservou sua integridade ao seguir o conselho de sua mãe.' WHERE "id" = '686bee59-69fb-4409-bbc6-3fa09957b20a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sansão foi o homem mais forte de Israel, capaz de resistir a exércitos e correntes. Contudo, ele não dominava seus próprios impulsos, agindo conforme os desejos imediatos do coração, sem calcular custos. Essa falha em controlar a si mesmo permitiu a entrada de Dalila em sua vida. A traição resultante levou Sansão à queda, demonstrando que ele não foi derrotado por seus inimigos externos, mas sucumbiu devido à ausência de muros internos que governassem sua vontade e suas escolhas.' WHERE "id" = '687659ad-e92f-48cc-a9c9-713c31b06dc6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para uma terra estranha, o jovem Daniel enfrentou um desafio diante das ordens dos oficiais babilônicos. O rei determinou que os jovens hebreus consumissem iguarias que violavam as leis dietéticas de Daniel. Enquanto os outros rapazes obedeceram ao decreto real, Daniel recusou-se firmemente a comer aqueles alimentos. Ele propôs um teste com legumes e água. Ao final do período estipulado, Daniel e seus companheiros demonstraram estar visivelmente mais saudáveis e fortes do que os demais jovens.' WHERE "id" = '68840473-c391-4f8d-a3e6-c71e96427e7e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na noite anterior à sua prisão e execução, Jesus reuniu seus discípulos para um momento decisivo. Em meio a um clima de iminente traição e medo pelo futuro, Ele lhes transmitiu uma promessa singular. Jesus declarou que estava deixando a sua própria paz com eles. Ele enfatizou que essa paz não se assemelhava àquela oferecida pelo mundo, pois não dependia de circunstâncias externas favoráveis, permanecendo firme mesmo diante do caos, da angústia e da dor daqueles homens presentes.' WHERE "id" = '68a9a487-ac17-4d60-a4a6-7f8d34eb0588';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a liderança de Israel diante da imensa responsabilidade de conduzir o povo rumo à terra prometida. Deus ordenou explicitamente que ele fosse forte e corajoso para cumprir essa missão árdua. Apesar do desafio monumental e da incerteza que pairava sobre o futuro, Josué obedeceu à instrução divina. Ele atravessou o rio Jordão com o povo, agindo com firmeza e determinação, fatos que mudaram permanentemente o curso da história daquela nação escolhida.' WHERE "id" = '68c6e9b3-63b9-4807-8b22-7d15ca2269e3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado para uma terra estranha, o jovem Daniel enfrentou uma difícil prova em Babilônia. Autoridades locais ordenaram que ele consumisse alimentos proibidos por sua fé. Daniel, mantendo sua integridade, recusou o banquete real e propôs ao responsável um teste de dez dias à base de legumes e água. Ao fim desse período, Daniel e seus amigos apresentavam uma aparência física muito superior à dos outros jovens que aceitaram a dieta do rei, provando a eficácia daquela decisão.' WHERE "id" = '690f0818-6426-42a0-b7dd-02f18192fff6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo sem limites, o filho mais novo enfrentou a miséria e a fome, chegando ao ponto de cuidar de porcos. Em meio à humilhação, ele caiu em si e decidiu retornar à casa do seu pai para pedir perdão e emprego. Ao avistá-lo vindo de longe, o pai correu ao seu encontro, abraçou-o calorosamente e o acolheu antes mesmo que ele pudesse terminar de expressar o seu profundo arrependimento por tudo.' WHERE "id" = '6a074623-3b00-4df7-8266-0064e9f0d5ed';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, permitiu que mulheres estrangeiras se tornassem parte íntima de sua vida. Ignorando a sabedoria que ele mesmo pregava, o rei manteve companhias cujos valores eram contrários à fé de Israel. Essa escolha negligente trouxe graves consequências, resultando na corrupção de sua espiritualidade e na posterior divisão do reino. O sábio monarca tornou-se, assim, o exemplo prático de como as influências de pessoas próximas podem destruir o legado de uma vida inteira.' WHERE "id" = '6a07741f-6307-4b19-ad64-bcd4f431e3da';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo e Silas foram espancados publicamente por ordem das autoridades locais em Filipos. Em seguida, foram lançados em uma cela de segurança máxima, onde tiveram seus pés presos a troncos de madeira. Apesar das feridas abertas, da dor física causada pelo açoite e da humilhação sofrida, eles permaneceram fiéis. À meia-noite, na escuridão daquela prisão, ambos não se lamentaram pela injustiça. Pelo contrário, começaram a cantar hinos de louvor a Deus enquanto os outros prisioneiros os ouviam atentamente.' WHERE "id" = '6a300176-ec49-493b-bddd-d58ebd5b4978';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Saul perseguiu Davi com seu exército por muito tempo. Em duas oportunidades distintas, Davi teve a chance clara de matar Saul e assumir o trono imediatamente. Embora seus próprios homens o incentivassem a executar o rei, alegando ser a vontade de Deus, Davi recusou terminantemente. Ele escolheu manter sua palavra e honrar a aliança feita anteriormente com Saul, mesmo diante da pressão. Anos mais tarde, Davi foi coroado rei, sendo reconhecido por todos como alguém totalmente confiável.' WHERE "id" = '6a30c8bc-cbdc-4d8e-99d8-1dba1c972330';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observou uma multidão de pessoas sobrecarregadas por dívidas e preocupações sob o domínio romano. Apontando para os pássaros que voam no céu e para as flores que crescem nos campos, ele destacou como Deus providencia o sustento a essas criaturas. Em seguida, o mestre questionou seus ouvintes sobre a inutilidade da inquietação diante da vida. Ele perguntou quem, por meio de qualquer preocupação, conseguiria acrescentar um único centímetro à própria estatura, revelando a limitação humana diante do controle divino.' WHERE "id" = '6a7560e5-61ce-49fd-9e83-71d116ec9106';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo encontrou-se na miséria extrema. Reconhecendo seu erro, ele decidiu retornar à casa de seu pai, esperando ser tratado apenas como um empregado. Enquanto ainda estava longe, o pai avistou seu filho, correu ao seu encontro e o abraçou afetuosamente. O jovem começou a pedir perdão, mas o pai, cheio de compaixão, recebeu-o imediatamente, restaurando sua dignidade e acolhendo-o de volta à família com grande alegria e festa.' WHERE "id" = '6b29661f-cff2-4b7f-94a6-3e4420167439';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó era um homem próspero que possuía uma grande família e muitos bens. Em um único dia, ele perdeu todos os seus filhos e suas propriedades em uma sequência de tragédias devastadoras. Diante de tamanha dor, Jó rasgou suas vestes, rapou a cabeça e prostrou-se em adoração ao Senhor. Ele reconheceu que viera ao mundo nu e que retornaria da mesma forma. Apesar da perda absoluta, Jó não pecou contra Deus nem proferiu qualquer palavra de insensatez.' WHERE "id" = '6b5c5aaf-832f-403e-b406-293f1dc5b5c8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Eli era sacerdote em Israel e conhecia profundamente a lei de Deus. No entanto, ele permitiu que seus filhos praticassem atos de corrupção dentro do santuário, negligenciando sua responsabilidade espiritual e falhando em corrigi-los. Por causa dessa omissão e da prioridade dada à família em detrimento da obediência divina, Deus pronunciou um severo julgamento sobre a casa de Eli. O sacerdote perdeu seu legado ao desprezar a autoridade de Deus, colhendo as consequências de sua própria conduta negligente.' WHERE "id" = '6b819475-5c1f-478c-a5f4-b72f8cd80d44';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os discípulos discutiam sobre quem seria o maior no Reino de Deus. Jesus, ao ouvir a controvérsia, interveio para ensinar sobre a verdadeira liderança. Ele explicou que, ao contrário dos governantes terrenos, aquele que deseja ser grande deve tornar-se servo de todos. O Mestre apresentou a si mesmo como o exemplo supremo dessa postura, declarando que não veio para ser servido, mas para servir e oferecer a própria vida como resgate em favor de muitas outras pessoas.' WHERE "id" = '6bd73bea-9c1b-4257-9167-705df9258e42';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido, a viúva Noemi decidiu retornar de Moabe para Belém. Suas noras, Orpá e Rute, a acompanharam inicialmente. No caminho, Noemi incentivou que voltassem para suas casas. Orpá partiu, mas Rute recusou firmemente. Ela declarou fidelidade incondicional à sogra, afirmando que o povo e o Deus de Noemi seriam também os seus. Assim, Rute acompanhou Noemi em sua jornada, abandonando sua própria terra e parentela para permanecer ao lado da sogra até o fim.' WHERE "id" = '6be30fd2-1ac1-46f8-8f80-4161b7c5a825';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio de sua geração, observou cuidadosamente como a direção da vida das pessoas é moldada pelas influências próximas. Ele testemunhou reis perderem reinos devido a conselheiros convenientes e viu jovens promissores destruírem seu potencial ao se associarem com companhias erradas. Com base nessa análise histórica, ele registrou que caminhar com sábios resulta em sabedoria para o indivíduo, enquanto manter laços constantes com insensatos inevitavelmente produz danos profundos em toda a trajetória existencial humana.' WHERE "id" = '6c3a41b0-3e35-4ce1-9596-8378cec4bc75';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, o líder que libertou Israel e falava com Deus, Josué assumiu a difícil responsabilidade de conduzir o povo. Diante de um território hostil e de uma missão desafiadora, Josué sentiu o peso da liderança. Em meio à incerteza, Deus falou com ele, garantindo sua presença constante na jornada. O Senhor ordenou que Josué fosse forte e corajoso, enfrentando o medo diante das ameaças, para que pudesse guiar o povo à terra prometida com total confiança.' WHERE "id" = '6c8897bd-cc5e-472d-b78b-5a3c829c6ce7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, ciente dos efeitos devastadores da dispersão de suas lealdades, estabelece um princípio fundamental para a integridade pessoal. Ele instrui que os olhos devem permanecer fixos no caminho adiante, evitando qualquer desvio para a direita ou para a esquerda. Essa disciplina de manter o foco visual e mental representa a anatomia do autogoverno. Salomão enfatiza que aquele que falha em controlar o rumo do próprio olhar perde, progressivamente, a direção de tudo o que genuinamente ama.' WHERE "id" = '6cc9e6c9-8e6e-4d56-90b2-8949870bd34a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante do poderoso rei Nabucodonosor, os jovens hebreus Sadraque, Mesaque e Abednego foram confrontados com a ordem imperial de se prostrarem diante de uma estátua de ouro. A pressão da multidão exigia a adoração imediata sob a ameaça de morte em uma fornalha ardente. Com coragem, eles se recusaram a ceder à exigência do monarca e afirmaram que não responderiam ao rei, mantendo sua fidelidade. Mesmo diante do fogo iminente, os três servos escolheram permanecer firmes em suas convicções.' WHERE "id" = '6d124e79-1d53-4ce2-91e0-d506bed03706';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugia de Saul, que desejava matá-lo. Ao buscar refúgio em uma caverna, Davi encontrou o rei, que entrou ali sozinho sem perceber a presença dos fugitivos. Embora seus homens o incentivassem a aproveitar a oportunidade para eliminar o monarca, Davi apenas cortou um pedaço do manto de Saul. Ao sair da caverna, o futuro rei revelou o tecido ao monarca, provando que poderia ter tirado sua vida, mas escolheu poupá-lo, deixando Saul profundamente impactado com aquela atitude.' WHERE "id" = '6d29b6b2-d8ee-4fd1-89b0-eda0b14b30ff';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao viajar entre a Galileia e Samaria, Jesus encontrou dez leprosos que clamaram por misericórdia. Ele ordenou que fossem apresentar-se aos sacerdotes e, enquanto caminhavam, todos foram curados instantaneamente. Apenas um homem, um samaritano, retornou para glorificar a Deus e agradecer a Jesus aos seus pés. O Mestre perguntou pelos outros nove que não voltaram e validou a atitude daquele estrangeiro. O homem foi curado de sua enfermidade física e também recebeu a salvação pela sua fé.' WHERE "id" = '6da3c037-5ffb-4992-a9e7-ee1950f2c497';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos se prostrassem sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem, mantendo firme sua lealdade ao Deus verdadeiro. Diante do monarca, os três jovens declararam que, mesmo que o Senhor não os livrasse da fornalha, eles jamais serviriam aos deuses babilônicos nem adorariam a estátua. A decisão deles permaneceu inabalável diante das ameaças de execução impostas pelo soberano.' WHERE "id" = '6dac9c73-cc0d-4d16-9363-d11e4913b580';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi foi apresentado ao rei Saul. Naquele mesmo momento, surgiu uma profunda amizade entre Davi e Jônatas, filho do monarca. Reconhecendo o valor de Davi, Jônatas demonstrou grande afeto ao entregar voluntariamente seu próprio manto, espada e outros pertences pessoais ao jovem. Os dois homens firmaram então um pacto solene de lealdade mútua, comprometendo-se a cuidar um do outro para sempre. Essa aliança selou uma união sincera, marcada pelo respeito e pela total entrega entre ambos.' WHERE "id" = '6dadf9ec-de2a-46de-956a-a6b233aa00f1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava para Jericó quando foi atacado por ladrões, que o deixaram ferido na estrada. Um sacerdote e um levita passaram pelo local, mas ignoraram a vítima e seguiram adiante. Um samaritano, porém, aproximou-se, cuidou de seus ferimentos e colocou-o em seu próprio animal. Ele levou o homem a uma hospedagem e pagou todas as despesas pelos cuidados recebidos, prometendo retornar para quitar qualquer saldo restante caso o custo do tratamento ultrapassasse o valor adiantado inicialmente.' WHERE "id" = '6db21c8a-2194-4bf8-a2ee-53cc06e45669';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia, onde o rei ordenou que comesse alimentos que contrariavam seus princípios religiosos. Diferente dos outros jovens, Daniel recusou a dieta real com firmeza e gentileza. Ele propôs ao responsável pelo grupo um teste de dez dias, consumindo apenas vegetais e água. Após esse período, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta que os demais. Diante desse resultado visível, o responsável permitiu que eles continuassem seguindo as suas convicções.' WHERE "id" = '6de2257a-a03c-4278-90be-55bee609b89b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na corte de Salomão, a sabedoria residia no domínio das palavras. Enquanto conselheiros prudentes mantinham o silêncio necessário para preservar segredos, aqueles que falavam excessivamente expunham informações confidenciais alheias, muitas vezes por puro descuido. Consequentemente, os homens que sabiam calar conquistavam a confiança do rei e mantinham sua proximidade. Por outro lado, os fofoqueiros, incapazes de guardar confidências, acabavam isolados, pois ninguém mais lhes confiava segredos, visto que suas palavras desmedidas destruíam os laços de respeito e lealdade pessoal.' WHERE "id" = '6df995de-d23a-41e8-bb38-6374c72156c3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas estabeleceram uma profunda aliança de lealdade diante das ameaças de Saul. Jônatas, filho e herdeiro do rei, decidiu apoiar Davi, entregando-lhe seu manto, armas e insígnias reais como sinal de um pacto incondicional. Quando o rei ordenou a execução do jovem futuro monarca, Jônatas arriscou sua própria vida para alertar seu amigo sobre o perigo iminente. Essa relação foi consolidada por escolhas corajosas e sacrifícios significativos, mantendo a integridade entre ambos apesar da hostilidade política reinante.' WHERE "id" = '6eaad80c-2d59-422e-bc91-c9448b4d8573';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens leprosos encontraram Jesus enquanto Ele viajava entre Samaria e Galileia. Ao avistarem o Mestre, clamaram por misericórdia. Jesus ordenou que fossem mostrar-se aos sacerdotes, e enquanto caminhavam, todos foram purificados da enfermidade. Apenas um samaritano retornou, glorificando a Deus em alta voz e prostrando-se aos pés de Jesus para agradecer. Jesus perguntou pelos outros nove, observando que somente aquele estrangeiro havia voltado para dar glória a Deus, e então o enviou em paz após sua cura.' WHERE "id" = '6ecf9f79-e375-4cdf-8f2d-0da34b88eb15';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança vivendo desregradamente, o filho mais novo enfrentou uma severa escassez de alimentos. Reduzido à condição de tratar porcos, ele reconheceu sua miséria e decidiu retornar à casa de seu pai. Planejando pedir para ser tratado como um simples empregado, o jovem iniciou o caminho de volta. Ao vê-lo de longe, o pai correu ao seu encontro, abraçou-o e o beijou, recebendo-o prontamente antes mesmo que o rapaz pudesse concluir sua confissão preparada durante a jornada.' WHERE "id" = '6ef6f6e8-b71f-4bfd-8de9-09725e1ebf36';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José servia como escravo na casa de Potifar, um alto oficial egípcio. A esposa de seu senhor passou a pressioná-lo diariamente para que se deitasse com ela. Em um momento em que ficaram a sós na casa, ela o agarrou por sua capa para forçá-lo. José, porém, recusou-se a pecar e fugiu da presença dela. Ao sair apressadamente, deixou sua veste nas mãos da mulher, que permaneceu sozinha enquanto ele escapava para preservar sua integridade diante de Deus.' WHERE "id" = '6f5b5b65-b540-4fdf-9913-72ca34ab6702';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jacó, após anos de fuga por ter enganado seu irmão Esaú, retornou ao seu encontro temendo um confronto violento. Ao se verem, Jacó prostrou-se sete vezes no chão em sinal de respeito e arrependimento. Contudo, Esaú correu ao encontro de Jacó, abraçou-o e chorou. Jacó insistiu para que seu irmão aceitasse presentes como sinal de paz. Embora Esaú tenha resistido inicialmente por possuir o suficiente, ele acabou aceitando a oferta e ambos seguiram caminhos distintos em reconciliação plena.' WHERE "id" = '6f5d93df-c548-4767-8827-7f0588ad1ce3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Pedro aproximou-se de Jesus com uma dúvida específica sobre a prática do perdão fraternal. Ele perguntou ao Mestre se seria necessário perdoar um amigo que o ofendesse até sete vezes. Em resposta, Jesus apresentou uma orientação surpreendente, estabelecendo que o perdão não deve ser limitado por números ou contagens específicas. O Mestre ensinou que a atitude de perdoar deve ser constante e ilimitada, superando qualquer expectativa de medida que Pedro havia sugerido inicialmente durante aquela conversa entre eles.' WHERE "id" = '6f8dd4a5-2e2c-46a5-a9a5-11a68f09b071';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo enfrentou uma vida marcada por constantes provações e ameaças severas ao seu ministério. Durante sua trajetória missionária, ele suportou o encarceramento em prisões, passou por naufrágios perigosos e sofreu traições de companheiros próximos. Apesar dessas adversidades extremas que colocavam sua sobrevivência em risco diário, ele descreveu sua realidade com precisão: embora pressionado por todos os lados, não foi esmagado. Mesmo sentindo-se perplexo diante das circunstâncias difíceis, Paulo afirmou categoricamente que nunca foi destruído durante seu trabalho.' WHERE "id" = '6fd2b101-84bf-4d64-b3d6-a415685e2179';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em vida desregrada, o filho mais novo caiu em profunda miséria. Reconhecendo que havia pecado gravemente contra o céu e contra seu pai, ele decidiu retornar para casa como um servo. Enquanto caminhava, planejou seu pedido de perdão. Ao avistá-lo de longe, o pai, tomado de compaixão, correu ao seu encontro. Antes que o jovem terminasse seu discurso, o pai o abraçou afetuosamente, restaurando sua dignidade e acolhendo-o de volta à família.' WHERE "id" = '7055993a-d4cf-4c59-87e5-6626875c631a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após perder o marido e os filhos em terra estrangeira, Noemi decidiu retornar a Belém. Ela aconselhou suas noras, Orpá e Rute, a permanecerem em Moabe para recomeçarem suas vidas. Orpá despediu-se e partiu, mas Rute escolheu acompanhar a sogra. Rejeitando a segurança de sua pátria e família, ela declarou que seguiria Noemi até a morte e que o Deus de sua sogra seria o seu. Assim, ambas partiram juntas rumo à cidade de Belém, abandonando o passado definitivamente.' WHERE "id" = '7073c018-c4b4-443a-8527-9300a4923ae5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sanbalate, Tobias e Gesém enviaram mensagens a Neemias quatro vezes, convidando-o para uma reunião nas planícies de Ono. O objetivo era atrair o líder para uma emboscada e interromper a reconstrução das muralhas de Jerusalém. Percebendo a cilada, Neemias respondeu firmemente que estava realizando uma grande obra e não poderia descer. Apesar das constantes ameaças, falsos rumores de traição e pressões psicológicas dos inimigos, ele manteve o trabalho ininterrupto até concluir o muro em cinquenta e dois dias.' WHERE "id" = '71743437-7040-411a-bf50-0274c8a7793d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreveu uma carta aos filipenses enquanto estava preso, preocupado com as divisões e rivalidades que ameaçavam a unidade daquela comunidade. Ele exortou os cristãos a abandonarem o orgulho e a considerarem sinceramente os outros como superiores a si mesmos. Como exemplo supremo dessa postura, Paulo apresentou Jesus Cristo, que, sendo Deus, humilhou-se e desceu à condição humana. O apóstolo enfatizou que a verdadeira força reside na disposição de servir, abandonando a busca egoísta por posições de destaque entre os irmãos.' WHERE "id" = '7236669e-a491-4fd5-a05c-38af8c772ec0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um alto cargo no império persa, despertando a inveja de seus rivais. Eles manipularam o rei para assinar um decreto que proibia orações a qualquer deus, exceto ao monarca, sob pena de morte. Consciente da proibição, Daniel não recuou nem alterou sua rotina. Ele subiu ao seu aposento, abriu as janelas que davam para Jerusalém e continuou a orar ao seu Deus três vezes ao dia, conforme fazia habitualmente, desafiando abertamente a nova lei imposta.' WHERE "id" = '72630474-0936-4137-98bd-5b1345e283a6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus dotou os animais com vozes distintas, permitindo que o leão rugisse, o pássaro cantasse e a abelha zumbisse conforme a necessidade. Da mesma forma, o Criador concedeu ao ser humano o dom da fala como um presente valioso. A Bíblia ensina que uma resposta branda possui o poder de cessar conflitos, agindo como água que extingue o fogo. Por outro lado, palavras proferidas com ira possuem a capacidade de ferir profundamente aqueles que nos cercam no cotidiano.' WHERE "id" = '728682f8-44b6-46a7-adc8-d427530dbb7b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel recusou-se a consumir os alimentos da mesa real, pois violavam suas convicções. Ele solicitou respeitosamente ao oficial responsável uma alternativa alimentar. Diante do receio do oficial em aceitar a proposta, Daniel sugeriu um teste de dez dias apenas com vegetais e água. Ao término do período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que os jovens que se alimentaram com as iguarias do rei.' WHERE "id" = '72fe5f41-3d85-4421-ae61-1bdc63447dd5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após conquistar Jerusalém, o rei Nabucodonosor selecionou jovens israelitas promissores, incluindo Daniel e seus três amigos, para servirem em sua corte babilônica. Eles receberam novos nomes e foram inseridos em uma cultura distinta. Confrontado com a imposição de consumir a comida real, que Daniel considerava impura, ele propôs em seu coração não se contaminar. Com firmeza e inteligência, recusou o banquete oferecido pelo rei, solicitando uma dieta de legumes e água, a qual foi concedida pelos responsáveis babilônicos.' WHERE "id" = '7345fbe9-a4fb-46ca-8006-a7c8101fc643';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, solicitou a Deus discernimento em vez de riquezas ou poder, escolhendo focar na sabedoria para governar. Em Provérbios, ele instruiu seu filho a manter o olhar sempre fixo adiante, evitando desvios laterais. Salomão enfatizou a importância de guardar o coração, pois dele procedem todas as direções da vida humana. Assim, ele ensinou que o destino de uma pessoa é moldado pelo acúmulo das escolhas feitas diariamente no silêncio da atenção pessoal.' WHERE "id" = '73d6c9cc-0777-48d0-acb1-f5c597640aea';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, observou profundamente a trajetória dos grandes impérios. Ele constatou que a estabilidade dos reinos não dependia do acúmulo de riquezas, mas da integridade de seus governantes. O monarca percebeu que muitos impérios entraram em colapso porque seus líderes deterioraram a própria conduta moral muito antes da chegada de inimigos externos. Para Salomão, a reputação consolidada por escolhas éticas e honestas sempre possui um valor superior a qualquer bem material.' WHERE "id" = '73ff69c4-fa8d-47cd-b21f-b3e93511c280';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas e Davi firmaram uma aliança profunda baseada na lealdade mútua. Sendo Jônatas o herdeiro legítimo do trono de Israel e Davi o escolhido por Deus, ambos superaram qualquer ambição pessoal. Jônatas demonstrou seu compromisso entregando a Davi sua própria túnica, suas vestes, sua espada, seu arco e seu cinto. Eles estabeleceram um pacto solene de amizade diante do Senhor. Esse acordo selado entre os dois permaneceu firme, garantindo proteção e fidelidade contínua durante todo o período da vida deles.' WHERE "id" = '747275e6-d168-47f7-92f5-514ea232f53b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra estranha onde tentaram obrigá-lo a consumir alimentos proibidos por sua consciência. Com postura serena, ele recusou a comida real e propôs um teste de dez dias aos seus cuidadores, optando por consumir apenas vegetais e água. Ao fim desse período, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta que os demais jovens. Assim, o grupo continuou sua dieta específica, mantendo-se fiel aos seus princípios diante da autoridade babilônica.' WHERE "id" = '74b5746e-a785-4e66-8293-054823e39cd6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão observou que muitas pessoas proclamavam sua própria lealdade, porém era difícil encontrar um homem verdadeiramente confiável. Ele constatou que a vida privada daqueles que possuem integridade corresponde exatamente às suas atitudes em público. Esse comportamento íntegro gera uma herança duradoura para os filhos que supera qualquer riqueza material. As ações realizadas em segredo, longe do olhar das outras pessoas, moldam o caráter e permanecem como um registro real sobre quem cada homem verdadeiramente é em sua essência.' WHERE "id" = '74c4564b-ba5b-4c77-b74f-3dbf547f4b82';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro, sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abede-Nego recusaram a ordem, mantendo-se firmes em sua decisão. Diante da ameaça direta do monarca, os três jovens declararam que seu Deus tinha poder para livrá-los daquela sentença. Contudo, afirmaram resolutamente que, mesmo que o livramento não ocorresse, eles jamais adorariam a imagem de ouro estabelecida pelo rei na Babilônia.' WHERE "id" = '74c76889-3ea6-427f-a36a-a22076cb6844';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi conquistou a amizade profunda do príncipe Jônatas. Reconhecendo Davi como seu igual, Jônatas selou um pacto de lealdade entregando-lhe seu próprio manto, espada, arco e cinto. Apesar da hostilidade do rei Saul, que desejava eliminar o jovem pastor, Jônatas arriscou sua posição real para proteger a vida de seu amigo. Essa aliança histórica entre ambos transcendeu a política do reino de Israel, perdurando fielmente contra todas as ameaças enfrentadas por eles ao longo do tempo.' WHERE "id" = '75235c01-a1ee-4bb3-b66e-cc902753707e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem que pediu sabedoria e construiu um reino de esplendor sem precedentes, viu seu coração se desviar devido ao excesso de mulheres e de riquezas. O rei mais sábio do mundo envelheceu fragmentado por não aplicar limites à sua própria vida. Em seus escritos, ele alertou que até o mel, embora seja um alimento puro e bom, torna-se destrutivo quando alguém o consome além da conta. Assim, o monarca reconheceu tardiamente a importância crucial de saber parar.' WHERE "id" = '75e7eba6-113d-4574-a9b9-37ce62956876';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Por quarenta dias, o exército de Israel permaneceu paralisado diante das provocações do gigante Golias, que desafiava os soldados israelitas diariamente. O medo dominava o acampamento e impedia qualquer reação. Davi, um jovem sem armadura ou treinamento militar formal, apresentou-se ao rei Saul para enfrentar o guerreiro filisteu. Para justificar sua confiança, Davi relatou suas experiências passadas protegendo ovelhas, quando matou um leão e um urso, crendo que Deus o livraria daquele gigante também naquela ocasião.' WHERE "id" = '76097aa2-11c3-4ad8-84fd-2412c5cb82d4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte da herança ao pai e partiu para terras distantes, onde desperdiçou todos os seus bens com uma vida desregrada. Após perder tudo e enfrentar uma terrível escassez de alimento, ele decidiu retornar para casa, arrependido de suas escolhas. Ao avistá-lo ainda longe, o pai, tomado por profunda compaixão, correu ao seu encontro, abraçou-o afetuosamente e o acolheu de volta. Assim, o jovem foi restaurado ao convívio familiar após reconhecer o seu próprio erro.' WHERE "id" = '764fad17-48f4-46d1-8748-6535f812a51e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o rei mais sábio do mundo, recebeu sua sabedoria como um presente direto de Deus. Com o passar do tempo, ele escolheu aproximar-se de pessoas que não amavam ao Senhor. Ao conviver constantemente com esses indivíduos, Salomão começou a praticar as mesmas ações erradas que eles. Gradualmente, sua sabedoria divina foi negligenciada, ficando esquecida. Por causa de suas más companhias, o rei mudou o seu caminho, sofrendo as consequências diretas das escolhas feitas através de suas amizades.' WHERE "id" = '76af388b-e478-47f4-8a26-36231b26c044';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio de sua geração, cercou-se inicialmente de conselheiros e companheiros que valorizavam a sabedoria em seu governo. Contudo, ao longo de seu reinado, o rei abriu espaço em sua mesa para vozes que contradiziam seus princípios fundamentais. Essa mudança na escolha de suas companhias diretas trouxe consequências graves, resultando na divisão do reino. O registro histórico demonstra que a convivência diária com tolos levou o monarca à deterioração, confirmando que as companhias moldam o destino humano.' WHERE "id" = '770d009a-2ed1-4bf6-bfce-538dd4285c3b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noé recebeu um aviso divino sobre eventos futuros que ainda não eram visíveis aos olhos humanos. Com profunda convicção, ele obedeceu à ordem de Deus e dedicou anos construindo uma arca gigantesca em terreno seco, desafiando a lógica da época. Enquanto as pessoas ao seu redor viviam indiferentes, Noé trabalhou incansavelmente com madeira e suor. Essa obediência concreta resultou na preservação da sua própria família diante do dilúvio que viria a destruir toda a criação sobre a terra.' WHERE "id" = '77e5fa17-9972-43b8-abaa-b0636d4a4643';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ananias e Safira venderam uma propriedade e decidiram reter parte do valor, entregando apenas uma fração aos apóstolos como se fosse a quantia total. O casal agiu em segredo, acreditando que ninguém presenciaria sua mentira. Contudo, Pedro confrontou ambos individualmente, revelando a farsa perante a comunidade. Por terem tentado enganar a Deus com essa dissimulação, o casal foi desmascarado e sofreu as consequências fatais de sua conduta, demonstrando que nenhuma ação humana permanece oculta aos olhos do Senhor.' WHERE "id" = '77f9ce04-5cc1-4ddd-8cbc-d9ad874b75da';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Noé construísse uma arca imensa, mesmo estando distante de qualquer oceano e sem sinais de chuva. Embora as pessoas ao seu redor zombassem daquela tarefa incomum, Noé iniciou a construção conforme as instruções divinas. Ele trabalhou fielmente enquanto o povo duvidava de suas intenções. Quando o dilúvio finalmente chegou sobre a terra, Noé, sua família e diversos animais já estavam abrigados dentro da estrutura. Assim, todos foram protegidos da grande enchente pelo barco pronto.' WHERE "id" = '77fb9fb5-5a9f-4b5e-9512-841099da434b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi perguntou se restava algum descendente de Saul para demonstrar bondade. Seus servos indicaram Mefibosete, filho de Jônatas, que vivia em Lodebar e possuía deficiência física nos dois pés. Davi mandou buscá-lo e o trouxe à corte. O monarca restaurou todas as terras pertencentes a Saul ao neto e concedeu ao rapaz o privilégio de comer constantemente à mesa real. Assim, Mefibosete passou a morar em Jerusalém, sendo tratado por Davi como um dos filhos do próprio rei.' WHERE "id" = '7805fa89-2492-4d6d-a648-789f00885226';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio da história, dedicou extensas reflexões ao papel da linguagem nas interações humanas. Ele observou atentamente como palavras precipitadas causaram a queda de monarcas, a dissolução de amizades sólidas e o rompimento irreparável de laços familiares. Com base em sua vasta experiência, Salomão concluiu que a língua detém um poder absoluto. Ela funciona como um instrumento capaz de determinar tanto a morte quanto a vida, moldando destinos e destruindo conexões humanas fundamentais.' WHERE "id" = '7813cad2-e5b7-4805-b3d8-034015eb6432';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Doze espias foram enviados para explorar a terra de Canaã. Ao retornarem, dez deles relataram que o local era habitado por gigantes, sentindo-se pequenos como gafanhotos diante dos inimigos, o que gerou grande desespero no povo. Em contrapartida, Josué e Calebe observaram a mesma terra e os mesmos gigantes, mas mantiveram uma postura confiante, afirmando que a conquista era possível. Enquanto a maioria permitiu que o medo paralisasse a missão, a dupla persistiu em uma visão de vitória divina.' WHERE "id" = '7837efe4-1767-4079-920e-4e5cb2957358';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado à corte do rei Nabucodonosor como um adolescente cativo. Pressionado a consumir as iguarias reais, ele resolveu não se contaminar, mantendo seus valores firmes. Daniel pediu ao chefe dos servos uma alternativa alimentar para si e seus três companheiros. Após dez dias de dieta baseada em vegetais e água, eles apresentaram uma aparência física superior e melhor saúde do que os jovens que comeram da mesa do rei, permanecendo fiéis às suas convicções diante da corte.' WHERE "id" = '7854d7d8-e478-4f91-9496-4d5eef1663c5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava sentado no templo observando as pessoas depositarem suas ofertas no cofre. Muitos ricos contribuíam com grandes quantias. Em seguida, uma viúva pobre aproximou-se e depositou duas moedas minúsculas. Jesus chamou seus discípulos e afirmou que aquela mulher havia ofertado mais do que todos os outros juntos. Enquanto os ricos doavam apenas o que lhes sobrava de suas riquezas, a viúva entregou tudo o que possuía, oferecendo voluntariamente todo o sustento que tinha para o seu viver diário.' WHERE "id" = '786396b9-4eba-418b-b6ae-3c61b1d35f41';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas isolado no campo. Durante as noites estreladas, ele tocava sua harpa e cantava espontaneamente para Deus com um coração transbordante. O jovem entoava louvores tanto em momentos de alegria quanto diante do perigo, como quando leões ameaçavam o rebanho. Para Davi, a adoração era um ato natural e constante. Deus ouvia atentamente cada nota, palavra e suspiro daquele menino simples que escolhia agradecer antes de apresentar seus pedidos pessoais.' WHERE "id" = '7871b353-4849-45e0-9dc3-b3b2b18b94c1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro, sob pena de morte na fornalha ardente. Enquanto o império inteiro obedecia, Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem. Confrontados diretamente pelo monarca, os três jovens mantiveram sua posição firme. Eles declararam que seu Deus era capaz de livrá-los daquele fogo e que, mesmo que não o fizesse, não adorariam outros deuses nem se curvariam diante daquela estátua erguida pelo rei.' WHERE "id" = '78cfa45a-bfba-4623-b213-c41d107cec82';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, observando a ruína de impérios e o desvio de caminhos por falta de foco, transmite instruções fundamentais a seu filho. Ele ordena que o jovem mantenha o olhar fixo no que está adiante, evitando distrações laterais. Salomão enfatiza a importância de ponderar a vereda dos pés e confirmar todos os passos em retidão. O conselho exige atenção plena para que a vida não se fragmente, mantendo-se sempre no caminho certo, sem desviar para a direita ou esquerda.' WHERE "id" = '78fecbc9-eb53-4263-833b-523deb185133';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abede-Nego adorassem uma estátua de ouro, sob pena de morte em uma fornalha ardente. Confrontados pelo monarca, os três jovens recusaram-se a curvar diante da imagem. Eles declararam firmemente que o Deus a quem serviam era capaz de livrá-los daquele fogo intenso. Contudo, afirmaram ao rei que, mesmo se não fossem salvos, jamais adorariam o ídolo de ouro ou a estátua que ele havia erguido na província da Babilônia.' WHERE "id" = '7923717e-11ca-4395-9c71-8eafa601084e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel recusou consumir os alimentos e vinhos oferecidos pelo rei, pois desejava manter sua fidelidade aos mandamentos de Deus. Com sabedoria, ele propôs ao chefe dos eunucos um período de teste de dez dias, alimentando-se apenas de vegetais e água. Ao final do prazo, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta que todos os outros jovens que comeram as iguarias reais, confirmando o sucesso de sua decisão.' WHERE "id" = '7995c480-bd3c-4784-95c7-6dc6359d9f71';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém a Jericó quando foi atacado, espancado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo caminho, mas ignoraram a vítima. Em seguida, um samaritano aproximou-se, sentiu compaixão e cuidou de suas feridas com azeite e vinho. Ele o colocou em seu próprio animal, levou-o a uma hospedagem e pagou por todos os cuidados necessários. Jesus concluiu questionando qual dos três homens se tornou, de fato, o próximo daquele sujeito ferido.' WHERE "id" = '79a64901-f56d-46c4-a178-e88248b2158a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga demonstra uma sabedoria instintiva e notável ao preparar-se para o futuro enquanto o sol ainda brilha. Sem esperar o rigoroso inverno chegar, ela trabalha diligentemente carregando grãos individualmente para garantir sua provisão. Observando esse comportamento, o sábio Salomão reconheceu que, embora pequena e sem força física, a formiga é um exemplo de prudência. Graças a esse planejamento antecipado e constante trabalho, esse pequeno inseto assegura sua subsistência e evita passar fome durante as estações mais difíceis.' WHERE "id" = '79a6d874-c0ab-4e61-be85-0ab5156ab462';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó era um homem íntegro e muito próspero, que vivia retamente diante de Deus. Em um único dia, ele sofreu uma perda devastadora e repentina, sendo privado de seus filhos, de todas as suas riquezas e de sua segurança. Apesar da magnitude desse colapso vertical em sua vida, Jó manteve sua postura firme diante das circunstâncias. Ele se prostrou diante do Senhor, recusando-se a amaldiçoá-Lo, permanecendo fiel à sua identidade e convicções mesmo após perder tudo o que possuía.' WHERE "id" = '79aa98da-071b-41c9-a99f-a9d85614bd12';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem prisioneiro levado à Babilônia, enfrentou a oportunidade de consumir os alimentos da mesa real. Contudo, ele decidiu em seu coração não se contaminar com tais iguarias. Sem alarde, Daniel propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de vegetais e água. Após esse período, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta que todos os outros jovens que se alimentaram com as finas porções do próprio rei.' WHERE "id" = '79fc425b-c100-46c7-b737-ec989ef0403b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O povo de Deus enfrentou um período de profunda aflição e sofrimento, comparável a um tropeço doloroso que os deixou prostrados. Diante dessa situação angustiante e aparentemente sem fim, o profeta Miquéias demonstrou coragem ao declarar que, apesar da queda, ele se levantaria novamente. Ele não ignorou a dor, mas escolheu não permanecer no chão. Deus observou seu sofrimento e o sustentou, transformando aquele momento de humilhação em um exemplo de superação que seria lembrado por muitas gerações futuras.' WHERE "id" = '7a4cfeee-8e63-4ae9-9aff-8f915de3f23c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a vitória de Davi sobre Golias, surgiu um profundo vínculo entre ele e o príncipe Jônatas. Reconhecendo o chamado divino sobre Davi, Jônatas selou uma aliança de amizade, presenteando-o com seu manto, armadura, espada e cinto. Quando o rei Saul planejou matar o jovem ungido, Jônatas interveio corajosamente para protegê-lo. Eles reafirmaram seu compromisso diante de Deus, jurando lealdade mútua, mesmo sob a ameaça constante do rei, consolidando uma parceria inquebrável baseada em integridade e honra.' WHERE "id" = '7b2aa24a-a751-4c1f-afa6-69e36d72b0ec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, dirigiu suas instruções aos jovens que enfrentavam decisões fundamentais para o futuro. Como um pai experiente, ele enfatizou a necessidade de guardar o coração com vigilância absoluta, pois dele procedem todas as fontes da vida. O sábio alertou que cada erro cometido ou passo dado fora da direção correta tem sua origem em uma escolha interna e silenciosa, feita bem antes de qualquer ação física ser percebida pelas outras pessoas.' WHERE "id" = '7b46a907-f9d1-4ee1-8fdb-89b83801cf5c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo sem limites em uma terra distante, o filho mais novo terminou sozinho, faminto e cuidando de porcos. Em meio à miséria, ele finalmente caiu em si, reconhecendo a própria situação. Decidido a mudar, o jovem levantou-se e iniciou sua longa jornada de retorno à casa paterna. Ao encontrar o pai, ele confessou humildemente seus erros e pecados, pedindo para ser tratado apenas como um dos servos em seu lar.' WHERE "id" = '7b5b6d55-dee1-4f19-b86c-0ac9b0d74c69';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Asafe convoca o povo de Israel a recordar os feitos históricos realizados por Deus no deserto. O salmista alerta contra a postura das gerações anteriores, que endureceram seus corações, esqueceram as obras divinas e tornaram-se rebeldes. Diante disso, ele estabelece um mandamento claro: o que foi visto e recebido deve ser fielmente transmitido aos filhos. O objetivo é assegurar que a descendência coloque sua confiança no Senhor, preservando a memória das maravilhas divinas e evitando a infidelidade.' WHERE "id" = '7b9a0304-4555-4ca2-afe6-72983076fb26';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão e Ló precisaram se separar porque a terra não suportava seus rebanhos juntos. Abraão permitiu que seu sobrinho escolhesse a direção a seguir. Ló observou o vale do Jordão, notando que era uma região fértil, abundante e bem irrigada. Ele optou por habitar ali, posicionando suas tendas em direção a Sodoma, apesar de conhecer a maldade extrema de seus habitantes. Assim, Ló deixou o convívio com seu tio e fixou residência nas proximidades daquela perigosa cidade específica.' WHERE "id" = '7be6be34-7a90-4f49-bece-2b25297b5ef5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após Tiago e João solicitarem lugares de destaque no Reino, Jesus reuniu os doze discípulos. Ele explicou que, diferentemente dos governantes gentios que exercem autoridade dominando seus subordinados, o padrão entre os seus seguidores deveria ser invertido. Jesus ensinou que quem deseja ser grande deve tornar-se servo de todos e quem almeja a liderança deve ser escravo. Ele concluiu afirmando que o próprio Filho do Homem não veio ao mundo para ser servido, mas para servir e dar sua vida.' WHERE "id" = '7c265c2e-b7e5-4a1f-a563-b76f176c5796';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus apareceu ao rei Salomão e ofereceu realizar qualquer pedido que ele desejasse. Em vez de escolher riquezas, poder ou triunfos militares, Salomão solicitou discernimento para julgar o povo com justiça. Essa escolha evidenciou a integridade que ele cultivava em seu interior desde antes de assumir o trono. Ao governar com retidão, o rei demonstrou que seu caráter era o verdadeiro fundamento de sua autoridade. Assim, Salomão consolidou sua reputação e tornou seu nome memorável através de sua conduta.' WHERE "id" = '7c485c31-3d4c-4a3d-ad4f-d0c2264af97e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após Davi derrotar Golias, ele e Jônatas estabeleceram um profundo vínculo de amizade no palácio real. Embora fosse o príncipe herdeiro e sucessor direto ao trono, Jônatas demonstrou total lealdade ao jovem pastor. Ele entregou voluntariamente a Davi seu próprio manto, espada e arco, selando um pacto de compromisso mútuo. Essa aliança entre os dois homens permaneceu inabalável diante de todas as futuras perseguições, exílios e constantes ameaças que enfrentaram ao longo de suas trajetórias no reino de Israel.' WHERE "id" = '7c55213d-e958-45f2-b174-6f2eab7e85a2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel recusou a porção de comida e vinho do rei, pois desejava manter sua fidelidade aos mandamentos de Deus. Ele propôs ao chefe dos eunucos um teste de dez dias, consumindo apenas vegetais e água. Ao final desse período, Daniel e seus três companheiros apresentavam uma aparência muito mais saudável e robusta do que todos os outros jovens que se alimentaram das iguarias reais. Assim, eles permaneceram sob a dieta específica escolhida.' WHERE "id" = '7cbc0c43-4316-453b-bcfe-e8568e7ba8cc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após vinte anos de separação, Jacó retornou para encontrar seu irmão Esaú, a quem enganara no passado. Temendo o reencontro, Jacó organizou sua família e enviou presentes como gesto de paz. Na hora da reunião, Esaú, que chegava com quatrocentos homens, correu ao encontro de Jacó. Em vez de atacar, ele abraçou o irmão, beijou-o e ambos choraram. Jacó insistiu para que Esaú aceitasse seus presentes, simbolizando a reconciliação entre os dois homens naquele momento decisivo.' WHERE "id" = '7d22eb1e-ce44-499b-ad29-38ef2d6285aa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em um sonho em Gibeão, Deus apareceu ao rei Salomão e ofereceu realizar qualquer pedido que ele fizesse. Diante daquela oportunidade extraordinária, Salomão não solicitou riquezas, vida longa ou a destruição de seus inimigos. Em vez disso, pediu a Deus um coração compreensivo e discernimento para julgar o povo com justiça e distinguir o bem do mal. Agradado com aquela petição humilde, Deus concedeu ao rei sabedoria incomparável, além de acrescentar honra e prosperidade ao seu reinado.' WHERE "id" = '7d281415-784a-41eb-8202-7a92e21d21c6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria extrema cuidando de porcos. Em meio à fome, ele decidiu retornar à casa de seu pai, reconhecendo seus erros e preparando um pedido de perdão. Durante o caminho de volta, o pai o avistou à distância e correu ao seu encontro. Antes mesmo que o jovem pudesse completar sua explicação, o pai o recebeu com um abraço, demonstrando total aceitação e acolhimento diante do seu sincero arrependimento.' WHERE "id" = '7d320e8d-03cc-4aff-9f64-947ef77f328c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança em terras distantes, o filho mais novo enfrentou uma severa escassez de mantimentos. Reconhecendo sua situação miserável, ele decidiu retornar à casa de seu pai, planejando pedir perdão e oferecer-se como um simples empregado. Enquanto caminhava, foi avistado de longe pelo pai, que correu ao seu encontro com compaixão. Antes mesmo de concluir sua confissão preparada, o jovem foi prontamente acolhido por um caloroso abraço, restaurando seu vínculo familiar naquela mesma hora.' WHERE "id" = '7d5a3b88-0d80-4b76-a06b-a12e411b6be5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel recusou-se a consumir as finas iguarias e o vinho do rei, pois desejava manter sua pureza conforme a lei de Deus. Daniel propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de legumes e água. Após esse período, Daniel e seus três amigos apresentavam uma aparência mais saudável e robusta que os demais jovens. Assim, o funcionário real permitiu que eles continuassem com sua dieta específica durante o cativeiro.' WHERE "id" = '7d5cbc8c-b05c-4558-89c2-179336bac6bf';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte da herança ao pai e partiu para uma terra distante. Lá, desperdiçou todos os seus bens e passou fome cuidando de porcos. Ao reconhecer seu erro, decidiu retornar para casa pedindo perdão. Ainda de longe, seu pai o avistou e correu ao seu encontro, recebendo-o com um abraço amoroso. O pai, cheio de alegria, vestiu o filho com roupas novas e organizou uma grande festa para celebrar o seu retorno definitivo ao lar.' WHERE "id" = '7d7bc14b-0f46-4b7a-979e-7ca46c8931f3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta direta à comunidade cristã da cidade de Corinto. Naquele ambiente urbano, os moradores enfrentavam constantes pressões sociais que influenciavam diretamente suas escolhas e comportamentos diários. Diante desse cenário, Paulo alertou os coríntios sobre a influência negativa exercida pelas más companhias, explicando como o convívio social próximo poderia corromper os bons costumes do grupo. Ele instou os fiéis a perceberem como aqueles ao seu redor estavam silenciosamente moldando e alterando seus valores fundamentais.' WHERE "id" = '7dd8f554-0349-47c3-9646-db5e59974d23';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pediu sua parte na herança e partiu para terras distantes, onde desperdiçou todos os seus bens vivendo dissolutamente. Após enfrentar uma severa escassez e passar fome, ele reconheceu seus erros e decidiu retornar à casa de seu pai para pedir perdão. Ao vê-lo aproximar-se de longe, o pai correu ao seu encontro, abraçou-o com profunda compaixão e o acolheu calorosamente. O filho foi restaurado ao convívio familiar, sendo recebido com grande alegria por seu pai amoroso.' WHERE "id" = '7df93031-75a5-4b6f-b11b-9c419d541f14';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, recebeu de Deus a capacidade de discernir limites. Ele escreveu que o excesso de algo bom, como o mel, torna-se prejudicial. Contudo, o próprio Salomão ignorou sua sabedoria. Ele acumulou riquezas imensas, firmou alianças proibidas e buscou prazeres desenfreados. Esses excessos corroeram sua integridade interior e destruíram a estabilidade de seu reinado. Como resultado direto dessas escolhas, o legado de Salomão acabou sendo dividido e enfraquecido após o término de seu longo governo.' WHERE "id" = '7e37095d-214a-46c7-8e1d-84f2202ba8ad';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após cometer adultério com Bate-Seba e ordenar a morte de seu marido Urias, o rei Davi permaneceu em silêncio por meses. O Senhor enviou o profeta Natã para confrontá-lo com uma parábola sobre um homem rico e um pobre. Ao compreender a gravidade de suas ações reveladas pelo profeta, Davi reconheceu sua culpa diante de Deus. Sem buscar justificativas ou transferir a responsabilidade por seus atos, o rei confessou sinceramente que havia pecado contra o Senhor naquele momento.' WHERE "id" = '7e940f27-bca8-41b2-8a7e-c3b9ea52fa02';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão recebeu um chamado divino para deixar sua terra natal e seus parentes em direção a um lugar que Deus lhe daria como herança. Sem possuir um mapa, um destino previamente revelado ou qualquer garantia visível sobre o futuro, ele obedeceu à ordem do Senhor. Com total disposição, Abraão partiu imediatamente rumo a uma região desconhecida. Mesmo diante da profunda incerteza sobre o caminho a percorrer, ele agiu conforme a palavra recebida, confiando plenamente na promessa do Criador.' WHERE "id" = '7ec05866-321e-4675-a94b-f32eec58fcca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após anos de afastamento devido a conflitos passados, Jacó decidiu retornar e enfrentar seu irmão Esaú. Temeroso, Jacó aproximou-se de seu irmão enquanto viajava com sua família. Ao avistar Jacó vindo de longe, Esaú não reagiu com a antiga ira esperada. Em vez disso, ele correu ao encontro de seu irmão, lançou-se sobre o seu pescoço, abraçou-o carinhosamente e ambos choraram juntos. Assim, o longo desentendimento familiar foi finalmente superado por meio desse encontro reconciliador entre os dois irmãos.' WHERE "id" = '7f395662-8ea3-41bb-96b2-dced21812183';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O exército filisteu posicionou-se em um monte contra as tropas de Israel no outro lado. Durante quarenta dias, o gigante Golias, um guerreiro filisteu de porte impressionante, desafiou os israelitas a um combate singular. O rei Saul e seus soldados, tomados por grande temor, permaneceram imóveis diante das provocações diárias do adversário. O desafio de Golias exigia um representante de Israel para decidir o destino das nações em confronto, mas nenhum homem ousou enfrentar o poderoso guerreiro filisteu.' WHERE "id" = '7f4f2f14-bdb6-4a81-bbfd-c05f8cdc4402';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de forma desregrada, um jovem atingiu o fundo do poço e decidiu retornar à casa de seu pai. Enquanto caminhava, planejou um pedido de desculpas sincero, reconhecendo seus erros. Antes que ele chegasse ao destino, seu pai avistou-o de longe e correu ao seu encontro, abraçando-o com compaixão. O filho confessou seu pecado e indignidade, mas o pai o acolheu prontamente, restaurando sua posição e celebrando seu retorno com alegria.' WHERE "id" = '7fd5c387-118e-494e-8480-0ce0aa1b8e07';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança, o filho pródigo enfrentou a miséria e caiu em si. Reconhecendo sua condição degradante, decidiu retornar à casa de seu pai, preparando um discurso de confissão. Ele levantou-se e iniciou a viagem de volta. Enquanto ainda estava longe, o pai o avistou no horizonte. Movido por profunda compaixão, o pai não aguardou sua chegada, mas correu ao seu encontro, abraçou-o e o recebeu prontamente, restaurando sua dignidade após o longo período de afastamento.' WHERE "id" = '80263e92-fa5d-4378-bb3a-48ea35898cca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi atacado por salteadores, que o espancaram e abandonaram semimorto. Um sacerdote e um levita passaram pelo caminho, mas ignoraram a vítima. Em seguida, um samaritano aproximou-se, tratou suas feridas com óleo e vinho e o levou a uma hospedaria. Ele pagou pelos cuidados necessários para a recuperação do ferido. Jesus contou essa parábola para ilustrar quem age como próximo, desafiando a percepção comum sobre compaixão e solidariedade humana diante da necessidade.' WHERE "id" = '802b3148-7872-41a5-ab88-2b23defc8281';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro, sob pena de morte na fornalha. Enquanto o reino obedecia à pressão, Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem. Convocados pelo monarca, os três jovens afirmaram com firmeza que seu Deus era capaz de livrá-los daquele fogo ardente. Contudo, declararam que, mesmo que o Senhor decidisse não os salvar da execução, eles jamais se ajoelhariam diante da estátua feita pelo rei babilônico.' WHERE "id" = '81a7c719-050e-408b-b8b7-4ac0f70200d3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem exilado na Babilônia, recusou consumir as iguarias oferecidas pelo rei, pois desejava manter sua fidelidade aos mandamentos de Deus. Ele solicitou respeitosamente ao guarda responsável que lhe servisse apenas vegetais e água por dez dias, em vez da comida do palácio. Após o período estabelecido, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que todos os outros jovens. O guarda aceitou a proposta, permitindo que eles continuassem seguindo sua dieta.' WHERE "id" = '81f3a7cd-af8d-4e54-9df6-1a790450a4a6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ananias e sua esposa Safira venderam uma propriedade e decidiram reter parte do valor, entregando o restante aos apóstolos como se fosse a quantia integral. O apóstolo Pedro confrontou o casal sobre a fraude cometida contra o Espírito Santo, questionando a mentira deliberada. Ambos mantiveram a versão falsa separadamente e caíram mortos diante da assembleia. O fato causou grande temor em toda a igreja, pois o julgamento divino revelou a intenção secreta de seus corações naquele momento.' WHERE "id" = '821ee168-f16c-4112-95d4-c65d7a7bcf2f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido em uma terra estrangeira, Noemi decidiu retornar a Belém e liberou suas noras de qualquer obrigação. Orpá despediu-se e partiu, mas Rute escolheu permanecer ao lado da sogra, apesar das adversidades. Com firme determinação, Rute declarou que acompanharia Noemi onde quer que fosse e que ambas dividiriam o mesmo destino, inclusive a morte. Assim, a moabita abandonou seu povo e seu passado para seguir Noemi fielmente até a cidade de Belém.' WHERE "id" = '82bd7e8b-0066-4da0-8551-56747dbdcdda';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo viajou intensamente para anunciar a mensagem de Jesus aos povos. Durante sua jornada missionária, enfrentou situações extremas de sofrimento, incluindo períodos de prisão, fome e frio rigoroso. Apesar de passar por todas essas provações severas, Paulo redigiu uma carta orientando os cristãos a expressarem gratidão a Deus em todas as circunstâncias. Ele mantinha essa postura firme, pois tinha a plena convicção de que o Senhor permanecia ao seu lado em cada momento de dificuldade enfrentada.' WHERE "id" = '82c1877d-1cec-4d5f-ad76-52f47a5e63bf';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem recebeu sua herança e partiu para uma terra distante, onde esbanjou todos os seus bens. Após enfrentar miséria e fome, ele reconheceu sua falha e decidiu retornar à casa de seu pai para pedir perdão e servir como um empregado. Enquanto ainda estava longe, seu pai o avistou. Movido por profunda compaixão, o pai correu ao seu encontro, abraçou-o afetuosamente e ordenou uma grande festa para celebrar o retorno de seu filho que estava perdido.' WHERE "id" = '82e5f32f-f8b1-4248-91c8-5982e1f1c08c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus ensinava aos seus discípulos sobre a importância da paz. Certa vez, enquanto o grupo discutia fervorosamente sobre quem entre eles seria o maior, Jesus interrompeu a contenda de forma marcante. Ele posicionou uma pequena criança bem no centro daquele ambiente, diante de todos. Ao fazer isso, o Mestre instruiu os seus seguidores a agirem com a mesma simplicidade e pureza dos pequeninos, destacando que aqueles que promovem a harmonia são reconhecidos pelo próprio Deus como seus filhos.' WHERE "id" = '83795294-31aa-4f70-b26a-cc477479c295';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, levado cativo à Babilônia, enfrentou o decreto real que exigia o consumo de alimentos proibidos por suas convicções. Em vez de ceder à pressão do ambiente, o jovem propôs ao oficial encarregado um teste de dez dias, alimentando-se apenas de vegetais e água. Após o período estipulado, Daniel e seus três companheiros apresentavam uma aparência física visivelmente mais saudável e vigorosa do que os demais jovens que se alimentaram com as iguarias servidas na mesa real babilônica.' WHERE "id" = '83ee85a4-dccb-422f-bc68-f259336f058c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sansão nasceu consagrado com força extraordinária para libertar seu povo, mas não dominou seus impulsos. Ele cedeu repetidamente ao orgulho, à vingança e aos seus desejos pessoais. Após relacionar-se com Dalila, perdeu sua força física ao ter o cabelo cortado. Como consequência de suas escolhas e fraquezas, foi capturado pelos filisteus. O homem destinado a ser um libertador terminou seus dias cego, acorrentado e humilhado como um troféu pelos seus inimigos, morrendo no templo dos filisteus.' WHERE "id" = '841d6d56-cdfe-4572-8cca-400c88ad371b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante da pressão de uma batalha iminente e do atraso de Samuel, o rei Saul sentiu o desespero das tropas e decidiu assumir o controle. Ele mesmo ofereceu o sacrifício, usurpando uma função que não lhe era permitida. Ao chegar, Samuel repreendeu duramente o monarca por sua atitude impulsiva e insensata. Esse gesto precipitado, motivado pela ansiedade e pelo medo do momento, custou a Saul a continuidade de seu reino, encerrando precocemente seu longo legado sobre Israel.' WHERE "id" = '8422b885-5871-4bb6-86bd-3f2a2d3e0393';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus participava de um banquete e observou os convidados disputando os lugares de maior destaque à mesa. Ele então compartilhou uma parábola sobre a importância da humildade. O Mestre explicou que, ao ser convidado para um banquete, a pessoa não deve ocupar o lugar de honra, pois alguém mais ilustre pode chegar e obrigá-la a mudar de assento. Concluiu que quem se exalta será humilhado, mas aquele que escolhe o lugar menos importante receberá a devida honra pública.' WHERE "id" = '8458c407-c054-4813-b9c4-363d0763eb08';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em seus dias finais, Josué reuniu todo o povo de Israel para um pronunciamento decisivo. Diante da nação, ele apresentou um desafio claro sobre a escolha de a quem adorar. Josué afirmou que o povo poderia optar pelos deuses dos povos vizinhos ou pelos ídolos dos seus antepassados. Contudo, declarou publicamente sua firme decisão pessoal e familiar, mantendo-se resoluto diante de todos. Sem se deixar influenciar pela multidão, ele reafirmou solenemente que serviria exclusivamente ao Senhor Deus.' WHERE "id" = '8481af38-2c60-4296-b82b-6de0056cb8f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança em escolhas imprudentes, o filho pródigo encontrou-se em total miséria. Reconhecendo sua situação deplorável, decidiu retornar à casa de seu pai, ensaiando um pedido de desculpas para trabalhar como um de seus empregados. Ao avistar o rapaz ainda longe, o pai correu ao seu encontro, abraçou-o com compaixão e ordenou aos servos que trouxessem a melhor túnica, um anel e sandálias, celebrando o retorno do filho com um banquete especial por ele estar vivo.' WHERE "id" = '84e07b67-191e-470f-bb37-e78d8f1f7f03';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro, sob pena de morte na fornalha. Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem, permanecendo de pé diante do monarca poderoso. Quando confrontados, os três afirmaram firmemente que seu Deus era capaz de livrá-los, mas, ainda que não o fizesse, não serviriam aos deuses babilônicos nem adorariam a estátua. Desafiando a autoridade real, os jovens mantiveram sua posição e foram lançados na fornalha ardente.' WHERE "id" = '85077400-dba3-42a7-95a7-6502e7335104';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão descreve dois perfis distintos entre as pessoas que convivem em sociedade. O primeiro indivíduo é aquele que possui o hábito de espalhar prontamente tudo o que ouve, agindo de maneira imprudente com as informações que recebe. Já o segundo perfil é formado por alguém que demonstra responsabilidade e caráter, mantendo o silêncio sobre segredos e confidências. O texto bíblico contrasta essas atitudes, mostrando que a postura de cada um diante de conversas cotidianas define sua própria integridade.' WHERE "id" = '85304d7e-f3f0-4c42-b267-71b84bb4e5c3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus apareceu a Salomão em um sonho e ofereceu realizar qualquer pedido do jovem rei. Em vez de solicitar riquezas, vida longa ou a morte de seus inimigos, Salomão pediu sabedoria e um coração capaz de ouvir, visando discernir o bem e o mal para governar corretamente o grande povo de Israel. Satisfeito com a escolha humilde, Deus concedeu a Salomão o entendimento solicitado e acrescentou ainda as honras e bens que ele não havia pedido originalmente.' WHERE "id" = '85cfee42-2dad-4209-aa77-49bf970ae17e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo percorria longas distâncias para anunciar a mensagem de Jesus às pessoas. Durante suas viagens missionárias, enfrentou cansaço, fome e medos constantes. Mesmo diante de tais dificuldades, ele mantinha um hábito contínuo de comunicação com Deus. Mais tarde, em sua carta aos tessalonicenses, o apóstolo resumiu essa experiência de vida ao registrar o conselho para que orassem sem cessar. Dessa forma, Paulo buscava forças para prosseguir em sua missão, vivendo como se o Criador estivesse sempre presente.' WHERE "id" = '85e797ea-97c3-4d86-bf0d-2d4015b97549';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Caminhando sobre as águas do mar da Galileia, Jesus foi avistado pelos seus discípulos. Pedro pediu autorização para ir até Ele e recebeu o convite. Ao sair do barco, Pedro caminhou sobre as águas milagrosamente, mantendo o foco em Jesus. No entanto, ao observar a força do vento e o tamanho das ondas, o medo surgiu e ele começou a afundar. Desesperado, o discípulo clamou por socorro, percebendo que a sua atenção havia se desviado da presença de Cristo.' WHERE "id" = '85ea4ec8-344a-497d-a15d-60bd986609bc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seus familiares, a viúva Noemi decidiu retornar de Moabe para Belém, incentivando sua nora Rute a permanecer em sua terra natal. Rute, porém, recusou a liberdade oferecida e reafirmou sua lealdade incondicional à sogra. Ela declarou que acompanharia Noemi aonde quer que fosse, adotando o seu povo e o seu Deus como seus. Superando o desconhecido, Rute deixou tudo para trás e caminhou ao lado de Noemi em direção a uma nova vida em Israel.' WHERE "id" = '860e8516-f44b-4a2b-8b3f-8b55dcce1286';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia, onde o rei ordenou que ele e seus amigos consumissem alimentos da mesa real, o que violava suas convicções. Apesar da pressão e do risco de morte, Daniel recusou o banquete real e propôs ao encarregado um teste de dez dias, alimentando-se apenas de vegetais e água. Ao final do período, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta do que todos os jovens que comeram daquela iguaria.' WHERE "id" = '8619925a-b2db-404e-8a73-7d03400e8b7f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do rei Salomão, seu filho Roboão assumiu o trono de Israel em Siquém. O povo pediu alívio dos impostos pesados impostos por seu pai. Roboão buscou orientação dos anciãos, que aconselharam servir o povo com bondade. Contudo, o novo rei rejeitou a sabedoria dos mais velhos e seguiu o conselho dos jovens que cresceram com ele. Por causa dessa decisão imprudente, o povo se rebelou e o reino de Israel dividiu-se sob sua liderança instável.' WHERE "id" = '86348a64-cb57-4f60-91a1-4973c09ebd8f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar o gigante Golias, Davi, um jovem pastor, encontrou Jônatas, o filho do rei Saul e herdeiro do trono de Israel. Entre os dois surgiu uma profunda conexão imediata, unindo suas almas de maneira singular. Como sinal dessa aliança incondicional, Jônatas decidiu entregar a Davi o seu próprio manto real, sua espada, seu arco e o seu cinto. Esse gesto consolidou um pacto de amizade entre os dois, transcendendo as diferenças de posição social e status político.' WHERE "id" = '868ed919-fd05-4c03-b15d-3fa4a8f7176c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No Éden, Deus concedeu liberdade a Adão e Eva, proibindo-os de comer o fruto da árvore do conhecimento. Uma serpente questionou a ordem divina, incitando dúvida. Atraída pela aparência do fruto, Eva decidiu comê-lo, e Adão, que estava presente, também consumiu o alimento. A desobediência imediata gerou a percepção da própria nudez e um sentimento profundo de vergonha. Temerosos, ambos tentaram se esconder de Deus entre as árvores do jardim após terem rompido o único limite estabelecido pelo Criador.' WHERE "id" = '86953bc9-9df1-4a08-acb9-2f921f38a8ae';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava no templo enquanto pessoas ricas depositavam grandes quantias como oferta. Em seguida, uma viúva pobre aproximou-se e colocou apenas duas pequenas moedas de cobre. Jesus chamou seus discípulos para notar a cena e afirmou que aquela mulher contribuiu mais do que todos os outros. Enquanto os ricos ofertaram apenas o que sobrava de suas riquezas, a viúva entregou tudo o que possuía para seu próprio sustento. Foi um gesto de entrega total sem qualquer cálculo financeiro prévio.' WHERE "id" = '86c593df-77d3-4853-a3cb-d392c4837bfd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um cargo de alta confiança no reino de Dário, despertando inveja em seus rivais. Sem encontrarem falhas em sua conduta, os opositores convenceram o rei a promulgar um decreto proibindo orações a qualquer deus, exceto ao próprio monarca. Mesmo ciente da nova lei e das consequências fatais, Daniel retornou para sua casa. Diante da janela aberta, ele ajoelhou-se e orou a Deus como fazia diariamente, mantendo sua fidelidade inabalável e desafiando o decreto real estabelecido contra ele.' WHERE "id" = '86dbb0f6-7621-48f8-843a-ace923451fd5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria extrema ao cuidar de porcos. Em um momento de lucidez, reconheceu sua situação deplorável e decidiu retornar à casa de seu pai. Ele preparou um discurso de arrependimento, admitindo que havia pecado contra o céu e contra seu progenitor. Com coragem, o jovem levantou-se e iniciou a longa caminhada de volta, decidindo encarar a realidade de seus erros e buscar o perdão de seu pai.' WHERE "id" = '86fe5ed8-7410-4e57-a80d-6e54cd3ae3a8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um passarinho chamado Bem-te-vi aprendeu a voar e recebeu um conselho de seu pai: não voar perto do rio durante ventos fortes. Certo dia, ao obedecer a essa orientação, o pássaro permaneceu em segurança no galho enquanto uma tempestade varria tudo abaixo dele. Outros pássaros que ignoraram o aviso caíram com a força do vento. O Bem-te-vi observou o desastre e compreendeu que seguir as instruções paternas era a atitude correta para garantir sua proteção naquele momento difícil.' WHERE "id" = '871ca97b-cc53-4201-80fe-0c0d242e7dd2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noemi, após perder o marido e os dois filhos em terra estrangeira, decidiu retornar a Belém. Ela estava acompanhada de suas duas noras, Orfa e Rute. Enquanto Orfa optou por se despedir e seguir seu próprio caminho, Rute tomou uma decisão diferente. Ela declarou fidelidade incondicional a Noemi, escolhendo abandonar seu povo e seus deuses para acompanhar a sogra. Rute selou esse compromisso solene, decidindo permanecer ao lado de Noemi, independente do destino que enfrentariam em Belém.' WHERE "id" = '8753be3f-8bda-4608-84c4-1e9712d6acb6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Deus convocou Josué para uma missão desafiadora: conduzir o povo de Israel rumo à terra prometida. Diante dos grandes obstáculos que encontraria pelo caminho, Josué sentiu temor pela responsabilidade imposta. O Senhor, contudo, ordenou que ele fosse forte e corajoso, garantindo que estaria ao seu lado em todos os lugares. Fortalecido por essa promessa divina, Josué obedeceu prontamente à ordem, assumindo seu papel como o novo líder que guiaria toda a nação israelita.' WHERE "id" = '8764c5bb-515d-4844-9796-ef7b4acd6c61';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo viveu na miséria, cuidando de porcos em uma terra distante. Em um momento de lucidez, ele reconheceu seus erros e decidiu retornar à casa de seu pai para pedir perdão. Ao se aproximar de casa, o jovem foi surpreendido pelo pai, que, ao vê-lo de longe, correu ao seu encontro com compaixão. Antes que terminasse sua confissão, o filho foi acolhido calorosamente, encerrando sua longa e penosa jornada.' WHERE "id" = '877c5432-5d28-4867-8b66-8138663cb080';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo João escreveu uma carta endereçada às comunidades cristãs que enfrentavam um período marcado pelo medo. Os fiéis temiam a perseguição, a rejeição social e a sensação de insuficiência diante dos desafios da época. Diante dessa realidade, João afirmou que o amor perfeito de Deus tem o poder de expulsar todo o medo, pois o temor humano está ligado à punição. Ele orientou os cristãos a confiarem plenamente no amor divino, superando a ansiedade causada por ameaças externas constantes.' WHERE "id" = '87bdd98f-48b1-4bd1-a4f4-698c94a5af6c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em uma vida desregrada longe de casa, o filho pródigo enfrentou a escassez e a solidão. Reconhecendo seu erro, ele decidiu retornar ao pai para confessar suas falhas pessoalmente. Ao iniciar a jornada de volta, foi avistado à distância pelo pai, que, movido por compaixão, correu ao seu encontro. Antes mesmo que o jovem terminasse de pronunciar sua confissão, o pai o acolheu com amor, restaurando sua dignidade perante a família reunida naquele momento.' WHERE "id" = '87cf1db0-c399-40f8-b418-b93539f5e190';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dissipar todos os seus bens em uma vida irresponsável longe de casa, o filho pródigo encontrou-se em total miséria. Ao refletir sobre sua condição, reconheceu os erros cometidos e decidiu retornar à casa de seu pai como um servo. Levantou-se da lama e iniciou o caminho de volta. O pai, que ansiosamente o aguardava no horizonte, avistou-o de longe. Em um gesto de profunda compaixão, correu ao encontro do filho, abraçando-o antes mesmo de qualquer palavra.' WHERE "id" = '87ea30c0-d3c0-4f01-9379-ab03535dbb42';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel era um servo fiel a Deus que mantinha seus costumes mesmo sob ordens reais. Quando o rei proibiu as orações públicas, Daniel manteve sua rotina de orar três vezes ao dia em seu quarto, sem se esconder. Sua lealdade gerou riscos de punição severa, mas ele permaneceu íntegro perante Deus, agindo da mesma forma em particular ou diante de todos. Mesmo ciente das consequências impostas pelo decreto, ele escolheu honrar sua fé, sendo sustentado pela presença divina constante.' WHERE "id" = '88047eaa-0c0b-4865-8ea9-0d07aef1f3f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após anos fugindo por ter roubado a bênção e a primogenitura de seu irmão Esaú, Jacó retornou para um reencontro temido. Ansioso e receoso de uma vingança, Jacó aproximou-se curvado, esperando hostilidade. Contudo, ao avistá-lo, Esaú correu ao seu encontro e o abraçou afetuosamente. Emocionado com a inesperada demonstração de paz, Jacó declarou que ver o rosto de seu irmão era como contemplar a face de Deus. Ambos compartilharam um momento de profunda reconciliação, encerrando um longo período de medo.' WHERE "id" = '88150a4c-cca0-415b-8f0c-cd952e829e25';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um alto cargo no império persa, despertando a inveja de seus rivais. Eles manipularam o rei Dario a assinar um decreto que proibia orações a qualquer deus, exceto ao monarca. Mesmo ciente da proibição, Daniel manteve sua rotina de oração voltada para Jerusalém. Por essa desobediência, foi preso e lançado em uma cova com leões famintos. Na manhã seguinte, o rei encontrou Daniel vivo, pois Deus enviou um anjo para fechar a boca dos animais.' WHERE "id" = '882097a5-d550-4d64-a4c4-f59802ea2324';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo encontrava-se encarcerado em uma cela escura, privado de conforto, de sua própria cama e da companhia de seus amigos. Apesar das circunstâncias difíceis e do isolamento, ele redigiu uma carta direcionada aos filipenses. Nela, o apóstolo orientou que, diante de qualquer preocupação ou medo que apertasse o coração, as pessoas deveriam apresentar todos os seus pedidos a Deus. Como resposta direta a esse ato de oração, uma paz profunda e inexplicável guardaria os corações daqueles fiéis.' WHERE "id" = '8821a468-441c-445c-8f90-bb2e36aded59';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus, embora sendo o maior de todos, reuniu seus discípulos para uma demonstração de humildade profunda. Ele pegou uma bacia com água e, ajoelhando-se no chão, lavou pessoalmente os pés sujos de cada um de seus amigos. Os discípulos observaram a cena surpresos, pois não esperavam que o mestre realizasse tal tarefa destinada a servos. Após completar o ato, Jesus explicou que, para ser considerado grande, é necessário aprender a cuidar e servir ao próximo com dedicação.' WHERE "id" = '885dc9a4-7bcc-4138-8752-abcf86b9da03';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ofereceu a Salomão a oportunidade de realizar qualquer pedido, incluindo riquezas, poder ou vingança contra seus inimigos. Em vez de escolher benefícios pessoais ou materiais, Salomão pediu sabedoria para governar o povo de Israel. Ele reconheceu a limitação de seu próprio entendimento diante da magnitude da tarefa real. Essa escolha demonstrou sua consciência sobre a dependência de Deus. Graças a esse pedido específico, Salomão recebeu a capacidade necessária para liderar com justiça e clareza durante seu reinado.' WHERE "id" = '8873a49c-0b15-49a0-9653-628e68576242';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a conquista de Jerusalém pelo rei Nabucodonosor, jovens israelitas foram levados ao palácio babilônico. Daniel, um dos cativos, recusou a comida real oferecida aos ídolos, pois desejava manter sua fidelidade aos mandamentos divinos. Ele propôs ao oficial encarregado um teste de dez dias com dieta de vegetais e água. Ao final do período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens, sendo aprovados pelo oficial responsável por sua alimentação.' WHERE "id" = '88cb68a9-93ab-4626-a30e-b50e02e1f7f7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em Filipos, Paulo e Silas foram açoitados publicamente e encarcerados em uma cela profunda com os pés presos em troncos. À meia-noite, enquanto os outros prisioneiros ouviam, eles cantavam hinos de louvor a Deus. Repentinamente, um forte terremoto sacudiu os alicerces da prisão. O poder do abalo sísmico abriu todas as portas das celas e fez com que as correntes que prendiam todos os detentos se soltassem imediatamente. Eles foram libertados de suas prisões físicas durante aquele evento sobrenatural.' WHERE "id" = '895b51f0-3029-4d8f-8409-3f5b3bacf7e9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão e Ló perceberam que a terra não comportava mais os seus rebanhos e decidiram pela separação. Abraão permitiu que o sobrinho escolhesse primeiro o destino. Ló observou as planícies do Jordão, atraído pela fertilidade e prosperidade visual do local, e decidiu habitar naquelas campinas. Ele se estabeleceu próximo a Sodoma, uma região reconhecida pela corrupção. Assim, Ló priorizou a conveniência da terra, aproximando sua família de um ambiente perigoso, sem considerar as consequências espirituais e sociais dessa decisão fatídica.' WHERE "id" = '898e6df5-de55-465b-ac49-3c8429c622ae';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez leprosos encontraram Jesus à distância e pediram misericórdia. Seguindo a ordem do Mestre, eles foram se apresentar aos sacerdotes e todos foram curados durante o percurso. Apenas um homem, ao notar que estava livre da doença, retornou para glorificar a Deus em voz alta e agradecer aos pés de Jesus. O Senhor questionou o paradeiro dos outros nove, que não voltaram para dar glória. Por fim, Jesus afirmou que a fé daquele samaritano o havia salvo.' WHERE "id" = '899d48a1-5939-4e7f-b1e0-cad0232c30ee';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi encontrou-se com o príncipe Jônatas. Embora fossem de classes sociais distintas, suas almas se uniram profundamente desde o primeiro instante daquele encontro. Jônatas, reconhecendo o valor do jovem pastor, decidiu honrá-lo com gestos concretos de entrega. Ele retirou seu próprio manto, sua espada, seu arco e seu cinto, entregando-os a Davi. Esses objetos representavam a identidade e a posição do príncipe herdeiro, selando uma aliança baseada em um vínculo de sacrifício e lealdade mútua.' WHERE "id" = '89bd09a3-ef19-4d43-9a63-03d079159725';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens, o filho mais novo caiu em si e decidiu retornar para a casa do seu pai. Em vez de enviar explicações, ele levantou-se e iniciou sua jornada de volta, ensaiando um discurso de rendição. Enquanto ainda estava longe, seu pai o avistou, correu ao seu encontro e o abraçou afetuosamente. O filho tentou confessar seus erros, mas o pai o acolheu prontamente, restaurando seu lugar na família antes mesmo de qualquer pedido.' WHERE "id" = '89fa8e1b-32af-4c6f-ab27-0f69a3f06fc9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago escreve uma epístola endereçada às comunidades de cristãos dispersas por diversas regiões. Esses fiéis haviam perdido seus lares, suas posições sociais e toda a estabilidade que possuíam anteriormente. Diante desse cenário de sofrimento e provações intensas, o autor inspirado revela que a fé submetida ao teste produz a paciência. Ele ensina que o desenvolvimento dessa virtude é um processo essencial, capaz de transformar o indivíduo e torná-lo uma pessoa madura, completa e totalmente íntegra perante Deus.' WHERE "id" = '8a7e03c5-9f68-4a71-8846-d01adc72c750';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio de toda a história, convocou seu filho para uma instrução fundamental. Ele orientou o jovem a manter o olhar fixo no caminho que estava à sua frente, evitando desviar os olhos do que era considerado correto. Além disso, o monarca aconselhou que seus pés permanecessem firmes na vereda reta, desviando-se de qualquer atalho tortuoso. Essa orientação visava garantir que o rapaz seguisse uma trajetória íntegra durante toda a sua existência.' WHERE "id" = '8ab2af02-c52b-47c4-be1f-c83534b005d7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jeremias descreve uma árvore plantada junto a um rio cujas raízes alcançam águas profundas. Quando o sol forte queima a vegetação ao redor e a seca prolongada assola a terra, essa árvore não sofre danos. Enquanto outras plantas murcham devido à falta de chuva, ela permanece viçosa, verde e cheia de vida. Sua resistência diante das condições climáticas adversas é garantida pela proximidade constante com o curso d’água, que supre todas as suas necessidades vitais mesmo em tempos difíceis.' WHERE "id" = '8ad92ef4-0735-459c-b88b-85570025f876';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança em terras distantes, o filho mais novo enfrentou uma severa fome. Reconhecendo seu erro, ele decidiu retornar à casa do pai, ensaiando um pedido de desculpas sincero. Enquanto caminhava de volta, seu pai o avistou de longe, correu em sua direção e o abraçou com compaixão antes mesmo que o rapaz terminasse sua confissão. O filho foi prontamente acolhido pelo pai, que demonstrou um amor incondicional ao recebê-lo de volta em seu lar.' WHERE "id" = '8b938ebd-4ee6-4d1f-a4bd-e0903a269033';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos os presentes se prostrassem perante ela ao som da música. Enquanto a multidão se curvava, os jovens hebreus Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem, mantendo-se de pé. Confrontados pelo monarca e ameaçados de execução na fornalha ardente, eles declararam com firmeza que não precisavam responder ao rei sobre sua decisão, mantendo sua fidelidade ao Deus único diante da iminente sentença de morte.' WHERE "id" = '8ba4550a-ea95-4cd4-9c75-0fde0d6aab07';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abede-Nego adorassem uma estátua de ouro, sob pena de morte em uma fornalha ardente. Confrontados pelo monarca, os três jovens recusaram curvar-se, afirmando que Deus os livraria ou, caso contrário, não serviriam aos deuses babilônicos. Por causa dessa resistência, foram lançados no fogo intenso. Milagrosamente, sobreviveram ilesos, sem marcas de fumaça, acompanhados por um quarto ser misterioso enquanto caminhavam pelo meio das chamas, provando a proteção divina diante da sentença real.' WHERE "id" = '8baa1d7c-be58-4583-badf-3c1499ea2a01';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão instruiu seu filho a manter o foco constante, olhando sempre para frente e evitando distrações laterais ou para trás. Ele utilizou o exemplo prático do pastor de ovelhas, que precisa dedicar atenção exclusiva a cada animal para garantir a segurança do rebanho. Enquanto o pastor que se dispersa permite que a ovelha mais frágil se perca, aquele que mantém seus olhos atentos protege todos sob seu cuidado, impedindo que qualquer um dos amados se desvie perigosamente.' WHERE "id" = '8bbec336-e40b-409e-8c5c-619c5679e6cd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Como cativo na Babilônia, Daniel recusou alimentar-se com as iguarias oferecidas pelo rei para não se contaminar. Com firmeza, ele solicitou ao supervisor uma alternativa durante um período de dez dias. O funcionário aceitou a proposta e permitiu que Daniel e seus três companheiros comessem apenas legumes e bebessem água. Ao término do prazo, eles apresentavam uma aparência muito mais saudável e robusta que os jovens que consumiram a dieta real, confirmando o resultado daquela escolha estratégica.' WHERE "id" = '8c0e2fca-92c4-4f49-b37a-5cab27e6eaf4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel foi selecionado para servir ao poderoso rei Nabucodonosor, recebendo a oferta de alimentos das iguarias reais. Determinado a não se contaminar, Daniel recusou o banquete e propôs ao guarda um teste de dez dias, alimentando-se apenas de legumes e água. Ao fim do período, a aparência de Daniel e de seus amigos mostrou-se muito mais saudável e robusta do que a dos jovens que consumiram as finas porções da mesa real.' WHERE "id" = '8c37856c-bc9f-4828-b98e-ae427c7a9889';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus ilustrou uma parábola sobre a fidelidade na administração de responsabilidades. O Mestre descreveu um servo que recebeu tarefas simples de seu senhor e as executou com total dedicação e capricho. Impressionado com o zelo demonstrado, o senhor passou a confiar ainda mais naquele servo. Como resultado da sua prudência e eficiência nos deveres menores, o homem recebeu novas incumbências de maior importância, fortalecendo a confiança e a proximidade entre eles dentro daquela estrutura de gestão doméstica.' WHERE "id" = '8ca10c27-617f-4b6f-a6ff-49f48c30cdc0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi interceptado por assaltantes, espancado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo local, viram a vítima e seguiram caminho sem prestar socorro. Posteriormente, um samaritano aproximou-se, sentiu compaixão e cuidou dos ferimentos do homem. Ele o colocou em seu próprio animal, levou-o a uma hospedaria e pagou pelas despesas necessárias para o seu tratamento e recuperação, demonstrando cuidado prático diante daquela situação trágica.' WHERE "id" = '8cb49aaa-53c1-43a8-a95f-0875b9559639';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O fazendeiro prepara o solo e semeia suas sementes na terra com expectativa. Ele não desenterra o plantio diariamente para verificar o progresso, mas confia no ciclo natural. O agricultor cuida da irrigação e aguarda pacientemente as chuvas necessárias durante o tempo estipulado. Ele compreende que a semente exige escuridão, silêncio e o período exato de desenvolvimento para se transformar em uma planta forte. Assim, o homem mantém a calma e aguarda o momento preciso da colheita final.' WHERE "id" = '8ccf38b7-288c-4e71-8700-45b217eb5a00';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em meio à miséria extrema, o filho pródigo alimentava porcos e passava fome, reconhecendo que sua liberdade havia se tornado autodestrutiva. Ele comparou sua situação atual com a abundância existente na casa de seu pai, onde até os servos tinham sustento. Decidido a mudar seu destino, ele abandonou o orgulho e o local onde estava. Sem aguardar por convites, o jovem levantou-se prontamente e iniciou o caminho de volta para casa, buscando reconciliar-se com o seu pai.' WHERE "id" = '8cd2997a-6835-45b2-9301-0edddaec9e50';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi cuidava de ovelhas no campo quando um leão tentou atacar seu rebanho. Apesar do medo, ele enfrentou a fera e resgatou a ovelha. Mais tarde, enquanto os soldados de Israel tremiam diante do gigante Golias no campo de batalha, Davi se apresentou voluntariamente para lutar. Mesmo sendo jovem e sem a compleição física de um guerreiro experiente, ele avançou contra o filisteu, confiando plenamente que Deus o protegeria e o capacitaria durante aquele confronto decisivo contra o inimigo.' WHERE "id" = '8ce4173c-b20b-42c0-b3c8-478add46cefb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario nomeou Daniel como um dos governadores do império persa. Invejados pela posição de Daniel, seus rivais convenceram o rei a decretar que ninguém poderia orar a outro deus senão a ele. Daniel desobedeceu e continuou orando ao seu Deus. Por isso, foi lançado na cova dos leões. O rei passou a noite aflito e, ao amanhecer, encontrou Daniel intacto. Deus enviou um anjo para fechar a boca dos leões, preservando a vida de seu servo.' WHERE "id" = '8d319cfd-2342-43d9-9c46-82c3a87b495e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel recusou as iguarias e o vinho da mesa do rei, pois violavam suas convicções. Em vez de criar um conflito, ele propôs um teste ao guarda responsável: durante dez dias, Daniel e seus três amigos comeriam apenas legumes e beberiam água. Após esse período, os quatro jovens apresentavam uma aparência mais saudável e robusta que todos os outros que consumiam as finas porções reais. Assim, mantiveram sua dieta fielmente preservada.' WHERE "id" = '8d63ffc9-7574-4c3e-a539-b18ba81ad956';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi apresentou-se diante do rei Saul para se voluntariar ao combate contra o gigante Golias. Embora fosse jovem, ele relatou suas experiências anteriores ao proteger as ovelhas de seu pai. Davi descreveu como enfrentou e matou um leão e um urso que tentaram atacar seu rebanho no campo, utilizando apenas a força de suas próprias mãos. Convencido pelo testemunho de suas vitórias passadas, Saul permitiu que Davi seguisse ao vale para lutar contra o guerreiro filisteu.' WHERE "id" = '8d9bd0cc-c11e-4da0-8dbe-f169d60ce43f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sadraque, Mesaque e Abednego foram levados à presença do rei Nabucodonosor após se recusarem a adorar a estátua de ouro erguida na planície de Dura. Diante da ameaça de serem lançados imediatamente em uma fornalha de fogo ardente, os três jovens responderam ao monarca de maneira firme. Eles declararam que o Deus a quem serviam poderia livrá-los daquele fogo, mas, ainda que Ele não o fizesse, não se curvariam diante da imagem, mantendo sua integridade diante da morte.' WHERE "id" = '8d9becd1-65ab-4523-ad92-19de705c3d43';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O jovem Samuel servia no templo e dormia perto do sacerdote Eli. Certa noite, Samuel ouviu uma voz chamando seu nome e procurou Eli, acreditando ser ele quem o chamava. Após o fato repetir-se três vezes, Eli compreendeu que era o Senhor falando com o menino. Ele orientou Samuel a responder prontamente caso tornasse a ouvir o chamado. Samuel obedeceu, posicionou-se para escutar e, a partir daquele momento, Deus começou a revelar revelações importantes ao jovem profeta.' WHERE "id" = '8e313150-16fc-443b-a198-e75eff888a8d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, convivia com Davi em um contexto de disputa pelo trono real. Em vez de encará-lo como um rival, Jônatas firmou um pacto de lealdade com ele. Quando o rei Saul manifestou o desejo de matar Davi, Jônatas agiu prontamente para protegê-lo. Ele alertou o amigo sobre o perigo iminente, enfrentando as consequências de sua decisão e colocando sua própria posição em risco para garantir a sobrevivência de Davi diante das ameaças de seu pai.' WHERE "id" = '8e464798-0b1f-437d-8b35-922eb3c5960c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido e dos filhos de Noemi em terra estrangeira, a viúva decidiu retornar para sua terra natal e libertou suas noras para que seguissem novos caminhos. Orpá despediu-se e partiu, mas Rute recusou-se a abandonar a sogra. Com uma decisão firme, ela declarou que acompanharia Noemi onde quer que fosse, compartilhando seu destino até a morte. Diante da insistência resoluta de Rute, Noemi aceitou sua companhia e ambas seguiram juntas em direção a Belém.' WHERE "id" = '8e8a434b-0925-4e4b-bb85-a8efd63b9038';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na noite em que Jesus foi preso, Pedro seguiu o mestre até o pátio do sumo sacerdote. Enquanto se aquecia junto ao fogo, três pessoas diferentes questionaram se ele era um dos discípulos de Jesus. Sob a pressão do ambiente e o medo das circunstâncias, Pedro negou conhecer Jesus em todas as três ocasiões. Após a última negativa, o galo cantou conforme o previsto. O apóstolo, cercado por estranhos, falhou em declarar publicamente sua lealdade ao seu senhor naquele momento.' WHERE "id" = '8ef9e9b3-4b89-4f13-bf9b-6209d6b03d8a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta a uma comunidade cristã composta por judeus e gentios que viviam em constante desavença. Devido a profundas diferenças étnicas, culturais e sociais, esses grupos carregavam séculos de desconfiança mútua mesmo compartilhando o mesmo espaço sagrado. Diante desse cenário de tensões, Paulo instruiu os fiéis sobre a necessidade da paz. Ele determinou que cada pessoa deveria assumir a responsabilidade pessoal de buscar a reconciliação, fazendo o máximo ao seu alcance para evitar conflitos.' WHERE "id" = '8fbb5c43-e72e-4062-9a5b-9ed25b8e5655';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O exército de Israel estava paralisado diante do desafio de Golias, um guerreiro de quase três metros que insultava o Deus vivo. Nenhum soldado israelita ousava enfrentá-lo. Davi, um jovem sem experiência militar, apresentou-se ao rei Saul para combater o gigante filisteu. Ele relatou suas experiências anteriores ao proteger o rebanho, quando matou leões e ursos sozinho no campo. Confiante, Davi dispôs-se a lutar contra Golias, visto que este desafiava as fileiras do exército do Deus de Israel.' WHERE "id" = '8fd9f9a2-58eb-46d0-b574-a8ac59dbee97';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jacó, após anos de fuga devido ao engano contra seu irmão Esaú, preparou-se para um reencontro tenso. Ao avistar Esaú aproximando-se com quatrocentos homens, Jacó organizou sua família e curvou-se sete vezes ao solo em sinal de submissão. Para sua surpresa, Esaú não buscou vingança. Em vez de usar armas, ele correu ao encontro de Jacó, abraçou-o e chorou. Após o reencontro, Esaú aceitou os presentes oferecidos, selando um momento histórico de paz e reconciliação entre ambos.' WHERE "id" = '90448640-27c1-4ac1-b999-1199aa3c9dc6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo ao palácio, o jovem Daniel enfrentou um dilema ao receber as iguarias oferecidas pelo rei, que violavam suas convicções. Enquanto os outros jovens aceitavam a comida real, Daniel manteve-se firme em sua decisão de não se contaminar. Ele propôs ao responsável um teste de dez dias com uma dieta de vegetais e água. Ao final do período, Daniel e seus amigos apresentavam uma aparência muito mais saudável e robusta do que todos que consumiam a porção real.' WHERE "id" = '90b96095-1551-41ef-93af-e89f9cea7de7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio da história bíblica, registrou uma verdade fundamental sobre a onisciência divina em seus provérbios. Ele declarou que os olhos do Senhor observam atentamente todos os lugares, vigiando constantemente as atitudes tanto dos homens maus quanto dos bons. Salomão compreendia profundamente a natureza do coração humano e sabia que as escolhas íntimas ocorrem no silêncio. Assim, estabeleceu que a consciência da presença constante de Deus é a base de toda sabedoria.' WHERE "id" = '90c2e967-1297-4e3e-934d-c8f1ccbc0bd0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel recebeu ordens de consumir os alimentos do rei. Decidido a não se contaminar, ele recusou a comida real, preferindo manter sua fidelidade. Com firmeza e respeito, Daniel solicitou ao responsável uma alternativa. Após dez dias alimentando-se apenas de legumes e água, ele e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que ingeriam as iguarias oferecidas pelo monarca babilônico perante toda a corte imperial.' WHERE "id" = '90d4e3ba-cd14-4543-9411-8290edc77729';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia e designado para servir no palácio real. Determinado a não se contaminar com a comida e o vinho oferecidos pelo rei, ele solicitou ao oficial responsável uma alternativa alimentar para si e seus três companheiros. Após dez dias de dieta baseada em legumes e água, o grupo foi comparado aos outros jovens. Eles apresentaram uma aparência mais saudável e robusta, demonstrando que a restrição alimentar escolhida foi superior à dos demais cativos.' WHERE "id" = '91769674-725a-47bd-96a3-22e07cd067a3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Aos dezessete anos, José recebeu sonhos sobre seu futuro, o que despertou a inveja de seus irmãos. Ele foi traído, vendido como escravo e encarcerado injustamente por muitos anos. Apesar das circunstâncias adversas, José permaneceu fiel em meio ao sofrimento prolongado. Quando o Faraó finalmente o convocou para interpretar seus sonhos, José demonstrou total preparo e sabedoria. Reconhecendo sua excelência, o Faraó o nomeou governador de todo o Egito, elevando-o a uma posição de autoridade suprema sobre a terra.' WHERE "id" = '918c4618-fac0-460f-a170-d924bf3dc73d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, um jovem sem experiência militar, apresentou-se diante do rei Saul para enfrentar o gigante Golias. Enquanto todo o exército israelita permanecia paralisado pelo terror, temendo o desafio do filisteu, o rapaz ousou voluntariar-se. Mesmo diante das dúvidas expressas por Saul e pelos próprios irmãos de Davi quanto à sua capacidade, o adolescente não se intimidou. Ele reconheceu o grave perigo diante de si, mas decidiu ignorar o medo paralisante e seguiu em frente para confrontar o inimigo.' WHERE "id" = '91ee266b-833a-44da-80e6-9ce693f69bed';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario decidiu nomear Daniel, um estrangeiro íntegro e competente, para uma posição de destaque no reino da Babilônia. Invejados, outros líderes conspiraram para derrubá-lo, convencendo o rei a assinar um decreto que proibia orações a qualquer deus, exceto ao próprio monarca. Mesmo ciente da lei, Daniel não se intimidou. Ele retornou para sua casa e, como fazia habitualmente, ajoelhou-se diante de sua janela aberta para orar ao Senhor, mantendo sua fidelidade diante de todos os seus inimigos.' WHERE "id" = '92743a78-bf16-41a1-acf5-35f100407386';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava sentado no templo, observando as pessoas depositarem suas ofertas no gazofilácio. Muitos ricos lançavam grandes quantias, ostentando sua generosidade. De repente, uma viúva pobre aproximou-se e depositou duas pequenas moedas, que valiam quase nada. Jesus chamou seus discípulos e afirmou que aquela mulher ofertou mais do que todos os outros juntos. Enquanto os ricos deram apenas o que sobrava de suas riquezas, ela entregou tudo o que possuía para o seu próprio sustento diário.' WHERE "id" = '92c535ba-d7d0-4063-9466-57ec78a924b1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um passarinho filhote sentia muito medo de saltar do seu ninho pela primeira vez. Sua mãe, posicionada por perto, incentivou o pequeno a confiar nela durante aquele momento decisivo. O filhote fechou os olhos, abriu suas pequenas asas e lançou-se corajosamente para fora do ninho. Ao realizar o salto, ele descobriu que era capaz de voar. A mãe pássaro observava tudo enquanto o filhote vencia o temor inicial, conseguindo finalmente planar pelo ar com sucesso e segurança.' WHERE "id" = '92cdeef3-78cd-44d7-8850-f6b444e130df';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi instruiu seu filho Salomão a guardar o coração, pois dele procedem as fontes da vida. Aprendendo que pequenas escolhas funcionam como tijolos na construção do caráter, Salomão compreendeu a importância da sabedoria. Quando teve a oportunidade de pedir algo a Deus, ele escolheu a sabedoria em vez de riqueza ou fama. Assim, ele edificou seu caráter em silêncio, compreendendo que a base sólida e invisível é o que realmente sustenta a grandeza de um homem diante de Deus.' WHERE "id" = '93394b1b-5aa9-405b-b933-3adc7975529a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, firmou uma profunda aliança de amizade com Davi. Como sinal de seu compromisso, o príncipe entregou suas vestes reais, sua espada, seu arco e seu cinto a Davi, reconhecendo-o como futuro rei. Quando Saul planejou matar Davi, Jônatas arriscou sua própria posição e desafiou seu pai para proteger o amigo. Eles renovaram seus votos de fidelidade, comprometendo-se a cuidar um do outro e de suas famílias, mesmo diante da fúria do rei.' WHERE "id" = '9374b217-2bd4-45db-acf4-035729a8947d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após Davi derrotar Golias, surgiu um forte laço de amizade entre ele e o príncipe Jônatas. Apesar de serem sucessores ao trono, Jônatas não nutriu rivalidade, mas demonstrou profundo respeito por Davi. Ele presenteou o amigo com seu próprio manto, armadura, arco e cinto. Quando o rei Saul sentiu inveja e planejou matar Davi, Jônatas arriscou a vida, enfrentou o próprio pai e alertou o amigo sobre o perigo, consolidando uma aliança fiel entre os dois homens.' WHERE "id" = '939c1a4f-f444-43b7-b3f7-4bd58bb8b6d2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, Daniel enfrentou o desafio de consumir os alimentos do rei, proibidos por suas leis. Em vez de ceder à pressão cultural, ele decidiu manter sua integridade e identidade. Daniel solicitou educadamente ao oficial responsável um teste de dez dias, consumindo apenas vegetais e água. Ao final desse período, ele e seus três companheiros hebreus apresentavam uma aparência mais saudável e robusta do que todos os outros jovens que haviam comido da porção real.' WHERE "id" = '93cd9872-0d17-42f2-b515-ca36fce5463a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem prisioneiro levado à Babilônia, recusou comer os alimentos da mesa real por violarem suas convicções. Enquanto os outros jovens aceitaram o banquete, ele pediu respeitosamente ao oficial uma alternativa. Daniel propôs um teste de dez dias consumindo apenas legumes e água. O funcionário aceitou a proposta e supervisionou a dieta. Após o período determinado, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos os jovens que comeram da mesa real.' WHERE "id" = '944fe49b-20ba-4c86-8f50-d2ac53e9b83a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, um jovem sem títulos ou exército, tornou-se um grande aliado de Jônatas, o príncipe herdeiro de Israel. Apesar de posições sociais distintas que naturalmente os colocariam como rivais, ambos estabeleceram um vínculo profundo. Jônatas reconheceu o caráter de Davi e decidiu selar uma aliança de amizade com ele. Esse pacto foi mantido firmemente por ambos, mesmo diante da forte oposição de Saul, o rei de Israel e pai de Jônatas, que se opunha à proximidade entre os dois.' WHERE "id" = '945ae6f4-4523-4e7b-a897-03ef248ccea8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A Sabedoria personificada declara sua presença ativa na condução da história humana. Ela afirma habitar entre governantes, orientando reis e príncipes na decretação da justiça e no governo das nações. Ao descrever sua própria atuação, ela demonstra que o verdadeiro exercício do poder não deriva da sorte ou da força física, mas da prudência. Através de sua influência, líderes alcançam estabilidade e determinam rumos duradouros, pois ela fornece a capacidade intelectual e moral necessária para sustentar grandes impérios.' WHERE "id" = '947f36c4-7bc0-481d-8af6-c2513ab62701';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante do rei Nabucodonosor, Sadraque, Mesaque e Abede-Nego enfrentaram uma escolha definitiva: prostrar-se perante uma estátua de ouro ou serem lançados em uma fornalha ardente. Enquanto a multidão se submetia ao decreto real, os três jovens recusaram curvar-se diante do ídolo. Com firmeza, responderam ao monarca que não precisavam oferecer defesas ou negociações sobre sua decisão. Mesmo sob a ameaça de morte iminente, eles mantiveram sua posição inabalável, recusando terminantemente adorar a imagem estabelecida pelo poderoso soberano da Babilônia.' WHERE "id" = '949d8188-a135-492c-b371-a048b0ffbb1c';
UPDATE "public"."dev_lessons" SET "share_summary" = NULL WHERE "id" = '94cd9980-d0d8-4b15-ba77-ce0542628b1f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo e Silas foram aprisionados em uma cela escura, mantidos sob fortes correntes nos pés. Em vez de lamentarem a situação, ambos decidiram cantar louvores a Deus durante a madrugada, sendo ouvidos pelos outros detentos. Repentinamente, um forte terremoto sacudiu as estruturas daquela prisão. O abalo sísmico provocou a abertura imediata de todas as portas do local e as correntes que prendiam os prisioneiros caíram por terra, permitindo que eles se libertassem daquela situação de cativeiro severo.' WHERE "id" = '9561ea7a-0d1c-4f51-9f04-0a68e0edc8ad';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus estabeleceu Adão e Eva no jardim do Éden, concedendo-lhes permissão para comer de todas as árvores, exceto da árvore do conhecimento do bem e do mal. Obedecendo à persuasão de uma serpente astuta, Eva decidiu comer o fruto proibido e ofereceu também a Adão, que aceitou. Ao consumirem o fruto, ambos desobedeceram à ordem divina direta. Esse ato imediato resultou em uma mudança irreversível na condição humana, marcando o início da queda e do pecado na história bíblica.' WHERE "id" = '95622578-935f-461f-8743-3e3d1e1e47b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança ao pai e partiu para terras distantes, onde desperdiçou todos os seus bens vivendo de forma inconsequente. A miséria e a fome o levaram ao arrependimento, decidindo retornar para casa. Ao avistá-lo ainda longe, o pai correu ao encontro do jovem, abraçou-o com ternura e o perdoou prontamente. O pai ordenou que preparassem uma grande festa para celebrar o retorno do filho, que estava perdido e finalmente foi encontrado com vida.' WHERE "id" = '957a9415-f320-4b83-bd86-6c3f0905e036';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pegou a herança do pai e partiu para uma terra distante, onde gastou todos os seus bens vivendo desordenadamente. Após enfrentar uma severa escassez e fome, ele decidiu retornar para casa a fim de pedir perdão. Enquanto o jovem se aproximava, seu pai o avistou de longe e, movido por compaixão, correu ao seu encontro. Ele abraçou o filho afetuosamente e preparou uma grande festa para celebrar o seu retorno, acolhendo-o de volta ao lar.' WHERE "id" = '95f5e763-1cac-4be9-b43f-01f7b3faaa83';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava sentado em uma encosta cercado por uma multidão de pessoas comuns. Durante o seu ensinamento, ele proferiu uma sentença que estabeleceu uma nova perspectiva sobre as relações humanas. Ele declarou que os pacificadores são bem-aventurados, pois seriam reconhecidos como filhos de Deus. Diferente daqueles que apenas evitam conflitos ou se silenciam por medo, o Mestre enfatizou a necessidade de agir ativamente em situações tensas, demonstrando coragem para intervir e promover a paz em momentos difíceis.' WHERE "id" = '964268fe-df3d-444d-b97c-d041a75c121e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Doze meses após receber um aviso divino em sonho, o rei Nabucodonosor caminhava orgulhoso pelos terraços de seu palácio, vangloriando-se de sua grandiosidade. Repentinamente, uma voz celestial sentenciou seu juízo. O monarca foi afastado do trono e passou sete anos vivendo como um animal, alimentando-se de capim e exposto ao orvalho. Ao término do período determinado, sua razão foi restaurada. Ele ergueu os olhos aos céus, reconheceu a soberania de Deus e foi finalmente reconduzido ao seu reino majestoso.' WHERE "id" = '966c3d60-090e-46e9-be36-fcebbc5921d0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem filhote de leão permanecia sempre próximo ao seu pai, recusando-se a afastar-se da manada. Embora os outros animais interpretassem sua atitude como covardia, ele compreendia a importância daquela proximidade para sua segurança. Ao crescer, o leão tornou-se um animal corajoso e sábio. Ele aprendeu desde cedo a respeitar os limites estabelecidos e a confiar inteiramente na proteção daquele que cuidava dele, garantindo assim sua integridade física e o seu desenvolvimento pleno dentro do bando familiar.' WHERE "id" = '967f0069-0b78-48d9-9f71-c40ab15b81c1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão observou a estrutura de uma cidade desprovida de muros de proteção. Ele percebeu que tal localidade torna-se profundamente vulnerável a ataques inimigos, pois sua defesa física foi abandonada. Comparando essa situação à condição humana, o sábio monarca descreveu um homem que carece de autocontrole. Assim como uma cidade sem muralhas, esse indivíduo permite que suas reações impulsivas destruam sua própria segurança. A fragilidade não advém de forças externas, mas da falta de domínio próprio interior.' WHERE "id" = '96a13569-1443-4fd4-8193-8d5297fafe96';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria extrema. Reconhecendo sua falha, decidiu retornar à casa de seu pai para confessar que havia pecado contra o céu e contra ele. Sem buscar desculpas ou negociações, o jovem caminhou de volta ao seu lar. Ao avistá-lo ainda distante, o pai correu ao seu encontro, acolhendo-o antes mesmo que o filho pudesse concluir suas palavras de arrependimento. Assim, o rapaz foi recebido novamente por seu progenitor.' WHERE "id" = '96cafd4e-e85a-47c3-bcb5-d6ad33c2392a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Saul perseguia Davi, que se escondia em uma caverna. Por um acaso, o rei entrou no mesmo local para descansar, ficando vulnerável diante de Davi e seus homens. Embora pressionado por seus soldados a eliminar o monarca, Davi recusou o pedido. Ele aproximou-se silenciosamente e cortou apenas a borda do manto de Saul. Posteriormente, fora da caverna, Davi exibiu o pedaço de tecido como prova de sua benevolência, declarando que jamais levantaria a mão contra o rei ungido.' WHERE "id" = '974a3a45-de25-4eeb-aaf8-f2242cdb6cb0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, e o jovem pastor Davi formaram uma amizade profunda e inesperada, selada por uma aliança de lealdade. Com o passar do tempo, o rei Saul decidiu eliminar Davi, percebendo nele uma ameaça ao seu trono. Ao descobrir os planos de morte do próprio pai contra seu melhor amigo, Jônatas não permaneceu em silêncio. Ele agiu rapidamente, alertando Davi sobre o perigo iminente, permitindo que o futuro rei escapasse para proteger a sua vida.' WHERE "id" = '981dde79-f03b-40f6-aec3-c1d7aafb9309';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em uma vida de excessos, o filho pródigo enfrentou a miséria e o abandono total. Em meio ao arrependimento, ele decidiu retornar à casa de seu pai, assumindo a responsabilidade por seus erros. Ao avistá-lo de longe, o pai não aguardou explicações ou justificativas, mas correu ao seu encontro com prontidão. Com um abraço acolhedor, ele restaurou a relação, marcando o início de um novo tempo para seu filho arrependido.' WHERE "id" = '98248dc7-a0f4-4d43-8a81-5b3b06fcea01';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo viveu na miséria e, finalmente, caiu em si. Ele decidiu abandonar aquela vida e retornar à casa de seu pai. Enquanto ainda estava longe, ensaiando seu pedido de perdão, o pai o avistou. Movido por um profundo amor, o progenitor não esperou que o filho se aproximasse; ele correu ao seu encontro, abraçou-o e o acolheu de volta, agindo com prontidão diante daquela decisão de retorno do filho.' WHERE "id" = '9838dc82-1553-4fde-b949-fd1e7f8e6f7e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança, o filho pródigo mergulhou na miséria extrema, passando fome. Percebendo que os empregados de seu pai viviam em melhores condições, ele decidiu retornar para casa. Preparou um discurso de confissão e iniciou a longa caminhada de volta, sem saber como seria recebido. Enquanto ainda estava longe, seu pai o avistou e, movido por profunda compaixão, correu ao seu encontro. O pai o abraçou afetuosamente, acolhendo o filho que retornava arrependido para o seu lar.' WHERE "id" = '98529a14-1187-46ea-8442-73a327a7fc9d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao assumir o trono de seu pai Davi, o rei Salomão recebeu de Deus uma oportunidade singular de realizar um pedido. Em vez de solicitar riquezas, poder ou a derrota de seus inimigos, Salomão pediu discernimento para governar seu povo com justiça e distinguir o certo do errado. Impressionado com tamanha sabedoria na escolha, Deus atendeu ao seu pedido e, como recompensa, concedeu-lhe também as riquezas e a glória que ele não havia solicitado anteriormente durante aquele momento.' WHERE "id" = '98949a97-c537-4821-ba69-aca28bc618c8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem pegou sua herança e partiu para terras distantes, onde desperdiçou todos os seus bens vivendo dissolutamente. Após enfrentar miséria extrema e fome, ele decidiu retornar à casa paterna para pedir perdão e oferecer-se como servo. Enquanto ainda estava longe, seu pai avistou-o, correu ao seu encontro e o abraçou com alegria. Mesmo diante da confissão de indignidade do filho, o pai ordenou que preparassem uma grande festa para celebrar o retorno daquele que estava perdido.' WHERE "id" = '98b1df70-48a2-45ce-933e-c2863857c9c7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado como prisioneiro para a Babilônia aos dezesseis anos. Quando o rei ordenou que ele e seus amigos comessem as iguarias da mesa real, Daniel recusou, pois o alimento violava suas convicções. Ele propôs ao oficial responsável um teste de dieta com legumes e água durante dez dias. Após esse período, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta do que todos os outros jovens que consumiram a porção diária do rei.' WHERE "id" = '98b6667e-b9fe-472a-bbae-db4a2468bb29';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após cometer adultério com Bate-Seba e ordenar a morte de Urias, o rei Davi viveu meses escondendo seu pecado. O profeta Natã visitou o monarca e apresentou uma parábola sobre um homem rico que roubou a única ovelha de um pobre. Indignado, Davi condenou tal ato. Natã revelou então que o rei era o próprio transgressor da história. Diante da acusação direta, Davi não negou os fatos e confessou perante Deus que havia pecado contra o Senhor.' WHERE "id" = '98cac8d5-e2c3-495e-8eef-195a4d386ec2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo na Babilônia, enfrentou um dilema ao receber as iguarias e o vinho da mesa real do rei Nabucodonosor. Decidido a não se contaminar, ele propôs ao chefe dos eunucos um período de prova de dez dias, alimentando-se apenas de vegetais e água. Ao final do teste, Daniel e seus três companheiros apresentaram uma aparência mais saudável e robusta do que todos os jovens que consumiram as porções oferecidas pela corte babilônica conforme ordenado anteriormente.' WHERE "id" = '9922ff9c-d6f4-45de-bdfb-36769a3bfb4a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante a reconstrução dos muros de Jerusalém, Neemias enfrentou a oposição de seus inimigos, que tentaram detê-lo repetidamente. Por quatro vezes, eles enviaram convites para uma reunião, buscando atraí-lo para fora da obra. Mantendo o foco em sua missão, Neemias recusou todos os chamados, afirmando que realizava um trabalho importante e não poderia descer. Graças a essa determinação e persistência, o líder concluiu a construção da muralha da cidade em um período total de cinquenta e dois dias.' WHERE "id" = '993181b9-3e2a-4ab7-a136-ec3501368871';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo na Babilônia, recusou consumir as finas iguarias e o vinho oferecidos pelo rei, pois tais alimentos violavam sua lei. Ele propôs ao chefe dos eunucos um período de prova de dez dias, alimentando-se apenas de vegetais e bebendo água. Após esse tempo, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que se alimentavam da porção real. Assim, o encarregado permitiu que mantivessem sua dieta escolhida.' WHERE "id" = '99ce0bac-6f91-46f5-9658-ebc9a39709a7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó era um homem íntegro e justo que vivia em Uz, possuindo grande fortuna e dez filhos. Em um único dia, ele sofreu uma série de calamidades devastadoras: perdeu todo o seu gado, seus bens e todos os seus filhos morreram em um acidente. Diante da tragédia, Jó rasgou suas vestes, rapou a cabeça e prostrou-se em adoração ao Senhor. Apesar da perda absoluta de sua riqueza e de sua família, ele não pecou nem atribuiu culpa a Deus.' WHERE "id" = '99dab588-2f10-41b0-972f-90da128c5f39';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi vendido como escravo por seus irmãos e levado ao Egito, onde enfrentou anos de injusta prisão. Anos depois, ocupando uma posição de grande autoridade no governo egípcio, ele reencontrou seus irmãos que buscavam alimento devido à fome severa. Quando eles se curvaram diante dele temerosos, José não buscou vingança. Em vez disso, garantiu o sustento deles e de suas famílias, declarando que Deus transformou o mal pretendido por eles em um propósito grandioso para salvar muitas vidas.' WHERE "id" = '9a02c584-3fb3-40df-9e2d-f79788ae22f7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, conheceu Davi durante um período de guerra e rivalidade política. Apesar de ser o herdeiro legítimo do trono, Jônatas demonstrou profunda afeição pelo jovem Davi. Em um gesto simbólico de aliança e reconhecimento, ele entregou seu próprio manto, sua espada e seu arco ao amigo. Selando esse compromisso, Jônatas e Davi estabeleceram um pacto de lealdade mútua, firmando uma amizade sincera que transcendia as tensões da corte e as ambições de poder da época.' WHERE "id" = '9a395f1b-ce1b-41e3-af68-4b0a42204d44';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de forma desenfreada, o filho mais novo atingiu a miséria absoluta. Em um momento de lucidez, ele reconheceu sua condição deplorável e decidiu retornar à casa de seu pai, planejando pedir apenas para trabalhar como um de seus empregados. Enquanto ainda estava longe, o pai avistou o rapaz e, movido por profunda compaixão, correu ao seu encontro. Antes que o filho pudesse terminar sua confissão, o pai o abraçou afetuosamente.' WHERE "id" = '9a4109ea-d190-4e9e-b783-31d64b064d7c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario escolheu Daniel para liderar o reino, despertando a inveja de seus rivais. Eles estabeleceram uma lei proibindo orações, visando incriminar Daniel. Apesar da ameaça, ele continuou orando fielmente a Deus em seu quarto. Por causa disso, foi lançado na cova dos leões. O rei, angustiado, visitou a cova na manhã seguinte e encontrou Daniel vivo e ileso. Deus fechou a boca dos animais, preservando a vida de seu servo diante daquela armadilha mortal planejada.' WHERE "id" = '9a5aaa66-a7fb-4b48-a21d-c2c26795e5ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José servia como escravo na casa de Potifar, no Egito. A esposa de seu senhor, constantemente, tentava seduzi-lo, pressionando-o para que se deitasse com ela. Embora estivesse sozinho e sem qualquer supervisão, José resistiu firmemente às investidas da mulher, recusando-se a pecar contra o seu senhor e contra Deus. Em um momento de insistência, ela o agarrou pelo manto, mas ele fugiu rapidamente para fora, deixando a veste em suas mãos e mantendo sua integridade intacta perante o Senhor.' WHERE "id" = '9a5f81ad-a491-45a3-b2b7-2911d344b428';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dois homens subiram ao templo para orar. O fariseu, em pé, orava consigo mesmo, enumerando suas virtudes e vangloriando-se por não ser como os demais homens, especialmente aquele cobrador de impostos. Por outro lado, o publicano, mantendo os olhos baixos e batendo no peito, suplicava apenas pela misericórdia divina. Jesus afirmou que o cobrador de impostos desceu para sua casa justificado por Deus, enquanto o fariseu não recebeu a mesma aprovação após apresentar sua própria justiça diante do Senhor.' WHERE "id" = '9a6daa6e-2ced-41f4-a297-3ca0d60cd564';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, levado como prisioneiro para a Babilônia, recusou-se a comer as iguarias e beber o vinho da mesa do rei para manter sua integridade. Ele propôs ao chefe dos oficiais um teste de dez dias, consumindo apenas vegetais e água. Ao fim desse período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos os jovens que comeram da mesa real. Assim, eles foram mantidos com uma dieta simples, conforme Daniel havia solicitado anteriormente.' WHERE "id" = '9a7799a8-bbc9-455e-a120-f71beebbd3e8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jovem cativo na Babilônia, Daniel foi levado ao palácio do rei Nabucodonosor para receber treinamento real. Ofereceram-lhe a mesma comida e o vinho da mesa do monarca, privilégios cobiçados na corte. Contudo, Daniel decidiu não se contaminar com os alimentos reais, conforme as leis judaicas. Ele propôs um teste ao oficial responsável, alimentando-se apenas de vegetais e água durante dez dias. Ao final, sua aparência mostrava-se mais saudável e robusta que a dos outros jovens alimentados pelo rei.' WHERE "id" = '9ad8497d-49e9-4f35-aa5d-cbf91cfd5b58';
UPDATE "public"."dev_lessons" SET "share_summary" = NULL WHERE "id" = '9bb34b37-2e8a-4c78-a1f3-2b790ebf9dcc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abednego adorassem uma estátua de ouro sob pena de morte em uma fornalha ardente. Os três jovens recusaram a ordem, mantendo sua fidelidade ao Deus de Israel. Em resposta à desobediência, o monarca mandou lançá-los no fogo intenso. Milagrosamente, eles foram preservados pelo Senhor em meio às chamas. Ao saírem do forno, os homens estavam ilesos e sem qualquer sinal de queimadura ou cheiro de fumaça em suas vestes oficiais.' WHERE "id" = '9bb39285-1cf9-4cdc-b7a3-b39e4529a68e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta à comunidade cristã de Corinto, que enfrentava fortes pressões sociais e influências externas. Membros do grupo abandonavam suas convicções originais para adotar comportamentos e crenças populares entre aqueles que os cercavam. Diante dessa crise de identidade, Paulo advertiu severamente sobre a influência negativa das más companhias no caráter humano. Ele explicou que a convivência constante com pessoas contrárias aos princípios cristãos corrompe inevitavelmente os bons costumes, alterando a integridade pessoal dos fiéis coríntios.' WHERE "id" = '9c68d70e-3ff8-49f3-81bb-60e99a024acd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava por uma estrada quando foi atacado por assaltantes, que o deixaram gravemente ferido e abandonado à beira do caminho. Um sacerdote e um levita passaram pelo local, mas ignoraram a vítima e seguiram adiante. Contudo, um samaritano, ao avistar o homem ferido, aproximou-se com compaixão. Ele tratou seus ferimentos com azeite e vinho, colocou-o sobre seu próprio animal e o conduziu a uma estalagem, onde pagou pessoalmente pelos cuidados necessários para a sua total recuperação.' WHERE "id" = '9c92505d-bead-4dc5-8963-06be5623f44b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Moisés pastoreava o rebanho de seu sogro no deserto quando avistou uma sarça que ardia em fogo, mas não se consumia. Ao aproximar-se por curiosidade, ouviu a voz de Deus ordenando que tirasse as sandálias, pois aquele local era terra santa. Imediatamente, Moisés obedeceu ao comando divino e cobriu o seu rosto, tomado pelo temor diante da presença do Senhor. Esse encontro singular marcou o momento em que o profeta reconheceu a grandeza e a santidade do Criador.' WHERE "id" = '9d2f7f4f-07b0-4822-b9da-6a9b83a67768';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma imensa estátua de ouro e ordenou que todos no império se curvassem diante dela sob pena de morte em uma fornalha. Sadraque, Mesaque e Abednego recusaram o decreto e foram confrontados diretamente pelo monarca. Mesmo sob ameaça, os três jovens mantiveram sua posição firme diante do rei. Eles declararam corajosamente que não serviriam ao ídolo, independentemente de Deus os livrar ou não das chamas, permanecendo fiéis à sua própria convicção diante da autoridade real.' WHERE "id" = '9d3d41d6-b19a-4787-b1cd-10017cc1b308';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José, governador do Egito, reencontrou seus irmãos que o haviam vendido como escravo anos antes. Ao reconhecê-los, José afastou os servos e chorou profundamente. Ele se revelou aos irmãos, que ficaram atônitos e temerosos diante de sua autoridade. José afirmou que Deus o enviara àquela terra para preservar vidas durante a fome. Após esclarecer que não buscava vingança, ele abraçou seus irmãos e chorou sobre eles, selando a reconciliação entre toda a família naquele momento histórico.' WHERE "id" = '9d431008-06c1-4d29-a637-8fe135c3bbcb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, utilizou sua sabedoria para selecionar cuidadosamente seus aliados e colaboradores mais próximos. O reino de Salomão era um reflexo direto da qualidade de suas relações estratégicas. Entretanto, ao permitir a entrada de influências imprudentes que contradiziam seus valores fundamentais, o monarca provocou o colapso interno de sua própria estrutura governamental. Conforme registrado nas Escrituras, quem caminha ao lado de sábios torna-se sábio, enquanto o companheiro de insensatos caminha para a total destruição.' WHERE "id" = '9d637486-f827-476c-9809-9e8c5149c5f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Elias, refugiado na montanha, aguardava uma manifestação divina. Um vento impetuoso partiu rochas, mas o Senhor não estava nele. Em seguida, um terremoto violento sacudiu a terra e um fogo intenso surgiu, porém Deus não estava no fogo. Após esses fenômenos grandiosos, seguiu-se um silêncio profundo, interrompido apenas por uma voz mansa e delicada. Foi nessa calmaria singular que Elias finalmente ouviu a presença de Deus, compreendendo que Ele falava através de um sussurro suave.' WHERE "id" = '9ddbea5d-2e12-42dd-b263-39ed6355e46b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dois passarinhos precisavam preparar seus ninhos antes da chegada do inverno rigoroso. Enquanto um dos pássaros preferiu brincar durante todo o dia, ignorando a necessidade de abrigo, o outro buscou com paciência os melhores galhos. Com esforço, ele construiu uma estrutura firme e protegida. Quando o vento frio finalmente atingiu o local, o ninho bem planejado resistiu à força da tempestade, enquanto o descuidado ficou sem abrigo, demonstrando a importância das escolhas feitas no momento certo.' WHERE "id" = '9e0dd2c7-5c71-47da-85a7-38f91a6c8ff3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi conquistou a admiração profunda de Jônatas, filho do rei Saul. Ambos selaram uma aliança de lealdade mútua, expressa quando Jônatas entregou suas vestes militares, espada e arco ao jovem pastor. Com o passar do tempo, a hostilidade de Saul contra Davi cresceu, levando o rei a planejar o assassinato de seu protegido. Percebendo o perigo iminente, Jônatas arriscou sua própria posição real para confrontar o pai e proteger Davi, garantindo que seu amigo sobrevivesse.' WHERE "id" = '9e7b2c7b-7a93-4ff0-bdac-68c1868ea2a8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel enfrentou um desafio quando o rei ordenou que todos consumissem alimentos proibidos pela sua lei. Enquanto seus amigos aceitaram a dieta real sem questionar, Daniel recusou-se firmemente a ingerir tais iguarias. Ele manteve uma postura calma e propôs um teste com uma alimentação diferente. Após o período determinado, Daniel e seus companheiros de fé apresentaram uma saúde superior e uma aparência mais robusta do que todos que obedeceram ao monarca.' WHERE "id" = '9e91eb8a-b26d-44a7-876e-fd9a87c110e7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua herança ao pai e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Após sofrer com a fome e cuidar de porcos, ele decidiu retornar para casa pedindo perdão. Ao vê-lo aproximar-se, o pai correu ao seu encontro, abraçou-o com alegria e ordenou uma grande festa. O jovem, que antes estava perdido, foi recebido de braços abertos, celebrando o seu retorno ao lar paterno com um banquete especial e generoso.' WHERE "id" = '9e9d770a-13a9-41ce-9400-094e5b5b87c5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto estava preso, o apóstolo Paulo escreveu aos filipenses sobre a natureza de Cristo. Ele descreveu que Jesus, sendo Deus, não considerou sua igualdade com o Pai como algo a ser retido por ambição. Pelo contrário, Cristo esvaziou-se a si mesmo, assumindo a forma de servo ao tornar-se semelhante aos seres humanos. Humilhando-se, ele foi obediente até a morte e morte de cruz. Esse relato histórico revela a disposição sacrificial de Jesus em servir e entregar sua própria vida.' WHERE "id" = '9edf04ae-f81d-41d6-9681-7471837cd1e6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se prostrassem diante de uma estátua de ouro, sob pena de morte em uma fornalha ardente. Enquanto a multidão obedecia, Sadraque, Mesaque e Abednego recusaram-se a adorar a imagem. Confrontados pelo monarca, os três jovens mantiveram a postura diante da ameaça. Eles afirmaram que seu Deus tinha poder para livrá-los da morte, mas declararam que, mesmo que isso não acontecesse, jamais se curvariam diante daquela estátua imposta pelo rei babilônico.' WHERE "id" = '9f63b71b-17de-4e6b-9a02-cc42c1eda717';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem prisioneiro levado à Babilônia, recusou consumir a comida da corte real que violava suas convicções. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de vegetais e água. O oficial aceitou a sugestão e observou o grupo. Ao final do período estipulado, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos os outros jovens que aceitaram a dieta oferecida pelo rei babilônico, comprovando sua fidelidade.' WHERE "id" = '9f87e186-f787-44b8-8f51-02b03fc62d08';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo João escreveu uma carta fundamental para uma comunidade cristã profundamente fragmentada pelo sentimento de medo. Esses fiéis viviam em um estado de vigilância constante, aguardando julgamentos, rejeições ou punições severas. Diante desse cenário de insegurança nos lares e nos vínculos interpessoais, João declarou que o amor maduro e perfeito possui a capacidade de expulsar o medo. Segundo ele, o amor substitui a lógica da autopreservação, removendo o temor de ser destruído ao se abrir para o próximo.' WHERE "id" = '9fbdcd89-0814-457c-a4a5-30238143c1e3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel e seus três amigos foram levados cativos para a Babilônia. O rei ofereceu aos jovens hebreus alimentos e vinhos refinados do palácio real. Contudo, Daniel decidiu não se contaminar com as iguarias e solicitou uma alternativa aos responsáveis por sua guarda. Após um período de prova de dez dias alimentando-se apenas de vegetais e água, eles apresentaram uma aparência visivelmente mais saudável e robusta do que todos os outros jovens que consumiram a dieta oferecida pelo rei.' WHERE "id" = '9fc134a1-5e9e-4d65-8279-31894a1c129d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra distante, onde enfrentou a pressão para consumir alimentos proibidos pela sua lei. Enquanto todos ao redor cediam às ordens reais, o jovem manteve sua postura de forma serena e firme, recusando-se a comer o banquete oferecido. Ele propôs um teste com vegetais e água aos responsáveis por sua guarda. Após dez dias, Daniel e seus amigos apresentavam uma aparência melhor e mais saudável do que os outros jovens, provando sua escolha.' WHERE "id" = '9fd83202-784e-4670-a8c5-69387dd90fe8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado como prisioneiro para a Babilônia, onde o rei ofereceu a ele e seus amigos uma dieta composta pelas iguarias e vinhos de sua própria mesa. Determinados a manter sua integridade, Daniel recusou o banquete real e solicitou ao guarda um teste de dez dias, alimentando-se apenas de legumes e água. Ao fim desse período, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta do que todos os jovens que consumiram a dieta do palácio.' WHERE "id" = 'a07f4e93-ebf6-4c93-a27a-588149513e23';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Rute, uma viúva estrangeira, chegou a Belém e começou a recolher restos da colheita nos campos. Boaz, dono daquelas terras, notou a presença dela e questionou seus servos sobre sua identidade. Ao descobrir a dedicação de Rute para com sua sogra Noemi, Boaz demonstrou generosidade. Ele permitiu que ela trabalhasse em seu campo e ordenou que seus trabalhadores deixassem cair espigas de propósito para que ela pudesse recolher, garantindo o sustento necessário para ela e para Noemi.' WHERE "id" = 'a0e1fa16-9a02-4673-83d0-7a549d1da98b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão observou atentamente o cotidiano dos corredores de seu palácio, onde segredos eram frequentemente revelados. Ele percebeu que aqueles que espalhavam fofocas traíam a confiança depositada neles, arruinando reputações e destruindo alianças políticas importantes. Em contrapartida, as pessoas que possuíam um espírito fiel mantinham o silêncio, protegendo informações delicadas. O monarca concluiu que o uso imprudente das palavras causava isolamento, enquanto a discrição e a lealdade eram os pilares essenciais para estabelecer relações humanas sólidas e duradouras.' WHERE "id" = 'a1220fba-61af-46b5-b39a-695016c0fec1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos em Roma, uma comunidade marcada por divisões profundas de etnia e status social. Diante desse cenário de tensões e hierarquias, ele instruiu os membros daquela igreja a darem preferência uns aos outros. Paulo exigiu que cada pessoa tratasse o próximo com honra, superando o orgulho pessoal. A orientação desafiava a estrutura social vigente, incentivando os cristãos a priorizarem o respeito mútuo, mesmo ao lidar com indivíduos considerados difíceis naquela sociedade diversa.' WHERE "id" = 'a12bf69b-305a-466d-bc51-26fefc76efc9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido, Noemi decidiu retornar a Belém e pediu que suas noras voltassem aos seus povos. Orpá obedeceu, mas Rute recusou partir. A moabita reafirmou sua lealdade, escolhendo seguir Noemi e adotar seu povo e seu Deus. Em Belém, Rute trabalhou no campo de Boaz, com quem se casou mais tarde. Essa união integrou Rute à linhagem do rei Davi e, posteriormente, à genealogia de Jesus Cristo, tornando-se uma figura central na história bíblica.' WHERE "id" = 'a16aacde-638f-42c7-806c-cef74174dfb5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante a última ceia, Jesus, plenamente consciente de sua autoridade divina e origem, levantou-se da mesa. Ele despindo-se de suas vestes, cingiu-se com uma toalha, encheu uma bacia com água e começou a lavar os pés de cada um de seus discípulos. Ao concluir o serviço, o Mestre retomou seu lugar. Ele explicou que, sendo o Senhor de todos, realizou aquela tarefa humilde para que os apóstolos seguissem seu exemplo, servindo uns aos outros com o mesmo gesto.' WHERE "id" = 'a2195e78-e189-45a0-b092-73e27726dbb0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e seus homens estavam escondidos em uma caverna quando o rei Saul entrou no mesmo local, sozinho e vulnerável. Os soldados de Davi o incentivaram a matar o rei, mas ele apenas cortou a borda do manto de Saul. Após o monarca sair da caverna, Davi aproximou-se, curvou-se e exibiu o pedaço de tecido como prova de sua benevolência. Saul reconheceu a integridade de Davi e, emocionado, cessou temporariamente a perseguição contra o futuro rei de Israel.' WHERE "id" = 'a24cbff1-e69c-4e81-b79e-d3f612795f0c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O mel é descrito nas Escrituras como um alimento bom, capaz de proporcionar alegria e doçura ao paladar. Contudo, o texto sagrado alerta que o consumo excessivo desse produto causa náuseas e enjoo. A narrativa utiliza o exemplo da abelha, que trabalha diligentemente na coleta do néctar, mas possui a sabedoria natural de saber o momento exato de parar. Assim, a Bíblia ensina que mesmo as coisas boas e agradáveis possuem limites que devem ser respeitados pelo homem.' WHERE "id" = 'a2aaffaa-bafa-4dc5-8204-64f676127ba7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O mel é descrito como um alimento muito saboroso, mas o seu consumo deve ser moderado. A Bíblia utiliza o exemplo de um urso que descobre uma colmeia para ilustrar essa ideia. O animal consome todo o mel disponível de uma única vez, sem qualquer limite. Como resultado direto dessa ingestão exagerada, o urso fica com a barriga tão cheia que perde a capacidade de se mover. Portanto, o excesso transforma algo bom em uma experiência prejudicial ao corpo.' WHERE "id" = 'a30ec068-6b13-4569-9a63-12ae55383f96';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deportado para a Babilônia, o jovem Daniel enfrentou o desafio de consumir os alimentos da mesa do rei, que violavam suas convicções religiosas. Em vez de ceder, ele tomou a firme decisão de não se contaminar. Daniel abordou respeitosamente o oficial responsável, propondo um teste de dez dias à base de legumes e água. Após o período, ele e seus amigos apresentaram uma aparência mais saudável que os demais jovens, comprovando que a fidelidade à lei resultou em preservação.' WHERE "id" = 'a33c7cfa-9db8-40ec-9e28-6dce9fa71756';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel exercia uma autoridade elevada no império persa, despertando a inveja de seus rivais. Eles articularam uma lei proibindo orações a qualquer deus, exceto ao rei, visando incriminar o profeta. Daniel não cedeu à pressão e manteve seu costume de orar abertamente com as janelas abertas. Descoberto, foi lançado na cova dos leões conforme o decreto real. Contudo, Deus enviou um anjo para fechar a boca dos animais, preservando a vida de Daniel completamente ileso naquele julgamento.' WHERE "id" = 'a3b22c94-77b2-4f98-8b77-739087cb32e5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança, o filho pródigo mergulhou na miséria extrema e percebeu a gravidade de suas escolhas. Ele decidiu retornar à casa paterna com um discurso de arrependimento. Ainda longe, foi avistado pelo pai, que correu ao seu encontro e o abraçou, interrompendo sua confissão. Sem aplicar punições, o pai ordenou que seus servos vestissem o rapaz com as melhores roupas e colocassem um anel em seu dedo, celebrando com uma grande festa o retorno do filho.' WHERE "id" = 'a3eb6679-94b0-4c80-9c35-35df5979fb98';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após receber sua herança, o filho mais novo partiu para uma terra distante e desperdiçou todos os seus bens vivendo dissolutamente. Em meio à miséria extrema, cuidando de porcos e passando fome, ele reconheceu seu erro. Decidiu retornar à casa do pai e pedir para trabalhar como um servo. Ao se aproximar, o pai o avistou de longe, correu ao seu encontro, abraçou-o e o beijou, acolhendo o filho que retornava arrependido após ter passado por grandes necessidades.' WHERE "id" = 'a3ff3e77-737d-4829-9cef-7e2caee527b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Samuel visitou a casa de Jessé para ungir o novo rei de Israel. Enquanto os irmãos mais velhos, incluindo Eliabe, se apresentavam, Deus instruiu Samuel a não considerar a aparência física, pois Ele examina o coração. Davi foi então chamado diretamente do campo, onde pastoreava ovelhas. Mesmo sendo o caçula e estando com a aparência simples, ele foi o escolhido e ungido por Samuel para ser o futuro rei, superando todas as expectativas humanas presentes naquele dia.' WHERE "id" = 'a487e39e-1e3b-467c-8b8a-be5aef567b0f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel servia no império babilônico sob constantes ameaças de seus rivais. Quando um decreto real proibiu qualquer forma de oração, ele não cedeu à pressão nem ocultou suas convicções. Pelo contrário, Daniel abriu as janelas de sua casa e continuou orando a Deus três vezes ao dia, conforme seu costume habitual. Devido a essa demonstração pública de fé, ele foi denunciado e lançado na cova dos leões, onde Deus interveio milagrosamente para preservar sua vida diante daqueles animais famintos.' WHERE "id" = 'a4ae0fcb-0c2f-4975-9bf9-9d8df236c3c9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel servia como funcionário confiável no império do rei Dario, destacando-se pela sua integridade inabalável. Invejado por outros oficiais, ele foi alvo de uma conspiração que resultou em um decreto real proibindo orações a outros deuses. Daniel manteve sua fidelidade e continuou orando, sendo lançado na cova dos leões por desobediência. No dia seguinte, o rei retornou ao local e constatou que Daniel estava vivo, pois Deus enviou um anjo para fechar a boca dos famintos animais.' WHERE "id" = 'a4c0faea-3ca0-4e73-854c-446cf5ed16f9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em uma vida desregrada, o filho pródigo enfrentou a miséria e a fome longe de casa. Reconhecendo sua situação, ele decidiu retornar ao seu pai com um coração arrependido e humilde. Enquanto ainda estava longe, o pai avistou o filho e, tomado pela compaixão, correu ao seu encontro. Antes mesmo que o jovem pudesse terminar sua confissão, o pai o abraçou calorosamente, iniciando prontamente o processo de restauração daquele filho arrependido.' WHERE "id" = 'a51eb426-ef1b-486d-a3f5-a3eedcf07371';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Pedro perguntou a Jesus sobre o limite do perdão. Em resposta, Jesus contou sobre um servo que devia uma fortuna impagável ao seu rei. Comovido, o monarca perdoou toda a dívida. Porém, ao encontrar um colega que lhe devia um valor mínimo, esse mesmo servo o lançou na prisão cruelmente. Ao saber do ocorrido, o rei confrontou o servo por sua falta de compaixão, revogou o perdão anteriormente concedido e o entregou aos algozes para sofrer o devido castigo.' WHERE "id" = 'a54034bd-4097-439b-825b-3abcfcebd0ff';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava por uma estrada quando foi atacado por assaltantes, que o deixaram gravemente ferido. Um sacerdote e um levita passaram pelo caminho, mas ignoraram a vítima. Em seguida, um samaritano aproximou-se, sentiu compaixão e cuidou dos ferimentos do desconhecido. Ele colocou o homem sobre seu próprio animal, levou-o a uma hospedaria e pagou pelas despesas necessárias para garantir sua recuperação total. Jesus contou este episódio para ilustrar a atitude prática daquele que socorre o próximo.' WHERE "id" = 'a5a0fbf1-2478-42bb-a5f2-afa12c55ebdb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança, o filho pródigo reconheceu sua miséria e decidiu retornar à casa de seu pai, planejando pedir para ser tratado como um simples empregado. Enquanto ele ainda estava longe, o pai o avistou e, movido por profunda compaixão, correu ao seu encontro. O jovem confessou seu erro, mas o pai, sem dar atenção ao pedido de servidão, ordenou imediatamente que seus servos trouxessem as melhores vestes, um anel e preparassem um banquete para celebrar seu retorno.' WHERE "id" = 'a5fcafdf-e950-47ad-8f94-98d7e4cd3319';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após três anos de seca, o profeta Elias subiu ao monte Carmelo confiante na chuva. Ele se curvou com o rosto entre os joelhos e ordenou que seu servo observasse o horizonte repetidamente. Seis vezes o céu permaneceu vazio, mas na sétima tentativa, uma pequena nuvem surgiu sobre o mar. Elias então anunciou a chegada da tempestade. Antes que a água caísse, o profeta agiu conforme a promessa e, logo em seguida, uma chuva torrencial inundou toda a terra.' WHERE "id" = 'a5fdd6f6-107a-4ed3-8e56-ca1ff7629b69';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pegou sua herança e partiu para uma terra distante, onde gastou todos os seus bens vivendo de forma desenfreada. Após perder tudo e enfrentar uma grave escassez, ele caiu em si e decidiu retornar à casa de seu pai para pedir perdão. Ao vê-lo aproximar-se de longe, o pai correu ao seu encontro, abraçou-o com profunda compaixão e preparou uma grande celebração. O jovem arrependido foi recebido com amor por seu pai, que o aguardava ansiosamente.' WHERE "id" = 'a61f7f7a-5e82-441e-9d90-837231c14343';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho mais novo passou fome cuidando de porcos. Ao perceber sua condição miserável, decidiu retornar à casa do pai para pedir perdão por seus atos. Enquanto caminhava, o pai o avistou de longe e correu ao seu encontro, acolhendo-o com um abraço. Sem repreensões, o pai ordenou aos servos que trouxessem o melhor manto e preparassem um banquete, celebrando o retorno seguro daquele que antes estava perdido e agora vivia.' WHERE "id" = 'a6707e01-37f7-4b9c-b4df-ff34b24dce91';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Após enfrentar uma severa fome, passou a cuidar de porcos e desejou comer a comida dos animais. Arrependido, decidiu retornar à casa de seu pai para trabalhar como empregado. Ao avistá-lo de longe, o pai correu ao seu encontro, abraçou-o e beijou-o, ordenando que preparassem uma grande festa para celebrar o retorno do filho perdido.' WHERE "id" = 'a729c3e1-69d1-4069-940a-8af3d1300204';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Pedro seguiu Jesus até o pátio do sumo sacerdote durante a noite do julgamento. Enquanto aguardava, uma serva questionou se ele era um dos discípulos de Jesus. Diante daquela pergunta e cercado por outras pessoas presentes no local, Pedro negou conhecer o Mestre. Esse episódio repetiu-se por três vezes consecutivas enquanto ele permanecia no pátio, aquecendo-se junto aos servos e oficiais. Assim, o discípulo afirmou repetidamente não ter qualquer ligação com Jesus antes que o galo cantasse.' WHERE "id" = 'a77fe634-5200-407a-87da-fd5907b3de04';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, levado cativo à Babilônia, recusou-se a consumir as iguarias oferecidas pelo rei, mantendo-se fiel aos seus princípios. Ele propôs ao chefe dos eunucos um teste de dez dias, alimentando-se apenas de vegetais e água, juntamente com seus três companheiros. Após o período determinado, o grupo demonstrou estar em melhor condição física e com aparência mais saudável que os demais jovens que aceitaram a dieta real. Assim, Daniel e seus amigos foram mantidos na corte babilônica pelos oficiais.' WHERE "id" = 'a7cdff4f-3222-4b0f-8037-6900f80ab298';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dois pássaros encontraram um galho alto e bonito para pousar. O primeiro pássaro voou rapidamente em direção ao galho sem observar sua condição e acabou caindo porque o objeto estava quebrado. O segundo pássaro agiu de maneira diferente, pois parou para analisar a situação cuidadosamente antes de tomar qualquer decisão. Após observar bem o local, o pássaro pousou no galho com total segurança. A narrativa ilustra a diferença entre a imprudência precipitada e a prudente atenção aos detalhes.' WHERE "id" = 'a810d545-28ac-451a-be34-88ad194b0cb1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, observou profundamente o comportamento humano ao longo de seu reinado. Ele testemunhou reis que foram arruinados por conselheiros lisonjeiros e jovens promissores que acabaram destruídos por más companhias. Baseado nessas experiências reais, o monarca concluiu que o convívio influencia diretamente o caráter. Ele declarou que aquele que caminha com pessoas sábias torna-se sábio, enquanto quem mantém amizade com insensatos inevitavelmente acaba se tornando semelhante a eles em suas atitudes.' WHERE "id" = 'a8313be4-2ebf-4545-b078-e044acaf383d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de sua estátua de ouro sob pena de morte. Enquanto a multidão obedecia prontamente, os jovens judeus Sadraque, Mesaque e Abednego permaneceram firmes em pé. Confrontados pelo monarca, eles declararam que seu Deus era capaz de livrá-los da fornalha ardente. Contudo, afirmaram resolutamente ao rei que, mesmo que o livramento não ocorresse, eles jamais adorariam a imagem erguida, mantendo sua posição diante da pressão imposta por todo aquele reino.' WHERE "id" = 'a841b546-6bd8-4eec-a856-929d305e04cb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao ver Jesus caminhando sobre as águas, Pedro pediu para ir ao seu encontro. Ao receber a permissão, ele desceu do barco e caminhou sobre o mar revolto em direção ao mestre. Por alguns instantes, o milagre aconteceu. No entanto, ao perceber a força do vento e o tamanho das ondas, o medo surgiu e Pedro começou a afundar. Imediatamente, ele clamou por socorro, enquanto a sua atenção se desviava de Jesus para a tempestade que o cercava.' WHERE "id" = 'a859722f-bc0d-4bd5-82e4-eb05ae178178';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi vendido por seus irmãos e viveu longos anos longe de casa. Posteriormente, ele tornou-se uma autoridade poderosa no Egito. Quando seus irmãos chegaram à região em busca de alimento devido à grande fome, encontraram José, que ainda mantinha sua identidade oculta. Ao revelar-se a eles, José não guardou mágoa pelos atos do passado. Em vez disso, ele decidiu perdoá-los prontamente, consolou seus familiares e os acolheu com um abraço, garantindo-lhes sustento e proteção durante aquele período.' WHERE "id" = 'a8af2227-c33c-4c44-b42f-86c337e112f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em Gibeão, Deus apareceu a Salomão durante um sonho e ofereceu conceder qualquer pedido que o jovem rei desejasse. Reconhecendo a enorme responsabilidade de governar o povo de Israel, Salomão não solicitou riquezas, vida longa ou a derrota de seus inimigos. Ele pediu a Deus um coração cheio de sabedoria e discernimento para julgar o povo com justiça. Aprovando a escolha, o Senhor atendeu ao seu pedido, prometendo também dar-lhe glória e riquezas que não solicitara.' WHERE "id" = 'a9ecc89e-5e93-4c43-82b2-e0788441f1fd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante a reconstrução dos muros de Jerusalém, Neemias enfrentou uma grave crise interna. Os judeus mais pobres, oprimidos por fome e impostos, sofriam com a cobrança de juros abusivos e a escravização de seus filhos por credores poderosos. Ao tomar conhecimento da situação, Neemias confrontou os líderes e nobres responsáveis, condenando duramente suas práticas opressoras. Diante da severa repreensão e do constrangimento coletivo, os credores reconheceram o erro, concordaram em restituir as terras, casas e juros cobrados aos necessitados.' WHERE "id" = 'a9f77cff-2e2d-4c9e-b8c8-19a17faf8370';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia e serviu na corte do rei Nabucodonosor. Ele recebeu um novo nome e a oferta de alimentos do palácio, mas decidiu não se contaminar com a comida real. O jovem propôs ao oficial responsável um teste de dez dias, consumindo apenas vegetais e água. Após esse período, Daniel e seus três companheiros apresentaram uma aparência mais saudável e robusta do que todos os outros jovens que se alimentavam com as iguarias do rei.' WHERE "id" = 'aa5d0c1f-097a-4b83-a232-1dd63437f48f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, Daniel recusou as finas iguarias da mesa do rei para não se contaminar. Ele propôs ao chefe dos eunucos um teste de dez dias, consumindo apenas vegetais e água. Após esse período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que todos os jovens que se alimentavam das porções reais. Assim, o supervisor permitiu que eles continuassem com a dieta escolhida, preservando a fidelidade aos seus princípios religiosos.' WHERE "id" = 'aa668727-af64-4abf-81f1-f241c733f176';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar todos os seus bens e enfrentar uma fome severa, o filho pródigo reconheceu sua miséria e decidiu retornar à casa de seu pai. Enquanto ainda estava longe, o pai o avistou e correu ao seu encontro, acolhendo-o com um abraço. O jovem planejava pedir para ser um servo, mas o pai ordenou que trouxessem as melhores vestes, um anel e calçados, celebrando o retorno com um banquete, pois aquele que estava morto havia voltado à vida.' WHERE "id" = 'aa87d4ea-bd23-4bdd-9967-00f626fe0e08';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado a uma terra estrangeira, o jovem Daniel enfrentou a imposição de consumir alimentos que contrariavam suas convicções. Enquanto os outros meninos aceitaram a dieta proposta, Daniel recusou-se firmemente a participar daquela prática, mantendo uma postura calma e determinada. Ele propôs um teste com seus guardas, alimentando-se apenas de legumes e água por dez dias. Ao final do período determinado, Daniel e seus amigos apresentaram uma aparência mais saudável e robusta do que todos os que ingeriram os alimentos reais.' WHERE "id" = 'ab01bdad-85d1-460c-a94d-b57d3210f978';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a assinatura do decreto real que proibia orações, Daniel manteve sua rotina de fé. Ele subiu ao quarto superior de sua casa, abriu as janelas voltadas para Jerusalém e orou a Deus três vezes ao dia, conforme seu costume habitual. Apesar do risco iminente de ser lançado aos leões, ele não cessou sua prática devocional privada. O ato de Daniel foi descoberto por seus inimigos, que denunciaram sua desobediência ao rei, resultando na consequência prevista pela lei estabelecida.' WHERE "id" = 'ab058a66-e8a0-4c00-bf9d-870a0c1ff489';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Saul, possuindo poder, exército e a palavra divina, enfrentou um momento decisivo de obediência. Cedendo à pressão popular, ele realizou um sacrifício que não lhe era permitido fazer. Confrontado pelo profeta Samuel sobre sua desobediência, o rei confessou abertamente que pecou ao temer o povo e seguir sua voz em vez de cumprir o mandamento de Deus. Por causa dessa decisão motivada pelo medo de rejeição, Saul acabou perdendo o seu reino diante da desobediência cometida.' WHERE "id" = 'ab8e1439-0ef5-4e4e-870d-da49ba7e6fb4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noemi, após perder o marido e os dois filhos em uma terra estrangeira, decidiu retornar para sua terra natal. Ela pediu que suas noras, Orpá e Rute, voltassem para as famílias delas em Moabe. Orpá despediu-se e partiu, mas Rute recusou-se a abandonar a sogra. Ela declarou fidelidade incondicional a Noemi e ao seu Deus, insistindo em acompanhá-la até Belém. Diante dessa determinação, Noemi cessou a insistência, e ambas seguiram juntas viagem em direção ao destino incerto.' WHERE "id" = 'ac0f74bd-0f5d-4c13-b91e-0dcd4607446a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugia de Saul quando o rei entrou em uma caverna para descansar sem perceber que Davi e seus homens estavam escondidos ali. Os soldados de Davi o encorajaram a matar o monarca naquele momento de vulnerabilidade. Davi, porém, recusou a oportunidade e cortou apenas a ponta do manto de Saul. Sentindo remorso por seu gesto, ele impediu seus homens de atacarem, declarando que não levantaria a mão contra o ungido do Senhor, poupando assim a vida real.' WHERE "id" = 'ad11ac93-5c52-4688-a647-4b6ec73281dc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua herança, partiu para uma terra distante e gastou todo o dinheiro. Vivendo na miséria e cuidando de porcos, ele decidiu retornar à casa de seu pai para pedir perdão e ser aceito como um servo. Enquanto ainda estava longe, o pai o avistou, correu ao seu encontro e o abraçou calorosamente. O jovem, que havia desperdiçado tudo em uma vida errada, encontrou o acolhimento imediato de seu pai ao decidir voltar para o lar.' WHERE "id" = 'ad2e1018-d3d1-4d98-8fcf-f25a4bcd40c5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugia de Saul, que desejava matá-lo. Ao entrar sozinho em uma caverna para descansar, o rei encontrou Davi e seus homens escondidos no local. Os soldados de Davi o incentivaram a atacar o soberano, alegando ser uma oportunidade divina. Davi aproximou-se silenciosamente, mas cortou apenas a orla do manto de Saul. Em seguida, ele impediu que seus homens ferissem o rei, justificando que não poderia tocar no ungido do Senhor, mesmo diante daquela oportunidade estratégica.' WHERE "id" = 'ad6b0810-18f7-4d67-9328-7728ecdd9d4c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio de sua época, registrou uma instrução fundamental em seus provérbios. Ele utilizou o exemplo do consumo de mel para ilustrar um princípio vital sobre o comportamento humano. O rei advertiu que, ao encontrar mel, deve-se comer apenas o suficiente para a satisfação. Ele explicou que o consumo excessivo, além da medida necessária, transforma algo prazeroso em algo prejudicial, alertando sobre a importância de identificar o momento exato de parar diante das decisões.' WHERE "id" = 'adaf02cc-f739-4e74-a578-5231b55e3ae4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noé recebeu um aviso divino sobre um evento futuro invisível. Embora não houvesse sinais de chuva ou qualquer evidência imediata, ele obedeceu fielmente à instrução recebida. Durante décadas, construiu uma enorme arca enquanto enfrentava o escárnio das pessoas ao seu redor. O trabalho árduo serviu para garantir a sobrevivência de sua família diante do dilúvio iminente. Noé manteve seu compromisso inabalável, concluindo a estrutura conforme as orientações de Deus, protegendo todos os seus familiares durante o julgamento mundial.' WHERE "id" = 'add6954a-7cb8-4bb3-91f2-3bed04332768';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo finalmente caiu em si, reconhecendo sua miserável condição. Ele decidiu retornar à casa do pai, preparando um discurso de arrependimento e humildade. Ao caminhar em direção ao seu lar, o pai, que aguardava ansiosamente, avistou-o de longe. Sem hesitar, o pai correu ao encontro do filho, acolhendo-o com compaixão e restauração imediata. O jovem foi recebido sem acusações, celebrando seu retorno em um gesto de perdão e amor paternal.' WHERE "id" = 'adf4aafc-1c28-40ed-a9a2-6a474481fd19';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, teve a oportunidade de pedir qualquer coisa a Deus. Em vez de escolher riquezas, poder ou a destruição de seus inimigos, ele solicitou entendimento para governar o povo. Reconhecendo sua própria limitação diante da imensidão da tarefa, ele buscou a sabedoria divina. Impressionado com essa escolha humilde e altruísta, Deus atendeu ao seu pedido e, generosamente, acrescentou também glória e riquezas, consolidando a grandeza do monarca diante de todo o mundo conhecido.' WHERE "id" = 'ae6864f6-36d1-4e44-a96a-1f1493c05410';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério e planejou um homicídio, ignorando a lei divina. O profeta Natã visitou o monarca e apresentou uma parábola sobre um homem rico que tomou a única ovelha de um pobre. Indignado com a injustiça relatada, Davi exigiu o devido julgamento para o culpado. Natã então revelou que o rei era o próprio homem da história. Diante da acusação direta, Davi não ofereceu desculpas nem transferiu sua culpa, reconhecendo que havia pecado contra o Senhor.' WHERE "id" = 'ae7886fd-e94a-48fc-ba7c-ac0e693883ce';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, a quem Deus concedeu grande sabedoria, deixou ensinamentos valiosos para seus filhos sobre as escolhas da vida. Ao observar o comportamento humano, ele percebeu como a pressão de pessoas maldosas pode influenciar as decisões dos outros. Por isso, Salomão deixou um conselho direto e firme registrado nas escrituras. Ele orientou que, sempre que pecadores tentarem convencer alguém a praticar ações erradas, a atitude correta e corajosa é recusar o convite e não seguir seus caminhos.' WHERE "id" = 'ae847446-bcd7-4aaf-b0f4-bdd06aead346';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi trabalhava como pastor cuidando de suas ovelhas no campo quando um urso enorme surgiu repentinamente para atacar um dos animais do rebanho. O jovem sentiu medo diante do perigo iminente, mas não fugiu da situação. Ele manteve o foco em Deus, buscando força e proteção para enfrentar a fera. Com coragem, Davi agiu prontamente para defender a ovelha do ataque do predador. O jovem pastor conseguiu proteger seu rebanho, superando o medo inicial através da confiança divina.' WHERE "id" = 'aecb0bc1-e915-4bde-919a-c2cff70eaa2e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de sua estátua de ouro. Sadraque, Mesaque e Abednego, porém, recusaram-se a adorar o ídolo. Confrontados pelo monarca e ameaçados com a fornalha ardente, os três hebreus mantiveram sua posição com firmeza absoluta. Declararam ao rei que seu Deus era capaz de livrá-los do fogo, mas afirmaram categoricamente que, mesmo que Ele decidisse não os salvar, jamais prestariam culto àquela imagem. Eles permaneceram fiéis e não se curvaram diante da ordem real.' WHERE "id" = 'aee47973-0811-4d2a-b74c-09b3ed48f72f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os discípulos Tiago e João solicitaram a Jesus os lugares de maior honra em seu futuro Reino. Diante desse pedido, Jesus instruiu seus seguidores sobre a verdadeira natureza da liderança. Ele afirmou que, entre eles, quem desejasse ser grande deveria tornar-se servo, e quem quisesse ser o primeiro, precisaria ser escravo de todos. Por fim, Jesus declarou que não veio ao mundo para ser servido, mas para servir e oferecer sua própria vida em resgate por muitas pessoas.' WHERE "id" = 'aeec84c6-ef43-4c2b-a9c4-13f7e2bfecf9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José possuía diversos irmãos que sentiam raiva dele. Em um ato de crueldade, eles lançaram José em um buraco profundo e o enviaram para uma terra distante e estranha. Sozinho, triste e amedrontado, José permaneceu fiel aos seus princípios mesmo diante daquela situação difícil. Ele esperou com calma pelo agir divino ao longo do tempo. Posteriormente, Deus transformou o destino de José, permitindo que ele alcançasse uma posição de autoridade e auxiliasse seus próprios irmãos, apesar da maldade anterior.' WHERE "id" = 'af21434d-c9f4-418e-8cad-bc2cf3dafae3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel recebeu ordens de se alimentar com as iguarias da mesa real, o que violava suas convicções religiosas. Em vez de aceitar, ele solicitou ao responsável uma dieta alternativa baseada apenas em vegetais e água. Após dez dias de teste, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que consumiram os alimentos do rei. Assim, eles foram autorizados a manter sua alimentação específica.' WHERE "id" = 'af6372c3-64ce-45fd-8018-a442ae1ff2e1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem recebeu sua herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo de forma desordenada. Após enfrentar uma severa escassez, ele passou a cuidar de porcos e sentiu muita fome. O rapaz decidiu retornar à casa de seu pai para pedir perdão por seus erros. Ao avistá-lo ainda longe, o pai, movido por profunda compaixão, correu ao encontro do filho e o acolheu com um caloroso abraço antes mesmo de qualquer pedido.' WHERE "id" = 'b09a3c58-9469-47c4-9462-11f5cc811ad0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noé vivia em uma região ensolarada onde nunca chovera. Deus ordenou que ele construísse uma arca gigantesca em terra seca, mesmo sem evidências de um dilúvio iminente. Enquanto as pessoas zombavam de sua atitude, Noé obedeceu fielmente, dedicando-se à construção do barco dia após dia. Quando as nuvens finalmente carregaram o céu e a chuva forte inundou a terra, Noé e toda a sua família já estavam seguros dentro da arca, conforme Deus havia prometido anteriormente ao patriarca.' WHERE "id" = 'b11279cc-1566-4dee-811c-dc3fbccaaa23';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, a liderança de Israel foi entregue a Josué, que servira fielmente ao profeta por décadas. Deus orientou Josué a não se desviar da lei, observando e praticando fielmente as instruções recebidas para obter sucesso. Josué não questionou o peso da transição ou os desafios que enfrentaria. Ele obedeceu rigorosamente às ordens divinas, atravessou o rio Jordão com o povo e liderou a conquista de Canaã, cumprindo seu papel na história da nação de Israel.' WHERE "id" = 'b11e84fe-0b65-4366-a92a-37465f16c1ed';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para a Babilônia, onde o rei ofereceu aos jovens hebreus as iguarias e o vinho de sua mesa. Decidido a não se contaminar com tais alimentos, Daniel solicitou ao chefe dos eunucos um período de prova de dez dias, consumindo apenas vegetais e água. Ao final do prazo, Daniel e seus três companheiros apresentaram uma aparência mais saudável e robusta que os demais jovens. Assim, o funcionário real passou a servir-lhes apenas alimentos permitidos.' WHERE "id" = 'b1512a8e-27df-4cb1-900f-34af5530ad47';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar Golias, Davi foi levado à presença do rei Saul. Naquele momento, conheceu Jônatas, filho do monarca. Diferente do que se esperava, os dois estabeleceram uma forte aliança de amizade. Jônatas desenvolveu um profundo afeto por Davi, amando-o como a si mesmo. Como sinal dessa união, o príncipe retirou seu manto, sua espada, seu arco e seu cinturão, entregando esses objetos preciosos ao jovem pastor. Esse gesto selou publicamente o compromisso de lealdade entre os dois novos amigos.' WHERE "id" = 'b15938c5-8d3e-456d-ade3-a26fddcdb0cc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, em um momento de profundo abandono e angústia, compôs o Salmo 22. Em vez de se render ao desespero, ele escolheu declarar que Deus habita entre os louvores do seu povo. Enquanto enfrentava circunstâncias adversas, Davi recordou que seus antepassados depositaram confiança no Senhor, louvaram-No e não foram envergonhados. Essa decisão deliberada de louvar, mesmo em meio à dor, marcou a trajetória do salmista, consolidando seu destino e o transformando de um simples pastor em um rei eterno.' WHERE "id" = 'b18db44f-28cf-4d7c-9b2b-95e1816d6acd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança em terras distantes, o filho pródigo enfrentou a escassez e passou a cuidar de porcos. Ao reconhecer sua miserável condição, decidiu retornar à casa do pai. Durante o caminho, ele planejou confessar que havia pecado contra o céu e contra o pai. Antes mesmo de concluir sua confissão, o pai avistou o jovem ao longe, correu ao seu encontro e o abraçou afetuosamente, acolhendo-o de volta como filho em meio à sua profunda humildade.' WHERE "id" = 'b18f83f3-5d3d-48d2-9313-7e9a60be34a5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após receber sua herança, o filho mais novo partiu para uma terra distante e desperdiçou todos os seus bens vivendo de forma desregrada. Diante de uma grande escassez e fome, o rapaz reconheceu o erro cometido, abandonou seu orgulho e decidiu retornar à casa de seu pai para pedir perdão. Ao avistá-lo ainda longe, o pai, tomado de compaixão, correu ao encontro do filho, acolhendo-o com um abraço antes mesmo que qualquer justificativa pudesse ser plenamente apresentada.' WHERE "id" = 'b1cfd858-7e50-4a54-9088-9c4507180f09';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo encontrou-se em extrema pobreza, alimentando porcos e passando fome. Reconhecendo seu erro, ele decidiu abandonar aquela vida e retornar à casa de seu pai. Ao caminhar de volta, ainda distante, o pai o avistou. Movido por profunda compaixão, o pai correu ao encontro do rapaz, abraçando-o antes mesmo que ele terminasse de falar. Assim, o filho foi recebido com acolhimento imediato, marcando o início de sua restauração completa.' WHERE "id" = 'b1d5b571-3cf4-490a-a047-5a691549db1e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus reuniu seus discípulos para ensinar que a verdadeira grandeza reside no serviço ao próximo, e não na autoridade. Ele próprio, sendo o mais importante, exemplificou essa postura servidora ao lavar os pés de seus amigos, preparar refeições, cuidar dos enfermos e acolher as crianças. Em vez de exigir qualquer tipo de assistência, Jesus escolheu servir primeiro. Com mãos generosas e um coração plenamente disponível, ele estabeleceu um novo padrão de conduta que marcou profundamente toda a humanidade.' WHERE "id" = 'b1e309a0-a2f1-4090-a9ec-00630fc3ea1a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Rute, uma estrangeira que abandonou sua terra e família para acompanhar sua sogra viúva, chegou ao campo de Boaz para colher espigas. Boaz reconheceu o sacrifício e o caráter daquela mulher diante de suas circunstâncias. Em vez de apenas permitir a colheita, ele ordenou deliberadamente que seus servos deixassem cair espigas extras para favorecê-la. Esse encontro no campo, marcado pela bondade consciente de Boaz, uniu a história dos dois e os inseriu na linhagem do Messias prometido.' WHERE "id" = 'b1e54fe0-4ba1-48e6-a96c-5fa502d414b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em uma vida desenfreada, o filho pródigo enfrentou a fome e a total indignidade. Ao cair em si, reconheceu o erro cometido, abandonou as desculpas e decidiu retornar à casa de seu pai como um servo. Levantou-se imediatamente e iniciou a longa caminhada de volta. O pai, avistando-o ainda de longe, correu ao encontro do rapaz, abraçou-o e o recebeu novamente em sua família com grande compaixão e amor fraternal.' WHERE "id" = 'b20cefe5-8be6-4e1d-86fc-4c3036686db9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em uma vida desregrada, o filho mais novo acabou sozinho em um país estrangeiro, passando fome enquanto cuidava de porcos. Em meio à miséria, o jovem reconheceu sua situação lamentável e decidiu retornar à casa de seu pai. Ao iniciar o caminho de volta e ainda estar longe, foi avistado pelo pai, que correu ao seu encontro com prontidão. Assim, o filho retornou ao seu lar, sendo acolhido por seu pai amoroso.' WHERE "id" = 'b27d5dd1-1369-4a3a-81bb-3f47653f5058';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra distante, onde o rei ordenou que ele consumisse as iguarias e vinhos da mesa real. Decidido a não se contaminar com tais alimentos, ele pediu ao oficial responsável que permitisse uma dieta de legumes e água por dez dias. Após esse período de teste, Daniel e seus três amigos apresentavam uma aparência física muito mais saudável e robusta que os outros jovens, sendo então mantidos sob essa dieta especial pelo encarregado.' WHERE "id" = 'b28af412-16e9-4354-aef0-c518e9673a4c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio que já viveu, registrou ensinamentos fundamentais sobre a natureza das palavras em Provérbios. Ele declarou que a verdade permanece firme para sempre, enquanto o testemunho falso dura apenas um breve momento. Salomão ensinou que o que alguém fala revela diretamente o conteúdo do seu próprio coração, seja em público ou no segredo. Assim, cada palavra proferida possui o poder real de construir ou de destruir algo na vida das pessoas.' WHERE "id" = 'b39c9dea-6db0-4310-8231-f79d64bf914a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Neemias liderava a reconstrução dos muros de Jerusalém, seus inimigos tentaram interromper o trabalho enviando repetidos convites para reuniões enganosas. Eles espalharam rumores falsos e proferiram ameaças veladas com o objetivo de distrair o líder. Contudo, Neemias recusou todos os quatro convites, afirmando firmemente que realizava uma grande obra e não poderia descer. Ele não se deixou levar por discussões ou distrações, mantendo o foco total na tarefa designada até que a reconstrução das muralhas fosse finalmente concluída.' WHERE "id" = 'b3ae5136-f88b-4e96-8d87-96ba141516ed';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias liderava a reconstrução dos muros de Jerusalém quando seus inimigos, Sambalate e Gesém, tentaram interromper a obra. Eles enviaram repetidas mensagens convidando Neemias para uma reunião, visando armar uma emboscada e difamar sua reputação. Percebendo a estratégia maliciosa para detê-lo, Neemias manteve sua posição no topo da muralha e recusou os convites. Ele respondeu firmemente que realizava um trabalho importante e não desceria. Apesar das ameaças e das mentiras constantes, ele prosseguiu com o serviço determinado.' WHERE "id" = 'b3d909b7-d466-4c46-a53f-6cd883f4f86b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a missão de liderar o povo de Israel rumo à terra prometida. Diante do desafio de enfrentar nações mais fortes, o novo líder recebeu uma orientação direta de Deus. O Criador ordenou que Josué fosse corajoso, agisse conforme a lei e permanecesse fiel aos seus mandamentos, sem desviar-se. Com a garantia da presença divina em todos os seus caminhos, Josué preparou-se para conduzir a nação e conquistar o território designado pelo Senhor.' WHERE "id" = 'b3ffb9f8-e486-451d-bc64-c01a1de5e302';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança vivendo de forma desenfreada, o filho mais novo caiu em si enquanto trabalhava cuidando de porcos. Em um momento de clareza, ele decidiu retornar à casa de seu pai, planejando pedir perdão e ser aceito apenas como um empregado. O jovem levantou-se e iniciou sua jornada de volta. Ao vê-lo ainda de longe, o pai, tomado por profunda compaixão, correu ao seu encontro e o abraçou, antecipando o pedido de arrependimento.' WHERE "id" = 'b448a5e8-9659-4116-b72d-20272dc0876c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas isoladamente no campo. Jônatas, filho do rei, decidiu ser seu companheiro, apesar das pressões externas. Ele protegeu Davi de maus-tratos, ofereceu apoio durante seus momentos de medo e compartilhou seus pertences pessoais. Essa aliança permitiu que ambos cultivassem uma confiança mútua profunda. Ao longo do tempo, o vínculo estabelecido entre os dois tornou Davi e Jônatas indivíduos muito mais corajosos e fortalecidos do que eram quando estavam sozinhos.' WHERE "id" = 'b44eb68e-7af9-49c4-a2f7-35b70f035931';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel foi pressionado a consumir as iguarias e o vinho servidos na mesa do rei. Decidido a não se contaminar com a dieta real, ele solicitou ao chefe dos eunucos que lhe permitisse comer apenas legumes e beber água durante dez dias. Após esse período de prova, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens, sendo assim autorizados a manter sua dieta específica permanentemente.' WHERE "id" = 'b4897e3e-c72e-4108-8778-e33c59d4491b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No Monte Carmelo, Elias desafiou quatrocentos e cinquenta profetas de Baal. Após o fracasso deles em obter fogo divino, Elias reconstruiu um altar, colocou o sacrifício e encharcou tudo com água três vezes. O profeta realizou uma breve oração ao Senhor. Imediatamente, o fogo desceu do céu, consumindo o holocausto, a lenha, as pedras e a água do rego. Diante do sinal sobrenatural, todo o povo prostrou-se com o rosto em terra e reconheceu que o Senhor é Deus.' WHERE "id" = 'b4b5a064-c810-4410-b29f-e6f3ed2c761b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava as pessoas depositarem ofertas no templo. Enquanto muitos ricos contribuíam com grandes quantias, uma viúva pobre aproximou-se e ofertou apenas duas pequenas moedas. Jesus atentou para o gesto daquela mulher e explicou aos seus discípulos que ela havia ofertado mais do que todos os outros. Enquanto os ricos doaram apenas o que lhes sobrava de suas riquezas, a viúva entregou tudo o que possuía para o seu próprio sustento, demonstrando total entrega em sua oferta humilde.' WHERE "id" = 'b4bcb47b-981d-4622-9840-b884af0da10a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Jesus estava com seus discípulos, eles começaram a discutir sobre quem seria o maior entre eles. Em resposta, Jesus colocou uma criança no meio do grupo para ensinar uma nova perspectiva sobre a grandeza. Ele explicou que, para alguém ser considerado grande, deveria aprender a servir aos outros. Jesus afirmou categoricamente que não veio ao mundo para ser servido por ninguém, mas para servir e dar a sua própria vida como resgate em favor de muitas pessoas.' WHERE "id" = 'b4f98091-2c1f-46d1-9811-475af879c59d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e ordenou a morte de Urias, seu marido. O profeta Natã visitou o rei e contou a parábola de um homem rico que roubou a única ovelha de um pobre. Indignado, Davi exigiu justiça contra o infrator. Natã revelou prontamente que Davi era o homem descrito na história. Diante da acusação direta e incontestável do profeta, o rei reconheceu seu pecado grave contra o Senhor, assumindo integralmente a responsabilidade por seus atos.' WHERE "id" = 'b52e2385-6550-4db5-95e4-96c706f62a38';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante o Sermão do Monte, Jesus dirigiu-se a uma grande multidão que enfrentava intensas tensões políticas, religiosas e domésticas. Diante desses conflitos, ele não elogiou aqueles que se esquivavam dos problemas, mas proclamou bem-aventurados os pacificadores. O Mestre apresentou a pacificação não como uma passividade ou covardia, mas como uma intervenção deliberada, corajosa e autoritária no meio do caos social. Jesus estabeleceu, portanto, que a verdadeira paz exige presença intencional e ação direta onde quer que a discórdia exista.' WHERE "id" = 'b5969176-d98e-4a4a-8491-043072f78958';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O gigante filisteu Golias desafiava diariamente o exército de Israel, causando pânico e paralisia entre os soldados experientes. Enquanto todos recuavam amedrontados diante da ameaça, o jovem pastor Davi apresentou-se perante o rei Saul. Ele relatou suas experiências anteriores ao proteger o rebanho, afirmando ter enfrentado leões e ursos sozinho no campo. Com essa convicção, Davi propôs combater o guerreiro gigante, recusando-se a aceitar o medo que dominava os combatentes israelitas diante daquele desafio militar imponente.' WHERE "id" = 'b5dcc534-b88a-493c-abc4-c154adb24212';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A borboleta inicia sua vida como uma pequena lagarta e se isola dentro de um casulo apertado. Enquanto permanece confinada, ocorre um processo interno de transformação silenciosa e necessária. Se o casulo for aberto prematuramente, a borboleta não desenvolverá a capacidade de voar, pois o período de espera é indispensável para o fortalecimento de suas asas. Deus estabeleceu esse ciclo natural para garantir que a transformação ocorra plenamente, permitindo que o inseto surja pronto para a sua existência.' WHERE "id" = 'b6954f15-f385-4efb-851a-e3d0c81a3737';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao saber que os filisteus atacavam a cidade de Queila, Davi buscou a orientação de Deus antes de tomar qualquer medida militar. Apesar da hesitação e do medo demonstrados por seus soldados, Davi não agiu por impulso. Ele consultou o Senhor novamente, recebendo uma confirmação clara sobre o ataque. Confiante na resposta divina, Davi mobilizou seus homens para enfrentar os filisteus. Obedecendo à direção recebida, ele obteve uma vitória decisiva, fundamentada na orientação divina obtida por meio da oração.' WHERE "id" = 'b764a190-bd92-4b9f-bf27-208ba795d028';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão observou a natureza dos materiais e dos homens por meio de uma comparação direta. Ele notou que, assim como o fogo do crisol coloca à prova a pureza da prata e o forno revela a verdadeira qualidade do ouro, o louvor serve como um teste decisivo para o caráter de alguém. Diante da aprovação pública, o que reside no interior do indivíduo é exposto, revelando se a exaltação externa corrompe sua integridade ou revela sua essência.' WHERE "id" = 'b77a0e0c-a89b-43ec-9d40-7e3efec89a74';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança ao pai e partiu para uma terra distante, onde gastou todos os seus bens vivendo de forma inconsequente. Após perder tudo, enfrentou extrema necessidade e precisou trabalhar cuidando de porcos. Ao reconhecer sua miséria, decidiu retornar à casa paterna para pedir perdão. Antes que ele chegasse, seu pai correu ao seu encontro, abraçou-o com profunda compaixão e ofereceu uma grande festa para celebrar o retorno daquele que estava perdido.' WHERE "id" = 'b79cb7ba-d6d0-484c-85e6-702f187a516d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho recebeu sua parte da herança, partiu para uma terra distante e desperdiçou todos os seus bens vivendo perdulariamente. Após enfrentar grave escassez e fome, decidiu retornar à casa de seu pai para pedir perdão por seus erros. Enquanto ainda estava longe, seu pai avistou-o, correu ao seu encontro e o abraçou afetuosamente. Mesmo após o filho reconhecer que não era digno, o pai celebrou o seu retorno com uma grande festa, acolhendo-o novamente em seu lar.' WHERE "id" = 'b818602e-3f89-4ffe-8e45-c073ea7af341';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens, o filho mais novo vivia na miséria, cuidando de porcos e passando fome. Ele refletiu sobre sua situação, reconhecendo que os servos de seu pai viviam com mais dignidade. Decidido, o jovem levantou-se e iniciou sua jornada de retorno para casa. Enquanto ainda estava distante, seu pai o avistou e correu ao seu encontro. O filho confessou seu erro, sendo prontamente recebido e restaurado pelo pai, que o acolheu com grande alegria.' WHERE "id" = 'b85e91cd-fefd-4999-9761-3281f42509cc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda sua herança em excessos, o filho pródigo enfrentou extrema miséria cuidando de porcos. Reconhecendo seu erro contra o pai e contra Deus, decidiu retornar para casa pedindo apenas uma oportunidade como servo. Ao iniciar o caminho de volta, foi avistado pelo pai, que correu ao seu encontro. Antes que pudesse articular qualquer desculpa, o filho foi recebido com um abraço acolhedor. O pai o aceitou prontamente, restaurando sua dignidade sem qualquer interrogatório ou humilhação pública.' WHERE "id" = 'b8985d60-7900-4a8d-bd48-588df9cc8533';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O jovem Samuel vivia no templo auxiliando o sacerdote Eli. Certa noite, ao dormir, Samuel ouviu alguém chamar seu nome por três vezes e prontamente correu até Eli, que negou ter chamado. Compreendendo a situação, o sacerdote instruiu o menino a responder ao Senhor caso ouvisse a voz novamente. Samuel voltou ao seu lugar, esperou em silêncio e atendeu ao chamado divino com a frase sugerida. Naquele momento, Deus começou a falar diretamente com o jovem servo dedicado.' WHERE "id" = 'b89e76d9-cd02-4f4d-9e83-b263150c7aa3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué recebeu a difícil missão de conduzir o povo de Israel rumo a uma terra desconhecida. Diante do desafio de atravessar rios e enfrentar cidades fortificadas, o líder sentiu medo. Deus, então, instruiu Josué a não se desesperar, prometendo acompanhá-lo em todos os seus passos. Confiando na presença divina, Josué obedeceu prontamente e iniciou a jornada. Sua decisão de avançar, mesmo diante de circunstâncias aterrorizantes, consolidou sua trajetória como um homem corajoso e fiel.' WHERE "id" = 'b8dd0ccf-bb1a-4232-a9cc-199f8fe3db39';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi perguntou se ainda restava algum descendente da casa de Saul para receber sua bondade. Foi apresentado Mefibosete, neto de Saul, que vivia escondido e possuía deficiência física nos dois pés. O rei ordenou que trouxessem o rapaz ao palácio, restaurou todas as propriedades que pertenciam a seu avô e estabeleceu que ele comesse permanentemente à mesa real. Assim, Mefibosete passou a residir em Jerusalém, sendo tratado por Davi como um dos filhos do próprio rei.' WHERE "id" = 'b8de8d5a-7a86-4861-b6aa-ab4173c6156f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Ao caminhar rumo a Jerusalém, Jesus encontrou dez leprosos que clamaram por misericórdia. O Mestre ordenou que se mostrassem aos sacerdotes e, enquanto seguiam o caminho, foram milagrosamente curados. Apenas um deles, um samaritano, retornou glorificando a Deus em alta voz e prostrou-se aos pés de Jesus para agradecer. Jesus então questionou o paradeiro dos outros nove, notando que somente aquele estrangeiro voltara para dar glória a Deus. O Senhor declarou que a fé do homem o salvou.' WHERE "id" = 'b90eaa18-ab94-4d7b-8731-363e78acfb25';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario nomeou Daniel, um jovem estrangeiro, como um dos governadores do império devido à sua notável integridade. Invejados, outros oficiais convenceram o rei a proibir orações dirigidas a qualquer deus exceto ele. Daniel, ciente do decreto, continuou orando abertamente três vezes ao dia. Por desobediência, ele foi lançado em uma cova com leões famintos. Na manhã seguinte, o monarca encontrou Daniel ileso, comprovando que Deus o protegeu milagrosamente contra a trama mortal preparada por seus rivais invejosos.' WHERE "id" = 'b98f4b2f-f5fb-4eea-9b5c-3878dc0d56ac';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e ordenou a morte de Urias para ocultar seu erro. O profeta Natã visitou o rei e narrou a história de um homem rico que roubou a única ovelha de um pobre. Indignado, Davi condenou o opressor sem perceber que era o alvo da parábola. Confrontado diretamente por Natã, o rei reconheceu sua culpa diante de Deus, confessando abertamente que havia pecado contra o Senhor, encerrando assim o seu longo período de silêncio.' WHERE "id" = 'b9a08d2c-18a8-4839-8e4a-f6ff1663be71';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O jovem Samuel vivia no templo auxiliando o sacerdote Eli. Certa noite, ao dormir, ouviu alguém chamar seu nome e correu até Eli, que negou tê-lo chamado. Após o evento repetir-se por três vezes, Eli compreendeu que Deus estava chamando o menino. Seguindo a orientação do sacerdote, Samuel respondeu ao chamado divino declarando que seu servo estava ouvindo. A partir daquela noite, Deus falou com Samuel, que cresceu e se tornou um dos grandes profetas de Israel.' WHERE "id" = 'b9cef692-ee4e-4d25-97f1-f279032b5f51';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, levado cativo à Babilônia, enfrentou um dilema ao receber as iguarias e o vinho da mesa real. Decidido a não se contaminar, ele solicitou respeitosamente ao chefe dos eunucos uma dieta alternativa baseada apenas em vegetais e água. O pedido foi atendido para um teste de dez dias. Ao final desse período, Daniel e seus três amigos apresentavam uma aparência mais saudável e robusta do que todos os jovens que consumiam a comida servida pelo próprio rei babilônico.' WHERE "id" = 'b9e7363a-9131-4d47-be37-06deb6db15c1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus apareceu ao rei Salomão e ofereceu realizar qualquer pedido que ele desejasse. Em vez de escolher riquezas, brinquedos ou poder, o monarca solicitou apenas sabedoria para governar o povo com justiça. A atitude humilde de Salomão agradou profundamente ao Senhor, que não apenas concedeu o discernimento pedido, mas também acrescentou abundantes bênçãos materiais e honra. Assim, Salomão tornou-se o homem mais sábio da história, demonstrando que priorizar o necessário é o caminho para uma vida próspera e equilibrada.' WHERE "id" = 'ba1995a9-9f85-4d80-ba82-57021c423381';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma estátua de ouro. Sadraque, Mesaque e Abede-Nego recusaram a ordem, mantendo-se firmes em sua fé. Enfurecido, o monarca ameaçou lançá-los em uma fornalha ardente caso não obedecessem. Os três amigos declararam que Deus os livraria, mas, caso contrário, não adorariam outros deuses. Eles foram lançados ao fogo, porém, permaneceram ilesos, sem qualquer dano, saindo da fornalha diante de todos, provando a proteção divina sobre suas vidas diante do rei.' WHERE "id" = 'ba2b9209-dd8a-4bb8-80b5-d024f6b3f106';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo caiu em si e decidiu retornar à casa de seu pai. Abandonando desculpas, ele levantou-se e iniciou a caminhada de volta. Ao avistá-lo à distância, o pai correu ao seu encontro com compaixão. Antes que o pai falasse, o filho confessou ter pecado contra o céu e contra ele, declarando-se indigno de ser chamado seu filho. Ele assumiu sua culpa perante o pai sem qualquer tipo de negociação.' WHERE "id" = 'bac3df14-ccd6-436e-9573-d4bf84738c2f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar sua herança, o filho pródigo passou fome enquanto cuidava de porcos. Em um momento de lucidez, reconheceu seus erros e decidiu retornar à casa de seu pai. Ele ensaiou um pedido de perdão, levantou-se do chiqueiro e iniciou a longa caminhada de volta. Enquanto ainda estava longe, seu pai o avistou. Movido por profunda compaixão, o pai correu ao encontro do filho, acolhendo-o antes mesmo que ele pudesse terminar de proferir sua humilde confissão planejada.' WHERE "id" = 'bb0ba133-44f9-4d8c-bbeb-a7efd3b4c20a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas nos campos durante a escuridão da noite. Frequentemente, ele ouvia ruídos estranhos e sentia medo, temendo estar completamente sozinho no campo. Em vez de fugir, Davi escolheu confiar inteiramente em Deus nos momentos de perigo. O jovem pastor cresceu e registrou em seus salmos a decisão de depositar sua confiança no Senhor sempre que o medo surgia. Assim, Davi enfrentou seus temores, mantendo sua fé firme em Deus.' WHERE "id" = 'bb103001-78b3-4543-9f5d-5fd493a0a40d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o monarca mais sábio de sua época, herdou um trono e a responsabilidade de forjar seu próprio caráter por meio de suas escolhas. Ao observar a trajetória de diversos reis, ele percebeu que muitos governantes acumulavam imensas fortunas, porém perdiam a confiança de seus súditos. Em contrapartida, notou homens comuns que possuíam uma reputação de integridade tão sólida que suas simples palavras superavam qualquer contrato formal. Assim, Salomão concluiu que um bom nome supera todas as riquezas.' WHERE "id" = 'bb493320-23b9-4efa-b974-31a50830c49c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho solicitou sua parte da herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo dissolutamente. Diante da miséria e da fome extrema, ele decidiu retornar à casa paterna para pedir perdão e ser tratado como um empregado. Enquanto ainda estava longe, o pai o avistou, correu ao seu encontro, abraçou-o calorosamente e o beijou. O pai providenciou novas vestes para o filho e organizou uma grande festa para celebrar seu retorno seguro.' WHERE "id" = 'bbd549b4-187b-431a-aa74-ff72d27a083c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após criar o jardim mais belo de todos, Deus estabeleceu uma missão específica para Adão. O Criador não deixou o local abandonado, mas entregou a responsabilidade de cultivá-lo ao primeiro homem. Adão precisava regar as diversas flores, observar o crescimento das árvores e nomear cada animal presente no espaço. Essa tarefa diária era indispensável para a manutenção do lugar. Assim, cada planta e criatura dependia diretamente da dedicação de Adão, que cumpria seu papel cuidando pessoalmente do jardim.' WHERE "id" = 'bc160a24-9b6b-4bcb-aae7-7c6ec91c07db';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado à Babilônia como escravo, o jovem Daniel recusou comer as finas iguarias da mesa do rei, pois violavam suas convicções religiosas. Com respeito, ele propôs ao oficial responsável um período de teste de dez dias, consumindo apenas vegetais e água. Após esse tempo, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens que se alimentaram das porções reais. Assim, o grupo permaneceu fiel aos seus princípios, mantendo a dieta específica planejada.' WHERE "id" = 'bc3146a2-8501-4de4-bd2c-c638cb9b2a46';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, possuidor de vasta sabedoria, imensa influência e incontável riqueza, refletiu profundamente sobre a essência da existência humana no ápice de seu reinado. Após acumular bens materiais e ouro em abundância, ele chegou à conclusão histórica de que a reputação de um homem supera qualquer fortuna acumulada em vida. Salomão registrou que o bom nome é a herança mais valiosa de uma pessoa, pois, após a morte, o que permanece é o caráter e não os bens.' WHERE "id" = 'bc825341-5128-4ace-9b65-2c81a6e60fbc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo desordenadamente. Após enfrentar fome e miséria, ele reconheceu seu erro e decidiu retornar à casa paterna para pedir perdão. Ao vê-lo aproximar-se de longe, o pai, tomado por profunda compaixão, correu ao seu encontro. Ele o abraçou e o acolheu com alegria, sem esperar justificativas, restaurando sua dignidade e recebendo-o de volta como um filho amado e perdoado.' WHERE "id" = 'bcde797f-fb60-42ec-84a7-2059ff102ed9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar toda a sua herança vivendo de forma desregrada, o filho mais novo chegou à miséria absoluta, alimentando-se com a comida dos porcos. Em meio à fome, ele reconheceu seus erros e decidiu retornar à casa do pai. Levantou-se, ensaiou um pedido de perdão e iniciou o caminho de volta. Mesmo à distância, o pai avistou o filho, correu ao seu encontro e o abraçou, iniciando a restauração daquele que retornava arrependido e humilde para o lar.' WHERE "id" = 'bcf737eb-d8dc-4ed1-aacd-056f958b9451';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Boaz encontrou Rute, uma viúva estrangeira, colhendo espigas em seu campo. Reconhecendo a vulnerabilidade dela, ele decidiu intervir ativamente em seu favor. Boaz ordenou aos seus servos que deixassem espigas extras propositalmente no caminho para que ela pudesse recolhê-las com facilidade. Além disso, ele garantiu pessoalmente a segurança da jovem durante o trabalho e a chamou pelo nome. Esse gesto de acolhimento e proteção de Boaz transformou a realidade daquela mulher estrangeira que buscava sustento em suas terras.' WHERE "id" = 'bd148c8b-7a60-4c4f-904e-8051404e45fb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo viveu na miséria, cuidando de porcos em um país distante. Ao refletir sobre sua condição deplorável, ele decidiu retornar à casa de seu pai. Abandonando o orgulho, o jovem levantou-se e iniciou a longa viagem de volta. Ao encontrar o pai, confessou seus erros, admitiu não ser mais digno de ser chamado de filho e pediu para ser tratado como um empregado. O arrependimento marcou seu retorno ao lar.' WHERE "id" = 'bdd2ff78-20a7-4af1-af3e-022783bdd25d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após anos de separação devido a um grave conflito familiar, Jacó retornou ao encontro de seu irmão Esaú temendo uma possível retaliação. Contudo, ao se aproximarem, a reação de Esaú foi surpreendentemente afetuosa. Ele correu ao encontro de Jacó, lançou-se sobre o pescoço do irmão e o abraçou calorosamente. Ambos os homens choraram profundamente durante esse momento de reencontro. Assim, a longa hostilidade entre os dois irmãos foi finalmente encerrada através de um gesto de reconciliação e perdão mútuo.' WHERE "id" = 'be058972-dff2-48b0-b0d0-8e94b467ffe4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria e uma fome severa. Em meio à sua humilhação, ele reconheceu o próprio erro e decidiu retornar à casa de seu pai. Ao dar os primeiros passos de volta, o rapaz foi avistado por seu pai, que corria ao seu encontro à distância. Sem qualquer hesitação, o pai o acolheu, oferecendo perdão e restauração imediata. Assim, o jovem abandonou o passado e foi plenamente recebido pelo pai.' WHERE "id" = 'be29eab7-f51d-49c0-8933-a1061763d64a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem filho pediu sua herança ao pai e partiu para terras distantes. Após gastar todos os seus recursos, enfrentou fome e solidão extrema. Arrependido, decidiu retornar para casa a fim de pedir perdão e ser tratado como um empregado. Enquanto ainda estava longe, seu pai avistou-o e correu ao seu encontro. Em vez de repreendê-lo, o pai o abraçou afetuosamente e organizou uma grande festa para celebrar o retorno daquele que estava perdido e enfim voltou.' WHERE "id" = 'be7d0885-21d0-47ce-b4d8-69491fc59804';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que Abrão deixasse sua terra, seus parentes e a casa de seu pai para seguir em direção a uma região que Ele lhe indicaria. O Senhor prometeu abençoá-lo e tornar grande o seu nome, prometendo que todas as famílias da terra seriam abençoadas por meio dele. Aos setenta e cinco anos, Abrão obedeceu prontamente à ordem divina. Ele partiu de Harã acompanhado de sua esposa Sarai, de seu sobrinho Ló e de todos os seus bens acumulados.' WHERE "id" = 'be835fb6-b7e9-4a19-ac72-aba44a5c5f51';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar o gigante e conquistar a confiança do rei Saul, Davi conheceu Jônatas, filho do monarca. Apesar da posição de destaque do jovem pastor, Jônatas não sentiu inveja de sua fama ou coragem. Ao contrário, os dois homens estabeleceram um vínculo profundo e verdadeiro. Eles selaram um pacto solene de amizade, comprometendo-se à lealdade mútua. Mesmo diante de dificuldades futuras, Jônatas permaneceu fiel ao seu amigo, defendendo-o e mantendo a promessa firmada entre ambos durante toda a vida.' WHERE "id" = 'be87d5f0-862d-4a71-a1fd-8480d930474a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua herança, o filho mais novo encontrou-se em extrema miséria, alimentando-se com a comida dos porcos. Ao reconhecer seu erro, decidiu retornar à casa de seu pai, esperando ser tratado apenas como um empregado. Enquanto ele ainda estava longe, seu pai avistou-o e, movido por profunda compaixão, correu ao seu encontro. Sem questionamentos ou críticas, o pai acolheu o jovem com um abraço afetuoso, restaurando imediatamente sua dignidade e restaurando-o como seu filho.' WHERE "id" = 'bed005e8-eeec-4d03-9fc6-eb15e83163ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após comerem do fruto proibido no Éden, Adão e Eva esconderam-se entre as árvores ao ouvirem a voz de Deus. O Criador chamou Adão, perguntando onde ele estava. Adão justificou o medo por sua nudez, admitindo que comera o fruto. Ao ser questionado sobre o ato, Adão transferiu a culpa para Eva, alegando que ela lhe dera o alimento. Por fim, Eva atribuiu a responsabilidade pela sua desobediência à serpente, que a enganara, frustrando o arrependimento diante de Deus.' WHERE "id" = 'bed3adf1-6749-4682-a853-f0759eb29f00';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario estabeleceu um decreto proibindo qualquer petição a deuses ou homens, exceto a ele, sob pena de morte na cova dos leões. Daniel, um alto oficial estrangeiro, conhecia a proibição real, mas manteve sua rotina diária de fé. Ele foi ao seu quarto, abriu as janelas voltadas para Jerusalém e orou ao Deus de Israel, conforme o costume. Mesmo diante da ameaça iminente de execução, Daniel manteve sua fidelidade, orando publicamente como fazia habitualmente todos os dias.' WHERE "id" = 'bed45b30-7451-4d8f-94b0-50fa42bcfbc9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou ao rei Saul que destruísse completamente os amalequitas. Contudo, Saul desobedeceu ao poupar o rei Agague e o melhor do gado, alegando que os animais serviriam para sacrifícios ao Senhor. O profeta Samuel confrontou Saul severamente, afirmando que a obediência é superior a qualquer sacrifício. Devido à sua rebeldia deliberada e à preferência pelo próprio julgamento em vez da ordem divina, Saul foi rejeitado por Deus, perdendo o direito de reinar sobre todo o povo de Israel.' WHERE "id" = 'bf9a00dd-321d-4578-80b1-4ccca0f26dd9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O gigante Golias desafiava o exército de Israel diariamente, causando pavor entre os soldados israelitas que recuavam diante de sua altura e ameaças. Davi, um jovem pastor sem experiência militar ou armadura oficial, apresentou-se ao rei Saul para enfrentar o guerreiro filisteu. Ele relatou suas experiências anteriores protegendo rebanhos contra leões e ursos, fundamentando sua confiança na fidelidade de Deus. Assim, Davi dispôs-se a lutar contra o gigante, confiando que o mesmo poder divino garantiria sua vitória definitiva.' WHERE "id" = 'bfc81c4f-f246-4574-9e8a-93866445d094';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após assumir o trono de Israel, o rei Salomão teve um encontro divino em um sonho. Deus permitiu que ele pedisse o que desejasse. Consciente da grandiosidade do seu reino e de suas próprias limitações, Salomão não solicitou riquezas, vida longa ou a derrota de inimigos. Em vez disso, ele pediu discernimento e sabedoria para julgar o povo e distinguir o bem do mal. Deus atendeu ao pedido, concedendo-lhe um coração sábio e compreensivo, superior a todos os seus antecessores.' WHERE "id" = 'c05d6fe9-84de-47b0-b169-2726eeb51ed7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua vasta sabedoria, riqueza e poder sobre Israel, registrou uma observação fundamental em seus provérbios. Ele utilizou a metáfora do mel para ilustrar um princípio sobre a natureza do consumo humano. Salomão descreveu que, embora o mel seja um alimento naturalmente bom e agradável, o seu consumo em excesso provoca náuseas e doenças no organismo. Assim, o sábio monarca alertou que mesmo elementos benéficos podem tornar-se prejudiciais quando não existe moderação em sua ingestão.' WHERE "id" = 'c147a283-7875-4669-adc0-4293a30e766a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em uma corte estrangeira, recusou consumir os alimentos e vinhos consagrados a ídolos babilônicos. Determinado a não se contaminar, ele propôs um teste ao oficial responsável. Durante dez dias, Daniel e seus três companheiros comeram apenas legumes e beberam água, enquanto os demais consumiam a dieta real. Ao final do período, a aparência deles era muito mais saudável e robusta que a dos outros jovens, levando o oficial a aceitar a dieta específica deles.' WHERE "id" = 'c1823bfd-a61a-40da-810a-3a49b725f382';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta direcionada a comunidades cristãs que enfrentavam um desgaste emocional e espiritual significativo. Os fiéis lidavam com pressões constantes para abandonar a retidão e ceder às facilidades do mundo, sentindo-se exaustos pela caminhada constante. Diante desse cenário de desânimo, Paulo instruiu os crentes a manterem a perseverança na prática do bem. Ele assegurou que o tempo da colheita viria com certeza, desde que não desistissem antes de alcançarem o propósito final planejado por Deus.' WHERE "id" = 'c1929830-6593-429e-ab7c-4698dbc4b8bb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu cartas direcionadas às igrejas primitivas que enfrentavam desânimo devido ao cansaço e às pressões sociais. Ele confrontou esses cristãos apresentando a lei da semeadura, na qual a colheita é inevitável. Comparando a vida cristã à agricultura, Paulo enfatizou que o progresso exige trabalho constante, mesmo quando invisível ou desprovido de reconhecimento imediato. O apóstolo defendeu que a perseverança é fundamental para obter resultados, alertando que abandonar o plantio prematuramente impede o sucesso esperado na colheita.' WHERE "id" = 'c19e0bdb-8ae0-4f00-88ec-4951e02b44a0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Josafá, rei de Judá, enfrentou a ameaça de três exércitos que avançavam contra seu povo. Diante da inferioridade militar, ele convocou a nação para buscar a ajuda divina. Seguindo uma estratégia incomum, o rei posicionou cantores à frente de seus guerreiros para louvar ao Senhor antes da batalha. No momento em que o povo começou a entoar cânticos de adoração, os exércitos inimigos se confundiram e atacaram uns aos outros, resultando em uma vitória completa para Judá sem combates.' WHERE "id" = 'c1ec4565-3de2-4533-940b-4453e42c0ea0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado como cativo para a Babilônia e confrontado com a mesa do rei. Recusando os alimentos reais para manter sua fidelidade, ele propôs ao guarda um teste de dez dias. Daniel e seus três companheiros consumiram apenas vegetais e água durante esse período. Ao final, eles apresentaram uma aparência mais saudável e robusta do que os outros jovens que comeram as iguarias do rei. Assim, o guarda permitiu que continuassem com a dieta escolhida por eles.' WHERE "id" = 'c1f91bac-b872-4fc5-a832-ff155c412f51';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria extrema ao cuidar de porcos. Reconhecendo sua condição, ele decidiu retornar à casa de seu pai, abandonando as desculpas. Enquanto caminhava, o pai o avistou de longe e correu ao seu encontro. Com o rosto envergonhado, o filho confessou seu erro, declarando que não era mais digno de ser chamado de filho. Imediatamente, o pai o acolheu com amor, restaurando sua posição e dignidade ali mesmo.' WHERE "id" = 'c2c64493-2948-4c41-920b-2568f0a9546e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O livro de Provérbios contrasta dois comportamentos humanos distintos diante da tomada de decisões. O indivíduo tolo caracteriza-se por acreditar em qualquer informação que recebe, precipitando-se em suas ações sem qualquer análise prévia. Em oposição, a pessoa prudente examina cuidadosamente cada passo antes de prosseguir em seu caminho. Esse sujeito ponderado avalia as circunstâncias e recua prontamente ao identificar sinais de perigo, demonstrando inteligência e cautela ao considerar as consequências de suas escolhas antes de efetivamente agir na vida.' WHERE "id" = 'c2fb831e-4e8f-4294-ae95-f5761ae56819';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua herança ao pai e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo de forma desregrada. Após enfrentar uma severa fome e extrema escassez, ele decidiu retornar para casa a fim de pedir perdão e ser aceito como um empregado. Enquanto ainda estava longe, o pai o avistou, correu ao seu encontro e o abraçou com compaixão. Em seguida, o pai ordenou uma grande festa para celebrar o retorno.' WHERE "id" = 'c38bb73d-aa8d-4745-bc9c-bafc46cb7c40';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido e dos filhos, Noemi decidiu retornar a Belém e liberou suas noras de qualquer compromisso. Orpá despediu-se e partiu, mas Rute fez uma escolha firme e diferente. Ela recusou abandonar a sogra, declarando que a seguiria onde quer que fosse, adotando seu povo e seu Deus. Abandonando sua terra natal e as possibilidades de um recomeço independente, Rute permaneceu ao lado de Noemi, honrando seu compromisso familiar com total dedicação e lealdade absoluta.' WHERE "id" = 'c397defb-8480-4793-b045-8c4834d51982';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua herança longe de casa, o filho pródigo enfrentou uma severa escassez de alimentos. Em um momento de reflexão, reconheceu seus erros e decidiu retornar à casa do pai. Ele se levantou e iniciou a longa caminhada de volta, sem saber como seria recebido. Ao avistá-lo de longe, o pai sentiu profunda compaixão, correu ao seu encontro e o abraçou, marcando o reencontro entre eles após o período de rebeldia e sofrimento vivido pelo rapaz.' WHERE "id" = 'c3b03f66-c29d-4c8d-89bb-92902a690150';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel ocupava um cargo de alto poder no império persa, despertando inveja entre outros oficiais. Quando o rei assinou um decreto proibindo qualquer petição a deuses ou homens, exceto ao monarca, Daniel manteve sua rotina de fé. Ignorando a ameaça de morte, ele retornou à sua casa, abriu as janelas voltadas para Jerusalém e orou ao Senhor conforme fazia habitualmente. Seus inimigos vigiavam cada passo, mas o profeta permaneceu fiel em seu quarto, privado de qualquer público presente.' WHERE "id" = 'c3bc0a60-eef4-46f4-a467-f485394df00f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de sua estátua de ouro sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abednego foram levados à presença do monarca e confrontados com a exigência. Eles recusaram-se a adorar a imagem, declarando com firmeza que o seu Deus era capaz de livrá-los daquele fogo. Os três jovens afirmaram categoricamente ao rei que, mesmo que o livramento não ocorresse, eles jamais serviriam aos seus deuses nem adorariam a estátua.' WHERE "id" = 'c3dcd695-fbb6-41cb-b681-383421adeb50';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Pedro pediu a Jesus permissão para caminhar sobre o mar em sua direção. O Mestre concedeu o pedido, e o discípulo saiu do barco, andando sobre as águas agitadas. No entanto, ao notar a força do vento e a intensidade da tempestade ao seu redor, Pedro sentiu medo e começou a submergir rapidamente. Desesperado, ele clamou por socorro, e Jesus imediatamente estendeu a mão, segurou o discípulo e o resgatou daquelas águas profundas antes que ele se afogasse completamente.' WHERE "id" = 'c41b6d0a-8a2f-4e5b-be7e-945e14892c02';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante uma severa seca, o profeta Elias viajou até Sarepta, onde encontrou uma viúva recolhendo gravetos. Ele pediu um pouco de água e pão. A mulher explicou que possuía apenas um punhado de farinha e um pouco de azeite, insuficientes para sobreviver. Elias ordenou que ela preparasse um bolo primeiro para ele. Obedecendo ao profeta, ela o alimentou. Milagrosamente, a farinha e o azeite não acabaram, sustentando a viúva, seu filho e Elias durante todo o tempo determinado.' WHERE "id" = 'c4384925-3a53-4158-ac96-0c09f24c4214';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi apresentou-se diante do rei Saul para enfrentar o gigante filisteu Golias. Embora o monarca tenha tentado vestir o jovem com sua própria armadura de bronze e equipamentos pesados, Davi recusou os itens por não estar acostumado com eles. O rapaz optou por seguir para o campo de batalha carregando apenas seu cajado, uma funda simples e cinco pedras escolhidas no riacho. Assim, ele avançou contra o adversário, confiando em seus próprios meios para aquele confronto decisivo.' WHERE "id" = 'c4c3af1b-ddf4-4189-bdd8-3347c1257c89';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Rute, após perder o marido, acompanhou sua sogra Noemi até uma terra estranha em busca de sustento. Para garantir o alimento, ela trabalhou colhendo restos em um campo pertencente a Boaz. Ao notar o esforço e a dedicação da jovem, Boaz a tratou com generosidade, ordenando que colhesse grãos livremente e oferecendo proteção durante o serviço. Esse encontro providencial permitiu que Rute recebesse amparo, transformando profundamente a realidade daquela família e garantindo um novo futuro para ambas.' WHERE "id" = 'c55f5c35-0422-497f-9af3-b8a9851a1eb6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro. Sadraque, Mesaque e Abede-Nego, porém, recusaram-se a adorar o ídolo. Confrontados pelo monarca e ameaçados com a morte em uma fornalha ardente, os três hebreus mantiveram sua posição firme. Declararam ao rei que seu Deus era capaz de salvá-los, mas afirmaram categoricamente que, mesmo que o livramento não ocorresse, eles jamais serviriam a outros deuses nem adorariam a estátua que o rei havia erigido.' WHERE "id" = 'c5838303-736a-42de-adfb-2e5f6bdecc07';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreveu uma carta aos cristãos da cidade de Éfeso, um centro urbano marcado por intensas disputas políticas e comerciais. Diante desse cenário de conflitos, o apóstolo orientou os fiéis a abandonarem a mentira e falarem sempre a verdade ao próximo. Ele utilizou a metáfora de um corpo para explicar que todos fazem parte de um mesmo organismo. Paulo alertou que a desonestidade entre os membros causa o adoecimento e a fragmentação fatal dessa comunhão, prejudicando relacionamentos fundamentais.' WHERE "id" = 'c5f62c00-9653-48e9-aab2-1a1517e0310d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dario, o rei, nomeou Daniel como um de seus principais administradores na Babilônia. Invejados, outros oficiais convenceram o rei a decretar uma lei proibindo qualquer petição a deuses ou homens, exceto ao soberano, durante trinta dias. Sob pena de morte na cova dos leões, Daniel desobedeceu à proibição. Mesmo ciente do risco fatal, ele retirou-se para seu quarto, abriu as janelas voltadas para Jerusalém e ajoelhou-se para orar a Deus, mantendo fielmente o seu costume diário de oração.' WHERE "id" = 'c5fdd837-f09c-4904-b4e9-cd0c7e85416e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava sentado no templo observando as pessoas depositarem suas ofertas no cofre. Muitos ricos contribuíram com grandes quantias, exibindo sua abundância. Logo depois, uma viúva pobre aproximou-se e depositou apenas duas pequenas moedas. Jesus chamou seus discípulos e afirmou que aquela mulher havia ofertado mais do que todos os outros. Enquanto os ricos doaram apenas o que lhes sobrava, a viúva entregou tudo o que possuía para seu próprio sustento, sacrificando o que era essencial para viver.' WHERE "id" = 'c604f61d-e0ca-4298-9012-b94ebd4e2ba2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jacó, após vinte anos de distanciamento, aproximou-se de seu irmão Esaú, temendo as consequências da antiga traição relacionada à primogenitura e à bênção paterna. Ao avistar o grupo de Jacó, Esaú correu ao seu encontro com inesperada disposição. Em vez de vingança, o irmão ofendido abraçou Jacó, beijou-o e ambos choraram juntos. Jacó ofereceu presentes como gesto de paz e reconhecimento, enquanto Esaú, inicialmente relutante, aceitou as dádivas, selando finalmente a reconciliação entre os dois membros da família.' WHERE "id" = 'c6056839-4927-4f6d-ade8-288fa3e645fc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel servia como um alto oficial na Babilônia, despertando a inveja de outros governantes. Eles conspiraram contra ele e convenceram o rei Dario a assinar um decreto proibindo qualquer petição a deuses ou homens, exceto ao próprio monarca, sob pena de morte na cova dos leões. Mesmo ciente da nova lei, Daniel retornou à sua casa e orou ao seu Deus com as janelas abertas, como era seu costume diário, mantendo sua fidelidade diante da proibição real imposta.' WHERE "id" = 'c61bac2f-24eb-404f-b095-430163cb74c3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José era um jovem que possuía muitos irmãos. Ao compartilhar seus sonhos, suas palavras impensadas causavam mágoas e criavam distâncias entre eles. Através de um processo longo e doloroso, Deus moldou o caráter de José, ensinando-o sobre o valor das declarações prudentes e gentis. Com o passar do tempo, ele aprendeu a utilizar termos que uniam as pessoas. Finalmente, foi por meio dessas palavras pacificadoras que José reconciliou toda a sua família, proporcionando um reencontro emocionante entre todos.' WHERE "id" = 'c63ba456-89be-46af-ae99-da8a42e5986e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sabendo que não cruzaria o rio Jordão, Moisés solicitou a Deus que nomeasse um novo líder para guiar o povo de Israel. Atendendo ao pedido, o Senhor indicou Josué para assumir a sucessão. Diante de toda a congregação, Moisés apresentou Josué, impôs suas mãos sobre ele e transferiu oficialmente a autoridade da liderança. Assim, o profeta cumpriu sua última missão pública, garantindo a continuidade da caminhada do povo sob o comando daquele que fora escolhido pelo próprio Deus.' WHERE "id" = 'c6b8df35-09a8-461f-82bd-c9569c1c3253';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus estava cercado por seus discípulos que disputavam posições de destaque no reino. Tiago e João almejavam os melhores lugares, gerando indignação e ciúme nos outros dez. Diante dessa contenda por poder, Jesus interveio com um ensinamento radical sobre a liderança. Ele afirmou que aquele que deseja ser o maior deve tornar-se servo de todos. Por fim, declarou que o próprio Filho do Homem não veio para ser servido, mas para servir e dar a vida como resgate.' WHERE "id" = 'c6f4a16d-e6ff-44ce-a1d2-c6b882a28025';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Rute, uma viúva estrangeira, decidiu acompanhar sua sogra Noemi até Belém. Para garantir o sustento, ela foi trabalhar no campo de Boaz, coletando espigas caídas após a colheita. Impressionado pelo caráter e fidelidade da jovem, Boaz a recebeu com extrema generosidade. Ele ordenou que seus servos oferecessem proteção, água e alimento, garantindo que ela colhesse com segurança. Esse encontro fortuito no campo transformou a vida de Rute, estabelecendo uma nova trajetória de provisão, amparo e dignidade para ambas.' WHERE "id" = 'c6fc003b-f896-4ed2-b919-623c0ae2416b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem recebeu sua herança e partiu para uma terra distante, onde gastou todos os seus bens vivendo de forma desenfreada. Após enfrentar uma severa fome e extrema necessidade, ele reconheceu seu erro e decidiu retornar à casa de seu pai, esperando ser tratado apenas como um empregado. Enquanto ainda estava longe, o pai avistou o filho, correu ao seu encontro, abraçou-o com profunda compaixão e o acolheu de volta, demonstrando um amor generoso ao recebê-lo em casa.' WHERE "id" = 'c70f7cdc-9259-4e1c-bc70-15e905566614';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Quando Salomão tornou-se rei de Israel, Deus apareceu-lhe em um sonho e ofereceu realizar qualquer desejo. O jovem monarca, diante da imensa responsabilidade de governar todo o povo, não solicitou riquezas, vida longa ou a derrota de seus adversários. Em vez disso, ele pediu a Deus sabedoria e discernimento para julgar o povo com justiça. Aprovando a escolha de Salomão, Deus concedeu-lhe um entendimento incomparável, além de outras dádivas que o rei nem sequer havia solicitado originalmente.' WHERE "id" = 'c71c5982-dd19-4438-82d5-f4e156aca62c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Encarcerado em uma prisão romana, o apóstolo Paulo escreveu uma carta fundamental à igreja de Filipos. Privado de liberdade e prestígio, ele instruiu os cristãos a abandonarem o egoísmo. O texto determina que cada crente deve considerar os outros superiores a si mesmo, buscando não apenas os seus próprios interesses, mas também os interesses do próximo. A mensagem, redigida dentro de correntes, estabelece um padrão de conduta relacional, exigindo uma reorientação radical do foco pessoal em favor da comunidade.' WHERE "id" = 'c78170b0-840d-4394-8fd5-6fabeeadf48d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus visitou a casa de Marta e Maria. Enquanto Marta se ocupava com diversas tarefas domésticas para servir ao convidado, Maria permaneceu sentada aos pés do Mestre, ouvindo atentamente seus ensinamentos. Incomodada com a falta de auxílio da irmã, Marta questionou Jesus sobre a situação. O Senhor respondeu que ela estava sobrecarregada com muitas preocupações, enquanto Maria havia escolhido a melhor parte, que não lhe seria tirada. Jesus destacou que apenas uma coisa era essencial naquele momento específico.' WHERE "id" = 'c8e392bf-6566-4e6d-a2f7-b2a88bd35ded';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago escreveu uma carta direcionada às comunidades cristãs dispersas que enfrentavam severas perseguições e pressões constantes. Em seu relato, o autor não prometeu alívio imediato aos aflitos, mas afirmou que as provações são ferramentas fundamentais de transformação. Ele utilizou o conceito grego hupomoné para definir a paciência como uma resistência ativa sob grande peso. Tiago descreveu essa condição não como uma espera passiva, mas como uma forja intensa, onde a firmeza dos fiéis desenvolve a completude do caráter cristão.' WHERE "id" = 'c9016fa1-b3df-4696-9862-9646fc305811';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos da cidade de Roma durante um período marcado por intensas tensões étnicas, religiosas e políticas. Essas divisões ameaçavam desintegrar a unidade das comunidades locais. Diante desse cenário complexo, Paulo instruiu os membros da igreja a buscarem ativamente a reconciliação. Ele estabeleceu como diretriz fundamental que cada indivíduo deve se esforçar pessoalmente, na medida de sua própria capacidade, para manter a paz com todos ao seu redor, independentemente dos conflitos externos existentes.' WHERE "id" = 'c9339f20-0192-4525-9b5c-88a4b74bc45e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi viveu uma trajetória marcada por diversos tropeços, erros, momentos de profunda tristeza e medo. Apesar das frequentes quedas que enfrentou ao longo de sua jornada, ele não permaneceu prostrado no chão. Davi constantemente buscava a Deus, confiando plenamente no auxílio divino para se reerguer. O Senhor sustentou a mão de Davi em cada dificuldade que ele atravessou, permitindo que o rei superasse seus fracassos e continuasse caminhando diante de sua própria história com o Criador.' WHERE "id" = 'c93562fa-2f86-4712-adc3-1e9868a30afc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sentado no templo, Jesus observava as pessoas depositarem suas ofertas. Muitos ricos contribuíam com grandes somas de dinheiro, exibindo gestos largos diante de todos. Em seguida, uma viúva pobre aproximou-se e ofertou apenas duas pequenas moedas, que possuíam valor irrisório. Jesus chamou seus discípulos e explicou que aquela mulher havia ofertado mais do que todos os outros. Enquanto os ricos doavam o que lhes sobrava, a viúva entregou tudo o que possuía para o próprio sustento diário.' WHERE "id" = 'c960ea86-9f48-4b75-9b3a-fa2d3c4da484';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado prisioneiro à Babilônia ainda jovem. O rei ordenou que ele e seus amigos consumissem as iguarias da mesa real, o que violava as leis de sua fé. Decidido a não se contaminar, Daniel solicitou ao chefe dos eunucos uma dieta de vegetais e água. Após um período de prova de dez dias, os jovens que recusaram a comida real apresentaram uma aparência mais saudável e robusta do que todos aqueles que comeram os alimentos servidos pelo rei.' WHERE "id" = 'c9bbbada-72c2-457d-be84-36005cce265a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José, vendido pelos irmãos por inveja, tornou-se autoridade no Egito após anos de escravidão e prisão. Quando seus irmãos viajaram ao Egito buscando alimento devido à fome, eles se apresentaram diante de José, que inicialmente não foi reconhecido por eles. Em um momento de profunda emoção, José revelou sua verdadeira identidade aos seus parentes. Ele chorou abertamente, assegurou-lhes o sustento, perdoou a traição do passado e abraçou seus irmãos, selando a reconciliação entre toda a sua família.' WHERE "id" = 'c9d89de9-2803-4485-a773-1ef2bf0b78c2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos quatorze anos, Daniel enfrentou a pressão do rei para consumir alimentos proibidos por suas convicções. Em vez de ceder aos costumes locais, ele solicitou calmamente uma alternativa alimentar para si e seus companheiros hebreus. Após um período de prova de dez dias, o grupo apresentou uma aparência física mais saudável e vigorosa do que todos os jovens que ingeriam as iguarias reais. Assim, Daniel manteve sua integridade diante das exigências da nova cultura imposta.' WHERE "id" = 'c9e88e2c-dfc6-49fe-a941-eba177f264a6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas nos campos. Quando um leão imenso surgiu para atacar o rebanho, Davi sentiu um forte medo em seu coração. Em vez de fugir ou paralisar, ele lembrou da proteção divina e enfrentou o animal feroz para defender a ovelha. Anos depois, já adulto, Davi compôs um salmo declarando que, mesmo diante de situações amedrontadoras, ele escolheu confiar em Deus. Essa experiência marcou sua vida desde a infância.' WHERE "id" = 'c9f17ec4-3d5e-4346-94df-36a2a2c1b4eb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, um jovem pastor corajoso, cuidava de suas ovelhas sozinho no campo. Certo dia, sentiu um medo profundo ao encontrar inimigos e buscou esconderijo. Em meio a essa situação angustiante, ele decidiu ser completamente honesto sobre seus sentimentos. Davi abriu o coração e falou diretamente com Deus a respeito de todo o seu temor. O Senhor, que observa todas as coisas, permaneceu ao lado dele durante aquele momento difícil, trazendo amparo e proteção diante do cenário de perigo enfrentado.' WHERE "id" = 'ca274345-5137-4c92-9dca-78f3d0338cfa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem exilado em uma terra estranha, recusou a dieta imposta pelo rei da Babilônia por convicções religiosas. Em vez de ceder à pressão dos que o cercavam, ele propôs ao guarda um teste de dez dias, alimentando-se apenas de vegetais e água. Após esse período, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que os jovens que consumiram as iguarias reais, confirmando que a obediência aos mandamentos divinos trouxera resultados superiores.' WHERE "id" = 'ca379b5f-ca9b-4eee-8d02-12b03bf9d01d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio da história, observou a trajetória de diversas personalidades ao longo do tempo. Ele percebeu que muitos monarcas poderosos caíram no esquecimento, enquanto pessoas comuns permaneceram lembradas por muitas gerações. Essa distinção não ocorreu devido ao acúmulo de riquezas ou bens materiais, mas fundamentou-se na integridade e no caráter demonstrado por cada indivíduo durante suas decisões mais difíceis. Assim, Salomão concluiu que um bom nome possui valor superior às grandes fortunas.' WHERE "id" = 'ca771bc3-b44d-41f5-bfd5-839bed291551';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém a Jericó quando foi atacado por salteadores, que o espancaram e deixaram semimorto na estrada. Um sacerdote e um levita passaram pelo caminho, viram a vítima e ignoraram seu estado. Posteriormente, um samaritano aproximou-se, tratou suas feridas com azeite e vinho, colocou-o em seu próprio animal e o levou a uma hospedaria. Ele pagou ao estalajadeiro pelas despesas médicas e assegurou que o homem recebesse todos os cuidados necessários para sua completa recuperação.' WHERE "id" = 'cacc59b7-a6b7-4c03-857b-ad3a8a45ec86';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Saul perseguia Davi movido por ciúmes, buscando matá-lo com seu exército. Em uma caverna no deserto de En-Gedi, o rei entrou para descansar e ficou vulnerável diante de Davi e seus homens. Embora incentivado a tirar a vida de Saul, Davi apenas cortou a ponta do manto real silenciosamente. Posteriormente, do alto de um rochedo, Davi mostrou o tecido como prova de sua lealdade. Diante daquela demonstração de misericórdia, o rei Saul chorou profundamente, reconhecendo a integridade do fugitivo.' WHERE "id" = 'cb5a6ec3-8a4b-4733-97b1-224dfb211fc1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após receber sua herança, o filho mais novo partiu para uma terra distante, onde desperdiçou todos os seus recursos vivendo de forma desregrada. Diante da miséria e da fome, ele reconheceu seus erros e decidiu retornar à casa paterna para pedir perdão, aceitando trabalhar como um simples servo. Enquanto se aproximava, seu pai o avistou de longe. Movido por profunda compaixão, o pai correu ao seu encontro, abraçou-o calorosamente e o recebeu de volta com amor, restaurando sua dignidade.' WHERE "id" = 'cb730837-4ca5-4e77-babf-2d1125e71cc9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo para a Babilônia, o jovem Daniel recusou-se a consumir as finas iguarias da mesa real por violarem suas convicções. Ele propôs ao oficial responsável um teste de dez dias, consumindo apenas vegetais e água. O oficial aceitou a sugestão e, ao final do período, Daniel e seus amigos apresentavam uma aparência física superior aos que ingeriam a porção do rei. Diante do resultado evidente e incontestável, o oficial permitiu que eles continuassem com a dieta escolhida.' WHERE "id" = 'cbb81446-ec1e-4522-862b-4db4c2f67e24';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus visitou a casa de Marta e Maria. Enquanto Marta se ocupava excessivamente com os preparativos domésticos, sentindo-se sobrecarregada pelo serviço, Maria escolheu sentar-se aos pés de Jesus para ouvir atentamente seus ensinamentos. Incomodada, Marta interrompeu o Mestre e questionou por que sua irmã não a ajudava. Jesus respondeu diretamente a Marta, observando que ela estava ansiosa e perturbada com muitas coisas, enquanto destacava que apenas uma coisa era necessária, reafirmando a prioridade da atenção de Maria.' WHERE "id" = 'cc13fa0a-447f-4085-882f-45e4ea96ca0e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sadraque, Mesaque e Abednego compareceram diante do rei Nabucodonosor, sob a pressão de uma multidão e sob a ameaça imediata de uma fornalha ardente. Enquanto os presentes se prostraram diante da estátua de ouro, os três jovens permaneceram em pé. Confrontados pelo monarca sobre a desobediência, eles declararam firmemente que não prestariam culto ao ídolo. Mesmo diante da possibilidade de morte, afirmaram que seu Deus poderia livrá-los, mas, ainda que isso não ocorresse, recusariam curvar-se perante o decreto imperial.' WHERE "id" = 'cc2372db-832a-4929-8e62-6882178b0b87';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio que já existiu, dedicou-se a observar atentamente o mundo e as dinâmicas humanas. A partir de suas reflexões, ele estabeleceu um princípio fundamental sobre as relações sociais e o caráter. Salomão concluiu que caminhar ao lado de pessoas sábias permite ao indivíduo absorver discernimento e conhecimento. Por outro lado, o rei alertou que aqueles que escolhem associar-se a insensatos inevitavelmente colhem consequências desastrosas, sendo moldados pelas atitudes de seus companheiros.' WHERE "id" = 'cc4a3799-d337-464d-9734-1e72c0a25110';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi e Jônatas estabeleceram uma aliança de amizade profunda, selada com presentes e promessas mútuas perante o Senhor. Jônatas, filho do rei Saul, amava Davi como a si mesmo e reconhecia seu valor. Em um gesto de lealdade, Jônatas entregou suas vestes, espada, arco e cinto ao jovem pastor, abdicando de seu direito ao trono. Essa união enfrentou as tensões provocadas pelo rei Saul, solidificando um pacto inabalável que perdurou diante de grandes riscos políticos e perseguições intensas.' WHERE "id" = 'cc9027ab-0d1e-4211-8cdd-ce7bccc2ad1f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Roboão assumiu o trono de Israel e enfrentou uma decisão crucial sobre o governo. Ele buscou conselhos de anciãos experientes, que sugeriram servir ao povo para garantir lealdade, e de seus amigos jovens, que propuseram impor maior carga. O rei decidiu ignorar os conselhos dos anciãos e seguiu a sugestão de seus colegas de infância. Consequentemente, o povo se rebelou contra o monarca, o que causou a divisão permanente do reino que seu pai, Salomão, havia edificado anteriormente.' WHERE "id" = 'cd23ce8d-7318-4586-b0a5-fd4090de5763';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago escreveu uma carta direcionada aos jovens cristãos que viviam espalhados em um mundo marcado pela hostilidade e pela instabilidade constante. Diante de tais adversidades, ele explicou que o processo de provação da fé tem o propósito específico de gerar a paciência. Quando esse exercício de resistência é plenamente desenvolvido, ele molda o caráter do fiel, tornando-o completo e sem falhas. O autor exortou os crentes a não buscarem atalhos, mas a suportarem o processo, mantendo a integridade necessária.' WHERE "id" = 'cdd5a554-71f4-4937-ba5e-3576de5ab0f9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi encontrava-se escondido com seus homens no fundo de uma caverna quando o rei Saul entrou no local para descansar. Os companheiros de Davi insistiram que Deus entregara o inimigo em suas mãos, pressionando-o a matá-lo. Davi, porém, recusou a oferta, aproximando-se silenciosamente apenas para cortar a borda do manto do monarca. Posteriormente, Davi saiu da caverna e chamou Saul, exibindo o pedaço do tecido como prova de que teve a oportunidade de matá-lo, mas escolheu poupá-lo.' WHERE "id" = 'ce4f2be0-309b-45af-b29f-d1d5e48b9e73';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte da herança e partiu para terras distantes, onde desperdiçou todos os seus bens vivendo dissolutamente. Diante da fome e da miséria, reconheceu seu erro e decidiu retornar à casa paterna para pedir perdão e ser tratado como um servo. Enquanto ainda estava longe, seu pai avistou o rapaz e correu ao seu encontro. Comovido, o pai o abraçou afetuosamente, celebrando o retorno do filho que estava perdido e agora foi encontrado com vida.' WHERE "id" = 'ce7adf3f-e5fa-408f-8cb8-bb5ab4adda63';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta direta à comunidade cristã situada na cidade de Corinto. Em um ambiente urbano agitado, repleto de pressões sociais e influências externas, ele alertou os crentes sobre os perigos da convivência inadequada. Paulo afirmou categoricamente que as más companhias corrompem os bons costumes. Essa orientação visava advertir aqueles cristãos sobre como a escolha do grupo ao qual pertenciam moldava diretamente seus comportamentos e atitudes, deixando marcas profundas em suas vidas diante das escolhas diárias.' WHERE "id" = 'cea00080-86c5-42ac-8bd0-fbaab46a34e5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após vencer Golias, Davi tornou-se amigo íntimo de Jônatas, filho do rei Saul. A conexão entre eles foi tão profunda que suas almas se uniram em um pacto de lealdade. Jônatas, reconhecendo Davi como alguém especial, decidiu presenteá-lo com suas vestes reais, incluindo seu manto, sua espada e seu arco. Posteriormente, diante da perseguição movida por Saul contra o jovem pastor, Jônatas reafirmou seu compromisso, protegendo a vida de seu amigo e fortalecendo a aliança estabelecida entre ambos.' WHERE "id" = 'ceab2454-aa86-4f28-b7dc-89b2022267cc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar sua herança vivendo de modo inconsequente, o filho pródigo enfrentou profunda miséria cuidando de porcos. Consciente de sua ruína, ele decidiu retornar à casa do pai, ensaiando uma confissão sincera para assumir seus erros. Ao avistá-lo caminhando de volta, o pai, tomado de grande compaixão, correu ao encontro do rapaz. Antes mesmo que o filho pudesse concluir seu discurso de arrependimento, o pai o abraçou prontamente, iniciando assim o processo de restauração daquele jovem.' WHERE "id" = 'ceca3ad2-cbce-40a2-abef-5242aa4e4cbd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após suceder Salomão, o rei Roboão reuniu-se com o povo em Siquém para ouvir um pedido de alívio nos fardos impostos pelo seu pai. O monarca consultou os anciãos, que sugeriram atender à solicitação, mas optou por seguir o conselho dos seus amigos de infância, que defenderam uma postura autoritária. Ao rejeitar os veteranos e impor condições severas aos israelitas, Roboão provocou a revolta das tribos. Como consequência direta dessa escolha, o reino de Israel dividiu-se permanentemente em dois.' WHERE "id" = 'cf8218dc-4c45-476c-b912-955b3ad1eb1f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho mais novo enfrentou uma severa escassez de alimentos e percebeu seu erro. Decidiu, então, retornar à casa de seu pai, preparando um discurso de arrependimento pelo caminho. Ao avistar o filho ainda distante, o pai correu ao seu encontro, demonstrando prontidão em recebê-lo de volta. O rapaz deu o passo necessário para o reencontro, enquanto o pai agiu com prontidão e compaixão, restaurando o relacionamento entre ambos imediatamente ali.' WHERE "id" = 'cfbe77bc-58c2-4363-9821-c1f129ac51f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após derrotar o gigante Golias, Davi foi visto pela primeira vez por Jônatas, o filho do rei Saul. Naquele momento, a alma de Jônatas se uniu profundamente à de Davi, estabelecendo um vínculo de amizade intensa. Como demonstração de lealdade e reconhecimento, o príncipe decidiu entregar ao jovem pastor seu manto real, sua espada, seu arco e seus outros objetos de poder. Esse gesto simbolizou a aliança estabelecida entre ambos, marcando o início de uma relação marcada por confiança.' WHERE "id" = 'd01d3aa6-5224-4931-881f-3e58aa04dd28';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jônatas, filho do rei Saul, enfrentou um dilema crucial ao escolher seu posicionamento político. Ignorando a possibilidade de manter privilégios reais na coroa, ele optou por firmar uma aliança incondicional com Davi, um fugitivo perseguido por seu próprio pai. Essa relação foi fundamentada na integridade, superando traições e desafios extremos. Mesmo em um ambiente de poder hostil, Jônatas permaneceu fiel a Davi, provando que sua lealdade transcendia interesses pessoais, consolidando um pacto memorável de amizade verdadeira nas Escrituras.' WHERE "id" = 'd0548f53-93eb-4bf0-9e1e-ae0a3476b8f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Duas mulheres apresentaram-se diante do rei Salomão reivindicando a maternidade do mesmo bebê. Elas viviam uma disputa intensa sobre quem seria a verdadeira mãe da criança. Salomão, reconhecido por sua profunda sabedoria e temor a Deus, analisou cuidadosamente os fatos e o comportamento de ambas as partes envolvidas. Com discernimento, o rei identificou quem dizia a verdade sobre a maternidade. Essa narrativa bíblica ilustra que a visão divina alcança todos os lugares, revelando plenamente o bem e o mal.' WHERE "id" = 'd06655ad-160b-4282-a938-5a78ca51f9de';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar toda a sua herança e viver na miséria, o filho mais novo caiu em si e reconheceu sua condição indigna. Decidiu retornar à casa de seu pai, preparando um discurso de arrependimento para pedir que fosse aceito como um empregado. Enquanto caminhava de volta, ainda distante, o pai o avistou. Movido por profunda compaixão, o pai correu ao encontro do filho, abraçou-o e o beijou antes mesmo de ouvir qualquer pedido de desculpas por suas ações.' WHERE "id" = 'd0b738e8-470a-478b-8b7f-4732da9f8db2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens, o filho pródigo finalmente caiu em si e reconheceu sua miséria. Decidido a mudar de vida, ele preparou um discurso de arrependimento e iniciou a longa caminhada de retorno à casa de seu pai. Antes mesmo de chegar ao destino, o pai o avistou no horizonte, correu ao seu encontro e o abraçou com compaixão. O jovem confessou seu erro, pedindo para ser tratado apenas como um dos empregados daquele lar.' WHERE "id" = 'd0b7a1a1-9532-460e-8fd9-c6515b6395c2';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, jovem cativo na Babilônia, recusou-se a consumir as iguarias e o vinho oferecidos pelo rei, por violarem seus princípios religiosos. Com respeito, propôs ao oficial responsável um teste de dez dias, consumindo apenas vegetais e água. O oficial aceitou o desafio e permitiu a dieta alternativa para o grupo. Após o período estipulado, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta do que os jovens que se alimentaram com os manjares reais.' WHERE "id" = 'd0cd6804-bdbe-4828-8584-891be8d616be';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido, a jovem moabita Rute enfrentou um momento de profunda tristeza, assim como sua sogra, Noemi. Embora Noemi tenha incentivado Rute a retornar para sua própria família, a nora recusou a oferta. Determinada, Rute decidiu permanecer ao lado de sua sogra, mesmo diante das incertezas e da longa jornada que as aguardava. Ela escolheu acompanhar Noemi, renunciando ao conforto de seu povo para manter o compromisso de lealdade com a mulher que amava.' WHERE "id" = 'd0df70f5-8e70-4c3b-90ec-49984a08474d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O livro de Provérbios estabelece uma distinção clara entre o comportamento de homens honestos e daqueles que mentem. O indivíduo que profere a verdade firma um testemunho duradouro, capaz de resistir ao passar do tempo e provar sua integridade. Em contraste, o mentiroso que distorce a realidade constrói sobre bases instáveis. A Escritura declara que a língua falsa dura apenas um breve momento, enquanto a palavra verdadeira permanece inabalável, consolidando-se permanentemente como uma lei da própria existência humana.' WHERE "id" = 'd1c1a574-fa46-4516-8aa4-1b0154c722ca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante da ordem do rei Nabucodonosor para adorarem uma estátua de ouro sob pena de morte, Sadraque, Mesaque e Abednego recusaram-se a dobrar os joelhos. O monarca, soberano poderoso, ameaçou lançá-los em uma fornalha ardente caso desobedecessem. Sem hesitar ou negociar, os três jovens declararam com firmeza ao rei que seu Deus era capaz de salvá-los. Contudo, afirmaram resolutamente que, mesmo que fossem libertos ou não, jamais prestariam culto aos deuses da Babilônia ou adorariam a imagem erguida por ele.' WHERE "id" = 'd1f3527e-c87f-41c5-a414-79a96ba4b530';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi era um jovem pastor que cuidava de suas ovelhas com muita dedicação. Sempre que cometia um erro, como deixar uma ovelha sozinha por descuido, ele confessava prontamente a verdade ao seu pai, apesar da vergonha que sentia. Por causa dessa postura constante, as pessoas ao seu redor passaram a considerá-lo um rapaz de absoluta confiança. Deus observava sua honestidade desde a infância e preparava o caminho de Davi, pois ele sempre falava a verdade em qualquer situação.' WHERE "id" = 'd22c4d1f-3891-40ac-9a00-ba578cd57649';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um viajante foi gravemente ferido na estrada e abandonado por pessoas que passavam apressadas. Em seguida, um samaritano aproximou-se do local e, ao perceber o sofrimento do homem, sentiu profunda compaixão. Ele interrompeu sua jornada para socorrê-lo, limpou e enfaixou suas feridas com cuidado. Após prestar os primeiros socorros, o samaritano acomodou o ferido e permaneceu ao seu lado, dedicando tempo e atenção necessários para garantir que ele estivesse totalmente seguro e recuperado daquela situação difícil.' WHERE "id" = 'd233e160-2e00-4cb7-8ef8-0ac77482021c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Samuel viajou até a casa de Jessé para ungir o novo rei de Israel por ordem divina. Sete filhos mais velhos passaram diante de Samuel, mas o Senhor não escolheu nenhum deles. Ao ser questionado sobre a existência de outros jovens, Jessé revelou que seu filho caçula, Davi, estava cuidando das ovelhas no campo. Davi foi trazido imediatamente e, conforme a orientação de Deus, o profeta o ungiu como o futuro monarca escolhido diante de seus irmãos.' WHERE "id" = 'd2650a56-c6d2-498d-a690-17e7811d5292';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Noé recebeu de Deus a instrução de construir uma arca gigantesca, embora nunca tivesse presenciado uma chuva forte na Terra. Diante do ceticismo das pessoas ao seu redor, ele decidiu confiar plenamente nas orientações divinas e obedeceu prontamente. Sem ver qualquer resultado imediato, ele dedicou-se à obra conforme o planejado. Essa atitude de fé inabalável resultou no salvamento de sua família e dos animais, provando que a obediência absoluta aos mandamentos de Deus concretiza grandes propósitos históricos.' WHERE "id" = 'd2dc1d37-c4a5-4ec7-9e82-e05f46a50d78';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi apresentou-se diante do rei Saul para se oferecer ao combate contra o gigante Golias. O jovem pastor relatou ao monarca suas experiências anteriores no campo, onde, sozinho, enfrentou e derrotou um leão e um urso que atacavam o rebanho de seu pai. Com base na proteção divina que já havia experimentado durante aqueles confrontos solitários, Davi assegurou a Saul que o Senhor, que o livrara das garras dos animais selvagens, também o libertaria das mãos daquele filisteu.' WHERE "id" = 'd3191f56-60a7-4676-bb71-24b37f2ccc5c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abednego se curvassem diante de uma estátua de ouro, sob pena de serem lançados em uma fornalha ardente. Os três jovens, mantendo sua fidelidade ao Senhor, responderam ao monarca que não precisavam se defender. Afirmaram com firmeza que seu Deus era poderoso para livrá-los daquele fogo. Declararam que, mesmo que o livramento não ocorresse, não adorariam o ídolo de ouro nem se curvariam perante a imagem erguida pelo rei babilônico.' WHERE "id" = 'd33dd0f3-2e5c-47c7-a188-d7134abdfa60';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Dario estabeleceu um decreto proibindo orações a qualquer deus ou homem, exceto a ele mesmo, por trinta dias. Daniel, um alto oficial do império persa, conhecia a ordem, mas manteve seus costumes inalterados. Ao chegar em casa, ele abriu as janelas do seu quarto, conforme fazia habitualmente, e orou a Deus três vezes ao dia. Sem buscar plateia ou aprovação, Daniel continuou sua prática de fé pública e privada, enfrentando as consequências impostas pelo decreto real vigente.' WHERE "id" = 'd4c5c8e5-b15c-4e6c-b117-901bae022215';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus dirigiu-se a uma grande multidão composta por trabalhadores e famílias que enfrentavam incertezas sobre o futuro. Durante seu discurso, ele apontou para os pássaros que voam no céu e para as flores que crescem nos campos, destacando como Deus provê sustento a essas criaturas. Em seguida, questionou os presentes sobre a inutilidade de suas preocupações excessivas, enfatizando que o cuidado divino alcança os seres humanos de forma plena. Assim, ele convidou o povo a confiar na provisão celestial diária.' WHERE "id" = 'd55e1326-75a2-470e-8f60-d32108c85b0e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante a última ceia, Jesus levantou-se da mesa, retirou seu manto e cingiu-se com uma toalha. Ele derramou água em uma bacia e começou a lavar os pés de seus discípulos. Pedro inicialmente resistiu àquela tarefa, que era costumeiramente delegada aos servos. Jesus prosseguiu, limpando os pés de cada um deles. Ao finalizar, o Mestre explicou aos seus seguidores que, sendo Ele o Senhor e Mestre, realizou aquele ato para que eles repetissem o mesmo exemplo uns com os outros.' WHERE "id" = 'd61bb654-bcf0-4328-b5d6-eaca1834631a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua vasta sabedoria, reflete sobre a condição humana diante da existência. Ele declara que o temor ao Senhor representa o fundamento essencial para o início de qualquer entendimento verdadeiro. Após explorar os limites da autossuficiência e testar diversos caminhos, o monarca conclui que ignorar a presença de Deus impede o crescimento genuíno do indivíduo. Assim, Salomão estabelece que a vida desconectada desse princípio norteador torna-se apenas uma repetição vazia que conduz inevitavelmente à ruína.' WHERE "id" = 'd6eec8e5-82b4-44e3-88ec-124fd65ae3dd';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio de sua geração, escreveu que a língua possui autoridade sobre a vida e a morte. Ele afirmou que aqueles que valorizam o uso das palavras colherão exatamente os frutos do que declararam. O texto estabelece que toda relação interpessoal é o resultado direto do que foi dito ou omitido. Assim, o sábio ensinou que a comunicação funciona como um instrumento de poder real, cujas consequências são inevitáveis e permanentes para todos.' WHERE "id" = 'd71e9a99-6f0a-4dd6-9b7f-b8cb8c7cde02';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, observou profundamente as trajetórias humanas para registrar uma verdade essencial. Ele analisou diversos exemplos bíblicos, contrastando vidas marcadas pela integridade com outras corrompidas por escolhas erradas. Entre seus registros, destaca-se Daniel, um jovem que manteve firme seu caráter e se recusou a ceder mesmo sob intensa pressão. Salomão concluiu que a construção de um bom nome e a conquista de um favor legítimo superam qualquer valor material ou riquezas passageiras.' WHERE "id" = 'd74101c8-76c7-440c-bf22-a0d6aa6dd1aa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante do rei Nabucodonosor, Sadraque, Mesaque e Abednego recusaram a ordem real de adorar a estátua de ouro erguida na planície de Dura. Enquanto a multidão se prostrava, os três jovens permaneceram de pé, desafiando a ameaça da fornalha ardente sete vezes mais quente. Declararam ao rei que seu Deus era capaz de livrá-los, mas, independentemente do resultado, jamais adorariam o ídolo. A firmeza dos hebreus em sua lealdade provocou a ira do soberano, que ordenou o lançamento imediato deles.' WHERE "id" = 'd762841e-5c73-4ff1-8369-1939da5e0359';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel recusou comer a comida oferecida pelo rei, pois violava seus princípios. Ele solicitou ao oficial responsável uma dieta baseada apenas em vegetais e água. O oficial aceitou o pedido e estabeleceu um período de teste de dez dias. Ao final desse tempo, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta que todos os outros jovens que consumiam as iguarias da mesa real. A escolha de Daniel foi honrada por Deus.' WHERE "id" = 'd78b6854-5573-4a02-b101-34147e825da9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Sadraque, Mesaque e Abednego enfrentaram o rei Nabucodonosor, que ordenou que todos se curvassem diante de uma estátua de ouro sob pena de morte. Enquanto a multidão obedecia ao decreto real, os três hebreus permaneceram de pé. Diante da pressão e da ameaça iminente da fornalha ardente, eles declararam ao monarca que seu Deus era capaz de livrá-los. Contudo, afirmaram que, mesmo que Ele não os salvasse, jamais adorariam a estátua de ouro erguida pelo rei babilônico.' WHERE "id" = 'd7d267ff-8684-461e-872d-cdfb49a01932';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido e de seus filhos em Moabe, Noemi decidiu retornar para sua terra natal, Belém. Suas noras, Orfa e Rute, acompanharam-na no início do caminho. Noemi pediu que retornassem para suas famílias, mas Rute, movida por profunda lealdade, recusou-se a abandoná-la. Ela declarou que seguiria Noemi para onde quer que fosse, adotando o seu povo e o seu Deus. Assim, ambas as mulheres seguiram juntas em direção a Belém para recomeçarem suas vidas.' WHERE "id" = 'd80f3f17-d675-4855-a7f8-3d8c6e2529f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, ainda jovem, apresentou-se perante o rei Saul para enfrentar o gigante Golias. Enquanto os soldados experientes de Israel estavam paralisados pelo medo diante da ameaça constante do guerreiro filisteu, Davi manteve sua determinação. Ele reconheceu o perigo que o inimigo representava para a nação e decidiu agir. Confiando em suas experiências anteriores ao proteger o rebanho contra leões e ursos, Davi preparou-se para combater o gigante, convicto de que Deus o livraria daquela situação difícil e perigosa.' WHERE "id" = 'd827d47e-6d54-4f65-b838-66dc056cec5e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos se curvassem perante ela. Shadraque, Mesaque e Abednego recusaram o decreto real, mantendo-se firmes contra a pressão pública. Confrontados pelo monarca, os três jovens afirmaram que não precisavam se explicar e permaneceram fiéis à sua fé. Consequentemente, foram lançados em uma fornalha de fogo ardente como punição. Entretanto, os três saíram do meio das chamas completamente ilesos, provando que sua coragem resistiu ao julgamento severo do rei.' WHERE "id" = 'd87983c8-3aad-4f41-bc33-fc222d2a4a7b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Os conselheiros do rei Dario conspiraram contra Daniel ao estabelecerem um decreto que proibia petições a qualquer deus ou homem, exceto ao soberano, durante trinta dias. O rei assinou a lei, tornando-a irrevogável conforme o costume medo-persa. Mesmo ciente do perigo e da armadilha armada, Daniel retornou à sua casa. Com as janelas abertas voltadas para Jerusalém, ele ajoelhou-se e orou ao seu Deus três vezes ao dia, mantendo sua rotina de fé, ignorando totalmente a proibição real.' WHERE "id" = 'd8b06c58-6bb9-4181-8e09-f1910300d650';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança, o filho mais novo terminou cuidando de porcos e passando fome. Percebendo sua condição miserável, ele decidiu retornar à casa do pai. Em vez de inventar desculpas, preparou uma confissão sincera, admitindo que não era mais digno de ser chamado filho. Ao levantar-se e caminhar em direção ao seu lar, foi avistado pelo pai, que correu ao seu encontro. Aquele momento marcou o retorno definitivo do jovem após reconhecer seus próprios erros cometidos anteriormente.' WHERE "id" = 'd8b08644-bad2-4b18-8791-f81b649a07a9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Do cárcere romano, o apóstolo Paulo antecipa sua iminente execução. Em seus momentos finais, ele faz um balanço definitivo de sua trajetória ministerial. O apóstolo afirma categoricamente ter combatido o bom combate, completado a carreira proposta e guardado a fé, apesar dos diversos naufrágios, perseguições e sofrimentos enfrentados ao longo de sua vida. Ele aguarda agora a coroa da justiça, que o Senhor, o justo juiz, lhe concederá naquele dia, recompensando a fidelidade demonstrada até o fim.' WHERE "id" = 'd8e72c46-8518-4b4c-9ff4-1f75c6441a2f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na antiguidade, os muros das cidades serviam como barreiras essenciais de proteção contra invasões inimigas, garantindo a sobrevivência dos habitantes. Sem essas defesas, o acesso aos invasores tornava-se imediato e a conquista da cidade era inevitável. Salomão utilizou essa imagem para descrever o estado de vulnerabilidade total de um homem que carece de domínio próprio. Assim como uma cidade sem muros fica exposta aos ataques, aquele que não governa suas próprias atitudes permanece totalmente indefeso diante dos perigos.' WHERE "id" = 'daa27d91-b4af-41a8-bcfc-c901a84e0c6e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a difícil missão de liderar o povo de Israel na conquista de terras habitadas por nações poderosas. Deus ordenou que ele fosse forte e corajoso, prometendo Sua presença constante em todos os caminhos. Diante desse desafio, Josué não recuou nem buscou aprovação popular. Ele atravessou o rio Jordão e, dia após dia, manteve a integridade de seu caráter em decisões privadas, o que fundamentou cada ato público realizado durante toda a jornada.' WHERE "id" = 'daddb5c9-c56e-4066-a5e6-13f840f990e8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após uma surpreendente vitória militar contra os filisteus, o profeta Samuel conduziu o povo de Israel até um local específico entre Mispa e Sem. Ali, ele ergueu uma grande pedra como um memorial público do socorro divino. Samuel batizou aquele monumento de Ebenezer, declarando que, até aquele momento, o Senhor havia sustentado os israelitas. O gesto estabeleceu um marco físico e permanente para que as futuras gerações lembrassem do auxílio de Deus em meio às batalhas do passado.' WHERE "id" = 'db193705-a86e-43d0-9a7c-d0f8bcda69ad';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, possuindo vasta autoridade e sabedoria, governou seu reino tentando basear todas as suas decisões exclusivamente em seu próprio entendimento intelectual. Com o passar do tempo, ele percebeu que a autossuficiência humana possui limites claros e frequentemente conduz a resultados frustrantes. Ao analisar sua trajetória, o monarca reconheceu que confiar apenas em sua perspectiva limitada não garantiu o sucesso esperado. Assim, ele registrou suas conclusões, aconselhando a buscar uma direção superior, superando a própria percepção pessoal.' WHERE "id" = 'db2958dc-8219-4fbc-a85e-d06f6a4b58b7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus criou a terra repleta de sementes capazes de florescer quando cultivadas adequadamente no solo. Ao plantar uma semente no lugar correto e regá-la com cuidado, ela se transforma em algo belo. Por outro lado, o descuido ou o plantio de espinhos resulta em plantas espinhosas. Assim, a Bíblia ilustra que as escolhas humanas funcionam como o plantio: realizar boas ações, como dividir brinquedos ou obedecer, constitui sementes positivas que resultam no florescimento de uma vida realmente bela.' WHERE "id" = 'db971527-024c-4aa9-af89-c80094505f6a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para uma terra distante sob o domínio do rei. Recebeu ordens de consumir alimentos proibidos por sua fé, mas recusou firmemente a dieta imposta. Daniel solicitou educadamente ao responsável que ele e seus amigos comessem apenas legumes e bebessem água durante dez dias. Após esse período de teste, o grupo demonstrou estar com uma aparência muito mais saudável e robusta que os demais jovens que aceitaram a alimentação do rei da Babilônia.' WHERE "id" = 'db9d6785-46c9-4e35-be64-b46b4e05fd80';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo João escreveu uma carta urgente para comunidades cristãs que enfrentavam um cenário de intensa perseguição e crescente rejeição social. Nesse contexto, o medo não era apenas uma emoção passageira, mas uma força ativa que afastava as pessoas, corrompia os laços comunitários e impunha um tormento constante aos crentes. Diante dessa realidade, João afirmou que o amor perfeito de Deus atua como um elemento decisivo que identifica, confronta e expulsa o medo, restaurando a unidade entre os irmãos.' WHERE "id" = 'dbb27042-a563-4012-bc02-c53b47c1d061';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua profunda sabedoria, dirigiu palavras de orientação ao seu próprio filho. O monarca instruiu o jovem a manter seus olhos fixos no caminho correto, evitando desvios ou distrações laterais durante sua jornada. Ele utilizou a comparação com o voo preciso de uma abelha em direção à flor para ilustrar a necessidade de foco total no objetivo. Salomão enfatizou que o direcionamento do olhar revela a verdadeira intenção e o destino do coração humano.' WHERE "id" = 'dc33476b-fbb3-493f-a140-bccee0e99178';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua herança ao pai e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo de forma desregrada. Após enfrentar uma severa fome, arrependeu-se e decidiu retornar para casa como um servo. Ao avistá-lo ainda distante, o pai correu ao seu encontro, abraçou-o com profunda compaixão e beijou-o. O pai ordenou prontamente aos servos que preparassem uma grande festa e vestissem o filho com roupas novas, celebrando seu retorno à família.' WHERE "id" = 'dc4fe927-8a59-4245-9b0a-7279838c9800';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem judeu foi assaltado, ferido e abandonado na estrada à beira da morte. Um sacerdote e um levita passaram pelo local, mas ignoraram o homem caído. Posteriormente, um samaritano aproximou-se, tratou as feridas da vítima com cuidado e a colocou sobre seu próprio animal. Ele levou o homem a uma estalagem, pagou pessoalmente pelas despesas necessárias com a hospedagem e o tratamento, garantindo que o ferido recebesse todos os cuidados essenciais até sua total e completa recuperação.' WHERE "id" = 'dc6e1b5f-559e-45e5-984f-0f016007b114';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O passarinho Tito vivia em uma árvore com seus amigos. Acidentalmente, ele destruiu o ninho de um companheiro e, por medo, mentiu sobre o ocorrido. Consequentemente, o grupo ficou triste e isolado de Tito. Tempos depois, ele decidiu confessar a verdade, pediu desculpas sinceras e auxiliou na reconstrução do ninho danificado. Após assumir seu erro, a amizade entre os pássaros foi restaurada e fortalecida, provando que a honestidade foi capaz de reconectar os laços entre eles novamente.' WHERE "id" = 'dc71d635-3382-4145-aca0-b6d99e266172';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo enfrentou a miséria e a fome vivendo entre os porcos. Reconhecendo sua condição deplorável, ele decidiu retornar à casa de seu pai, assumindo a culpa por seus erros. O rapaz levantou-se e iniciou a caminhada de volta. Enquanto ainda estava longe, seu pai avistou o filho chegando. Movido por profunda compaixão, o pai correu ao encontro dele, abraçando-o antes mesmo que o jovem pudesse completar o seu pedido.' WHERE "id" = 'dcbd656c-0230-48b8-9a96-f05c2d32546e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria, instruiu os jovens sobre os perigos das distrações e escolhas precipitadas no cotidiano. Como um pai zeloso que compreende os riscos de um olhar disperso, ele orientou seus leitores a manterem a atenção focada no que é essencial. Salomão advertiu para que não se desviasse o olhar para caminhos laterais, pois pequenas mudanças de direção, se não corrigidas, conduzem inevitavelmente a um destino final distante do objetivo que foi originalmente traçado.' WHERE "id" = 'dd44129d-04d6-4c98-89ee-baee6df15655';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos se prostrassem ao som de instrumentos. Sadraque, Mesaque e Abednego recusaram a ordem, mantendo-se firmes diante do monarca furioso. Eles afirmaram que seu Deus os livraria, mas, caso não o fizesse, jamais adorariam ídolos. Por essa postura, foram lançados em uma fornalha aquecida sete vezes mais. O milagre ocorreu e os três jovens saíram daquele fogo intenso sem sofrerem qualquer dano ou mesmo o cheiro de fumaça.' WHERE "id" = 'dd44f25f-7453-4eb1-b2ad-f0923ca2de6c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O gigante Golias desafiava o exército de Israel diariamente, provocando medo e imobilidade nos soldados israelitas. Enquanto os experientes guerreiros recuavam diante da ameaça, o jovem pastor Davi apresentou-se ao rei Saul para enfrentar o filisteu. Davi não possuía armadura, mas relatou suas experiências anteriores ao proteger seu rebanho contra leões e ursos. Confiante em seu histórico de coragem, o jovem decidiu confrontar o gigante, ignorando o temor que paralisava todos os outros homens do campo de batalha.' WHERE "id" = 'dd52e612-9e8e-4aa2-9571-53ea9ca1fecc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Doze espias foram enviados por Moisés para explorar a terra de Canaã. Ao retornarem, todos confirmaram que a terra era fértil e abundante, conforme a promessa divina. Contudo, dez homens relataram que o povo local era forte e as cidades eram fortificadas, sentindo-se como gafanhotos diante dos gigantes. Em contraste, Josué e Calebe mantiveram uma postura confiante, incentivando a conquista imediata do território. A divergência entre os doze espias sobre o relato da exploração dividiu o acampamento israelita.' WHERE "id" = 'dd6bc3bf-2fc3-4421-afb5-d7265a0ff7ba';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos da Galácia que se sentiam exaustos devido à dificuldade de praticar o bem constantemente sem receber reconhecimento. Ele os aconselhou a não desistirem de suas boas ações, mesmo diante da fadiga ou do desânimo. Paulo afirmou que, se permanecessem firmes em seu propósito e não permitissem que o cansaço interrompesse seu serviço ao próximo, eles alcançariam o momento determinado por Deus para colherem os frutos de todo o esforço realizado.' WHERE "id" = 'dd8b9c8a-5af4-4cfa-956f-ac06a3514062';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel recusou consumir os alimentos oferecidos pelo rei, mantendo sua fidelidade aos princípios divinos. Ele propôs ao oficial responsável um teste de dez dias, alimentando-se apenas de legumes e água. Após esse período, Daniel e seus três companheiros apresentaram uma saúde física superior à dos demais jovens que comeram das iguarias reais. O rei os avaliou e constatou que a sabedoria e o entendimento deles superavam dez vezes todos os magos do reino.' WHERE "id" = 'dddfa063-95db-4ceb-9593-eefb102097ca';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar seus bens e passar fome cuidando de porcos em terra distante, o filho pródigo finalmente caiu em si. Ele decidiu retornar à casa de seu pai, planejando pedir para ser tratado como um simples servo. Enquanto caminhava, o rapaz ensaiou seu pedido de perdão. Ao vê-lo de longe, o pai correu ao seu encontro. Antes mesmo de o filho conseguir proferir qualquer palavra, o pai o abraçou calorosamente, acolhendo-o de volta ao lar com grande compaixão.' WHERE "id" = 'de1f0cfd-146c-44d4-86dd-b2d3d07091b4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho pródigo viveu na miséria, chegando a cuidar de porcos. Consciente de seus erros, decidiu retornar à casa do pai para pedir perdão e ser aceito como empregado. Ao avistá-lo de longe, o pai correu ao seu encontro, abraçou-o com profunda compaixão e ordenou que preparassem uma grande festa. Ele restaurou a dignidade do filho, vestindo-o com as melhores roupas, celebrando alegremente o retorno daquele que estava perdido e agora vivia.' WHERE "id" = 'de435c3d-2b33-466d-a3b0-8c87abad6812';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, conhecido por sua vasta sabedoria e governo sobre Israel, observou a natureza do consumo humano. Ele utilizou o mel como uma metáfora precisa para ilustrar a necessidade de limites. Segundo seu registro em Provérbios, o mel é um alimento agradável e desejável, porém, o consumo em excesso provoca náuseas e mal-estar físico. Assim, Salomão definiu que a sabedoria reside na capacidade de desfrutar com moderação, evitando que o desejo natural se transforme em um excesso destrutivo.' WHERE "id" = 'deabf29b-3f3e-45ec-a39d-2dc6cc3d9288';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para a Babilônia e recebeu a ordem de consumir as finas iguarias da mesa do rei. Determinado a manter seus valores, ele recusou o alimento real e propôs ao chefe dos eunucos um período de teste de dez dias, consumindo apenas vegetais e água. Após esse tempo, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que os demais jovens. Assim, o funcionário real aceitou a dieta alternativa proposta por eles.' WHERE "id" = 'df78fc61-7823-487f-8b07-b495b4d38f83';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo à Babilônia ainda jovem. O rei ordenou que ele e seus amigos consumissem as finas iguarias da mesa real. Daniel, contudo, resolveu em seu coração não se contaminar com a comida e o vinho do monarca. Ele propôs ao chefe dos eunucos um período de teste de dez dias, alimentando-se apenas de vegetais e água. Ao final desse prazo, Daniel e seus amigos apresentavam uma aparência mais saudável e robusta que todos os outros jovens.' WHERE "id" = 'df876a26-0686-4304-9731-09d329c9c7ba';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó quando foi atacado, roubado e deixado semimorto na estrada. Um sacerdote e um levita passaram pelo local, mas ignoraram a vítima e seguiram caminho. Em seguida, um samaritano se aproximou, sentiu compaixão e cuidou dos ferimentos daquele estranho. Ele colocou o homem sobre seu próprio animal, levou-o a uma hospedaria e pagou todas as despesas necessárias para garantir sua total recuperação. O samaritano agiu prontamente diante daquela triste situação.' WHERE "id" = 'dfe4b9de-8a38-4bd3-93e0-5b5339d4c22c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O profeta Elias viajou até Sarepta e encontrou uma viúva que recolhia gravetos. Com pouco suprimento, restavam-lhe apenas um punhado de farinha e um pouco de azeite. Elias pediu que ela preparasse um pão para ele primeiro. A mulher obedeceu e fez conforme solicitado. Por causa desse gesto, a farinha na vasilha e o azeite na botija não acabaram, cumprindo a promessa divina feita pelo profeta. Durante todo o período da seca, eles tiveram alimento garantido diariamente.' WHERE "id" = 'dffcd4ce-9517-45c0-a612-d03f78342b3d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo enfrentou a extrema pobreza e a miséria. Em um momento de profunda lucidez, ele reconheceu seus erros e decidiu retornar à casa de seu pai para pedir trabalho como um simples empregado. Enquanto caminhava de volta, seu pai o avistou de longe e, movido por compaixão, correu em sua direção. Sem hesitar, o pai o abraçou afetuosamente, acolhendo seu filho arrependido de volta ao lar naquele exato momento.' WHERE "id" = 'e0128362-f5cc-4e87-919d-ad2cc4efe999';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho pródigo viveu na miséria, alimentando porcos e passando fome. Em um momento de clareza, ele reconheceu seus erros e decidiu retornar à casa de seu pai. Enquanto o jovem caminhava de volta, ainda distante, seu pai o avistou. Movido por profunda compaixão, o pai não esperou que o filho chegasse ou se explicasse; ele correu ao seu encontro, acolhendo-o imediatamente após o longo período de separação daquela família.' WHERE "id" = 'e03dd933-d1f1-4518-a631-1cbab04ecbcc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Durante uma grande seca em Israel, uma viúva em Sarepta possuía apenas um pouco de farinha e azeite para uma última refeição com seu filho. O profeta Elias aproximou-se e pediu que ela o servisse primeiro. Embora o pedido fosse humanamente arriscado diante da escassez, a mulher obedeceu prontamente. Consequentemente, o azeite e a farinha não acabaram durante todo o período da seca. Assim, a provisão divina sustentou milagrosamente a casa da viúva e de seu filho pequeno.' WHERE "id" = 'e06e490b-a4d0-4620-976f-7a07af05d9c3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio de sua época, observou atentamente o comportamento de reis, mercadores e amigos próximos. Ele constatou que pessoas comuns, sob pressão, frequentemente escolhiam proferir mentiras convenientes em vez de dizer a verdade. O sábio registrou que, enquanto o testemunho verdadeiro proporciona liberdade a quem o carrega, a palavra falsa e torta acaba por aprisionar aquele que a soltou. Assim, Salomão destacou o peso permanente e o efeito destruidor das falsas declarações proferidas diariamente.' WHERE "id" = 'e14c9996-a0de-429a-befe-fc0d84f5d4f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem solicitou sua parte na herança paterna e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo de modo dissoluto. Após enfrentar uma grave escassez de alimentos e passar necessidade, ele decidiu retornar à casa de seu pai para pedir perdão e ser tratado como um empregado. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o com grande alegria e promoveu uma festa celebrando o retorno de seu filho.' WHERE "id" = 'e1c90f99-206e-4af2-9caa-3210c730c636';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos a adorassem. Sadraque, Mesaque e Abednego recusaram o decreto real, afirmando que não serviriam aos seus deuses. Diante da ameaça da fornalha ardente, os três jovens mantiveram sua posição, confiando na soberania divina. Irritado com a desobediência, o monarca ordenou que fossem lançados ao fogo intenso. Contudo, eles sobreviveram milagrosamente à sentença, saindo da fornalha ilesos, sem que houvesse neles qualquer sinal do fogo ou cheiro de fumaça.' WHERE "id" = 'e1e43f45-8ea6-4537-8345-d92266f37c97';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens vivendo de forma desregrada longe de casa, o filho pródigo enfrentou a miséria e a fome. Reconhecendo seu erro, ele decidiu retornar à casa de seu pai para pedir perdão e oferecer-se como um servo. Ao avistá-lo vindo de longe, o pai correu ao encontro do rapaz, abraçando-o e recebendo-o prontamente de volta. O jovem foi restaurado por seu pai, que escolheu acolhê-lo com amor em vez de puni-lo pela falha.' WHERE "id" = 'e1ea8ccd-ae81-4af3-a8ea-ce27798fe21f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio da história, utilizou uma metáfora para explicar o autocontrole. Ele comparou uma pessoa incapaz de dominar seus impulsos a uma cidade desprovida de muros protetores. Naquela época, muralhas espessas eram essenciais para resguardar a população contra invasores, ventos fortes e destruição externa. Sem essa barreira física, a cidade ficava vulnerável a qualquer perigo. Salomão concluiu que, sem autocontrole, o indivíduo permite que situações prejudiciais invadam seu coração e causem desordem.' WHERE "id" = 'e1f4f37b-db45-4546-832e-21849cb1fe15';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta às igrejas da Galácia para orientar os cristãos sobre a responsabilidade individual. Ele instruiu que cada pessoa deve examinar as suas próprias obras em vez de se comparar com os outros ou julgar o próximo. O texto destaca a importância de assumir a responsabilidade pelas próprias atitudes e escolhas. Paulo enfatiza que, diante das consequências e dos resultados de suas ações, cada indivíduo deve carregar o seu próprio fardo, mantendo a integridade pessoal.' WHERE "id" = 'e31686ca-b202-44d9-8ebe-021fe6c2fcdb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem partiu de casa levando todos os seus bens, mas desperdiçou tudo e acabou vivendo na miséria, cuidando de porcos. Ao reconhecer seu erro, decidiu retornar à casa do pai. Enquanto ainda estava longe, o pai o avistou na estrada e, movido por grande compaixão, correu ao seu encontro. Antes mesmo que o filho pudesse pedir perdão, o pai o abraçou calorosamente, celebrando o retorno daquele que um dia se perdeu em sua jornada solitária.' WHERE "id" = 'e3317bb7-c8db-4511-aa81-850c357bc038';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus criou um jardim exuberante repleto de árvores frutíferas e diversos animais. Após concluir a obra, o Criador chamou Adão e estabeleceu uma missão específica para ele naquele lugar. Deus entregou o jardim ao primeiro homem, ordenando que ele não apenas desfrutasse dos recursos disponíveis, mas que trabalhasse ativamente na manutenção daquele ambiente. Adão recebeu a responsabilidade de regar, guardar e zelar cuidadosamente por toda a criação, tratando com zelo e dedicação tudo o que havia recebido.' WHERE "id" = 'e345af9b-4f0a-4fe7-8da5-9fba7a165408';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que o rei Saul destruísse totalmente os amalequitas e seus bens. Contudo, Saul desobedeceu ao poupar o rei inimigo e os melhores animais, justificando sua ação como um sacrifício. Ao chegar, o profeta Samuel confrontou Saul ao ouvir o som dos rebanhos. O rei tentou se explicar, mas Samuel afirmou que a obediência é superior a qualquer oferenda. Por ignorar a instrução divina e priorizar suas próprias vontades, Saul foi rejeitado por Deus como rei de Israel.' WHERE "id" = 'e3d191c6-0803-49c4-8be2-d02eb44b7281';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O livro de Provérbios apresenta uma observação direta sobre a natureza humana ao afirmar que muitos se autoproclamam fiéis, embora encontre homens verdadeiramente confiáveis seja uma tarefa difícil. O texto destaca que o homem que vive com integridade em sua conduta cotidiana, mesmo quando está longe dos olhares públicos, estabelece uma base sólida. Consequentemente, esse padrão de retidão silenciosa torna-se um legado valioso, permitindo que seus descendentes recebam a bênção de um caráter formado por escolhas constantes.' WHERE "id" = 'e41485f1-83ea-40b3-9b07-157e66ed47f9';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias decidiu reconstruir o muro de Jerusalém, que se encontrava em ruínas. Durante a execução da obra, ele enfrentou zombarias de opositores e o desânimo de seus próprios companheiros, que temiam o fracasso. Apesar da forte resistência e do grande cansaço físico, Neemias manteve o foco e trabalhou diligentemente dia após dia. Sua persistência resultou na conclusão da restauração dos muros. Assim, a cidade de Jerusalém foi totalmente protegida e fortificada graças ao compromisso inabalável de Neemias.' WHERE "id" = 'e4221015-dc78-4d18-975d-e4e10fcc3885';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José foi visitar seus irmãos no campo, mas eles, movidos por uma intensa inveja, conspiraram contra ele. Os irmãos capturaram José e o lançaram dentro de um poço fundo e seco. Rúben tentou intervir para salvar o rapaz, porém não obteve sucesso em sua tentativa. Posteriormente, o grupo decidiu vender José a mercadores desconhecidos que passavam pelo local. Assim, José foi levado para longe de sua casa, sofrendo as consequências diretas das decisões tomadas por seus próprios irmãos.' WHERE "id" = 'e47f0701-f3e6-4e96-a933-f6ffed3d4756';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, um jovem cativo em Babilônia, recusou a dieta real composta por iguarias e vinhos do monarca. Para manter seus princípios, ele solicitou ao chefe dos eunucos uma alimentação composta apenas por legumes e água. O oficial aceitou o desafio e permitiu um período de prova de dez dias. Ao final desse tempo, Daniel e seus três amigos apresentaram uma aparência mais saudável e robusta que todos os outros jovens que consumiam a mesma porção oferecida pelo rei.' WHERE "id" = 'e4c03ff4-84be-4e56-b6e5-d1a822b88aaa';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dissipar toda a sua herança em uma vida desregrada, o filho mais novo enfrentou uma severa escassez de alimentos. Em meio à miséria, ele reconheceu sua condição e decidiu retornar à casa de seu pai. Enquanto caminhava de volta, ensaiando um pedido de perdão, o pai avistou-o de longe. Movido por grande compaixão, o pai correu ao encontro do rapaz, abraçou-o e o recebeu prontamente, marcando o fim do exílio voluntário daquele filho arrependido e transformado.' WHERE "id" = 'e4e8b88e-7a93-407f-91e2-509052b6d7b5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus instruiu seus seguidores sobre o comportamento diante do altar durante o culto. Ele estabeleceu que, se alguém estiver prestes a oferecer sua dádiva e se lembrar de que um irmão possui algo contra si, deve agir imediatamente. A ordem divina exige que o ofertante deixe sua oferta diante do altar, retire-se para se reconciliar primeiro com a pessoa ferida e somente após esse processo de restauração retorne ao lugar de adoração para apresentar sua oferta a Deus.' WHERE "id" = 'e4f0f4a1-942f-41fb-8878-076558737803';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo afundou na miséria extrema. Em um momento de profunda reflexão, ele decidiu retornar à casa de seu pai, esperando ser tratado apenas como um empregado. Enquanto ainda estava longe, seu pai correu ao seu encontro, abraçou-o e o beijou. O pai ordenou que seus servos trouxessem as melhores roupas, um anel e calçados, preparando um grande banquete para celebrar o retorno daquele que estava perdido e foi encontrado.' WHERE "id" = 'e50301ce-96ec-45e7-8ee5-f5d235f8bbe8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias liderava a reconstrução dos muros de Jerusalém quando inimigos ridicularizaram o projeto e conspiraram contra a obra. Diante das ameaças e do cansaço do povo, Neemias agiu com determinação estratégica. Ele reorganizou a equipe, distribuindo funções específicas entre os trabalhadores. Enquanto metade da força de trabalho continuava a edificar a estrutura, a outra metade permanecia armada para a defesa constante. Assim, mantendo a vigilância e a perseverança, o grupo concluiu o muro, frustrando as intenções dos adversários.' WHERE "id" = 'e5074c8f-90e2-4076-8387-9789f4912985';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, a responsabilidade de liderar a nação de Israel rumo à terra prometida recaiu sobre Josué. Diante do desafio de enfrentar povos poderosos e desconhecidos, ele sentiu medo. Deus interveio diretamente e ordenou que Josué não se apavorasse, garantindo sua presença constante. Com essa instrução divina, Josué foi convocado a agir com coragem e firmeza, mantendo-se fiel à lei dada por Moisés enquanto avançava para cumprir a missão de conduzir o povo escolhido.' WHERE "id" = 'e528c2c8-43d9-42ce-b219-e327de504abe';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte do marido de Noemi, ela pediu que suas noras retornassem às famílias de origem. Orpá obedeceu e partiu, mas Rute recusou a ordem da sogra. Com firmeza, a moabita declarou que acompanharia Noemi aonde quer que fosse e que morreria onde ela morresse. Diante da insistência resoluta de Rute, Noemi cessou os protestos e ambas seguiram juntas rumo a Belém. Essa decisão de Rute selou um compromisso de lealdade profunda entre as duas mulheres diante do futuro.' WHERE "id" = 'e54a7253-3df3-4d06-8d9b-cc92cc71e12f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias, governador de Jerusalém durante a reconstrução da cidade, deparou-se com um grave conflito social. Judeus pobres clamavam contra nobres e autoridades que exploravam seus irmãos com juros abusivos, penhorando casas e filhos. Indignado, Neemias confrontou os líderes, questionando a falta de temor a Deus em suas condutas. Ele exigiu a cessação imediata daquelas práticas opressoras e, como exemplo de liderança, abriu mão de seus próprios privilégios e direitos como governador, incentivando o povo a restaurar a justiça.' WHERE "id" = 'e57a5fd6-ae58-4f06-bc11-5dc170b097d7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'No início, toda a humanidade compartilhava um único idioma e decidiu edificar uma cidade com uma torre que alcançasse os céus para alcançar renome. O projeto avançava rapidamente devido à unidade de comunicação entre os construtores. Observando a ambição humana, Deus decidiu intervir diretamente. Ele confundiu o idioma de todos, tornando impossível o entendimento mútuo. Como resultado, a construção da torre foi interrompida imediatamente e o povo acabou sendo disperso por toda a superfície da Terra.' WHERE "id" = 'e57d0e94-2e5c-4c5d-abb1-51c62d05aad3';
UPDATE "public"."dev_lessons" SET "share_summary" = 'A formiga Mira trabalhava diariamente carregando migalhas para seu formigueiro antes da chegada do inverno rigoroso. Enquanto isso, seus amigos gafanhotos apenas pulavam e brincavam, negligenciando o armazenamento de qualquer alimento. Quando o frio finalmente chegou, o formigueiro de Mira estava abastecido e aquecido, garantindo sua sobrevivência. A formiga agiu com prudência, demonstrando que o hábito de pensar antes de agir, ouvindo os mais experientes e planejando o futuro, foi fundamental para proteger a si mesma durante a estação.' WHERE "id" = 'e60930d4-c175-4be5-b644-287490d4f25e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um pequeno passarinho decidiu deixar seu ninho pela primeira vez na vida. Ao olhar para baixo, sentiu um grande medo da altura e hesitou em saltar. A mãe pássaro posicionou-se logo abaixo, mantendo suas asas abertas e assegurando ao filhote que o seguraria caso fosse necessário. Confiando plenamente na proteção materna, o passarinho respirou fundo e pulou do ninho. O esforço foi recompensado imediatamente, pois o filhote conseguiu abrir suas asas e voar pelo céu com sucesso.' WHERE "id" = 'e609a19a-81c2-4f00-84d6-4656a538f817';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido e de seus dois filhos, Noemi decidiu retornar de Moabe para Belém. Suas noras, Orfa e Rute, a acompanharam inicialmente. Orfa despediu-se, mas Rute, apesar da perda e da dificuldade, escolheu permanecer fiel à sua sogra. Ela declarou a Noemi que a seguiria para onde quer que fosse, adotando seu povo e seu Deus como seus. Juntas, as duas mulheres viajaram para Belém, iniciando uma nova trajetória de providência divina para Rute.' WHERE "id" = 'e6a14654-0211-4aa2-89f9-a4226fa4fb27';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho decidiu abandonar o lar após receber sua parte na herança. Ele viajou para longe, gastou todos os seus bens e passou por grandes necessidades, enfrentando a fome. Arrependido, decidiu retornar à casa de seu pai para pedir perdão por seus atos. Enquanto ainda estava distante, seu pai, que o aguardava ansiosamente, correu em sua direção. Sem hesitar, o pai o abraçou afetuosamente, acolhendo o filho que retornava, mesmo após todos os seus graves erros anteriores.' WHERE "id" = 'e6b2722f-b836-4228-9acb-a9c2d3f0577b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugia de Saul, que desejava sua morte. Escondido no fundo de uma caverna, Davi viu o rei entrar sozinho sem perceber sua presença. Os soldados de Davi o incentivaram a eliminar o inimigo, declarando ser uma oportunidade enviada por Deus. Davi aproximou-se silenciosamente e cortou apenas um pedaço do manto real. Após o ato, ele sentiu um profundo remorso por ter desrespeitado o ungido do Senhor, contendo-se e impedindo que seus homens atacassem o rei Saul.' WHERE "id" = 'e6fb4733-a011-47aa-a29e-e17bdba73f52';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após perder o marido e os filhos na terra de Moabe, Noemi decidiu retornar a Belém. Ela aconselhou suas noras viúvas, Orfa e Rute, a permanecerem em suas casas para buscarem um novo futuro. Orfa despediu-se de Noemi e retornou ao seu povo. Rute, porém, recusou-se a partir e declarou lealdade absoluta à sogra, insistindo em acompanhá-la. Diante da firme determinação de Rute em segui-la e adotar seu Deus e seu povo, Noemi cessou de insistir com ela.' WHERE "id" = 'e71161b2-9f9a-4632-a25b-1dd2f9bf4353';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias, um copeiro do rei persa, recebeu notícias de que os muros de Jerusalém estavam destruídos e a cidade permanecia em ruínas. Movido por essa realidade, ele planejou silenciosamente uma solução, obteve permissão do monarca e viajou até o local. Apesar de enfrentar oposição severa, escárnios constantes e ameaças frequentes, Neemias liderou o esforço de reconstrução das muralhas. Ele manteve seu compromisso inabalável com o trabalho, enfrentando todos os desafios físicos e políticos até completar a obra necessária.' WHERE "id" = 'e7be93d2-804a-4d3d-8fba-0166dde61eec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido e de seus filhos, Noemi decidiu retornar para a cidade de Belém. Ela liberou suas noras, Orpá e Rute, para seguirem seus próprios caminhos. Orpá despediu-se e retornou ao seu povo, mas Rute recusou-se a partir. Em uma escolha deliberada e fiel, Rute decidiu acompanhar sua sogra em sua jornada incerta. Ela permaneceu ao lado de Noemi, comprometendo-se inteiramente com o destino de sua sogra, sem abandonar o caminho que trilhavam juntas até chegarem.' WHERE "id" = 'e7f495e7-67c8-4851-adbf-24df5834748e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de seu marido, Noemi, uma viúva, decidiu retornar à sua terra natal e liberou suas noras para seguirem seus próprios caminhos. Enquanto Orpá optou por partir e regressar à sua família, Rute recusou a oferta de despedida. Com firme determinação, ela escolheu permanecer ao lado de sua sogra, declarando que estaria com ela até a morte, onde quer que Noemi vivesse. Assim, Rute abandonou seu povo e seu passado para seguir fielmente Noemi rumo a Belém.' WHERE "id" = 'e84860ad-68d6-43c4-8da6-70705888c30b';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus ordenou que o rei Saul destruísse totalmente os amalequitas, sem poupar nada. Saul, porém, desobedeceu ao preservar o rei Agague e o melhor do gado, alegando intenções de sacrifício. Ao encontrar Saul, o profeta Samuel ouviu os animais e confrontou o monarca sobre sua falha. Saul tentou justificar seus atos com pretextos religiosos, mas Samuel repreendeu sua postura, enfatizando que a obediência é superior a qualquer oferenda. Aquele momento marcou a rejeição definitiva de Saul por Deus.' WHERE "id" = 'e919f788-d946-4250-9fe5-574a17f3e5b6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem viajava de Jerusalém para Jericó, quando foi interceptado por ladrões que o espancaram e o abandonaram quase morto na estrada. Um sacerdote e um levita passaram pelo local, viram o ferido, mas seguiram adiante sem prestar qualquer auxílio. Por fim, um samaritano aproximou-se, sentiu compaixão e cuidou de seus ferimentos com cuidado. Ele transportou o homem em seu próprio animal até uma hospedaria, onde pagou todas as despesas necessárias para garantir a plena recuperação daquela vítima.' WHERE "id" = 'e921f86e-2b8d-4775-8407-d1fa07579e46';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio que já existiu, registrou uma verdade fundamental sobre a comunicação humana no livro de Provérbios. Ele afirmou categoricamente que a língua possui o poder tanto de trazer a vida quanto de causar a morte. Através dessa declaração, Salomão descreveu uma realidade prática e constante, onde as palavras proferidas nunca são neutras. Elas sempre atuam como instrumentos ativos, capazes de construir relacionamentos ou provocar a destruição de reputações entre as pessoas.' WHERE "id" = 'e936ac04-ac38-4357-96fc-9dd4e352247d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel, aos dezesseis anos, foi levado cativo para a Babilônia. O rei impôs que ele e seus amigos consumissem alimentos da mesa real, contrários às suas leis. Decidido a não se contaminar, Daniel solicitou respeitosamente ao oficial responsável uma alternativa alimentar, recusando a dieta imposta. Após dez dias de dieta baseada em vegetais e água, Daniel e seus amigos apresentaram uma aparência mais saudável e robusta que os jovens que comeram das iguarias servidas pelo rei babilônico.' WHERE "id" = 'e963259f-68c6-45a8-bb16-708b788c91a8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, notável por sua sabedoria concedida por Deus, governou Israel com discernimento singular. Em suas observações sobre a vida, ele registrou o provérbio que destaca a influência direta das companhias no caráter de um indivíduo. Salomão afirmou claramente que caminhar ao lado de pessoas sábias resulta em sabedoria própria. Por outro lado, ele alertou que manter amizade com tolos traz inevitáveis danos. Essa reflexão histórica reflete como o convívio molda constantemente as escolhas humanas e seus comportamentos.' WHERE "id" = 'e976b58e-e634-4e55-8d03-00427abee1b7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Davi cometeu adultério com Bate-Seba e ordenou a morte de Urias para ocultar seu erro. O profeta Natã visitou o rei e narrou a parábola de um homem rico que roubou a única ovelha de um vizinho pobre. Indignado, Davi condenou a injustiça, mas Natã revelou que ele era o protagonista daquela história. Confrontado com a verdade de seus atos, o rei não ofereceu desculpas e admitiu perante o profeta: pequei contra o Senhor Deus.' WHERE "id" = 'e9922b14-b4f8-4ccc-aa24-01196dd2d937';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria em Israel, observou cuidadosamente o comportamento humano e as consequências das palavras proferidas. Ele constatou que uma resposta branda possui o poder de apaziguar conflitos, funcionando como água sobre um fogo iniciante. Em contrapartida, palavras rudes e agressivas intensificam as disputas, gerando destruição. Salomão concluiu que o uso prudente da língua fortalece relacionamentos, promove a resolução de problemas e atua como uma árvore de vida, produzindo frutos bons para todos.' WHERE "id" = 'e998c93e-dc89-4b5a-9969-e763dac179b5';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar toda a sua herança, o filho mais novo afundou na miséria absoluta e passou fome. Em um momento de lucidez, ele decidiu abandonar sua vida desregrada e retornar à casa de seu pai para pedir emprego como um servo. Ao iniciar a caminhada de volta, o rapaz foi avistado por seu pai enquanto ainda estava distante. Movido por profunda compaixão, o pai correu ao encontro do filho, abraçou-o calorosamente e o recebeu de volta com alegria.' WHERE "id" = 'ea15e075-89c2-4f5d-a965-c9a991381ecc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, reconhecido como o homem mais sábio da história, detinha poder, riquezas imensas e grandes conquistas militares. Ao observar a trajetória de reis, comerciantes, jovens e idosos, ele analisou a natureza humana em diversas circunstâncias da vida. Após essa profunda reflexão sobre o que verdadeiramente perdura diante do tempo e da morte, Salomão concluiu que o bom nome possui um valor superior a qualquer fortuna acumulada. Ele registrou esse princípio fundamental para orientar as futuras gerações sobre o caráter.' WHERE "id" = 'ea69ba36-4d9d-46f9-acf8-42decf9a01f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão observou que a verdadeira estabilidade dos lares não provinha de riquezas acumuladas, mas do caráter de seus governantes. Ele notou famílias que resistiam a intensas pressões enquanto outras sucumbiam diante de pequenas adversidades. A distinção fundamental entre elas não residia em talentos ou posses materiais, mas na reverência que pais e mães mantinham diante de Deus. Esse temor profundo servia como uma âncora firme, sustentando os filhos e orientando as decisões familiares durante os momentos de crises inevitáveis.' WHERE "id" = 'eacd1878-9d52-4b80-b171-cdee46887139';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão e Ló decidiram separar seus rebanhos, pois a terra era insuficiente para ambos. Abraão permitiu que Ló escolhesse primeiro o destino. Ló observou o vale fértil do Jordão, bem irrigado, e optou por aquela região, aproximando-se progressivamente da perversa cidade de Sodoma. Enquanto isso, Abraão permaneceu com as terras restantes, aceitando o que sobrou após a decisão de seu sobrinho. Assim, cada um seguiu seu próprio caminho, estabelecendo suas moradias em locais distintos conforme a escolha feita.' WHERE "id" = 'eaf38796-7fd1-4df2-8bfa-5864e651ecb4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, o jovem Daniel enfrentou um desafio direto quando o rei ordenou que ele consumisse as mesmas iguarias da corte real. Recusando-se a violar suas convicções, Daniel propôs ao responsável um teste prático de dez dias, substituindo a comida servida por vegetais e água. Após esse período, Daniel e seus amigos apresentaram uma aparência mais saudável e robusta que todos os outros jovens que haviam aceitado a dieta do rei, provando a eficácia da escolha.' WHERE "id" = 'eb079864-830a-4ca6-bd3b-4d57805a767a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta à igreja de Filipos enquanto permanecia acorrentado dentro de uma prisão romana, sem qualquer certeza sobre o seu futuro. Mesmo sob a pressão da iminente execução e das condições precárias de seu cativeiro, ele direcionou um conselho específico aos membros da comunidade livre. Paulo instruiu os crentes a demonstrarem moderação diante de todos os homens, enfatizando que esse comportamento era essencial para preservar os laços relacionais, mesmo em meio a situações adversas.' WHERE "id" = 'eb0a7b24-fc07-4840-a164-cc2e72a15ead';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué recebeu a difícil missão de conduzir o povo de Israel rumo à terra prometida. Ele enfrentaria nações poderosas e territoriais, vivenciando um momento de grande incerteza sobre como liderar o povo diante de obstáculos monumentais. Nesse contexto, Deus ordenou diretamente a Josué que fosse forte e corajoso. O Criador garantiu que estaria presente com ele em cada passo da jornada, assegurando que o seu auxílio seria maior que qualquer desafio encontrado na conquista.' WHERE "id" = 'eb35d77b-ab4b-45f3-8240-a8008abac7f4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus observava atentamente as pessoas que depositavam suas ofertas no templo de Jerusalém. Enquanto os ricos lançavam grandes quantias com naturalidade, uma viúva pobre aproximou-se e ofertou duas pequenas moedas. Jesus destacou o gesto daquela mulher, afirmando aos seus discípulos que ela havia contribuído com mais do que todos os outros. Enquanto os demais ofertaram apenas o que lhes sobrava da abundância, a viúva entregou tudo o que possuía para o seu próprio sustento, demonstrando total entrega.' WHERE "id" = 'eb4dade7-7f50-49ed-af8f-1b5aac8b41c8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos cristãos de Filipos enquanto estava encarcerado. Enfrentando condições difíceis, incertezas e o risco constante em sua prisão, ele instruiu os fiéis sobre como lidar com as aflições. Paulo orientou que não deveriam se render à ansiedade, mas apresentar todos os seus pedidos a Deus por meio de orações e súplicas com ações de graças. Como resultado, a paz divina, que excede todo o entendimento, guardaria os corações e mentes daqueles que creem.' WHERE "id" = 'eb67af82-e5e0-4900-92ef-28664eb1a4f8';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar toda a sua herança em uma terra distante, o filho pródigo enfrentou a fome severa. Percebendo sua condição deplorável, ele decidiu retornar à casa de seu pai para pedir perdão. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o e o beijou afetuosamente. Ele ordenou aos seus servos que trouxessem a melhor veste, um anel e sandálias para o rapaz, preparando um grande banquete para celebrar o retorno do filho arrependido.' WHERE "id" = 'ebe83357-165a-4104-b8f1-9f8014bbbe53';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar toda a sua herança vivendo sem limites, o filho pródigo enfrentou a escassez e a solidão. Reconhecendo seus erros com honestidade, ele decidiu retornar à casa de seu pai. Ao se aproximar, assumiu sua culpa e pediu para ser tratado como um servo. O pai, avistando-o de longe, correu ao seu encontro com compaixão. Antes que o filho terminasse seu pedido de perdão, o pai o acolheu prontamente, restaurando sua posição e celebrando seu retorno imediato.' WHERE "id" = 'ec5d6e5f-4eec-47fe-8812-b74639c904c1';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem retirou sua herança e partiu de casa, desperdiçando todos os seus bens em uma vida distante. Diante da miséria e da fome, ele reconheceu seu erro e decidiu retornar ao lar paterno para pedir perdão. Enquanto o filho ainda estava longe, seu pai, movido por compaixão, correu ao seu encontro. O pai o abraçou afetuosamente, celebrando seu retorno com alegria. Assim, o filho foi acolhido de volta à família, encerrando sua jornada de afastamento e grande arrependimento.' WHERE "id" = 'ece59bf2-ccae-401a-9ded-edcfe9dd8fc4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos os súditos de seu reino se prostrassem diante de uma estátua de ouro. Sadraque, Mesaque e Abede-Nego recusaram a ordem, mantendo-se firmes em sua decisão diante da multidão que obedecia ao monarca. Confrontados pelo rei e pela ameaça da fornalha ardente, os três jovens declararam abertamente que não adorariam deuses estranhos. Eles afirmaram que, mesmo que Deus não os livrasse do fogo, não se curvariam diante da imagem que o rei levantou.' WHERE "id" = 'ed030b61-e80c-4811-a49e-7403acb12931';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu sua parte na herança ao pai, partiu para uma terra distante e dissipou todos os bens vivendo de forma desregrada. Após enfrentar uma severa escassez, ele passou fome e desejou alimentar-se com a comida dos porcos. Decidido a retornar, o jovem voltou para casa, planejando pedir perdão. Avistando-o de longe, o pai correu ao seu encontro, abraçou-o com grande alegria e ordenou uma festa imediata para celebrar o retorno daquele que estava perdido.' WHERE "id" = 'ed31a386-a14e-4e03-a2c7-9699f58fe915';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um jovem filho recebeu sua herança, partiu para terras distantes e desperdiçou todos os seus bens vivendo de forma desenfreada. Após enfrentar uma severa escassez e fome extrema, ele reconheceu seus erros e decidiu retornar à casa de seu pai. Ao avistá-lo ainda longe, o pai, tomado por uma profunda compaixão, correu ao seu encontro. Antes que o rapaz concluísse seu pedido de perdão, o pai o abraçou afetuosamente, celebrando o retorno de seu filho arrependido.' WHERE "id" = 'ed3ae9db-03f7-4764-bb82-830171a3761d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após gastar todos os seus bens vivendo de forma inconsequente, o filho pródigo enfrentou a miséria e a fome. Em um momento de profunda reflexão, ele decidiu abandonar sua condição atual e retornar à casa do pai. Ao chegar, confessou abertamente seus erros, assumindo total responsabilidade por suas escolhas. O pai, que aguardava ansiosamente por seu retorno, avistou-o de longe. Sem esperar o fim do pedido de perdão, ele correu ao encontro do filho, recebendo-o com grande alegria.' WHERE "id" = 'ed4d89c7-60df-459c-a5a9-9dd7b4e9d000';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança em terras distantes, o filho pródigo enfrentou uma fome severa e finalmente caiu em si. Decidido a mudar, ele abandonou sua vida de erros e iniciou o caminho de volta para a casa de seu pai. Enquanto se aproximava, ainda preparando um discurso de rendição, o pai avistou o rapaz de longe. Ele correu ao seu encontro, acolhendo o filho com um abraço imediato, restaurando sua dignidade e interrompendo qualquer hesitação.' WHERE "id" = 'ed561735-d234-428a-91de-e1429398b003';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após dilapidar sua herança em um país distante, o filho mais novo enfrentou uma severa escassez e decidiu retornar à casa de seu pai. Mesmo carregando o peso de sua ruína, ele caminhou de volta com a intenção de pedir perdão. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o e ordenou a seus servos que vestissem o jovem com as melhores roupas e preparassem um banquete festivo para celebrar o seu retorno seguro.' WHERE "id" = 'ed731cf1-fccf-4072-a086-5c185329b314';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após perder o marido e os filhos na terra de Moabe, Noemi decidiu retornar para Belém e liberou suas noras, Orpá e Rute, de quaisquer obrigações. Orpá despediu-se e partiu, mas Rute recusou-se a abandonar a sogra. Com profunda determinação, Rute declarou que o povo de Noemi seria o seu povo e o seu Deus seria o seu Deus. Elas seguiram juntas a viagem rumo a Belém, consolidando um pacto de lealdade inabalável entre as duas mulheres naquele momento difícil.' WHERE "id" = 'edb4ecf3-0499-456f-8593-1271e834f6dc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel foi levado cativo para a Babilônia, onde o rei ordenou que consumisse iguarias que contrariavam suas convicções religiosas. Diferente dos outros jovens que aceitaram a dieta real, Daniel posicionou-se com firmeza e propôs um teste ao guarda responsável. Ele e seus três companheiros alimentaram-se apenas de vegetais e água durante dez dias. Ao final do período, apresentavam uma aparência mais saudável e robusta que os demais, provando que sua escolha fundamentada na obediência divina trouxe resultados superiores.' WHERE "id" = 'edc945da-d355-4488-a720-664cf1c1fa52';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José tinha dezessete anos quando seus irmãos o avistaram ao longe e planejaram matá-lo. Eles discutiram intenções cruéis e alimentaram o ódio entre si através de conversas constantes. Após convencerem uns aos outros, desistiram do homicídio direto, mas decidiram agir com maldade. Quando uma caravana de ismaelitas passou pelo caminho, os irmãos retiraram José da cisterna onde o mantinham preso e o venderam como escravo por vinte moedas de prata, enviando-o para o Egito contra sua própria vontade.' WHERE "id" = 'ee8bfb71-7d8d-4fec-8473-9632d97f731f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'José trabalhava na casa de Potifar, um oficial egípcio, quando passou a ser constantemente assediado pela esposa de seu senhor. Embora ela o pressionasse diariamente para que deitassem juntos, José recusou todas as investidas, recusando-se a pecar contra o seu patrão e contra Deus. Em um momento de insistência, a mulher agarrou José por sua capa, mas ele a deixou para trás e fugiu apressado para fora. Por causa desse evento, José enfrentou falsas acusações e acabou preso.' WHERE "id" = 'eef31058-523b-4522-b912-b63f9961df1a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus narrou a história de um administrador que, ao ser acusado de desperdiçar os bens do seu senhor, precisou prestar contas de sua gestão. Sabendo que perderia o cargo, o homem agiu de forma astuta e desonesta para garantir seu futuro. Ele chamou os devedores do seu patrão e reduziu as dívidas de cada um, visando conquistar apoio para quando fosse demitido. Essa atitude visava assegurar que outras pessoas o recebessem em suas casas após perder o emprego.' WHERE "id" = 'ef4fbcb3-4fbb-407e-911a-facbadc8fa1d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Uma ovelha vivia tranquilamente no campo sob os cuidados de seu pastor. Certo dia, outras ovelhas a convidaram para fugir do caminho correto, alegando que seria divertido e passaria despercebido. Sentindo o perigo, a ovelha pequena recusou o convite e escolheu permanecer ao lado do pastor. Ao anoitecer, as ovelhas que se afastaram retornaram assustadas e arrependidas. O pastor as recebeu com gentileza, enquanto a ovelha que permaneceu fiel a ele terminou o dia em total segurança.' WHERE "id" = 'efa3d93b-ed3b-4ff9-943e-055a8320ab8f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi encontrava-se em uma situação de extremo perigo ao buscar refúgio em um território estrangeiro. Para preservar sua própria vida diante do rei Abimeleque, o futuro monarca de Israel precisou fingir insanidade. Enquanto estava sob essa humilhação forçada, ele não apenas buscou o livramento divino, mas escolheu entoar cânticos de adoração a Deus. Mesmo diante do medo e da fragilidade, Davi elevou sua voz em louvor, reconhecendo a soberania do Criador em meio à sua aflição pessoal e incerteza.' WHERE "id" = 'efcca292-9760-42f8-af04-af0d981e8113';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O livro de Provérbios registra a sabedoria acumulada por gerações em Israel sobre o uso das palavras. O texto descreve o comportamento do insensato, que fala impulsivamente, em contraste com o homem prudente, que filtra seus pensamentos e escolhe cuidadosamente o que dizer. Na cultura israelita, os anciãos respeitados eram aqueles que dominavam o silêncio estratégico. Assim, a confiança da comunidade dependia da capacidade de indivíduos ponderarem cada declaração feita, evitando discursos apressados que pudessem comprometer a integridade coletiva.' WHERE "id" = 'f01474a7-76b2-43c9-814e-960ae55d6a22';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O filho que desperdiçou seus bens passou fome enquanto cuidava de porcos. Ao refletir sobre sua condição, ele decidiu retornar à casa de seu pai para confessar o erro. Sem inventar desculpas, levantou-se e iniciou a longa caminhada de volta. O pai, avistando-o de longe, correu ao seu encontro com compaixão antes mesmo que o rapaz terminasse sua confissão. O jovem foi prontamente acolhido, marcando o momento decisivo de sua restauração após o período de total abandono.' WHERE "id" = 'f0539362-311a-41fe-bb10-413810378252';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o sábio monarca que governou Israel, descreveu a vulnerabilidade das cidades antigas desprovidas de muralhas protetoras. Ele observou que uma localidade sem tais defesas tornava-se um alvo indefeso, permitindo a entrada imediata de exércitos inimigos para o saque e a destruição total. Ao utilizar essa imagem estratégica, o rei comparou a fragilidade desses territórios expostos à condição daqueles indivíduos que falham em governar a si mesmos, tornando-se suscetíveis a qualquer impulso, fraqueza ou provocação externa enfrentada no cotidiano.' WHERE "id" = 'f1044ecb-e869-4c6f-9a0c-39b2187c605e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua sabedoria, ensinou que a companhia influencia diretamente o caráter e o destino das pessoas. Ele ilustrou essa verdade comparando o comportamento de um passarinho que convivia com águias e alcançava grandes altitudes. Contudo, ao passar a andar com aves que preferiam voos rasos e comportamentos desordenados, o pássaro perdeu sua habilidade de voar alto. Assim, o texto bíblico estabelece o princípio de que as amizades moldam a vida e as escolhas futuras.' WHERE "id" = 'f19c0c06-809f-4c69-8612-fed0f27b5e44';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, Daniel recusou comer as iguarias do rei para manter sua fidelidade a Deus. Ele propôs ao oficial responsável um teste de dez dias, consumindo apenas vegetais e água. O oficial aceitou o desafio e submeteu Daniel e seus três companheiros à dieta proposta. Ao final do período, os jovens apresentavam uma aparência mais saudável e robusta que os demais, que se alimentaram das porções reais. Assim, Daniel manteve seus princípios perante a corte babilônica.' WHERE "id" = 'f1b0e0fb-fe68-4958-bd1d-ed86fc142239';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi cometeu adultério e arquitetou o assassinato de Urias, ocultando seus graves pecados por meses. Após ser confrontado pelo profeta Natã, o rei reconheceu sua culpa diante de Deus. Ele não tentou justificar suas ações ou negociar com o Senhor, mas confessou abertamente seus atos e pediu purificação sincera. Em um momento de profunda humilhação, Davi ofereceu a Deus um espírito contrito e um coração arrependido, reconhecendo sua total dependência do perdão divino para ser restaurado em sua alma.' WHERE "id" = 'f1dbfdf3-93e8-4620-9265-3d0975ad7acb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Adão e Eva viviam no Jardim do Éden, onde desfrutavam de comunhão plena com Deus. Seduzidos pela serpente, ambos decidiram desobedecer à ordem divina e comeram o fruto da árvore proibida. Ao serem confrontados pelo Criador sobre o ato, a honestidade deu lugar à transferência de culpa. Adão culpou Eva por sua atitude, enquanto ela responsabilizou a serpente pelo engano. O casal evitou assumir a responsabilidade direta pelo erro, resultando em uma mudança definitiva na natureza de seu relacionamento.' WHERE "id" = 'f2c54b65-4077-49fa-b16d-5433eecd64cc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Preso em uma cela romana e acorrentado, o apóstolo Paulo aguardava um julgamento que poderia resultar em sua morte. Mesmo diante da incerteza sobre o futuro, ele redigiu uma carta aos filipenses. Nela, o apóstolo instruiu os destinatários a não se angustiarem com circunstância alguma. Em vez do desespero, ele apresentou a oração como resposta ao sofrimento. Como resultado, Paulo garantiu que a paz de Deus, que excede todo o entendimento, guardaria os corações e mentes de todos os cristãos.' WHERE "id" = 'f32b7df2-77b7-4d39-9a46-6b439d270f57';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido como o homem mais sábio que já existiu, observou profundamente o impacto das companhias no caráter humano. Ele registrou o princípio de que caminhar ao lado de pessoas sábias conduz à sabedoria, enquanto a associação com os tolos resulta inevitavelmente em prejuízo. Como alguém que valorizava o discernimento, Salomão comparou a influência das amizades a uma tinta que colore o papel. Por isso, ele selecionava cautelosamente quem permanecia ao seu redor em sua jornada.' WHERE "id" = 'f39deef4-a15a-4d6a-9c7c-dff0023a3879';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um filho pediu ao pai a sua parte da herança e partiu para uma terra distante, onde desperdiçou todos os seus bens vivendo de modo inconsequente. Após enfrentar uma severa escassez e miséria, decidiu retornar à casa paterna para pedir perdão. Ao vê-lo aproximar-se ainda de longe, o pai correu ao seu encontro, abraçou-o e o beijou com profunda alegria. O pai então ordenou que preparassem uma grande festa para celebrar o retorno do seu filho.' WHERE "id" = 'f3c06230-0fe2-4012-b0db-3dbd4f81f551';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que Sadraque, Mesaque e Abednego se curvassem diante de uma grande estátua de ouro, sob a ameaça de serem lançados em uma fornalha ardente caso desobedecessem. Diante da imposição do monarca, os três jovens hebreus recusaram-se firmemente a adorar o ídolo. Eles declararam ao rei que não precisavam se defender, pois Deus era capaz de livrá-los. Mesmo sob risco de morte, escolheram manter sua integridade e não se curvaram diante da imagem construída pelo rei.' WHERE "id" = 'f41907f4-5b05-48a4-a830-8e45e31250eb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da terra, refletiu sobre a natureza do excesso na vida humana. A partir de suas observações, ele utilizou a metáfora do mel para ilustrar um princípio fundamental. Salomão constatou que ingerir mel em demasia provoca náuseas e vômitos. Da mesma forma, ele observou reis e figuras poderosas que ruíram ao buscar fama, prazer ou poder sem limites. O rei concluiu que a moderação é um elemento essencial para preservar a integridade diante das tentações.' WHERE "id" = 'f55777f5-4616-499a-9a59-04fc5e413f2c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Neemias liderava a reconstrução dos muros de Jerusalém enfrentando forte oposição dos inimigos, que ridicularizavam o trabalho e ameaçavam atacar a cidade. O povo enfrentava exaustão diante das tensões constantes e dos rumores externos. Para garantir a segurança e o progresso da obra, Neemias organizou os trabalhadores em dois grupos distintos: metade dedicava-se à construção das muralhas, enquanto a outra metade permanecia armada em vigilância. Graças a essa estratégia de proteção e foco, o muro foi finalmente concluído.' WHERE "id" = 'f57ab870-fc6c-40dd-9851-66eab5859958';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de uma grande estátua de ouro, sob pena de morte. Sadraque, Mesaque e Abede-Nego recusaram a ordem, afirmando que não adorariam outros deuses. Por causa dessa negativa, o monarca mandou lançá-los em uma fornalha ardente. Milagrosamente, os três homens sobreviveram ao fogo intenso, saindo ilesos e sem qualquer cheiro de fumaça em suas vestes. Esse evento marcou a preservação de suas vidas diante da exigência real por adoração idólatra.' WHERE "id" = 'f6109ba4-fde9-45e8-a8df-e80b03a97b2d';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi, um jovem pastor, decidiu enfrentar o gigante Golias, que intimidava os soldados israelitas no campo de batalha. Enquanto os guerreiros temiam o oponente, Davi recordou suas vitórias anteriores contra um leão e um urso. Armado apenas com uma funda e cinco pedras lisas, o jovem avançou contra o filisteu. Ele lançou uma pedra que atingiu a testa de Golias, levando o gigante ao chão. Sem espada, Davi triunfou sobre o inimigo e garantiu uma grande vitória.' WHERE "id" = 'f63c640d-f948-4f0a-9de6-49e3f4d9bcb4';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jó era um homem de caráter inabalável que vivia com integridade. De forma repentina, ele enfrentou uma sucessão de tragédias severas, perdendo todos os seus rebanhos, servos e seus dez filhos em um único dia. Diante da destruição absoluta de seus bens e de sua família, Jó não amaldiçoou a Deus. Em vez disso, ele prostrou-se no chão, aceitou a dor da perda irreparável e declarou que o nome do Senhor deveria ser bendito, apesar de tudo o ocorrido.' WHERE "id" = 'f68db836-c0df-4d21-bdd2-cf11504f5fd0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O apóstolo Paulo escreveu uma carta aos coríntios abordando a prática da generosidade cristã. Ele estabeleceu o princípio de que a colheita é proporcional à semeadura realizada por cada fiel. Paulo enfatizou que a contribuição não deve ser feita por obrigação ou pressão externa, mas por uma decisão deliberada do coração. Assim, o autor reforçou que Deus ama aquele que dá com alegria, pois a generosidade reflete uma convicção interior e a confiança total na providência divina e abundante.' WHERE "id" = 'f6ef35ba-c295-4668-9f0d-b2ca9a4e4943';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Dez homens leprosos avistaram Jesus e suplicaram por misericórdia mantendo distância conforme a lei. Ao serem instruídos por Ele a se apresentarem aos sacerdotes, todos foram curados durante o trajeto. Apenas um homem, um samaritano, retornou imediatamente para glorificar a Deus em voz alta e prostrar-se aos pés de Jesus com gratidão. Diante disso, o Mestre questionou o paradeiro dos outros nove, já que todos haviam sido purificados, mas somente aquele estrangeiro reconheceu a origem do milagre recebido.' WHERE "id" = 'f7999c2a-3710-4f77-9699-b30f2aff46cf';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado à Babilônia, o jovem Daniel enfrentou pressões para consumir os alimentos da mesa real, contrariando suas convicções. Em vez de ceder como a maioria, Daniel propôs ao chefe dos eunucos um período de teste de dez dias, alimentando-se apenas de vegetais e água. Ao fim desse prazo, Daniel e seus amigos apresentavam aparência mais saudável e robusta que os jovens que comeram das iguarias do rei. Assim, eles permaneceram fiéis às suas leis dietéticas sob supervisão babilônica.' WHERE "id" = 'f79b1726-a640-495e-a8b1-16ab192c610a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desobedecerem a ordem divina e comerem do fruto proibido, Adão e Eva esconderam-se no jardim. Quando Deus chamou Adão e questionou se ele havia comido da árvore proibida, o homem respondeu que a mulher, dada por Deus, o induzira ao erro. Em seguida, o Senhor perguntou a Eva o motivo de sua ação, e ela prontamente transferiu a culpa para a serpente, alegando que o animal a enganou. Assim, ambos esquivaram-se de assumir a responsabilidade direta pelo ato.' WHERE "id" = 'f8290849-1e48-48ca-a9b4-cad38325f583';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Na véspera de sua morte, Jesus levantou-se da mesa, amarrou uma toalha na cintura e lavou os pés de cada um de seus discípulos. Pedro resistiu inicialmente ao gesto, mas Jesus o corrigiu, afirmando ser necessário para manter comunhão com Ele. Após lavar os pés de todos, inclusive do traidor, Jesus retornou ao seu lugar. Ele explicou aos doze que, como Mestre, havia servido, estabelecendo o exemplo para que seus seguidores repetissem o mesmo ato de serviço humilde.' WHERE "id" = 'f844e7f3-b13b-4d6f-b496-5c5c715aed3a';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Salomão, o homem mais sábio da história, recebeu de Deus a capacidade de discernir sobre a vida. Observando o comportamento humano, ele escreveu que o mel deve ser consumido apenas o suficiente para evitar o vômito causado pelo excesso. Apesar dessa sabedoria, o próprio rei negligenciou seus conselhos. Ao multiplicar esposas e aliar-se a ídolos estrangeiros, Salomão permitiu que seus apetites internos descontrolados prevalecessem. Assim, o monarca que conhecia a teoria acabou por destruir sua própria trajetória pessoal.' WHERE "id" = 'f86ee0b2-35f3-4241-9634-5c6b26757eba';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi cuidava das ovelhas de seu pai no campo quando um urso atacou o rebanho. Apesar do medo natural, o jovem enfrentou o animal feroz para proteger os animais. Anos mais tarde, diante do gigante Golias, que intimidava todo o exército de Israel, Davi recordou sua vitória sobre o urso. Confiante na proteção divina, ele não recuou diante da ameaça. O pastor superou o temor, posicionou-se contra o guerreiro filisteu e preparou-se para enfrentar o grande desafio adiante.' WHERE "id" = 'f87a2e07-cbc9-42e9-82e4-6f4dd4c21baf';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo escreveu uma carta à comunidade cristã de Colossos, composta por diversos grupos sociais e culturais como judeus, gregos, escravos e homens livres que conviviam sob o mesmo teto espiritual. Diante das inevitáveis tensões daquela convivência, ele instruiu esses fiéis a se revestirem de misericórdia, bondade, humildade e mansidão. O apóstolo enfatizou a necessidade prática de suportarem uns aos outros com paciência e de perdoarem qualquer queixa existente entre eles, fortalecendo assim a unidade daquele grupo específico.' WHERE "id" = 'f882cc99-b294-4e7e-b5a2-4a506df85c0f';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel enfrentou o desafio de consumir a porção de alimentos oferecida pelo rei. Determinado a não se contaminar, ele propôs a Aspenaz um teste de dez dias, consumindo apenas legumes e água. Após o período estipulado, a aparência de Daniel e de seus três amigos tornou-se visivelmente melhor e mais saudável do que a dos jovens que ingeriram a dieta real. Assim, o encarregado permitiu que continuassem com sua alimentação específica.' WHERE "id" = 'f969ec3a-4624-43d4-aae7-719c2c4dd119';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Enquanto Neemias liderava a reconstrução dos muros de Jerusalém, seus adversários tentaram interromper a obra por meio de convites insistentes para reuniões. Sanbalate e Gesém enviaram mensagens repetidas, buscando atraí-lo para o campo com intenções maliciosas. Percebendo a armadilha, Neemias recusou cada convocação, respondendo prontamente que estava ocupado com um grande projeto e não poderia descer. Apesar das pressões e rumores fabricados contra ele, Neemias manteve o foco na construção, ignorando as tentativas de distração dos seus inimigos.' WHERE "id" = 'f9ebd5b3-2a25-46e4-b593-c48793eba3de';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Saul perseguia Davi com seu exército pelo deserto. Ao entrar sozinho em uma caverna para descansar, não percebeu que Davi e seus homens estavam escondidos no local. Os companheiros de Davi sugeriram que ele matasse o rei, mas Davi apenas cortou a ponta do manto de Saul secretamente. Após Saul sair, Davi apresentou o pedaço de tecido, revelando que teve a oportunidade de feri-lo, mas escolheu poupar sua vida, declarando que sua mão não se voltaria contra ele.' WHERE "id" = 'fa32de29-0896-46d8-ac39-d47ea20c7932';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Um homem foi atacado, roubado e abandonado à beira da morte na estrada. Dois líderes religiosos passaram pelo local e ignoraram a vítima. Em seguida, um samaritano aproximou-se, tratou os ferimentos do homem com óleo e vinho e o colocou sobre seu próprio animal. Ele o levou a uma hospedaria, cuidou dele e pagou as despesas da estadia. Além disso, o samaritano prometeu ao estalajadeiro reembolsar qualquer custo adicional que surgisse durante o período de recuperação daquela pessoa.' WHERE "id" = 'fa54e49a-4adf-4f0d-a47f-0272ebbc9c4e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia, Daniel recusou-se a consumir as iguarias oferecidas pelo rei, pois desejava manter-se fiel aos seus princípios. Ele propôs ao chefe dos eunucos um período de teste de dez dias, alimentando-se apenas de legumes e água, em vez da dieta real. Ao final desse prazo, Daniel e seus três companheiros apresentavam uma aparência mais saudável e robusta que os outros jovens que ingeriam a comida servida pelo rei. Assim, eles mantiveram sua dieta específica.' WHERE "id" = 'fa6a5ae2-f7ab-49bf-b674-d94c00c36206';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ordenou que todos se curvassem diante de sua imensa estátua de ouro, sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abede-Nego foram convocados para realizar tal ato publicamente. Diante da pressão de todo o império, os três homens recusaram firmemente a ordem real. Eles declararam que não precisavam responder ao rei sobre a decisão. Sem ceder, mantiveram sua posição inabalável enquanto enfrentavam a ameaça direta de serem lançados vivos ao fogo intenso.' WHERE "id" = 'fc0056d5-41a3-481b-8e6d-3f7a307fd7ef';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O fazendeiro prepara a terra e planta uma semente na umidade do solo. Ele dedica tempo para regar o terreno e aguarda pacientemente pelo desenvolvimento da plantação, sem remover o solo para verificar o crescimento. O agricultor confia no ciclo da natureza enquanto a chuva cai e o sol aquece o campo. Finalmente, após esse período de espera indispensável, o broto verde rompe a superfície. Tiago utiliza esse exemplo agrícola para ilustrar a importância da paciência diante do tempo.' WHERE "id" = 'fc0130c7-3f26-4b7a-87df-4cd5ea9d7f30';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei proibiu qualquer oração que não fosse dirigida a ele, estabelecendo a cova dos leões como punição. Daniel, ciente do decreto e das consequências fatais, recusou-se a interromper seus costumes. Ele retirou-se para o seu quarto, abriu as janelas voltadas para Jerusalém e ajoelhou-se para orar três vezes ao dia, conforme sua prática habitual. Daniel manteve sua fidelidade a Deus e sua rotina de devoção, mesmo sabendo que estava sendo vigiado por aqueles que buscavam sua ruína política.' WHERE "id" = 'fc1557e6-e1a5-442c-9a3a-523731d381e7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Salomão, reconhecido por sua profunda sabedoria, dirigiu orientações fundamentais ao seu filho para guiar o comportamento diário. Ele instruiu que o jovem mantivesse o olhar fixo exclusivamente à frente, evitando distrações laterais. Além disso, o monarca enfatizou a necessidade de manter os pés firmes no caminho correto, seguindo uma trajetória de retidão. Essas instruções visavam consolidar uma vida íntegra, estabelecendo passos constantes e deliberados, garantindo que o jovem permanecesse fiel a um rumo preciso e determinado.' WHERE "id" = 'fc57b1a5-f8ce-4227-a5d3-b2b75c384572';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Paulo encontrava-se preso em uma cela romana, aguardando sua iminente execução. De lá, ele escreveu uma carta endereçada a Timóteo, um jovem líder que demonstrava sinais de hesitação e medo diante das crescentes pressões ministeriais. O apóstolo, reconhecendo o chamado e os dons espirituais do rapaz, buscou encorajá-lo. Ele afirmou categoricamente que Deus não concedeu um espírito de covardia, mas de poder, amor e moderação, instando Timóteo a não recuar, mas a permanecer firme em sua missão designada.' WHERE "id" = 'fc71b9fa-fb40-462e-9466-af5a31a405e6';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após esbanjar sua herança em terras distantes, o filho mais novo enfrentou a miséria cuidando de porcos. Em meio à fome, ele reconheceu seus erros e decidiu retornar à casa do seu pai para pedir perdão. Ao se levantar e iniciar a caminhada de volta, foi avistado pelo pai, que correu ao seu encontro. Antes mesmo de receber explicações detalhadas, o pai o acolheu com um abraço caloroso, celebrando o retorno daquele que estava perdido e finalmente voltou.' WHERE "id" = 'fc76b386-735d-4181-af1b-3537fe6a4102';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Moisés, Josué assumiu a liderança de Israel em um momento de transição decisivo. Diante da nação que aguardava atravessar a fronteira para a Terra Prometida, Josué recebeu orientações diretas de Deus. O Senhor ordenou que ele fosse forte e corajoso para conduzir o povo, garantindo sua presença constante durante toda a jornada. Sem manuais ou antecessores, Josué recebeu a incumbência divina de liderar os israelitas, fundamentando sua nova autoridade na obediência total à palavra revelada.' WHERE "id" = 'fc9eabc7-08df-4c68-b01c-8c6e3b953a19';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Tiago escreve às comunidades cristãs diante de um cenário marcado por promessas quebradas, conflitos internos e pressões externas. Ele instrui os fiéis sobre a importância fundamental da integridade no discurso cotidiano. O apóstolo determina que o sim deve ser sim e o não deve ser não, rejeitando o uso de juramentos solenes ou performances de honra. A mensagem destaca que a necessidade de jurar revela a falta de peso da palavra e exige coerência entre afirmações e ações.' WHERE "id" = 'fcac3298-d34c-45f0-b8f3-cd1f36191241';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Diante da imposição do rei Nabucodonosor para que todos adorassem uma estátua de ouro, a maioria da multidão se curvou. Entretanto, Sadraque, Mesaque e Abede-Nego permaneceram de pé, recusando a ordem real sob a ameaça de serem lançados em uma fornalha ardente. Confrontados pelo monarca sobre a desobediência, os três jovens declararam firmemente que seu Deus era capaz de livrá-los, mas, ainda que isso não ocorresse, eles jamais adorariam ídolos ou prestariam reverência à imagem que o rei erigira.' WHERE "id" = 'fd21c6c8-46c3-4b5d-bc9c-88dd8f3b9fb7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Adão e Eva viviam em um belo jardim, onde Deus lhes deu tudo, exceto o fruto de uma árvore específica. Desobedecendo à ordem divina, ambos comeram o fruto proibido. Ao ouvirem a voz de Deus no jardim, o casal sentiu medo e escondeu-se atrás das árvores. Quando Deus perguntou onde estavam, eles foram confrontados por sua transgressão. Adão e Eva tentaram ocultar o erro, mas a presença do Criador revelou a verdade sobre o que haviam feito ali.' WHERE "id" = 'fd782a4b-1e16-4dc2-99c5-71e8b2e6cbcc';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Levado cativo à Babilônia aos dezesseis anos, Daniel enfrentou a pressão de consumir as iguarias oferecidas pelo rei. Decidido a manter sua fidelidade, ele propôs ao chefe dos eunucos um teste prático de dez dias, alimentando-se apenas de vegetais e água. Após o período determinado, Daniel e seus três companheiros apresentaram uma aparência mais saudável e robusta que os jovens que comeram da porção real. Assim, o supervisor permitiu que eles continuassem com sua dieta específica durante o cativeiro.' WHERE "id" = 'fe5a7532-0b0b-43e1-b267-b806965d224c';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Daniel vivia longe de sua terra natal, em um país estrangeiro onde ninguém conhecia seus antecedentes familiares. Mesmo em um ambiente distante e sem a vigilância de seus pais, o jovem manteve sua integridade constante. Diariamente, ele agia com honestidade, gentileza e fidelidade aos seus princípios religiosos, independentemente de quem estivesse observando. Com o passar do tempo, o rei e todo o seu reino notaram uma distinção em seu comportamento, revelando publicamente a solidez do caráter cultivado em segredo.' WHERE "id" = 'fe5a776e-61a4-4db6-82f8-6739753bcbeb';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Deus estabeleceu uma ordem precisa na criação, onde cada ser compreende seu papel e tempo. O sol nasce no momento certo, o pássaro canta conforme a natureza, e o filhote de leão aprende a obedecer ao rugido do pai. O animal segue essa voz protetora por confiar que o progenitor identifica perigos invisíveis. Salomão, reconhecido como o homem mais sábio da história, compreendeu essa dinâmica fundamental e declarou que o temor a Deus constitui o princípio de todo conhecimento.' WHERE "id" = 'fea4b109-031d-4e3d-a0ea-70f1ab334534';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo encontrou-se na miséria extrema, alimentando-se da comida destinada aos porcos. Reconhecendo sua condição, ele decidiu retornar à casa de seu pai para pedir perdão e ser tratado como um simples empregado. Enquanto ainda estava longe, seu pai avistou o jovem caminhando. Movido por profunda compaixão, o pai correu ao encontro do filho, abraçou-o calorosamente e o beijou, acolhendo-o antes mesmo de ouvir o pedido de desculpas ensaiado.' WHERE "id" = 'feb2bc8b-b801-44df-b68b-24269b988912';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após desperdiçar toda a sua herança, o filho mais novo enfrentou fome e profunda humilhação em uma terra distante. Ao cair em si, reconheceu seu erro e decidiu retornar à casa de seu pai como um servo arrependido. Enquanto ainda estava longe, seu pai avistou o jovem, correu ao seu encontro e o recebeu com compaixão. Sem deixar o filho concluir seu discurso, o pai o abraçou, restaurando sua dignidade e encerrando o período de separação familiar.' WHERE "id" = 'fec8ea0d-a53c-47e7-9b48-8b0d415092d0';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Abraão recebeu o chamado de Deus para deixar sua terra natal e partir rumo a uma região desconhecida que ele receberia como herança. Obedecendo prontamente à ordem divina, o patriarca iniciou sua jornada em direção ao destino prometido, mesmo sem saber exatamente para onde estava indo. Ele confiou na promessa de Deus e seguiu viagem com sua família e pertences. Sua atitude demonstra o início de uma caminhada baseada unicamente na palavra firme do Criador naquele tempo.' WHERE "id" = 'fecbcd66-d9a3-4567-8b97-90493a021c6e';
UPDATE "public"."dev_lessons" SET "share_summary" = 'O rei Nabucodonosor ergueu uma estátua de ouro e ordenou que todos os povos se prostrassem perante ela, sob pena de morte em uma fornalha ardente. Sadraque, Mesaque e Abednego recusaram-se a obedecer à ordem real. Diante do monarca, os três jovens afirmaram que seu Deus poderia livrá-los, mas declararam que, mesmo se isso não acontecesse, jamais adorariam o ídolo. Mantendo firme sua decisão diante da autoridade, eles enfrentaram a sentença e foram lançados dentro do fogo.' WHERE "id" = 'fed87b24-e7a0-40b4-9ec9-fbae858148ec';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Jesus viajava quando encontrou dez homens que sofriam de uma grave enfermidade na pele. Mantendo distância, eles clamaram por misericórdia ao Mestre. Atendendo ao pedido, Jesus curou todos instantaneamente enquanto caminhavam. Apenas um deles, ao perceber que fora sarado, voltou glorificando a Deus em alta voz e prostrou-se aos pés de Jesus para agradecer. Jesus então perguntou pelos outros nove, notando que somente aquele estrangeiro retornou para expressar sua profunda gratidão pelo milagre que acabara de receber.' WHERE "id" = 'ff25a3d5-0036-4bad-a82b-fc6a6cfdb8ab';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Após a morte de Salomão, Roboão assumiu o trono de Israel. Os anciãos aconselharam o novo rei a governar com justiça para manter a lealdade do povo. Contudo, Roboão rejeitou a sabedoria dos mais velhos e preferiu seguir as orientações autoritárias e arrogantes de seus jovens amigos. Essa decisão imprudente gerou grande descontentamento entre os israelitas. Como consequência direta dessa escolha, o reino foi dividido e Roboão perdeu o controle sobre dez das doze tribos de Israel rapidamente.' WHERE "id" = 'ff750cc1-a678-48b3-9886-31c1cd6b2888';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Davi fugiu ao perceber que Saul planejava matá-lo. Ao consultar Jônatas, o filho do rei, ambos confirmaram a intenção homicida de Saul contra o jovem. Jônatas, arriscando seu próprio futuro e a fúria do pai, estabeleceu um pacto de aliança com Davi. Ele revelou os planos de Saul e ajudou o amigo a escapar em segurança para o campo. Assim, Jônatas protegeu a vida de Davi, priorizando o juramento de lealdade mútua acima da sua posição real.' WHERE "id" = 'ffa931db-9b73-4073-88ac-ad393d6560a7';
UPDATE "public"."dev_lessons" SET "share_summary" = 'Em um único dia, Jó foi surpreendido pela perda devastadora de seus rebanhos, de todos os seus servos e de seus dez filhos. Diante da destruição repentina de tudo o que havia construído ao longo da vida, ele rasgou suas vestes em sinal de luto, raspou a cabeça e prostrou-se em adoração ao Senhor. O relato bíblico afirma que, mesmo sofrendo intensamente diante daquela tragédia incalculável, Jó não pecou e nem atribuiu qualquer erro a Deus.' WHERE "id" = 'ffc603e3-5db0-44a2-b9ae-51530cf91653';
